window.HADITH_CACHE["ibnu-majah_1"] = {"501":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ سُوَيْدِ بْنِ قَيْسٍ عَنْ مُعَاوِيَةَ بْنِ حُدَيْجٍ عَنْ مُعَاوِيَةَ بْنِ أَبِي سُفْيَانَأَنَّهُ سَأَلَ أُخْتَهُ أُمَّ حَبِيبَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِي الثَّوْبِ الَّذِي يُجَامِعُ فِيهِ قَالَتْ نَعَمْ إِذَا لَمْ يَكُنْ فِيهِ أَذًى","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] berkata, telah memberitakan kepada kami [Laits bin Sa'd] dari [Yazid bin Abu Habib] dari [Suwaid bin Qais] dari [Mu'awiyah bin Judaih] dari [Mu'awiyah bin Abu Sufyan]; bahwasanya ia pernah bertanya kepada saudara perempuannya, [Ummu Habibah], istri Nabi shallallahu 'alaihi wasallam; \"Apakah Rasulullah shallallahu 'alaihi wasallam pernah shalat dengan kain yang ia pakai untuk bersetubuh?\" Ummu Habibah menjawab; \"Iya, jika tidak terkena kotoran.\""},"502":{"ar":"حَدَّثَنَا هِشَامُ بْنُ خَالِدٍ الْأَزْرَقُ حَدَّثَنَا الْحَسَنُ بْنُ يَحْيَى الْخُشَنِيُّ حَدَّثَنَا زَيْدُ بْنُ وَاقِدٍ عَنْ بُسْرِ بْنِ عُبَيْدِ اللَّهِ عَنْ أَبِي إِدْرِيسَ الْخَوْلَانِيِّ عَنْ أَبِي الدَّرْدَاءِ قَالَخَرَجَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَأْسُهُ يَقْطُرُ مَاءً فَصَلَّى بِنَا فِي ثَوْبٍ وَاحِدٍ مُتَوَشِّحًا بِهِ قَدْ خَالَفَ بَيْنَ طَرَفَيْهِ فَلَمَّا انْصَرَفَ قَالَ عُمَرُ بْنُ الْخَطَّابِ يَا رَسُولَ اللَّهِ تُصَلِّي بِنَا فِي ثَوْبٍ وَاحِدٍ قَالَ نَعَمْ أُصَلِّي فِيهِ وَفِيهِ أَيْ قَدْ جَامَعْتُ فِيهِ","id":"Telah menceritakan kepada kami [Hisyam bin Khalid Al Azraq] berkata, telah menceritakan kepada kami [Al Hasan bin Yahya Al Khusyani] berkata, telah menceritakan kepada kami [Zaid bin Waqid] dari [Busr bin Ubaidullah] dari [Abu Idris Al Khaulani] dari [Abu Darda`] ia berkata; Rasulullah shallallahu 'alaihi wasallam keluar mengunjungi kami, sedang dari kepalanya mengalir air (sisa mandi), kemudian beliau shalat bersama kami dengan satu kain mutawakhisyan (memakai dengan cara menyelimutkan pada tubuh). Tatkala beliau berlalu pergi, Umar bin Al Khaththab bertanya; \"Ya Rasulullah, engkau mengimami kami dengan satu kain?\" beliau bersabda: \"Benar, aku shalat dengan mengenakan satu kain, dan di dalamnya ada sisa dari persetubuhanku.\" "},"503":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا يَحْيَى بْنُ يُوسُفَ الزِّمِّيُّ ح و حَدَّثَنَا أَحْمَدُ بْنُ عُثْمَانَ بْنِ حَكِيمٍ حَدَّثَنَا سُلَيْمَانُ بْنُ عُبَيْدِ اللَّهِ الرَّقِّيُّ قَالَا حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَمْرٍو عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَسَأَلَ رَجُلٌ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِي الثَّوْبِ الَّذِي يَأْتِي فِيهِ أَهْلَهُ قَالَ نَعَمْ إِلَّا أَنْ يَرَى فِيهِ شَيْئًا فَيَغْسِلَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Yahya bin Yusuf Az Zimmi]. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Ahmad bin Utsman bin Hakim] berkata, telah menceritakan kepada kami [Sulaiman bin Ubaidullah Ar Raqqi] keduanya berkata; telah menceritakan kepada kami [Ubaidullah bin 'Amru] dari [Abdul Malik bin Umair] dari [Jabir bin Samurah] ia berkata; Seorang laki-laki bertanya kepada Nabi shallallahu 'alaihi wasallam; \"apakah seseorang boleh shalat dengan mengenakan kain yang ia kenakan untuk bersetubuh dengan isterinya?\" beliau menjawab: \"Ya boleh, kecuali ia melihat sesuatu pada kain tersebut, maka hendaklah ia mencucinya.\""},"504":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ هَمَّامِ بْنِ الْحَارِثِ قَالَبَالَ جَرِيرُ بْنُ عَبْدِ اللَّهِ ثُمَّ تَوَضَّأَ وَمَسَحَ عَلَى خُفَّيْهِ فَقِيلَ لَهُ أَتَفْعَلُ هَذَا قَالَ وَمَا يَمْنَعُنِي وَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَفْعَلُهُقَالَ إِبْرَاهِيمُ كَانَ يُعْجِبُهُمْ حَدِيثُ جَرِيرٍ لِأَنَّ إِسْلَامَهُ كَانَ بَعْدَ نُزُولِ الْمَائِدَةِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Al A'masy] dari [Ibrahim] dari [Hammam Ibnul Harits] ia berkata; [Jarir bin Abdullah kencing], kemudian ia berwudlu dan mengusap khufnya. Lalu ditanyakan kepadanya; \"Kenapa engkau melakukan ini?\" ia menjawab; \"Apa yang menghalangiku! Aku pernah melihat Rasulullah shallallahu 'alaihi wasallam melakukan seperti itu.\" Ibrahim berkata; \"Orang-orang merasa ta'ajub dengan hadits Jarir, sebab ia masuk Islam setelah turunnya surat Al Maidah.\""},"505":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا أَبُو هَمَّامٍ الْوَلِيدُ بْنُ شُجَاعِ بْنِ الْوَلِيدِ حَدَّثَنَا أَبِي وَابْنُ عُيَيْنَةَ وَابْنُ أَبِي زَائِدَةَ جَمِيعًا عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ حُذَيْفَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ وَمَسَحَ عَلَى خُفَّيْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki']. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Abu Hammam Al Walid bin Syuja' bin Al Walid] berkata, telah menceritakan kepada kami [Bapakku] dan [Ibnu 'Uyainah] dan [Ibnu Abu Za`idah] semuanya dari [Al A'masy] dari [Abu Wa`il] dari [Hudzaifah] berkata; \"Rasulullah shallallahu 'alaihi wasallam berwudlu dan mengusap bagian atas kedua khufnya.\""},"506":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ نَافِعِ بْنِ جُبَيْرٍ عَنْ عُرْوَةَ بْنِ الْمُغِيرَةِ بْنِ شُعْبَةَ عَنْ أَبِيهِ الْمُغِيرَةِ بْنِ شُعْبَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ خَرَجَ لِحَاجَتِهِ فَاتَّبَعَهُ الْمُغِيرَةُ بِإِدَاوَةٍ فِيهَا مَاءٌ حَتَّى فَرَغَ مِنْ حَاجَتِهِ فَتَوَضَّأَ وَمَسَحَ عَلَى الْخُفَّيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Yahya bin Sa'id] dari [Sa'd bin Ibrahim] dari [Nafi' bin Jubair] dari [Urwah Ibnul Mughirah bin Syu'bah] dari bapaknya [Al Mughirah bin Syu'bah] dari Rasulullah shallallahu 'alaihi wasallam; bahwasanya beliau keluar untuk buang hajat, lalu Al Mughirah mengikutinya dengan membawa seember air, ketika selesai beliau berwudlu dan mengusap kedua khufnya.\""},"507":{"ar":"حَدَّثَنَا عِمْرَانُ بْنُ مُوسَى اللَّيْثِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ سَوَاءٍ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّهُ رَأَى سَعْدَ بْنَ مَالِكٍ وَهُوَ يَمْسَحُ عَلَى الْخُفَّيْنِ فَقَالَ إِنَّكُمْ لَتَفْعَلُونَ ذَلِكَ فَاجْتَمَعْنَا عِنْدَ عُمَرَ فَقَالَ سَعْدٌ لِعُمَرَ أَفْتِ ابْنَ أَخِي فِي الْمَسْحِ عَلَى الْخُفَّيْنِ فَقَالَ عُمَرُ كُنَّا وَنَحْنُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَمْسَحُ عَلَى خِفَافِنَا لَا نَرَى بِذَلِكَ بَأْسًا فَقَالَ ابْنُ عُمَرَ وَإِنْ جَاءَ مِنْ الْغَائِطِ قَالَ نَعَمْ","id":"Telah menceritakan kepada kami [Imran bin Musa Al Laitsi] berkata, telah menceritakan kepada kami [Muhammad bin Sawa] berkata, telah menceritakan kepada kami [Sa'id bin Abu 'Arubah] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar], Bahwasanya ia pernah melihat Sa'd bin Malik sedang mengusap kedua khufnya, maka ia pun bertanya; \"Apa alasan kalian melakukan itu?\" Maka kami berkumpul menghadap Umar, dan berkatalah Sa'd kepada Umar; \"Wahai putra saudaraku, berilah kami fatwa dalam masalah mengusap kedua khuf.\" [Umar] berkata: \"Ketika bersama Rasulullah shallallahu 'alaihi wasallam kami mengusap khuf, dan kami tidak menganggap tindakan itu salah.\" Ibnu Umar; \"Meski datang dari buang air besar?\" Ia menjawab; \"Iya.\" "},"508":{"ar":"حَدَّثَنَا أَبُو مُصْعَبٍ الْمَدَنِيُّ حَدَّثَنَا عَبْدُ الْمُهَيْمِنِ بْنُ الْعَبَّاسِ بْنِ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيُّ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَسَحَ عَلَى الْخُفَّيْنِ وَأَمَرَنَا بِالْمَسْحِ عَلَى الْخُفَّيْنِ","id":"Telah menceritakan kepada kami [Abu Mush'ab Al Madani] berkata, telah menceritakan kepada kami [Abdul Muhaimin bin Al 'Abbas bin Sahl bin Sa'd As Sa'idi] dari [Bapaknya] dari [Kakeknya] berkata; \"Rasulullah shallallahu 'alaihi wasallam mengusap kedua khufnya, dan beliau juga memerintahkan kami untuk mengusap kedua khuf.\""},"509":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا عُمَرُ بْنُ عُبَيْدٍ الطَّنَافِسِيُّ حَدَّثَنَا عُمَرُ بْنُ الْمُثَنَّى عَنْ عَطَاءٍ الْخُرَاسَانِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكُنْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَقَالَ هَلْ مِنْ مَاءٍ فَتَوَضَّأَ وَمَسَحَ عَلَى خُفَّيْهِ ثُمَّ لَحِقَ بِالْجَيْشِ فَأَمَّهُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] berkata, telah menceritakan kepada kami [Umar bin Ubaid At Thanafusi] berkata, telah menceritakan kepada kami [Umar bin Al Mutsanna] dari ['Atho` Al Khurasani] dari [Anas bin Malik] ia berkata; Aku pernah bersama Rasulullah shallallahu 'alaihi wasallam dalam suatu perjalanan, beliau bertanya: \"Apakah ada air?\" kemudian beliau pun berwudlu dan mengusap kedua khufnya. Setelah itu beliau menyusul tentara dan mengimami mereka.\""},"510":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا دَلْهَمُ بْنُ صَالِحٍ الْكِنْدِيُّ عَنْ حُجَيْرِ بْنِ عَبْدِ اللَّهِ الْكِنْدِيِّ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِأَنَّ النَّجَاشِيَّ أَهْدَى لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُفَّيْنِ أَسْوَدَيْنِ سَاذَجَيْنِ فَلَبِسَهُمَا ثُمَّ تَوَضَّأَ وَمَسَحَ عَلَيْهِمَا","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Dalham bin Shalih Al Kindi] dari [Hujair bin Abdullah Al Kindi] dari [Ibnu Buraidah] dari [Bapaknya] berkata; \"Raja Najasyi memberi hadiah kepada Nabi shallallahu 'alaihi wasallam dua khuf hitam yang sederhana, maka beliau memakainya, kemudian berwudlu dan mengusap keduanya.\""},"511":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا ثَوْرُ بْنُ يَزِيدَ عَنْ رَجَاءِ بْنِ حَيْوَةَ عَنْ وَرَّادٍ كَاتِبِ الْمُغِيرَةِ بْنِ شُعْبَةَ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَسَحَ أَعْلَى الْخُفِّ وَأَسْفَلَهُ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Tsaur bin Yazid] dari [Raja` bin Haiwah] dari [Warrad] penulis Al Mughirah bin Syu'bah, dari [Al Mughirah bin Syu'bah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam mengusap bagian atas dan bawah khufnya.\" "},"512":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُصَفَّى الْحِمْصِيُّ قَالَ حَدَّثَنَا بَقِيَّةُ عَنْ جَرِيرِ بْنِ يَزِيدَ قَالَ حَدَّثَنِي مُنْذِرٌ حَدَّثَنِي مُحَمَّدُ بْنُ الْمُنْكَدِرِ عَنْ جَابِرٍ قَالَمَرَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِرَجُلٍ يَتَوَضَّأُ وَيَغْسِلُ خُفَّيْهِ فَقَالَ بِيَدِهِ كَأَنَّهُ دَفَعَهُ إِنَّمَا أُمِرْتَ بِالْمَسْحِ وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدِهِ هَكَذَا مِنْ أَطْرَافِ الْأَصَابِعِ إِلَى أَصْلِ السَّاقِ وَخَطَّطَ بِالْأَصَابِعِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mushaffa Al Himshi] ia berkata; telah menceritakan kepada kami [Baqiyyah] dari [Jarir bin Yazid] ia berkata; telah menceritakan kepada kami [Mundzir] berkata, telah menceritakan kepada kami [Muhammad bin Al Munkadir] dari [Jabir] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam melewati seorang lelaki yang sedang berwudlu dan mencuci kedua khufnya, maka dengan tangannya seakan-akan mendorongnya beliau bersabda: \"Kamu hanya diperintah untuk mengusapnya.\" Beliau bersabda lagi sambil memperagakan dengan tangannya: \"Seperti ini.\" Mulai dari bagian ujung jari hingga ke pangkal betis, dan menggaris dengan jari-jarinya.\" "},"513":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ قَالَ سَمِعْتُ الْقَاسِمَ بْنَ مُخَيْمِرَةَ عَنْ شُرَيْحِ بْنِ هَانِئٍ قَالَسَأَلْتُ عَائِشَةَ عَنْ الْمَسْحِ عَلَى الْخُفَّيْنِ فَقَالَتْ ائْتِ عَلِيًّا فَسَلْهُ فَإِنَّهُ أَعْلَمُ بِذَلِكَ مِنِّي فَأَتَيْتُ عَلِيًّا فَسَأَلْتُهُ عَنْ الْمَسْحِ فَقَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُنَا أَنْ نَمْسَحَ لِلْمُقِيمِ يَوْمًا وَلَيْلَةً وَلِلْمُسَافِرِ ثَلَاثَةَ أَيَّامٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] ia berkata; aku mendengar [Al Qasim bin Mukhaimirah] dari [Syuraih bin Hani`] berkata; aku bertanya kepada Aisyah seputar mengusap kedua khuf, maka ia pun berkata; \"Datanglah kepada [Ali], sebab ia lebih tahu dariku dalam persoalan ini.\" Maka aku pun mendatanginya dan bertanya tentang mengusap khuf, maka ia menjawab; \"Rasulullah shallallahu 'alaihi wasallam memerintahkan kami, agar bagi orang yang muqim mengusap selama satu hari satu malam dan bagi orang yang safar tiga hari tiga malam.\""},"514":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ أَبِيهِ عَنْ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ عَمْرِو بْنِ مَيْمُونٍ عَنْ خُزَيْمَةَ بْنِ ثَابِتٍ قَالَجَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلْمُسَافِرِ ثَلَاثًا وَلَوْ مَضَى السَّائِلُ عَلَى مَسْأَلَتِهِ لَجَعَلَهَا خَمْسًا","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Sufyan] dari [Bapaknya] dari [Ibrahim At Taimi] dari ['Amru bin Maimun] dari [Khuzaimah bin Tsabit] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam menetapkan bagi orang yang muqim untuk mengusap khuf selama tiga hari, sekiranya orang yang bertanya itu tetap minta, sungguh beliau akan menetapkannya menjadi lima hari.\""},"515":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ قَالَ سَمِعْتُ إِبْرَاهِيمَ التَّيْمِيَّ يُحَدِّثُ عَنْ الْحَارِثِ بْنِ سُوَيْدٍ عَنْ عَمْرِو بْنِ مَيْمُونٍ عَنْ خُزَيْمَةَ بْنِ ثَابِتٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ثَلَاثَةُ أَيَّامٍ أَحْسِبُهُ قَالَ وَلَيَالِيهِنَّ لِلْمُسَافِرِ فِي الْمَسْحِ عَلَى الْخُفَّيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dari [Salamah bin Kuhail] ia berkata; aku mendengar [Ibrahim At Taimi] menceritakan dari [Al Harits bin Suwaid] dari ['Amru bin Maimun] dari [Khuzaimah bin Tsabit] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tiga hari, -dan aku kira beliau mengatakan; - \"dan tiga malam bagi musafir untuk mengusap kedua khufnya.\""},"516":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ قَالَ حَدَّثَنَا عُمَرُ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي خَثْعَمٍ الثُّمَالِيُّ قَالَ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالُوا يَا رَسُولَ اللَّهِ مَا الطُّهُورُ عَلَى الْخُفَّيْنِ قَالَ لِلْمُسَافِرِ ثَلَاثَةُ أَيَّامٍ وَلَيَالِيهِنَّ وَلِلْمُقِيمِ يَوْمٌ وَلَيْلَةٌ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Abu Kuraib] keduanya berkata; telah menceritakan kepada kami [Zaid bin Al Hubab] ia berkata; telah menceritakan kepada kami [Umar bin Abdullah bin Abu Khats'am Ats Tsumali] ia berkata; telah menceritakan kepada kami [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Abu Hurairah] ia berkata; Para sahabat bertanya; \"Ya Rasulullah, bagaimana cara bersucinya kedua khuf?\" Beliau menjawab: \"Bagi musafir tiga hari tiga malam, dan bagi orang yang muqim satu hari satu malam.\""},"517":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَبِشْرُ بْنُ هِلَالٍ الصَّوَّافُ قَالَا حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ عَبْدِ الْمَجِيدِ قَالَ حَدَّثَنَا الْمُهَاجِرُ أَبُو مَخْلَدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرَةَ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ رَخَّصَ لِلْمُسَافِرِ إِذَا تَوَضَّأَ وَلَبِسَ خُفَّيْهِ ثُمَّ أَحْدَثَ وُضُوءًا أَنْ يَمْسَحَ ثَلَاثَةَ أَيَّامٍ وَلَيَالِيَهُنَّ وَلِلْمُقِيمِ يَوْمًا وَلَيْلَةً","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] dan [Bisyr bin Hilal Ash Shawwaf] keduanya berkata; telah menceritakan kepada kami [Abdul Wahhab bin Abdul Majid] ia berkata; telah menceritakan kepada kami [Al Muhajir Abu Makhlad] dari [Abdurrahman bin Abu Bakrah] dari [Bapaknya] dari Nabi shallallahu 'alaihi wasallam; bahwa beliau memberi keringanan bagi seorang musafir yang mengenakan khuf, apabila ia batal dan ingin berwudlu, hendaknya ia mengusap selama tiga hari tiga malam, dan bagi orang yang muqim satu hari satu malam.\""},"518":{"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى وَعَمْرُو بْنُ سَوَّادٍ الْمِصْرِيَّانِ قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَنْبَأَنَا يَحْيَى بْنُ أَيُّوبَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ رَزِينٍ عَنْ مُحَمَّدِ بْنِ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ أَيُّوبَ بْنِ قَطَنٍ عَنْ عُبَادَةَ بْنِ نُسَيٍّ عَنْ أُبَيِّ بْنِ عِمَارَةَ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ صَلَّى فِي بَيْتِهِ الْقِبْلَتَيْنِ كِلْتَيْهِمَاأَنَّهُ قَالَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمْسَحُ عَلَى الْخُفَّيْنِ قَالَ نَعَمْ قَالَ يَوْمًا قَالَ وَيَوْمَيْنِ قَالَ وَثَلَاثًا حَتَّى بَلَغَ سَبْعًا قَالَ لَهُ وَمَا بَدَا لَكَ","id":"Telah menceritakan kepada kami [Harmalah bin Yahya] dan ['Amru bin Sawwad] keduanya berkata; telah menceritakan kepada kami [Abdullah bin Wahb] berkata, telah memberitakan kepada kami [Yahya bin Ayyub] dari [Abdurrahman bin Razin] dari [Muhammad bin Yazid bin Abu Ziyad] dari [Ayyub bin Qathan] dari [Ubadah bin Nusai] dari [Ubai bin 'Imarah], bahwasanya Rasulullah shallallahu 'alaihi wasallam pernah shalat di rumahnya menghadap dua kiblat, dan pada saat itu ia bertanya kepada Rasulullah shallallahu 'alaihi wasallam; \"Apakah aku boleh mengusap kedua khuf?\" beliau menjawab: \"Ya, \" ia bertanya lagi; \"Untuk sehari?\" beliau menjawab: \"Bisa juga untuk dua hari, \" ia bertanya; \"Dan tiga hari?\" hingga mencapai tujuh hari. Rasulullah menjawab: \"Terserah menurutmu.\" "},"519":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُوسُفَ السُّلَمِيُّ حَدَّثَنَا أَبُو عَاصِمٍ حَدَّثَنَا حَيْوَةُ بْنُ شُرَيْحٍ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ الْحَكَمِ بْنِ عَبْدِ اللَّهِ الْبَلَوِيِّ عَنْ عَلِيِّ بْنِ رَبَاحٍ اللَّخْمِيِّ عَنْ عُقْبَةَ بْنِ عَامِرٍ الْجُهَنِيِّأَنَّهُ قَدِمَ عَلَى عُمَرَ بْنِ الْخَطَّابِ مِنْ مِصْرَ فَقَالَ مُنْذُ كَمْ لَمْ تَنْزِعْ خُفَّيْكَ قَالَ مِنْ الْجُمُعَةِ إِلَى الْجُمُعَةِ قَالَ أَصَبْتَ السُّنَّةَ","id":"Telah menceritakan kepada kami [Ahmad bin Yusuf As Sulami] berkata, telah menceritakan kepada kami [Abu 'Ashim] berkata, telah menceritakan kepada kami [Haiwah bin Syuraih] dari [Yazid bin Abu Habib] dari [Al Hakam bin Abdullah Al Balwi] dari [Ali bin Rabah Al Lakhmi] dari [Uqbah bin Amir Al Juhani] bahwasanya ia datang dari Mesir menemui [Umar bin Al Khaththab], lalu bertanya, \"Sejak kapan kamu tidak melepas kedua khufmu?\" ia menjawab; \"Sejak hari Jum'at hingga hari jum'at.\" Umar berkata, \"Engkau telah sesuai sunnah.\""},"520":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي قَيْسٍ الْأَوْدِيِّ عَنْ الْهُزَيْلِ بْنِ شُرَحْبِيلَ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ وَمَسَحَ عَلَى الْجَوْرَبَيْنِ وَالنَّعْلَيْنِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Sufyan] dari [Abu Qais Al Audi] dari [Al Huzail bin Syurahbil] dari [Al Mughirah] berkata; \"Rasulullah shallallahu 'alaihi wasallam berwudlu lalu mengusap kedua kaus kaki dan kedua sandal.\""},"521":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا مُعَلَّى بْنُ مَنْصُورٍ وَبِشْرُ بْنُ آدَمَ قَالَا حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ عِيسَى بْنِ سِنَانٍ عَنْ الضَّحَّاكِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَرْزَبٍ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ وَمَسَحَ عَلَى الْجَوْرَبَيْنِ وَالنَّعْلَيْنِ قَالَ الْمُعَلَّى فِي حَدِيثِهِ لَا أَعْلَمُهُ إِلَّا قَالَ وَالنَّعْلَيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Mu'alla bin Manshur] dan [Bisyr bin Adam] keduanya berkata; telah menceritakan kepada kami [Isa bin Yunus] dari [Isa bin Sinan] dari [Adl Dlahhak bin Abdurrahman bin 'Arzab] dari [Abu Musa Al Asy'ari]; bahwasanya Rasulullah shallallahu 'alaihi wasallam berwudlu lalu mengusap kedua kaus kaki dan kedua sandalnya.\" Al Mu'alla berkata tentang haditsnya, \"Aku tidak mengetahui kecuali bahwa ia mengatakan, \"Dan kedua sandalnya.\""},"522":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ الْأَعْمَشِ عَنْ الْحَكَمِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ كَعْبِ بْنِ عُجْرَةَ عَنْ بِلَالٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَسَحَ عَلَى الْخُفَّيْنِ وَالْخِمَارِ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] berkata, telah menceritakan kepada kami [Isa bin Yunus] dari [Al A'masy] dari [Al Hakam] dari [Abdurrahman bin Abu Laila] dari [Ka'ab bin Ujrah] dari [Bilal] berkata; \"Rasulullah shallallahu 'alaihi wasallam mengusap kedua khuf dan khimarnya (semacam surban untuk ikat kepala).\""},"523":{"ar":"حَدَّثَنَا دُحَيْمٌ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ مُصْعَبٍ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ حَدَّثَنَا أَبُو سَلَمَةَ عَنْ عَمْرِو بْنِ أُمَيَّةَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْسَحُ عَلَى الْخُفَّيْنِ وَالْعِمَامَةِ","id":"Telah menceritakan kepada kami [Duhaim] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Al Auza'i]. (dalan jalur lain disebutkan, telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Muhammad bin Mush'ab] berkata, telah menceritakan kepada kami [Al Auza'i] berkata, telah menceritakan kepada kami [Yahya bin Abu Katsir] berkata, telah menceritakan kepada kami [Abu Salamah] dari ['Amru bin Umaiyyah] ia berkata; \"Aku melihat Rasulullah shallallahu 'alaihi wasallam mengusap kedua khuf dan imamahnya (surban yang dililitkan pada kepala).\""},"524":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ عَنْ دَاوُدَ بْنِ أَبِي الْفُرَاتِ عَنْ مُحَمَّدِ بْنِ زَيْدٍ عَنْ أَبِي شُرَيْحٍ عَنْ أَبِي مُسْلِمٍ مَوْلَى زَيْدِ بْنِ صُوحَانَ قَالَكُنْتُ مَعَ سَلْمَانَ فَرَأَى رَجُلًا يَنْزِعُ خُفَّيْهِ لِلْوُضُوءِ فَقَالَ لَهُ سَلْمَانُ امْسَحْ عَلَى خُفَّيْكَ وَعَلَى خِمَارِكَ وَبِنَاصِيَتِكَ فَإِنِّي رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْسَحُ عَلَى الْخُفَّيْنِ وَالْخِمَارِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yunus bin Muhammad] dari [Dawud bin Abul Furat] dari [Muhammad bin Zaid] dari [Abu Syuraih] dari [Abu Muslim] mantan budak Zaid bin Shuhan, ia berkata; Aku pernah bersama [Salman], tiba-tiba ia melihat seorang lelaki melepas kedua khufnya untuk berwudlu. Maka iapun menegurnya; \"Usaplah kedua khuf, imamah dan ubun-ubunmu. Karena aku pernah melihat Rasulullah shallallahu 'alaihi wasallam mengusap kedua khuf dan surbannya.\""},"525":{"ar":"حَدَّثَنَا أَبُو طَاهِرٍ أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ حَدَّثَنَا مُعَاوِيَةُ بْنُ صَالِحٍ عَنْ عَبْدِ الْعَزِيزِ بْنِ مُسْلِمٍ عَنْ أَبِي مَعْقِلٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ وَعَلَيْهِ عِمَامَةٌ قِطْرِيَّةٌ فَأَدْخَلَ يَدَهُ مِنْ تَحْتِ الْعِمَامَةِ فَمَسَحَ مُقَدَّمَ رَأْسِهِ وَلَمْ يَنْقُضْ الْعِمَامَةَ","id":"Telah menceritakan kepada kami [Abu Thahir Ahmad bin 'Amru bin As Sarh] berkata, telah menceritakan kepada kami [Abdullah bin Wahb] berkata, telah menceritakan kepada kami [Mu'awiyah bin Shalih] dari [Abdul Aziz bin Muslim] dari [Abu Ma'qil] dari [Anas bin Malik] ia berkata; \"Aku pernah melihat Rasulullah shallallahu 'alaihi wasallam berwudlu sementara beliau mengenakan imamah Qithriyyah, lalu beliau memasukkan tangannya pada bagian bawah surbannya, kemudian mengusap bagian depan kepalanya dan tidak melepaskan surbannya.\""},"526":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ عَمَّارِ بْنِ يَاسِرٍ أَنَّهُ قَالَسَقَطَ عِقْدُ عَائِشَةَ فَتَخَلَّفَتْ لِالْتِمَاسِهِ فَانْطَلَقَ أَبُو بَكْرٍ إِلَى عَائِشَةَ فَتَغَيَّظَ عَلَيْهَا فِي حَبْسِهَا النَّاسَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ الرُّخْصَةَ فِي التَّيَمُّمِ قَالَ فَمَسَحْنَا يَوْمَئِذٍ إِلَى الْمَنَاكِبِ قَالَ فَانْطَلَقَ أَبُو بَكْرٍ إِلَى عَائِشَةَ فَقَالَ مَا عَلِمْتُ إِنَّكِ لَمُبَارَكَةٌ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] berkata, telah menceritakan kepada kami [Al Laits bin Sa'd] dari [Ibnu Syihab] dari [Ubaidullah bin Abdullah] dari ['Ammar bin Yasir] bahwasanya ia berkata; kalung Aisyah jatuh hingga ia tertinggal karena mencarinya. Lalu Abu Bakar menemui Aisyah dengan murka karena pasukan tertahan melanjutkan perjalanan karena sebab dirinya. Maka Allah pun menurunkan ruhshah untuk bertayamum. 'Ammar bin Yasir berkata; \"Maka ketika itu kami mengusap hingga pundak-pundak kami.\" 'Ammar bin Yasir berkata; \"Akhirnya Abu Bakar pergi menemui Aisyah dan berkata; \"Aku tidak tahu bahwa engkau membawa berkah.\""},"527":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عُمَرَ الْعَدَنِيُّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرٍو عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ عَنْ عَمَّارِ بْنِ يَاسِرٍ قَالَتَيَمَّمْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْمَنَاكِبِ","id":"Telah menceritakan kepada kami [Muhammad bin Abu Umar Al Adani] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari ['Amru] dari [Az Zuhri] dari [Ubaidullah bin Abdullah] dari [Bapaknya] dari [Amar bin Yasir] berkata; \"Kami bersama Rasulullah shallallahu 'alaihi wasallam berwudlu hingga pundak.\""},"528":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ ح و حَدَّثَنَا أَبُو إِسْحَقَ الْهَرَوِيُّ حَدَّثَنَا إِسْمَعِيلُ بْنُ جَعْفَرٍ جَمِيعًا عَنْ الْعَلَاءِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُ��لَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ جُعِلَتْ لِي الْأَرْضُ مَسْجِدًا وَطَهُورًا","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib] berkata, telah menceritakan kepada kami [Abdul Aziz bin Abu Hazim]. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Abu Ishaq Al Harawi] berkata, telah menceritakan kepada kami [Isma'il bin Ja'far] semuanya dari [Al 'Ala`] dari [Bapaknya] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bumi dijadikan untukku sebagai masjid dan alat bersuci.\" "},"529":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّهَا اسْتَعَارَتْ مِنْ أَسْمَاءَ قِلَادَةً فَهَلَكَتْ فَأَرْسَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُنَاسًا فِي طَلَبِهَا فَأَدْرَكَتْهُمْ الصَّلَاةُ فَصَلَّوْا بِغَيْرِ وُضُوءٍ فَلَمَّا أَتَوْا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَكَوْا ذَلِكَ إِلَيْهِ فَنَزَلَتْ آيَةُ التَّيَمُّمِ فَقَالَ أُسَيْدُ بْنُ حُضَيْرٍ جَزَاكِ اللَّهُ خَيْرًا فَوَاللَّهِ مَا نَزَلَ بِكِ أَمْرٌ قَطُّ إِلَّا جَعَلَ اللَّهُ لَكِ مَخْرَجًا وَجَعَلَ لِلْمُسْلِمِينَ فِيهِ بَرَكَةً","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Usamah] dari [Hisyam bin 'Urwah] dari [Bapaknya] dari [Aisyah] bahwasanya ia pernah meminjam sebuah kalung dari Asma`, namun kalung itu hilang hingga Nabi shallallahu 'alaihi wasallam mengutus beberapa orang untuk mencarinya. Lalu waktu shalat tiba dan mereka shalat dengan tanpa wudlu, maka setelah kembali mereka mengadukan hal itu kepada Nabi shallallahu 'alaihi wasallam, dan turunlah ayat tentang tayamum. Usaid bin Hudlair lalu berkata; \"Semoga Allah memberimu kebaikan. Demi Allah, tidaklah Ia menurunkan ayat kepadamu kecuali itu merupakan jalan keluar bagimu dan berkah bagi kaum muslimin.\""},"530":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ ذَرٍّ عَنْ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِأَنَّ رَجُلًا أَتَى عُمَرَ بْنَ الْخَطَّابِ فَقَالَ إِنِّي أَجْنَبْتُ فَلَمْ أَجِدْ الْمَاءَ فَقَالَ عُمَرُ لَا تُصَلِّ فَقَالَ عَمَّارُ بْنُ يَاسِرٍ أَمَا تَذْكُرُ يَا أَمِيرَ الْمُؤْمِنِينَ إِذْ أَنَا وَأَنْتَ فِي سَرِيَّةٍ فَأَجْنَبْنَا فَلَمْ نَجِدْ الْمَاءَ فَأَمَّا أَنْتَ فَلَمْ تُصَلِّ وَأَمَّا أَنَا فَتَمَعَّكْتُ فِي التُّرَابِ فَصَلَّيْتُ فَلَمَّا أَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ ذَلِكَ لَهُ فَقَالَ إِنَّمَا كَانَ يَكْفِيكَ وَضَرَبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدَيْهِ إِلَى الْأَرْضِ ثُمَّ نَفَخَ فِيهِمَا وَمَسَحَ بِهِمَا وَجْهَهُ وَكَفَّيْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Dzar] dari [Sa'id bin Abdurrahman bin Abza] dari [Bapaknya] berkata; \"Seorang laki-laki datang menemui Umar Ibnul Khaththab dan bertanya; \"Aku junub namun tidak mendapatkan air?\" maka Umar menjawab; \"Janganlah engkau shalat.\" Lalu ['Ammar bin Yasir] berkata; \"Wahai Amirul Mukminin, tidakkah engkau ingat ketika aku dan engkau dalam sebuah ekspedisi mengalami junub dan kita tidak mendapatkan air. Waktu itu engkau tidak shalat sedangkan aku bergulingan di tanah kemudian shalat. Maka ketika aku datang menemui Nabi shallallahu 'alaihi wasallam dan aku sebutkan hal itu kepada beliau, beliau lalu bersabda: \"Sebenarnya cukup bagimu, lalu beliau memukulkan kedua tangannya ke tanah dan meniupnya, lalu beliau mengusapkan kedua tangannya ke wajah dan kedua telapak tangannya.\""},"531":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا حُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ ابْنِ أَبِي لَيْلَى عَنْ الْحَكَمِ وَسَلَمَةَ بْنِ كُهَيْلٍ أَنَّهُمَا سَأَلَا عَبْدَ اللَّهِ بْنَ أَبِي أَوْفَى عَنْ التَّيَمُّمِ فَقَالَأَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَمَّارًا أَنْ يَفْعَلَ هَكَذَا وَضَرَبَ بِيَدَيْهِ إِلَى الْأَرْضِ ثُمَّ نَفَضَهُمَا وَمَسَحَ عَلَى وَجْهِهِ قَالَ الْحَكَمُ وَيَدَيْهِ وَقَالَ سَلَمَةُ وَمِرْفَقَيْهِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Humaid bin Abdurrahman] dari [Ibnu Abu Laila] dari [Al Hakam] dan [Salamah bin Kuhail] bahwa keduanya bertanya kepada [Abdullah bin Abu Aufa] tentang tayamum, maka ia pun menjawab, \"Nabi shallallahu 'alaihi wasallam memerintahkan 'Ammar untuk melakukan seperti ini, lalu ia menepukkan kedua tangannya ke tanah, kemudian mengibaskannya dan mengusap mukanya, [Al Hakam] berkata; \"Dan kedua tangannya.\" Sementara [Salamah] menyebutkan, \"Dan kedua sikunya.\""},"532":{"ar":"حَدَّثَنَا أَبُو الطَّاهِرِ أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ الْمِصْرِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ قَالَ أَنْبَأَنَا يُونُسُ بْنُ يَزِيدَ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ عَمَّارِ بْنِ يَاسِرٍحِينَ تَيَمَّمُوا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ الْمُسْلِمِينَ فَضَرَبُوا بِأَكُفِّهِمْ التُّرَابَ وَلَمْ يَقْبِضُوا مِنْ التُّرَابِ شَيْئًا فَمَسَحُوا بِوُجُوهِهِمْ مَسْحَةً وَاحِدَةً ثُمَّ عَادُوا فَضَرَبُوا بِأَكُفِّهِمْ الصَّعِيدَ مَرَّةً أُخْرَى فَمَسَحُوا بِأَيْدِيهِمْ","id":"Telah menceritakan kepada kami [Abu Ath Thahir Ahmad bin 'Amru bin As Sarh Al Mishri] berkata, telah menceritakan kepada kami [Abdullah bin Wahb] berkata; telah memberitakan kepada kami [Yunus bin Yazid] dari [Ibnu Syihab] dari [Ubaidullah bin Abdullah] dari ['Ammar bin Yasir] ketika ia bertayamum bersama Rasulullah shallallahu 'alaihi wasallam beliau memerintahkan kaum muslimin, lalu mereka pun memukulkan kedua tangannya ke tanah tanpa menggenggam tanah sedikitpun, lalu mereka mengusap muka satu kali. Setelah itu mereka mengulangi lagi, mereka memukulkan kedua telapak tangannya ke tanah sekali lagi dan mengusapkannya ke tangan.\""},"533":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ حَبِيبِ بْنِ أَبِي الْعِشْرِينِ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ يُخْبِرُأَنَّ رَجُلًا أَصَابَهُ جُرْحٌ فِي رَأْسِهِ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ أَصَابَهُ احْتِلَامٌ فَأُمِر�� بِالِاغْتِسَالِ فَاغْتَسَلَ فَكُزَّ فَمَاتَ فَبَلَغَ ذَلِكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ قَتَلُوهُ قَتَلَهُمْ اللَّهُ أَوَلَمْ يَكُنْ شِفَاءَ الْعِيِّ السُّؤَالُ قَالَ عَطَاءٌ وَبَلَغَنَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَوْ غَسَلَ جَسَدَهُ وَتَرَكَ رَأْسَهُ حَيْثُ أَصَابَهُ الْجِرَاحُ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] berkata, telah menceritakan kepada kami [Abdul Hamid bin Hubaib bin Abu Al Isyrin] berkata, telah menceritakan kepada kami [Al Auza'i] dari ['Atho` bin Abu Rabah] berkata; aku mendengar [Ibnu 'Abbas] berkata; \"Pada masa Rasulullah shallallahu 'alaihi wasallam ada seorang laki-laki yang kepalanya terkena luka, laki-laki tersebut mimpi basah, lalu ia diperintahkan untuk mandi hingga lukanya bertambah parah dan mati. Maka sampailah berita itu kepada Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Mereka telah membunuhnya, semoga Allah akan membunuhnya. Tidaklah obat orang yang bodoh itu bertanya.\" 'Atho` berkata, \"Telah sampai kepada kami bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekiranya ia hanya membasuh badannya dan mengecualikan kepalanya yang terkena luka.\""},"534":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ كُرَيْبٍ مَوْلَى ابْنِ عَبَّاسٍ حَدَّثَنَا ابْنُ عَبَّاسٍ عَنْ خَالَتِهِ مَيْمُونَةَ قَالَتْوَضَعْتُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غُسْلًا فَاغْتَسَلَ مِنْ الْجَنَابَةِ فَأَكْفَأَ الْإِنَاءَ بِشِمَالِهِ عَلَى يَمِينِهِ فَغَسَلَ كَفَّيْهِ ثَلَاثًا ثُمَّ أَفَاضَ عَلَى فَرْجِهِ ثُمَّ دَلَكَ يَدَهُ بِالْأَرْضِ ثُمَّ مَضْمَضَ وَاسْتَنْشَقَ وَغَسَلَ وَجْهَهُ ثَلَاثًا وَذِرَاعَيْهِ ثَلَاثًا ثُمَّ أَفَاضَ الْمَاءَ عَلَى سَائِرِ جَسَدِهِ ثُمَّ تَنَحَّى فَغَسَلَ رِجْلَيْهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Al A'masy] dari [Salim bin Abu Al Ju'd] dari [Kuraib] -mantan pelayan Ibnu 'Abbas- telah menceritakan kepada kami [Ibnu 'Abbas] dari bibinya [Maimunah] ia berkata; \"Aku menyiapkan air mandi Nabi shallallahu 'alaihi wasallam, lalu beliau pun mandi junub. Beliau menuangkan bejana dengan tangan kirinya ke tangan kanan dan membasuhnya tiga kali, kemudian beliau menuangkan pada kemaluannya lalu menggosokkan tangannya ke bumi. Setelah itu beliau berkumur, memasukkan air ke hidung dan membasuh wajahnya tiga kali, serta kedua sikunya tiga kali. Kemudian menuangkan air ke seluruh tubuh, kemudian menjauh dari tempat mandinya dan mencuci kedua kakinya.\""},"535":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ حَدَّثَنَا صَدَقَةُ بْنُ سَعِيدٍ الْحَنَفِيُّ حَدَّثَنَا جُمَيْعُ بْنُ عُمَيْرٍ التَّيْمِيُّ قَالَانْطَلَقْتُ مَعَ عَمَّتِي وَخَالَتِي فَدَخَلْنَا عَلَى عَائِشَةَ فَسَأَلْنَاهَا كَيْفَ كَانَ يَصْنَعُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ غُسْلِهِ مِنْ الْجَنَابَةِ قَالَتْ كَانَ يُفِيضُ عَلَى كَفَّيْهِ ثَلَاثَ مَرَّاتٍ ثُمَّ يُدْخِلُهَا فِي الْإِنَاءِ ثُمَّ يَغْسِلُ رَأْسَهُ ثَلَاثَ مَرَّاتٍ ثُمَّ يُفِيضُ عَلَى جَسَدِهِ ثُمَّ يَقُومُ إِلَى الصَّلَاةِ وَأَمَّا نَحْنُ فَإِنَّا نَغْسِلُ رُؤْسَنَا خَمْسَ مَرَّاتٍ مِنْ أَجْلِ الضَّفْرِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul Malik bin Abu Asy Syawarib] berkata, telah menceritakan kepada kami [Abdul Wahid bin Ziyad] berkata, telah menceritakan kepada kami [Shodaqoh bin Sa'id Al Hanafi] berkata, telah menceritakan kepada kami [Jumai' bin Umair At Taimi] ia berkata; \"Aku bersama dengan bibiku dari pihak ayah dan ibu menemui Aisyah, lalu kami bertanya kepadanya bagaimana Rasulullah shallallahu 'alaihi wasallam mandi junub. [Aisyah] menjawab, \"Beliau menuangkan air ke dalam telapak tangannya tiga kali baru memasukkan tangannya ke dalam bejana. Dan membasuh kepalanya tiga kali baru menuangkan air ke seluruh tubuhnya. Setelah itu beliau pergi melaksanakan shalat. Adapun kami (isteri-isteri Nabi) mandi dengan membasuh kepala hingga lima kali karena masalah rambut (panjang).\""},"536":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي إِسْحَقَ عَنْ سُلَيْمَانَ بْنِ صُرَدٍ عَنْ جُبَيْرِ بْنِ مُطْعِمٍ قَالَتَمَارَوْا فِي الْغُسْلِ مِنْ الْجَنَابَةِ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَّا أَنَا فَأُفِيضُ عَلَى رَأْسِي ثَلَاثَ أَكُفٍّ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Al Ahwash] dari [Abu Ishaq] dari [Sulaiman bin Shurad] dari [Jubair bin Muth'im] ia berkata; \"Para sahabat berdebat masalah cara mandi junub di sisi Rasulullah shallallahu 'alaihi wasallam, maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Aku menuangkan air ke atas kepalaku sebanyak tiga telapak tangan.\" "},"537":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا ابْنُ فُضَيْلٍ جَمِيعًا عَنْ فُضَيْلِ بْنِ مَرْزُوقٍ عَنْ عَطِيَّةَ عَنْ أَبِي سَعِيدٍأَنَّ رَجُلًا سَأَلَهُ عَنْ الْغُسْلِ مِنْ الْجَنَابَةِ فَقَالَ ثَلَاثًا فَقَالَ الرَّجُلُ إِنْ شَعْرِي كَثِيرٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ أَكْثَرَ شَعْرًا مِنْكَ وَأَطْيَبَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki']. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Ibnu Fudlail] semuanya dari [Fudlail bin Marzuq] dari ['Athiyah] dari [Abu Sa'id] bahwa seorang laki-laki bertanya kepadanya tentang mandi junub, maka ia menjawab; \"Tiga kali.\" Lelaki itu bertanya kembali, \"Sesungguhnya rambutku sangat lebat.\" Abu Sa'id menjawab; \"Rasulullah shallallahu 'alaihi wasallam rambutnya lebih banyak dan lebih bagus dari rambutmu.\" "},"538":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ قَالَ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ جَابِرٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَنَا فِي أَرْضٍ بَارِدَةٍ فَكَيْفَ الْغُسْلُ مِنْ الْجَنَابَةِ فَقَالَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَّا أَنَا فَأَحْثُو عَلَى رَأْسِي ثَلَاثًا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata; telah menceritakan kepada kami [Hafsh bin Ghiyats] dari [Ja'far bin Muhammad] dari [Bapaknya] dari [Jabir] ia berkata; \"Wahai Rasulullah, aku berada di suatu wilayah yang sangat dingin, bagaimana aku harus mandi junub?\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Aku menuangkan air ke atas kepalaku sebanyak tiga kali.\""},"539":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بِنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ ابْنِ عَجْلَانَ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِي هُرَيْرَةَسَأَلَهُ رَجُلٌ كَمْ أُفِيضُ عَلَى رَأْسِي وَأَنَا جُنُبٌ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَحْثُو عَلَى رَأْسِهِ ثَلَاثَ حَثَيَاتٍ قَالَ الرَّجُلُ إِنَّ شَعْرِي طَوِيلٌ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكْثَرَ شَعْرًا مِنْكَ وَأَطْيَبَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Khallad Al Ahmar] dari [Ibnu 'Ajlan] dari [Sa'id bin Abu Sa'id] dari [Abu Hurairah] bahwa ia pernah ditanya oleh seorang laki-laki, \"Berapa kali aku harus menuangkan air ke atas kepalaku ketika junub?\" ia menjawab; \"Rasulullah shallallahu 'alaihi wasallam menuangkan tiga siraman di atas kepalanya.\" Laki-laki itu berkata; \"Sesungguhnya rambutku sangat panjang?\" Abu Hurairah berkata, \"Rasulullah shallallahu 'alaihi wasallam rambutnya lebih panjang dan lebih baik dari milikmu.\""},"540":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَبْدُ اللَّهِ بْنُ عَامِرِ بْنِ زُرَارَةَ وَإِسْمَعِيلُ بْنُ مُوسَى السُّدِّيُّ قَالُوا حَدَّثَنَا شَرِيكٌ عَنْ أَبِي إِسْحَقَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَتَوَضَّأُ بَعْدَ الْغُسْلِ مِنْ الْجَنَابَةِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Abdullah bin 'Amir bin Zurarah] dan [Isma'il bin Musa As Suddi] mereka berkata; telah menceritakan kepada kami [Syarik] dari [Abu Ishaq] dari [Al Aswad] dari [Aisyah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam tidak berwudlu setelah mandi janabah.\""},"541":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا شَرِيكٌ عَنْ حُرَيْثٍ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَغْتَسِلُ مِنْ الْجَنَابَةِ ثُمَّ يَسْتَدْفِئُ بِي قَبْلَ أَنْ أَغْتَسِلَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Syarik dari Huraits] dari [Huraits] dari [Asy Sya'bi] dari [Masruq] dari [Aisyah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam mandi dari janabah, kemudian beliau menghangatkan badannya pada tubuhku sebelum aku mandi.\""},"542":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ الْأَعْمَشِ عَنْ أَبِي إِسْحَقَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُجْنِبُ ثُمَّ يَنَامُ وَلَا يَمَسُّ مَاءً حَتَّى يَقُومَ بَعْدَ ذَلِكَ فَيَغْتَسِلَ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah menceritakan kepada kami [Abu Bakr bin Ayyasy] dari [Al A'masy] dari [Abu Ishaq] dari [Al Aswad] dari [Aisyah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam junub kemudian tidur tanpa menyentuh air. Setelah itu beliau bangun dan mandi.\""},"543":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي إِسْحَقَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ كَانَتْ لَهُ إِلَى أَهْلِهِ حَاجَةٌ قَضَاهَا ثُمَّ يَنَامُ كَهَيْئَتِهِ لَا يَمَسُّ مَاءً","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Al Ahwash] dari [Abu Ishaq] dari [Al Aswad] dari [Aisyah] ia berkata; \"Jika Rasulullah shallallahu 'alaihi wasallam ingin menyetubuhi isterinya, beliau melakukannya kemudian tidur dalam keadaan seperti itu tanpa menyentuh air.\""},"544":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُجْنِبُ ثُمَّ يَنَامُ كَهَيْئَتِهِ لَا يَمَسُّ مَاءًقَالَ سُفْيَانُ فَذَكَرْتُ الْحَدِيثَ يَوْمًا فَقَالَ لِي إِسْمَعِيلُ يَا فَتَى يُشَدُّ هَذَا الْحَدِيثُ بِشَيْءٍ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq] dari [Al Aswad] dari [Aisyah] berkata; \"Rasulullah shallallahu 'alaihi wasallam jika junub beliau tidur dalam keadaan seperti itu tanpa menyentuh air.\" Sufyan berkata; \"Pada suatu hari aku menyebutkan hadits ini, maka berkatalah Isma'il kepadaku; \"Wahai anak muda, hadits ini ada sesuatu yang mengikatnya (butuh penafsiran).\""},"545":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ الْمِصْرِيُّ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَرَادَ أَنْ يَنَامَ وَهُوَ جُنُبٌ تَوَضَّأَ وُضُوءَهُ لِلصَّلَاةِ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh Al Mishri] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Az Zuhri] dari [Abu Salamah] dari [Aisyah] ia berkata; \"Jika Rasulullah shallallahu 'alaihi wasallam ingin tidur dalam keadaan junub, maka beliau berwudlu sebagaimana wudlunya ketika shalat.\""},"546":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ عُمَرَ بْنَ الْخَطَّابِ قَالَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيَرْقُدُ أَحَدُنَا وَهُوَ جُنُبٌ قَالَ نَعَمْ إِذَا تَوَضَّأَ","id":"Telah menceritakan kepada kami [An Nashr bin Ali Al Jahdlami] berkata, telah menceritakan kepada kami [Abdul A'la] berkata, telah menceritakan kepada kami [Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] bahwa Umar Ibnul Khaththab berkata kepada Rasulullah shallallahu 'alaihi wasallam, \"Apakah salah seorang dari kami boleh tidur dalam keadaan junub?\" beliau menjawab: \"Boleh, jika berwudlu.\""},"547":{"ar":"حَدَّثَنَا أَبُو مَرْوَانَ الْعُثْمَانِيُّ مُحَمَّدُ بْنُ عُثْمَانَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ الْهَادِ عَنْ عَبْدِ اللَّهِ بْنِ خَبَّابٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّهُ كَانَ تُصِيبُهُ الْجَنَابَةُ بِاللَّيْلِ فَيُرِيدُ أَنْ يَنَامَ فَأَمَرَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَتَوَضَّأَ ثُمَّ يَنَامَ","id":"Telah menceritakan kepada kami [Abu Marwan Al Utsmani Muhammad bin Utsman] berkata, telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Yazid bin Abdullah bin Al Hal] dari [Abdullah bin Khabbab] dari [Abu Sa'id Al Khudri]; bahwasanya pada suatu malam ia junub lalu ingin tidur kembali, namun Rasulullah shallallahu 'alaihi wasallam memerintahkannya untuk berwudlu baru setelah itu tidur.\" "},"548":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ حَدَّثَنَا عَاصِمٌ الْأَحْوَلُ عَنْ أَبِي الْمُتَوَكِّلِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَتَى أَحَدُكُمْ أَهْلَهُ ثُمَّ أَرَادَ أَنْ يَعُودَ فَلْيَتَوَضَّأْ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul Malik bin Abu Asy Syawarib] berkata, telah menceritakan kepada kami [Abdul Wahid bin Ziyad] berkata, telah menceritakan kepada kami ['Ashim Al Ahwal] dari [Abu Al Mutawakkil] dari [Abu Sa'id Al Khudri] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian menyetubuhi isterinya dan ingin mengulanginya, hendaklah ia berwudlu.\""},"549":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ وَأَبُو أَحْمَدَ عَنْ سُفْيَانَ عَنْ مَعْمَرٍ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَطُوفُ عَلَى نِسَائِهِ فِي غُسْلٍ وَاحِدٍ","id":"Telah menceritakan kepada kami [Muhammad Ibnul Mutsanna] berkata, telah menceritakan kepada kami [Abdurrahman bin Mahdi] dan [Abu Ahmad] dari [Sufyan] dari [Ma'mar] dari [Qotadah] dari [Anas] berkata; \"Nabi shallallahu 'alaihi wasallam menggilir isteri-isterinya dengan satu kali mandi.\""},"550":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ صَالِحِ بْنِ أَبِي الْأَخْضَرِ عَنْ الزُّهْرِيِّ عَنْ أَنَسٍ قَالَوَضَعْتُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غُسْلًا فَاغْتَسَلَ مِنْ جَمِيعِ نِسَائِهِ فِي لَيْلَةٍ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Shalih bin Abu Al Ahdlar] dari [Az Zuhri] dari [Anas] ia berkata; \"Aku menyediakan air untuk mandi Rasulullah shallallahu 'alaihi wasallam, lalu beliau mandi setelah menggilir semua isterinya dalam satu malam.\""},"551":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَنْبَأَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا حَمَّادٌ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي رَافِعٍ عَنْ عَمَّتِهِ سَلْمَى عَنْ أَبِي رَافِعٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَافَ عَلَى نِسَائِهِ فِي لَيْلَةٍ وَكَانَ يَغْتَسِلُ عِنْدَ كُلِّ وَاحِدَةٍ مِنْهُنَّ فَقِيلَ لَهُ يَا رَسُولَ اللَّهِ أَلَا تَجْعَلُهُ غُسْلًا وَاحِدًا فَقَالَ هُوَ أَزْكَى وَأَطْيَبُ وَأَطْهَرُ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] berkata, telah memberitakan kepada kami [Abdu Ash Shamad] berkata, telah menceritakan kepada kami [Hammad] berkata, telah menceritakan kepada kami [Abdurrahman bin Abu Rafi'] dari bibinya [Salma] dari [Abu Rafi'], berkata; \"Nabi shallallahu 'alaihi wasallam menggilir semua isterinya semalam, dan beliau mandi setiap menggilir salah seorang dari mereka. Beliau lalu ditanya; \"Ya Rasulullah, kenapa tidak engkau jadikan dalam satu kali mandi saja?\" Beliau menjawab: \"Hal itu lebih bersih, lebih baik dan lebih suci.\""},"552":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا ابْنُ عُلَيَّةَ وَغُنْدَرٌ وَوَكِيعٌ عَنْ شُعْبَةَ عَنْ الْحَكَمِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَرَادَ أَنْ يَأْكُلَ وَهُوَ جُنُبٌ تَوَضَّأَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ibnu 'Ulayyah] dan [Ghundar] dan [Waki'] dari [Syu'bah] dari [Al Hakam] dari [Ibrahim] dari [Al Aswad] dari [Aisyah] ia berkata; \"Jika Rasulullah shallallahu 'alaihi wasallam ingin makan ketika dalam kondisi junub beliau berwudlu terlebih dahulu.\""},"553":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُمَرَ بْنِ هَيَّاجٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ صُبَيْحٍ حَدَّثَنَا أَبُو أُوَيْسٍ عَنْ شُرَحْبِيلَ بْنِ سَعْدٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَسُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْجُنُبِ هَلْ يَنَامُ أَوْ يَأْكُلُ أَوْ يَشْرَبُ قَالَ نَعَمْ إِذَا تَوَضَّأَ وُضُوءَهُ لِلصَّلَاةِ","id":"Telah menceritakan kepada kami [Muhammad bin Umar bin Hayyaj] berkata, telah menceritakan kepada kami [Isma'il bin Shubaih] berkata, telah menceritakan kepada kami [Abu Uwais] dari [Syurahbil bin Sa'd] dari [Jabir bin Abdullah] ia berkata; Nabi shallallahu 'alaihi wasallam ditanya tentang junub; \"bolehkah seseorang tidur, atau makan, atau minum (dalam keadaan junub)?\" beliau bersabda: \"Boleh, jika ia berwudlu sebagaimana wudlunya untuk shalat.\""},"554":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ ابْنُ الْمُبَارَكِ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا أَرَادَ أَنْ يَأْكُلَ وَهُوَ جُنُبٌ غَسَلَ يَدَيْهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdullah Ibnul Mubarak] dari [Yunus] dari [Az Zuhri] dari [Abu Salamah] dari [Aisyah], ia menuturkan; \"Nabi shallallahu 'alaihi wasallam jika ingin makan sedang beliau dalam keadaan junub, maka beliau mencuci tangannya.\""},"555":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ عَبْدِ اللَّهِ بْنِ سَلَمَةَ قَالَدَخَلْتُ عَلَى عَلِيِّ بْنِ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُ فَقَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْتِي الْخَلَاءَ فَيَقْضِي الْحَاجَةَ ثُمَّ يَخْرُجُ فَيَأْكُلُ مَعَنَا الْخُبْزَ وَاللَّحْمَ وَيَقْرَأُ الْقُرْآنَ وَلَا يَحْجُبُهُ وَرُبَّمَا قَالَ لَا يَحْجُزُهُ عَنْ الْقُرْآنِ شَيْءٌ إِلَّا الْجَنَابَةُ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dari ['Amru bin Murrah] dari [Abdullah bin Salamah] ia berkata; Aku menemui [Ali bin Abu Thalib], lalu ia berkata; \"Rasulullah shallallahu 'alaihi wasallam masuk ke dalam WC dan menyelesaikan hajatnya, kemudian beliau keluar lalu makan roti dan daging serta membaca Al Qur`an bersama kami, dan tidak ada yang menghalanginya, -dan mungkin saja ia mengatakan; - \"tidak ada yang menghalanginya untuk membaca Al Qur`an selain junub.\""},"556":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَقْرَأُ الْقُرْآنَ الْجُنُبُ وَلَا الْحَائِضُقَالَ أَبُو الْحَسَنِ وَحَدَّثَنَا أَبُو حَاتِمٍ حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَقْرَأُ الْجُنُبُ وَالْحَائِضُ شَيْئًا مِنْ الْقُرْآنِ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] berkata, telah menceritakan kepada kami [Isma'il bin 'Ayyasy] berkata, telah menceritakan kepada kami [Musa bin Uqbah] dari [Nafi'] dari [Ibnu Umar] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang junub dan wanita haid tidak boleh membaca Al Qur`an.\" Abul Hasan berkata; telah menceritakan kepada kami Abu Hatim berkata, telah menceritakan kepada kami Hisyam bin 'Ammar berkata, telah menceritakan kepada kami Isma'il bin Ayyasy berkata, telah menceritakan kepada kami Musa bin 'Uqbah dari Nafi' dari Ibnu Umar ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang junub dan wanita haid tidak boleh membaca sesuatu pun dari Al Qur`an.\" "},"557":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا الْحَارِثُ بْنُ وَجِيهٍ حَدَّثَنَا مَالِكُ بْنُ دِينَارٍ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ تَحْتَ كُلِّ شَعَرَةٍ جَنَابَةً فَاغْسِلُوا الشَّعَرَ وَأَنْقُوا الْبَشَرَةَ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] berkata, telah menceritakan kepada kami [Al Harits bin Wajih] berkata, telah menceritakan kepada kami [Malik bin Dinar] dari [Muhammad bin Sirin] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya di bawah setiap rambut itu terdapat janabah, maka basuhlah rambut dan bersihkan kulit wajah kalian.\""},"558":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ حَدَّثَنِي عُتْبَةُ بْنُ أَبِي حَكِيمٍ حَدَّثَنِي طَلْحَةُ بْنُ نَافِعٍ حَدَّثَنِي أَبُو أَيُّوبَ الْأَنْصَارِيُّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الصَّلَوَاتُ الْخَمْسُ وَالْجُمُعَةُ إِلَى الْجُمُعَةِ وَأَدَاءُ الْأَمَانَةِ كَفَّارَةٌ لِمَا بَيْنَهَا قُلْتُ وَمَا أَدَاءُ الْأَمَانَةِ قَالَ غُسْلُ الْجَنَابَةِ فَإِنَّ تَحْتَ كُلِّ شَعَرَةٍ جَنَابَةً","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] berkata, telah menceritakan kepada kami [Yahya bin Hamzah] berkata, telah menceritakan kepada saya ['Utbah bin Abu Hakim] berkata, telah menceritakan kepadaku [Thalhah bin Nafi'] berkata, telah menceritakan kepadaku [Abu Ayyub Al Anshari] berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Shalat lima waktu, jum'at ke jum'at berikutnya dan menunaikan amanah adalah penghapus dosa.\" Aku bertanya; \"Apa yang dimaksud dengan menunaikan amanah?\" beliau menjawab: \"Mandi janabah, sesungguhnya di bawah setiap rambut itu terdapat janabah.\""},"559":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا الْأَسْوَدُ بْنُ عَامِرٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ زَاذَانَ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ تَرَكَ مَوْضِعَ شَعَرَةٍ مِنْ جَسَدِهِ مِنْ جَنَابَةٍ لَمْ يَغْسِلْهَا فُعِلَ بِهِ كَذَا وَكَذَا مِنْ النَّارِقَالَ عَلِيٌّ فَمِنْ ثَمَّ عَادَيْتُ شَعَرِي وَكَانَ يَجُزُّهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Al Aswad bin Amir] berkata, telah menceritakan kepada kami [Hammad bin Salamah] dari ['Atho` bin As Sa`ib] dari [Zadzan] dari [Ali bin Abu Thalib], dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa meninggalkan sekadar satu lembar rambut dari tubuhnya ketika mandi junub, maka ia akan diperlakukan begini dan begini dalam neraka.\" Ali berkata; \"Karena itu aku selalu mengulang-ulang (membasuh) rambutku.\" Dan ia memendekkan rambutnya."},"560":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْن�� أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ زَيْنَبَ بِنْتِ أُمِّ سَلَمَةَ عَنْ أُمِّهَا أَمِّ سَلَمَةَ قَالَتْجَاءَتْ أُمُّ سُلَيْمٍ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَتْهُ عَنْ الْمَرْأَةِ تَرَى فِي مَنَامِهَا مَا يَرَى الرَّجُلُ قَالَ نَعَمْ إِذَا رَأَتْ الْمَاءَ فَلْتَغْتَسِلْ فَقُلْتُ فَضَحْتِ النِّسَاءَ وَهَلْ تَحْتَلِمُ الْمَرْأَةُ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَرِبَتْ يَمِينُكِ فَبِمَ يُشْبِهُهَا وَلَدُهَا إِذًا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Hisyam bin 'Urwah] dari [Bapaknya] dari [Zainah binti Ummu Salamah] dari ibunya [Ummu Salamah] ia berkata; Ummu Sulaim datang menemui Nabi shallallahu 'alaihi wasallam dan bertanya tentang seorang wanita yang mimpi basah dalam tidurnya sebagaimana seorang laki-laki bermimpi, maka beliau menjawab: \"Ya, jika ia melihat air maka hendaklah ia mandi.\" Aku berkata; \"Engkau telah membuka aiلا wanita, apakah wanita juga bisa bermimpi?\" Nabi shallallahu 'alaihi wasallam menjawab: \"semoga engkau selalu bersama keuntungan, kalau begitu dari mana anaknya dapat menyerupainya! \""},"561":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ وَعَبْدُ الْأَعْلَى عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ أُمَّ سُلَيْمٍ سَأَلَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمَرْأَةِ تَرَى فِي مَنَامِهَا مَا يَرَى الرَّجُلُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَأَتْ ذَلِكَ فَأَنْزَلَتْ فَعَلَيْهَا الْغُسْلُ فَقَالَتْ أُمُّ سَلَمَةَ يَا رَسُولَ اللَّهِ أَيَكُونُ هَذَا قَالَ نَعَمْ مَاءُ الرَّجُلِ غَلِيظٌ أَبْيَضُ وَمَاءُ الْمَرْأَةِ رَقِيقٌ أَصْفَرُ فَأَيُّهُمَا سَبَقَ أَوْ عَلَا أَشْبَهَهُ الْوَلَدُ","id":"Telah menceritakan kepada kami [Muhammad Ibnul Mutsanna] berkata, telah menceritakan kepada kami [Ibnu Abu Adi] dan [Abdul A'la] dari [Sa'id bin Abu 'Arubah] dari [Qotadah] dari [Anas] bahwa Ummu Sulaim bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang seorang wanita yang bermimpi dalam tidur sebagaimana seorang laki-laki bermimpi. Maka Rasulullah shallallahu 'alaihi wasallam menjawab: \"Jika seorang wanita bermimpi seperti itu hingga orgasme maka ia wajib mandi.\" Ummu Salamah berkata; \"Wahai Rasulullah, mungkinkah itu terjadi?\" beliau menjawab; \"Ya, air laki-laki kental berwarna putih, sedangkan air wanita adalah cair dan berwarna kuning. Manapun keduanya yang lebih dahulu, atau lebih tinggi maka anaknya nanti akan menyerupainya.\""},"562":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ خَوْلَةَ بِنْتِ حَكِيمٍ أَنَّهَاسَأَلَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمَرْأَةِ تَرَى فِي مَنَامِهَا مَا يَرَى الرَّجُلُ فَقَالَ لَيْسَ عَلَيْهَا غُسْلٌ حَتَّى تُنْزِلَ كَمَا أَنَّهُ لَيْسَ عَلَى الرَّجُلِ غُسْلٌ حَتَّى يُنْزِلَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Ali bin Zaid] dari [Sa'id Ibnul Musayyab] dari [Khaulah binti Hakim]; bahwasanya ia bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang seorang wanita yang mimpi basah dalam tidur sebagaimana seorang laki-laki mimpi, maka beliau menjawab: \"Ia tidak wajib mandi hingga orgasme sebagaimana seorang laki-laki tidak wajib mandi hingga ia orgasme.\""},"563":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَيُّوبَ بْنِ مُوسَى عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ عَنْ عَبْدِ اللَّهِ بْنِ رَافِعٍ عَنْ أُمِّ سَلَمَةَ قَالَتْقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي امْرَأَةٌ أَشُدُّ ضَفْرَ رَأْسِي أَفَأَنْقُضُهُ لِغُسْلِ الْجَنَابَةِ فَقَالَ إِنَّمَا يَكْفِيكِ أَنْ تَحْثِي عَلَيْهِ ثَلَاثَ حَثَيَاتٍ مِنْ مَاءٍ ثُمَّ تُفِيضِي عَلَيْكِ مِنْ الْمَاءِ فَتَطْهُرِينَ أَوْ قَالَ فَإِذَا أَنْتِ قَدْ طَهُرْتِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Ayyub bin Musa] dari [Sa'id bin Abu Sa'id Al Khudri] dari [Abdullah bin Rafi'] dari [Ummu Salamah] ia berkata; Aku bertanya; \"Wahai Rasulullah, aku adalah wanita yang kuat ikatan rambutnya, apakah aku harus membuka gulungan rambutku untuk mandi junub?\" beliau bersabda: \"Sebenarnya cukup bagimu untuk menuangkan tiga kali tuangan air, setelah itu guyurlah tubuhmu dan bersuci dengan air, -atau beliau mengatakan; - \"Jika demikian maka engkau telah suci.\""},"564":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ أَيُّوبَ عَنْ أَبِي الزُّبَيْرِ عَنْ عُبَيْدِ بْنِ عُمَيْرٍ قَالَ بَلَغَ عَائِشَةَأَنَّ عَبْدَ اللَّهِ بْنَ عَمْرٍو يَأْمُرُ نِسَاءَهُ إِذَا اغْتَسَلْنَ أَنْ يَنْقُضْنَ رُءُوسَهُنَّ فَقَالَتْ يَا عَجَبًا لِابْنِ عَمْرٍو هَذَا أَفَلَا يَأْمُرُهُنَّ أَنْ يَحْلِقْنَ رُءُوسَهُنَّ لَقَدْ كُنْتُ أَنَا وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَغْتَسِلُ مِنْ إِنَاءٍ وَاحِدٍ فَلَا أَزِيدُ عَلَى أَنْ أُفْرِغَ عَلَى رَأْسِي ثَلَاثَ إِفْرَاغَاتٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Isma'il bin 'Ulaiyah] dari [Ayyub] dari [Abu Az Zubair] dari [Ubaid bin Umair] berkata; Telah sampai kepada [Aisyah] bahwa Abdullah bin 'Amru menyuruh isteri-isterinya membuka gulungan rambutnya ketika mandi junub. Maka Aisyah pun berkata; \"Mengherankan sekali Ibnu 'Amru ini, kenapa tidak sekalian ia perintahkan isteri-isterinya untuk menggundul kepalanya? Sungguh, aku pernah mandi bersama Rasulullah shallallahu 'alaihi wasallam dalam satu bejana, aku tidak menambah siraman pada rambut kepalaku selain tiga guyuran air.\""},"565":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عِيسَى وَحَرْمَلَةُ بْنُ يَحْيَى الْمِصْرِيَّانِ قَالَا حَدَّثَنَا بْنُ وَهْبٍ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ أَنَّ أَبَا السَّائِبِ مَوْلَى هِشَامِ بْنِ زُهْرَةَ حَدَّثَهُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَغْتَسِلْ أَحَدُكُمْ فِي الْمَاءِ الدَّائِمِ وَهُوَ جُنُبٌ فَقَالَ كَيْفَ يَفْعَلُ يَا أَبَا هُرَيْرَةَ قَالَ يَتَنَاوَلُهُ تَنَاوُلًا","id":"Telah menceritakan kepada kami [Ahmad bin Isa Al Mishri] dan [Harmalah bin Yahya Al Mishri] keduanya berkata; telah menceritakan kepada kami [Ibnu Wahb] dari ['Amru Ibnul Harits] dari [Bukair bin Abdullah Ibnul Asyaj] bahwa [Abu Sa`ib] mantan budak Hisyam bin Zuhrah menceritakan kepadanya; bahwa ia mendengar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah salah seorang dari kalian mandi dalam air yang diam (tidak mengalir) sedang ia dalam keadaan junub.\" Abu As Sa`ib berkata; \"Lalu apa yang dilakukan Rasulullah, wahai Abu Hurairah?\" ia menjawab; \"Beliau mengambilnya alakadarnya saja (sekedar untuk mandi).\""},"566":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا غُنْدَرٌ مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ شُعْبَةَ عَنْ الْحَكَمِ عَنْ ذَكْوَانَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ عَلَى رَجُلٍ مِنْ الْأَنْصَارِ فَأَرْسَلَ إِلَيْهِ فَخَرَجَ رَأْسُهُ يَقْطُرُ فَقَالَ لَعَلَّنَا أَعْجَلْنَاكَ قَالَ نَعَمْ يَا رَسُولَ اللَّهِ قَالَ إِذَا أُعْجِلْتَ أَوْ أُقْحِطْتَ فَلَا غُسْلَ عَلَيْكَ وَعَلَيْكَ الْوُضُوءُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Muhammad bin Basysyar] keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] dari [Syu'bah] dari [Al Hakam] dari [Dzakwan] dari [Abu Sa'id Al Khudri] berkata; \"Rasulullah shallallahu 'alaihi wasallam melewati seorang lelaki Anshar, lalu beliau mengutus utusan kepadanya hingga ia keluar menemui Rasulullah dengan rambut yang masih basah. Maka beliau pun bertanya: \"Sepertinya kami telah menjadikan kamu terburu-buru?\" laki-laki itu menjawab; \"Benar, wahai Rasulullah.\" Beliau bersabda: \"Jika engkau dibuat terburu-buru (menyelesaikan persetubuhan), -atau beliau mengatakan, - \"engkau belum mencapai orgasme, maka engkau tidak perlu mandi dan cukup bagimu berwudlu.\""},"567":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ ابْنِ السَّائِبِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سُعَادَ عَنْ أَبِي أَيُّوبَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَاءُ مِنْ الْمَاءِ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari ['Amru bin Dinar] dari [Ibnu As Sa`ib] dari [Abdurrahman bin Su'ad] dari [Abu Ayyub] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Adanya air (mandi) itu karena air (mani).\""},"568":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ الطَّنَافِسِيُّ وَعَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ قَالَا حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ أَنْبَأَنَا عَبْدُ الرَّحْمَنِ بْنُ الْقَاسِمِ أَخْبَرَنَا الْقَاسِمُ بْنُ مُحَمَّدٍ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْإِذَا الْتَقَى الْخِتَانَانِ فَقَدْ وَجَبَ الْغُسْلُ فَعَلْتُهُ أَنَا وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاغْتَسَلْنَا","id":"Telah menceritakan kepada kami [Ali bin Muhammad Ath Thanafusi] dan [Abdurrahman bin Ibrahim Ad Dimasyqi] keduanya berkata; telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Al Auza'i] berkata, telah memberitakan kepada kami [Abdurrahman Ibnul Qasim] berkata, telah mengabarkan kepada kami [Al Qasim bin Muhammad] dari [Aisyah] isteri Nabi shallallahu 'alaihi wasallam, ia menuturkan; \"Jika dua khitan telah bertemu maka telah wajib mandi. Aku dan Rasulullah shallallahu 'alaihi wasallam pernah melakukannya hingga kami pun mandi.\""},"569":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ أَنْبَأَنَا يُونُسُ عَنْ الزُّهْرِيِّ قَالَ قَالَ سَهْلُ بْنُ سَعْدٍ السَّاعِدِيُّ أَنْبَأَنَا أُبَيُّ بْنُ كَعْبٍ قَالَإِنَّمَا كَانَتْ رُخْصَةً فِي أَوَّلِ الْإِسْلَامِ ثُمَّ أُمِرْنَا بِالْغُسْلِ بَعْدُ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Utsman bin Umar] berkata, telah memberitakan kepada kami [Yunus] dari [Az Zuhri] ia berkata; [Sahal bin Sa'd As Sa'idi] berkata, telah memberitakan kepada kami [Ubai bin Ka'ab] ia berkata; \"Hal itu adalah keringanan di awal-awal Islam, setelah itu kami diperintahkan untuk mencuci.\""},"570":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا الْفَضْلُ بْنُ دُكَيْنٍ عَنْ هِشَامٍ الدَّسْتُوَائِيِّ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ أَبِي رَافِعٍ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا جَلَسَ الرَّجُلُ بَيْنَ شُعَبِهَا الْأَرْبَعِ ثُمَّ جَهَدَهَا فَقَدْ وَجَبَ الْغُسْلُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Al Fadhl bin Dukain] dari [Hisyam Ad Dustuwa`i] dari [Qotadah] dari [Al Hasan] dari [Abu Rafi'] dari [Abu Hurairah], dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Jika seorang laki-laki duduk di atas empat cabangnya yang empat lalu bersungguh-sungguh, maka ia wajib mandi.\""},"571":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ حَجَّاجٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا الْتَقَى الْخِتَانَانِ وَتَوَارَتْ الْحَشَفَةُ فَقَدْ وَجَبَ الْغُسْلُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Hajjaj] dari ['Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika dua khitan bertemu dan kepala dzakar (penis) laki-laki tersembunyi dalam kemaluan wanita, wajib mandi.\""},"572":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا حَمَّادُ بْنُ خَالِدٍ عَنْ الْعُمَرِيِّ عَنْ عُبَيْدِ اللَّهِ عَنْ الْقَاسِمِ عَنْ عَائِشَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا اسْتَيْقَظَ أَحَدُكُمْ مِنْ نَوْمِهِ فَرَأَى بَلَلًا وَلَمْ يَرَ أَنَّهُ احْتَلَمَ اغْتَسَلَ وَإِذَا رَأَى أَنَّهُ قَدْ احْتَلَمَ وَلَمْ يَرَ بَلَلًا فَلَا غُسْلَ عَلَيْهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Hammad bin Khalid] dari [Al Umari] dari [Ubaidullah] dari [Al Qasim] dari [Aisyah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika salah seorang dari kalian bangun tidur lalu mendapati sesuatu yang basah padahal tidak merasa bermimpi, maka ia wajib mandi. Dan barangsiapa bermimpi namun tidak mendapatkan sesuatu yang basah, maka ia tidak wajib mandi.\""},"573":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ الْعَنْبَرِيُّ وَأَبُو حَفْصٍ عَمْرُو بْنُ عَلِيٍّ الْفَلَّاسُ وَمُجَاهِدُ بْنُ مُوسَى قَالُوا حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا يَحْيَى بْنُ الْوَلِيدِ أَخْبَرَنِي مُحِلُّ بْنُ خَلِيفَةَ حَدَّثَنِي أَبُو السَّمْحِ قَالَكُنْتُ أَخْدُمُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَانَ إِذَا أَرَادَ أَنْ يَغْتَسِلَ قَالَ وَلِّنِي فَأُوَلِّيهِ قَفَايَ وَأَنْشُرُ الثَّوْبَ فَأَسْتُرُهُ بِهِ","id":"Telah menceritakan kepada kami [Al 'Abbas bin Abdul Azhim Al \"Anbari] dan [Abu Hafsh 'Amru bin Ali Al Fallas] dan [Mujahid bin Musa] mereka berkata; telah menceritakan kepada kami [Abdurrahman bin Mahdi] berkata, telah menceritakan kepada kami [Yahya bin Al Walid] berkata, telah mengabarkan kepadaku [Muhill bin Khalifah] berkata, telah menceritakan kepadaku [Abu As Samh] ia berkata; Aku pernah menjadi pelayan Nabi shallallahu 'alaihi wasallam. Jika ingin mandi, beliau bersabda: \"Belakangilah aku, \" maka aku membelakanginya dengan tengkukku, dan aku membentangkan kain, agar aku dapat menutupinya."},"574":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ الْمِصْرِيُّ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ نَوْفَلٍ أَنَّهُ قَالَسَأَلْتُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَبَّحَ فِي سَفَرٍ فَلَمْ أَجِدْ أَحَدًا يُخْبِرُنِي حَتَّى أَخْبَرَتْنِي أُمُّ هَانِئٍ بِنْتُ أَبِي طَالِبٍ أَنَّهُ قَدِمَ عَامَ الْفَتْحِ فَأَمَرَ بِسِتْرٍ فَسُتِرَ عَلَيْهِ فَاغْتَسَلَ ثُمَّ سَبَّحَ ثَمَانِيَ رَكَعَاتٍ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh Al Mishri] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Ibnu Syihab] dari [Abdullah bin Abdullah bin Naufal] Bahwasanya ia berkata; Aku bertanya apakah benar bahwasanya Rasulullah shallallahu 'alaihi wasallam bertasbih (shalat sunnah) di dalam safar, namun tidak ada seorang pun yang memberiku kabar tentang hal itu hingga [Ummu Hani` binti Ali bin Abu Thalib] mengabarkan kepadaku, bahwasanya Rasulullah ketika datang pada tahun penaklukan, beliau meminta untuk dibuatkan satir, maka beliau pun dibuatkan satir dan mandi. Setelah itu beliau bertasbih delapan raka'at.\""},"575":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدِ بْنِ ثَعْلَبَةَ الْحِمَّانِيُّ حَدَّثَنَا عَبْدُ الْحَمِيدِ أَبُو يَحْيَى الْحِمَّانِيُّ حَدَّثَنَا الْحَسَنُ بْنُ عُمَارَةَ عَنْ الْمِنْهَالِ بْنِ عَمْرٍو عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَغْتَسِلَنَّ أَحَدُكُمْ بِأَرْضِ فَلَاةٍ وَلَا فَوْقَ سَطْحٍ لَا يُوَارِيهِ فَإِنْ لَمْ يَكُنْ يَرَى فَإِنَّهُ يُرَى","id":"Telah menceritakan kepada kami [Muhammad bin Ubaid bin Tsa'labah Al Himmani] berkata, telah menceritakan kepada kami [Abdul Hamid Abu Yahya Al Himmani] berkata, telah menceritakan kepada kami [Al Hasan bin Umarah] dari [Al Minhal bin 'Amru] dari [Abu Ubaidah] dari [Abdullah bin Mas'ud] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jangan sekali-kali salah seorang di antara kalian mandi di tanah lapang dan di atas atap yang tidak ditutupi oleh sesuatu, karena jika dia tidak dapat melihat sesungguhnya dia terlihat.\""},"576":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ أَرْقَمَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَرَادَ أَحَدُكُمْ الْغَائِطَ وَأُقِيمَتْ الصَّلَاةُ فَلْيَبْدَأْ بِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah memberitakan kepada kami [Sufyan bin Uyainah] dari [Hisyam bin 'Urwah] dari [Bapaknya] dari [Abdullah bin Arqam] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian ingin buang hajat dan iqamah telah dikumandangkan, maka hendaklah ia mendahulukan buang hajatnya.\""},"577":{"ar":"حَدَّثَنَا بِشْرُ بْنُ آدَمَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ حَدَّثَنَا مُعَاوِيَةُ بْنُ صَالِحٍ عَنْ السَّفْرِ بْنِ نُسَيْرٍ عَنْ يَزِيدَ بْنِ شُرَيْحٍ عَنْ أَبِي أُمَامَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يُصَلِّيَ الرَّجُلُ وَهُوَ حَاقِنٌ","id":"Telah menceritakan kepada kami [Bisyr bin Adam] berkata, telah menceritakan kepada kami [Zaid Ibnul Hubab] berkata, telah menceritakan kepada kami [Mu'awiyah bin Shalih] dari [As Safar bin Nusair] dari [Yazid bin Syuraih] dari [Abu Umamah] berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang seorang laki-laki shalat dengan menahan kencing.\""},"578":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ إِدْرِيسَ الْأَوْدِيِّ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَقُومُ أَحَدُكُمْ إِلَى الصَّلَاةِ وَبِهِ أَذًى","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Usamah] dari [Idris Al Audi] dari [Bapaknya] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah salah seorang di antara kalian bangun untuk menegakkan shalat sementara dia terkena kotoran.\""},"579":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُصَفَّى الْحِمْصِيُّ حَدَّثَنَا بَقِيَّةُ عَنْ حَبِيبِ بْنِ صَالِحٍ عَنْ يَزِيدَ بْنِ شُرَيْحٍ عَنْ أَبِي حَيٍّ الْمُؤَذِّنِ عَنْ ثَوْبَانَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ لَا يَقُومُ أَحَدٌ مِنْ الْمُسْلِمِينَ وَهُوَ حَاقِنٌ حَتَّى يَتَخَفَّفَ","id":"Telah menceritakan kepada kami [Muhammad Ibnul Mushaffa Al Himshi] berkata, telah menceritakan kepada kami [Baqiyyah] dari [Habib bin Shalih] dari [Yazid bin Syurahbil] dari [Abu Hay Al Mu`adzdzin] dari [Tsauban] dari Rasulullah shallallahu 'alaihi wasallam, bahwasanya beliau bersabda: \"Janganlah seorang dari kaum muslimin berdiri shalat sedangkan ia menahan kencing hingga memperingannya.\""},"580":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ عَنْ الْمُنْذِرِ بْنِ الْمُغِيرَةِ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ أَنَّ فَاطِمَةَ بِنْتَ أَبِي حُبَيْشٍ حَدَّثَتْهُأَنَّهَا أَتَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَشَكَتْ إِلَيْهِ الدَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا ذَلِكَ عِرْقٌ فَانْظُرِي إِذَا أَتَى قَرْؤُكِ فَلَا تُصَلِّي فَإِذَا مَرَّ الْقَرْءُ فَتَطَهَّرِي ثُمَّ صَلِّي مَا بَيْنَ الْقَرْءِ إِلَى الْقَرْءِ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Yazid bin Abu Habib] dari [Bukair bin Abdullah] dari [Al Mundzir Ibnul Mughirah] dari ['Urwah bin Az Zubair] bahwa [Fatimah binti Abu Hubaisy] menceritakan kepadanya, bahwasanya ia pernah datang menemui Rasulullah shallallahu 'alaihi wasallam mengeluhkan tentang darah, maka Rasulullah shallallahu 'alaihi wasallam pun menjawab: \"Itu hanyalah penyakit, maka tunggulah. Jika tiba waktu Qar` (haidl) mu maka janganlah engkau shalat, jika haidl itu telah usai maka bersucilah, kemudian shalatlah antara haidl hingga berikutnya.\" "},"581":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْجَرَّاحِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْجَاءَتْ فَاطِمَةُ بِنْتُ أَبِي حُبَيْشٍ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنِّي امْرَأَةٌ أُسْتَحَاضُ فَلَا أَطْهُرُ أَفَأَدَعُ الصَّلَاةَ قَالَ لَا إِنَّمَا ذَلِكِ عِرْقٌ وَلَيْسَ بِالْحَيْضَةِ فَإِذَا أَقْبَلَتْ الْحَيْضَةُ فَدَعِي الصَّلَاةَ وَإِذَا أَدْبَرَتْ فَاغْسِلِي عَنْكِ الدَّمَ وَصَلِّيهَذَا حَدِيثُ وَكِيعٍ","id":"Telah menceritakan kepada kami [Abdullah Ibnul Jarrah] berkata, telah menceritakan kepada kami [Hammad bin Zaid]. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Hisyam bin 'Urwah] dari [Bapaknya] dari [Aisyah] ia berkata; Fatimah binti Abu Hubaisy datang menemui Rasulullah shallallahu 'alaihi wasallam dan bertanya; \"Wahai Rasulullah, aku adalah wanita yang keluar darah istihadlah hingga tidak suci, maka apakah aku boleh meninggalkan shalat?\" beliau menjawab: \"Itu hanyalah penyakit dan bukan haidl. Jika haidl itu tiba maka tinggalkan shalat dan jika telah usai maka bersihkanlah darah dari dirimu (mandi) dan kerjakan shalat.\" Hadits ini adalah hadits Waki'."},"582":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ إِمْلَاءً عَلَيَّ مِنْ كِتَابِهِ وَكَانَ السَّائِلُ غَيْرِي أَنْبَأَنَا ابْنُ جُرَيْجٍ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ إِبْرَاهِيمَ بْنِ مُحَمَّدِ بْنِ طَلْحَةَ عَنْ عِمْرَانَ بْنِ طَلْحَةَ عَنْ أُمِّ حَبِيبَةَ بِنْتِ جَحْشٍ قَالَتْكُنْتُ أُسْتَحَاضُ حَيْضَةً كَثِيرَةً طَوِيلَةً قَالَتْ فَجِئْتُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْتَفْتِيهِ وَأُخْبِرُهُ قَالَتْ فَوَجَدْتُهُ عِنْدَ أُخْتِي زَيْنَبَ قَالَتْ قُلْتُ يَا رَسُولَ اللَّهِ إِنَّ لِي إِلَيْكَ حَاجَةً قَالَ وَمَا هِيَ أَيْ هَنْتَاهُ قُلْتُ إِنِّي أُسْتَحَاضُ حَيْضَةً طَوِيلَةً كَبِيرَةً وَقَدْ مَنَعَتْنِي الصَّلَاةَ وَالصَّوْمَ فَمَا تَأْمُرُنِي فِيهَا قَالَ أَنْعَتُ لَكِ الْكُرْسُفَ فَإِنَّهُ يُذْهِبُ الدَّمَ قُلْتُ هُوَ أَكْثَرُ فَذَكَرَ نَحْوَ حَدِيثِ شَرِيكٍ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Abdurrazzaq] dengan mendektekan kepadaku dari bukunya -dan orang yang bertanya bukan aku- berkata, telah memberitakan kepada kami [Ibnu Juraij] dari [Abdullah bin Muhammad bin Aqil] dari [Ibrahim bin Muhammad bin Thalhah] dari [Imran bin Thalhah] dari [Ummu Habibah binti Jahsy] ia berkata; Aku mengeluarkan darah istihadlah sangat banyak dan dalam waktu yang lama. lantas aku mendatangi Nabi shallallahu 'alaihi wasallam untuk mengabarkan dan meminta fatwa kepada beliau.\" Ia berkata; \"Aku mendapati beliau sedang berada di sisi saudara perempuanku, Zainab. Aku pun berkata; \"Wahai Rasulullah, Aku punya keperluan denganmu, \" beliau bertanya: \"Keperluan apa itu?\" aku menjawab; \"Aku mengeluarkan darah istihadlah sangat banyak dan dalam waktu yang lama, hingga hal itu menghalangiku dari shalat dan puasa, lalu apa yang engkau perintahkan?\" beliau menjawab: \"Hendaknya engkau menggunakan kapas, karena itu akan menghilangkan darah, \" aku berkata; \"Darahnya lebih banyak! \" lalu ia menyebutkan sebagaimana hadits Syarik diatas."},"583":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا أَبُو أُسَامَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ أُمِّ سَلَمَةَ قَالَتْسَأَلَتْ امْرَأَةٌ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ إِنِّي أُسْتَحَاضُ فَلَا أَطْهُرُ أَفَأَدَعُ الصَّلَاةَ قَالَ لَا وَلَكِنْ دَعِي قَدْرَ الْأَيَّامِ وَاللَّيَالِي الَّتِي كُنْتِ تَحِيضِينَ قَالَ أَبُو بَكْرٍ فِي حَدِيثِهِ وَقَدْرَهُنَّ مِنْ الشَّهْرِ ثُمَّ اغْتَسِلِي وَاسْتَثْفِرِي بِثَوْبٍ وَصَلِّي","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Abu Usamah] dari [Ubaidullah bin Umar] dari [Nafi'] dari [Sulaiman bin Yasar] dari [Ummu Salamah] ia berkata; Seorang wanita bertanya kepada Nabi shallallahu 'alaihi wasallam, ia berkata; \"Aku adalah wanita yang keluar darah istihadlah hingga tidak suci, maka apakah aku boleh meninggalkan shalat?\" beliau menjawab: \"Tidak, namun engkau hanya boleh meninggalkannya pada hari-hari engkau haid.\" Abu Bakr menyebutkan dalam haditsnya; \"dan sesuai kebiasaannya dalam setiap bulan, setelah itu mandi dan sumbatlah dengan kain dan lakukanlah shalat.\""},"584":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ قَالَتْجَاءَتْ فَاطِمَةُ بِنْتُ أَبِي حُبَيْشٍ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنِّي امْرَأَةٌ أُسْتَحَاضُ فَلَا أَطْهُرُ أَفَأَدَعُ الصَّلَاةَ قَالَ لَا إِنَّمَا ذَلِكِ عِرْقٌ وَلَيْسَتْ بِالْحَيْضَةِ اجْتَنِبِي الصَّلَاةَ أَيَّامَ مَحِيضِكِ ثُمَّ اغْتَسِلِي وَتَوَضَّئِي لِكُلِّ صَلَاةٍ وَإِنْ قَطَرَ الدَّمُ عَلَى الْحَصِيرِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan [Abu Bakr bin Abu Syaibah] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Al A'masy] dari [Habib bin Abu Tsabit] dari [Urwah bin Az Zubair] dari [Aisyah] ia berkata; Fatimah binti Hubaisy datang menemui Nabi shallallahu 'alaihi wasallam dan bertanya; \"Sesungguhnya aku adalah wanita yang keluar darah istihadlah hingga tidak suci, maka apakah aku boleh meninggalkan shalat?\" beliau menjawab: \"Tidak, itu hanyalah penyakit dan bukan haidl. Jauhilah shalat di hari-hari haidlmu kemudian shalatlah, dan wudlulah pada setiap shalat meskipun darah menetes di atas tikar.\""},"585":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَإِسْمَعِيلُ بْنُ مُوسَى قَالَا حَدَّثَنَا شَرِيكٌ عَنْ أَبِي الْيَقْظَانِ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ أَبِيهِ عَنْ جَدِّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمُسْتَحَاضَةُ تَدَعُ الصَّلَاةَ أَيَّامَ أَقْرَائِهَا ثُمَّ تَغْتَسِلُ وَتَتَوَضَّأُ لِكُلِّ صَلَاةٍ وَتَصُومُ وَتُصَلِّي","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Isma'il bin Musa] keduanya berkata; telah menceritakan kepada kami [Syarik] dari [Abul Yaqzhan] dari [Adi bin Tsabit] dari [Bapaknya] dari [Kakeknya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Wanita yang mengalami istihadlah hendaknya meninggalkan shalat di hari-hari haidlnya, kemudian ia mandi dan berwudlu di setiap shalat, dan ia tetap berpuasa serta shalat.\""},"586":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ وَعَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ أَنَّ عَائِشَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْاسْتُحِيضَتْ أُمُّ حَبِيبَةَ بِنْتُ جَحْشٍ وَهِيَ تَحْتَ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ سَبْعَ سِنِينَ فَشَكَتْ ذَلِكَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ هَذِهِ لَيْسَتْ بِالْحَيْضَةِ وَإِنَّمَا هُوَ عِرْقٌ فَإِذَا أَقْبَلَتْ الْحَيْضَةُ فَدَعِي الصَّلَاةَ وَإِذَا أَدْبَرَتْ فَاغْتَسِلِي وَصَلِّي قَالَتْ عَائِشَةُ فَكَانَتْ تَغْتَسِلُ لِكُلِّ صَلَاةٍ ثُمَّ تُصَلِّي وَكَانَتْ تَقْعُدُ فِي مِرْكَنٍ لِأُخْتِهَا زَيْنَبَ بِنْتِ جَحْشٍ حَتَّى إِنَّ حُمْرَةَ الدَّمِ لَتَعْلُو الْمَاءَ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Abu Al Mughirah] berkata, telah menceritakan kepada kami [Al Auza'i] dari [Az Zuhri] dari [Urwah bin Az Zubair] dan [Amrah binti Abdurrahman], bahwa [Aisyah] isteri Nabi shallallahu 'alaihi wasallam menuturkan; Ummu Habibah binti Jahsy -isteri Abdurrahman bin Auf- keluar darah istihadlah selama tujuh tahun, hingga iapun mengadukan hal itu kepada Nabi shallallahu 'alaihi wasallam, maka Nabi shallallahu 'alaihi wasallam bersabda; \"Sesungguhnya ini bukanlah haidl tetapi penyakit, jika haidl tiba maka tinggalkanlah shalat dan jika ia telah usai maka mandi dan kerjakanlah shalat.\" Aisyah berkata; \"Ummu Habibah mandi setiap akan melaksanakan shalat, ia berendam di dalam mirkan (bak besar) milik saudara perempuannya, Zainab binti Jahsy, hingga warna darahnya mengalahkan warna air.\" "},"587":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا شَرِيكٌ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ إِبْرَاهِيمَ بْنِ مُحَمَّدِ بْنِ طَلْحَةَ عَنْ عَمِّهِ عِمْرَانَ بْنِ طَلْحَةَ عَنْ أُمِّهِ حَمْنَةَ بِنْتِ جَحْشٍأَنَّهَا اسْتُحِيضَتْ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ إِنِّي اسْتُح��ضْتُ حَيْضَةً مُنْكَرَةً شَدِيدَةً قَالَ لَهَا احْتَشِي كُرْسُفًا قَالَتْ لَهُ إِنَّهُ أَشَدُّ مِنْ ذَلِكَ إِنِّي أَثُجُّ ثَجًّا قَالَ تَلَجَّمِي وَتَحَيَّضِي فِي كُلِّ شَهْرٍ فِي عِلْمِ اللَّهِ سِتَّةَ أَيَّامٍ أَوْ سَبْعَةَ أَيَّامٍ ثُمَّ اغْتَسِلِي غُسْلًا فَصَلِّي وَصُومِي ثَلَاثَةً وَعِشْرِينَ أَوْ أَرْبَعَةً وَعِشْرِينَ وَأَخِّرِي الظُّهْرَ وَقَدِّمِي الْعَصْرَ وَاغْتَسِلِي لَهُمَا غُسْلًا وَأَخِّرِي الْمَغْرِبَ وَعَجِّلِي الْعِشَاءَ وَاغْتَسِلِي لَهُمَا غُسْلًا وَهَذَا أَحَبُّ الْأَمْرَيْنِ إِلَيَّ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yazid bin Harun] berkata, telah memberitakan kepada kami [Syarik] dari [Abdullah bin Muhammad bin Aqil] dari [Ibrahim bin Muhammad bin Thalhah] dari pamannya [Imran bin Thalhah] dari ibunya [Hamnah binti Jahsy], bahwasanya ia pernah mengalami istihadlah pada masa Rasulullah shallallahu 'alaihi wasallam, ia pun mendatangi Rasulullah shallallahu 'alaihi wasallam dan berkata; \"Sesungguhnya aku mengeluarkan darah istihadlah yang sangat deras, \" beliau bersabda: \"Sumbatlah dengan kapas, \" ia berkata; \"darahku lebih dari itu, ia mengalir sangat deras, \" beliau bersabda: \"Sumbatlah dengan kain, lalu tentukanlah kebiasaan haidl sesuai dengan ilmu Allah enam atau tujuh hari, setelah itu hendaklah engkau mandi, shalat dan puasa dua puluh tiga atau dua puluh empat hari. Akhirkanlah waktu shalat zhuhur dan majukanlah shalat ashar, serta mandilah untuk melaksanakan kedua shalat tersebut. Juga, akhirkanlah shalat maghrib dan majukan shalat isya, serta mandilah untuk melaksanakan kedua shalat tersebut, inilah yang lebih aku sukai dari dua perkara itu.\""},"588":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ وَعَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ ثَابِتِ بْنِ هُرْمُزَ أَبِي الْمِقْدَامِ عَنْ عَدِيِّ بْنِ دِينَارٍ عَنْ أُمِّ قَيْسٍ بِنْتِ مِحْصَنٍ قَالَتْسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ دَمِ الْحَيْضِ يُصِيبُ الثَّوْبَ قَالَ اغْسِلِيهِ بِالْمَاءِ وَالسِّدْرِ وَحُكِّيهِ وَلَوْ بِضِلَعٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dan [Abdurrahman bin Mahdi] keduanya berkata; telah menceritakan kepada kami [Sufyan] dari [Tsabit bin Hurmuz Abul Miqdam] dari [Adi bin Dinar] dari [Ummu Qais binti Mihshan] ia berkata; Aku bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang darah haidl yang mengenai kain, beliau menjawab: \"Cucilah dengan air dan daun Sidr, serta gosoklah meskipun dengan kuku.\""},"589":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ فَاطِمَةَ بِنْتِ الْمُنْذِرِ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ الصِّدِّيقِ قَالَتْسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ دَمِ الْحَيْضِ يَكُونُ فِي الثَّوْبِ قَالَ اقْرُصِيهِ وَاغْسِلِيهِ وَصَلِّي فِيهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Khalid Al Ahmar] dari [Hisyam bin 'Urwah] dari [Fatimah binti Al Mundzir] dari [Asma` binti Abu Bakar Ash Shiddiq] ia berkata; Rasulullah shallallahu 'alaihi wasallam ditanya tentang darah haidl yang mengenai kain, maka beliau menjawab: \"Kerik dan cucilah, setelah itu shalatlah dengannya.\""},"590":{"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهَا قَالَتْإِنْ كَانَتْ إِحْدَانَا لَتَحِيضُ ثُمَّ تَقْرُصُ الدَّمَ مِنْ ثَوْبِهَا عِنْدَ طُهْرِهَا فَتَغْسِلُهُ وَتَنْضَحُ عَلَى سَائِرِهِ ثُمَّ تُصَلِّي فِيهِ","id":"Telah menceritakan kepada kami [Harmalah bin Yahya] berkata, telah menceritakan kepada kami [Ibnu Wahb] berkata, telah mengabarkan kepadaku ['Amru bin Al Harits] dari [Abdurrahman bin Qasim] dari [Bapaknya] dari [Aisyah] isteri Nabi shallallahu 'alaihi wasallam, ia berkata; \"Jika salah seorang dari kami mengalami haidl kemudian darah merembes dari kainnya tatkala dalam keadaan suci, maka ia mencucinya dan memerciki semuanya kemudian shalat dengan kain tersebut.\" "},"591":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ مُعَاذَةَ الْعَدَوِيَّةِ عَنْ عَائِشَةَأَنَّ امْرَأَةً سَأَلَتْهَا أَتَقْضِي الْحَائِضُ الصَّلَاةَ قَالَتْ لَهَا عَائِشَةُ أَحَرُورِيَّةٌ أَنْتِ قَدْ كُنَّا نَحِيضُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ نَطْهُرُ وَلَمْ يَأْمُرْنَا بِقَضَاءِ الصَّلَاةِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ali bin Mushir] dari [Sa'd bin Abu 'Arubah] dari [Qotadah] dari [Mu'adzah Al 'Adawiyah] dari [Aisyah]; bahwasanya ada seorang wanita yang bertanya kepadanya; apakah wanita haidl harus mengqadla shalat? Aisyah berkata kepada wanita tersebut; \"Apakah engkau seorang Haruriah? Kami pernah mengalami haidl kemudian suci di masa Nabi shallallahu 'alaihi wasallam, namun beliau tidak memerintahkan kami untuk mengqadla shalat.\""},"592":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي إِسْحَقَ عَنْ الْبَهِيِّ عَنْ عَائِشَةَ قَالَتْقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَاوِلِينِي الْخُمْرَةَ مِنْ الْمَسْجِدِ فَقُلْتُ إِنِّي حَائِضٌ فَقَالَ لَيْسَتْ حَيْضَتُكِ فِي يَدِكِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Al Ahwash] dari [Abu Ishaq] dari [Al Bahi] dari [Aisyah] ia berkata; Rasulullah shallallahu 'alaihi wasallam berkata kepadaku: \"Ambilkan tikar kecil di masjid untukku, \" tapi aku menyela; \"Aku dalam keadaan haid! \" maka beliau pun bersabda: \"Haidmu bukan di tanganmu.\""},"593":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُدْنِي رَأْسَهُ إِلَيَّ وَأَنَا حَائِضٌ وَهُوَ مُجَاوِرٌ تَعْنِي مُعْتَكِفًا فَأَغْسِلُهُ وَأُرَجِّلُهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Hisyam bin 'Urwah] dari [Bapaknya] dari [Aisyah] ia berkata; \"Ketika aku haidl, Nabi shallallahu 'alaihi wasallam mendekatkan kepalanya kepadaku, sedang beliau waktu itu setatusnya mujawir (i'tikaaf), hingga aku bisa membasuh dan menyela-nyela rambutnya.\""},"594":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا سُفْيَانُ عَنْ مَنْصُورِ بْنِ صَفِيَّةَ عَنْ أُمِّهِ عَنْ عَائِشَةَ قَالَتْلَقَدْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَضَعُ رَأْسَهُ فِي حِجْرِي وَأَنَا حَائِضٌ وَيَقْرَأُ الْقُرْآنَ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Abdurrazzaq] berkata, telah memberitakan kepada kami [Sufyan] dari [Manshur bin Shafiah] dari [ibunya] dari [Aisyah], ia menuturkan; \"Pernah Rasulullah shallallahu 'alaihi wasallam meletakkan kepalanya di pangkuanku sambil membaca Al Qur`an, padahal aku sedang haidl.\""},"595":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْجَرَّاحِ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ عَبْدِ الْكَرِيمِ ح و حَدَّثَنَا أَبُو سَلَمَةَ يَحْيَى بْنُ خَلَفٍ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ مُحَمَّدِ بْنِ إِسْحَقَ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ الشَّيْبَانِيِّ جَمِيعًا عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَسْوَدِ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكَانَتْ إِحْدَانَا إِذَا كَانَتْ حَائِضًا أَمَرَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تَأْتَزِرَ فِي فَوْرِ حَيْضَتِهَا ثُمَّ يُبَاشِرُهَا وَأَيُّكُمْ يَمْلِكُ إِرْبَهُ كَمَا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْلِكُ إِرْبَهُ","id":"Telah menceritakan kepada kami [Abdullah Ibnul Jarrah] berkata, telah menceritakan kepada kami [Abu Al Ahwash] dari [Abdul Karim]. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Abu Salamah Yahya bin Khalaf] berkata, telah menceritakan kepada kami [Abdul A'la] dari [Muhammad bin Ishaq]. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ali bin Mushir] dari [Asy Syaibani] semuanya dari [Abdurrahman Ibnul Aswad] dari [Bapaknya] dari [Aisyah], ia berkata; \"Jika salah seorang dari kami haid, maka Nabi shallallahu 'alaihi wasallam memerintahkan kepadanya untuk mengenakan kain sarung (antara pusar dan apa yang di bawahnya) baru Rasulullah mencumbuinya. Dan hendaklah kalian menguasai syahwatnya sebagaimana Rasulullah shallallahu 'alaihi wasallam menguasainya.\" "},"596":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْكَانَتْ إِحْدَانَا إِذَا حَاضَتْ أَمَرَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تَأْتَزِرَ بِإِزَارٍ ثُمَّ يُبَاشِرُهَا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Ibrahim] dari [Al Aswad] dari [Aisyah] ia berkata; \"Jika salah seorang dari kami mengalami haid, maka Nabi shallallahu 'alaihi wasallam memerintahkannya untuk memakai kain sarung, kemudian Rasulullah mencumbuinya.\""},"597":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو حَدَّثَنَا أَبُو سَلَمَةَ عَنْ أُمِّ سَلَمَةَ قَالَتْكُنْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي لِحَافِهِ فَوَجَدْتُ مَا تَجِدُ النِّسَاءُ مِنْ الْحَيْضَةِ فَانْسَلَلْتُ مِنْ اللِّحَافِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَفِسْتِ قُلْتُ وَجَدْتُ مَا تَجِدُ النِّسَاءُ مِنْ الْحَيْضَةِ قَالَ ذَلِكِ مَا كَتَبَ اللَّهُ عَلَى بَنَاتِ آدَمَ قَالَتْ فَانْسَلَلْتُ فَأَصْلَحْتُ مِنْ شَأْنِي ثُمَّ رَجَعْتُ فَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَعَالَيْ فَادْخُلِي مَعِي فِي اللِّحَافِ قَالَتْ فَدَخَلْتُ مَعَهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Muhammad bin Bisyr] berkata, telah menceritakan kepada kami [Muhammad bin 'Amru] berkata, telah menceritakan kepada kami [Abu Salamah] dari [Ummu Salamah] ia berkata; \"Aku dan Rasulullah shallallahu 'alaihi wasallam berada dalam satu selimut miliknya, namun aku mengalami haidl sebagaimana wanita haidl hingga aku keluar dari dalam selimutnya. Maka Rasulullah shallallahu 'alaihi wasallam pun bertanya: \"Apakah kamu haidl?\" aku menjawab; \"Aku mengalami haidl sebagaimana wanita mengalaminya?\" beliau bersabda: \"Itu adalah ketetapan Allah untuk anak cucu Adam.\" Ummu Salamah berkata; Aku lalu keluar dari dalam selimut dan merapikan kondisiku setelah itu aku kembali lagi, Rasulullah shallallahu 'alaihi wasallam kemudian berkata kepadaku: \"Kemari dan masuklah ke dalam selimut.\" Ummu Salamah berkata; \"Maka aku pun masuk selimut bersama beliau.\""},"598":{"ar":"حَدَّثَنَا الْخَلِيلُ بْنُ عَمْرٍو حَدَّثَنَا ابْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ سُوَيْدِ بْنِ قَيْسٍ عَنْ مُعَاوِيَةَ بْنِ حُدَيْجٍ عَنْ مُعَاوِيَةَ بْنِ أَبِي سُفْيَانَ عَنْ أُمِّ حَبِيبَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَأَلْتُهَا كَيْفَ كُنْتِ تَصْنَعِينَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْحَيْضَةِ قَالَتْ كَانَتْ إِحْدَانَا فِي فَوْرِهَا أَوَّلَ مَا تَحِيضُ تَشُدُّ عَلَيْهَا إِزَارًا إِلَى أَنْصَافِ فَخِذَيْهَا ثُمَّ تَضْطَجِعُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Al Khalil bin 'Amru] berkata, telah menceritakan kepada kami [Ibnu Salamah] dari [Muhammad bin Ishaq] dari [Yazid bin Abu Habib] dari [Suwaid bin Qais] dari [Mu'awiyah bin Hudaij] dari [Mu'awiyah bin Abu Sufyan] dari [Ummu Habibah] istri Nabi shallallahu 'alaihi wasallam, Mu'awiyah berkata; Aku bertanya kepadanya; apa yang engkau lakukan bersama Rasulullah ketika haidl?\" ia menjawab; \"Pertama kali yang segera dilakukan oleh salah seorang dari kami adalah menutup antara paha dengan kain, setelah itu berbaring bersama Rasulullah shallallahu 'alaihi wasallam.\" "},"599":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ حَكِيمٍ الْأَثْرَمِ عَنْ أَبِي تَمِيمَةَ الْهُجَيْمِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَتَى حَائِضًا أَوْ امْرَأَةً فِي دُبُرِهَا أَوْ كَاهِنًا فَصَدَّقَهُ بِمَا يَقُولُ فَقَدْ كَفَرَ بِمَا أُنْزِلَ عَلَى مُحَمَّدٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Hakim Al Atsari] dari [Abu Tamimah Al Hujaimi] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menyetubuhi wanita haidl, atau menyetubuhi wanita dari duburnya, atau mendatangi dukun lalu membenarkan apa yang diucapkannya maka ia telah kafir dengan wahyu yang diturunkan kepada Muhammad.\""},"600":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ وَمُحَمَّدُ بْنُ جَعْفَرٍ وَابْنُ أَبِي عَدِيٍّ عَنْ شُعْبَةَ عَنْ الْحَكَمِ عَنْ عَبْدِ الْحَمِيدِ عَنْ مِقْسَمٍ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الَّذِي يَأْتِي امْرَأَتَهُ وَهِيَ حَائِضٌ قَالَ يَتَصَدَّقُ بِدِينَارٍ أَوْ بِنِصْفِ دِينَارٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dan [Muhammad bin Ja'far] dan [Ibnu Abu 'Adi] dari [Syu'bah] dari [Al Hakam] dari [Abdul Hamid] dari [Miqsam] dari [Ibnu 'Abbas] dari Nabi shallallahu 'alaihi wasallam tentang seseorang yang mendatangi isterinya yang sedang haidl, beliau mengatakan: \"Hendaknya ia bersedekah dengan satu dinar atau setengahnya.\""},"601":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهَا وَكَانَتْ حَائِضًا انْقُضِي شَعْرَكِ وَاغْتَسِلِي قَالَ عَلِيٌّ فِي حَدِيثِهِ انْقُضِي رَأْسَكِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Hisyam bin 'Urwah] dari [bapaknya] dari [Aisyah] bahwa Nabi shallallahu 'alaihi wasallam berkata kepadanya ketika sedang haidl: \"Urailah rambutmu kemudian mandilah.\" -Ali menyebutkan dalam haditsnya, -\"Lepaskanlah gulungan rambutmu.\""},"602":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ إِبْرَاهِيمَ بْنِ مُهَاجِرٍ قَالَ سَمِعْتُ صَفِيَّةَ تُحَدِّثُ عَنْ عَائِشَةَأَنَّ أَسْمَاءَ سَأَلَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْغُسْلِ مِنْ الْمَحِيضِ فَقَالَ تَأْخُذُ إِحْدَاكُنَّ مَاءَهَا وَسِدْرَهَا فَتَطْهُرُ فَتُحْسِنُ الطُّهُورَ أَوْ تَبْلُغُ فِي الطُّهُورِ ثُمَّ تَصُبُّ عَلَى رَأْسِهَا فَتَدْلُكُهُ دَلْكًا شَدِيدًا حَتَّى تَبْلُغَ شُؤُونَ رَأْسِهَا ثُمَّ تَصُبُّ عَلَيْهَا الْمَاءَ ثُمَّ تَأْخُذُ فِرْصَةً مُمَسَّكَةً فَتَطْهُرُ بِهَا قَالَتْ أَسْمَاءُ كَيْفَ أَتَطَهَّرُ بِهَا قَالَ سُبْحَانَ اللَّهِ تَطَهَّرِي بِهَا قَالَتْ عَائِشَةُ كَأَنَّهَا تُخْفِي ذَلِكَ تَتَبَّعِي بِهَا أَثَرَ الدَّمِ قَالَتْ وَسَأَلَتْهُ عَنْ الْغُسْلِ مِنْ الْجَنَابَةِ فَقَالَ تَأْخُذُ إِحْدَاكُنَّ مَاءَهَا فَتَطْهُرُ فَتُحْسِنُ الطُّهُورَ أَوْ تَبْلُغُ فِي الطُّهُورِ حَتَّى تَصُبَّ الْمَاءَ عَلَى رَأْسِهَا فَتَدْلُكُهُ حَتَّى تَبْلُغَ شُؤُونَ رَأْسِهَا ثُمَّ تُفِيضُ الْمَاءَ عَلَى جَسَدِهَا فَقَالَتْ عَائِشَةُ نِعْمَ النِّسَاءُ نِسَاءُ الْأَنْصَارِ لَمْ يَمْنَعْهُنَّ الْحَيَاءُ أَنْ يَتَفَقَّهْنَ فِي الدِّينِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dari [Ibrahim bin Muhajir] berkata; aku mendengar [Shafiah] menceritakan dari [Aisyah], bahwa Asma` bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang mandi junub, lalu beliau menjawab: \"Salah seorang dari kalian mengambil air dan daun Sidr lalu ia bersuci dan membaguskan bersucinya, atau hingga menjadi bersih. Setelah itu hendaknya ia menuangkan air di kepalanya seraya memijat-mijatnya dengan kuat hingga sampai meresap di pori-pori kepalanya. Kemudian menuangkan air di kemaluannya lalu mengambil potongan kapas untuk membersihkannya.\" Asma` bertanya; \"Bagaimana cara aku membersihkannya?\" beliau bersabda: \"Subhaanallah, bersihkanlah dengannya! \" Aisyah berkata -dengan mengucapkannya dengan pelan-, \"Engkau bersihkan sisa darah itu dengan kapas tersebut.\" Aisyah berkata; Asma` juga bertanya Rasulullah tentang cara mandi junub, maka beliau pun menjawab: \"Salah seorang dari kalian mengambil air lalu ia bersuci dan membaguskan bersucinya, atau hingga menjadi bersih. Setelah itu hendaknya ia menuangkan air di kepalanya seraya memijat-mijatnya dengan kuat hingga meresap sampai pori-pori kepalanya. Kemudian tuangkan air ke seluruh tubuhnya.\" Aisyah berkata; \"Sebaik-baik wanita adalah wanita Anshar, rasa malu tidak menjadi penghalang mereka untuk memperdalam ilmu agama.\""},"603":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ الْمِقْدَامِ بْنِ شُرَيْحِ بْنِ هَانِئٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكُنْتُ أَتَعَرَّقُ الْعَظْمَ وَأَنَا حَائِضٌ فَيَأْخُذُهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَضَعُ فَمَهُ حَيْثُ كَانَ فَمِي وَأَشْرَبُ مِنْ الْإِنَاءِ فَيَأْخُذُهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَضَعُ فَمَهُ حَيْثُ كَانَ فَمِي وَأَنَا حَائِضٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dari [Al Miqdam bin Syuraih bin Hani`] dari [Bapaknya] dari [Aisyah], ia berkata; \"Aku menggigit tulang sedangkan aku dalam keadaan haidl, lalu Rasulullah shallallahu 'alaihi wasallam mengambilnya dan meletakkan mulutnya persis dimana mulutku aku letakkan. Dan aku minum dengan cangkir, lalu Rasulullah shallallahu 'alaihi wasallam mengambilnya dan meletakkan mulutnya persis dimana mulutku aku letakkan, padahal aku dalam keadaan haidl.\""},"604":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ أَنَسٍأَنَّ الْيَهُودَ كَانُوا لَا يَجْلِسُونَ مَعَ الْحَائِضِ فِي بَيْتٍ وَلَا يَأْكُلُونَ وَلَا يَشْرَبُونَ قَالَ فَذُكِرَ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنْزَلَ اللَّهُ{ وَيَسْأَلُونَكَ عَنْ الْمَحِيضِ قُلْ هُوَ أَذًى فَاعْتَزِلُوا النِّسَاءَ فِي الْمَحِيضِ }فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اصْنَعُوا كُلَّ شَيْءٍ إِلَّا الْجِمَاعَ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Abu Al Walid] berkata, telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Anas] berkata; Orang-orang Yahudi tidak mau duduk, makan dan minum bersama wanita haid. Maka hal itu diceritakan kepada Nabi shallallahu 'alaihi wasallam, maka Allah pun menurunkan ayat: \"Mereka bertanya kepadamu tentang haidl. Katakanlah: 'Haidl itu adalah suatu kotoran.' Oleh sebab itu hendaklah kamu menjauhkan diri dari wanita di waktu haid, \" lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Lakukanlah segala sesuatu kecuali persetubuhan.\""},"605":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ يَحْيَى قَالَا حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا ابْنُ أَبِي غَنِيَّةَ عَنْ أَبِي الْخَطَّابِ الْهَجَرِيِّ عَنْ مَحْدُوجٍ الذُّهْلِيِّ عَنْ جَسْرَةَ قَالَتْ أَخْبَرَتْنِي أُمُّ سَلَمَةَ قَالَتْدَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَرْحَةَ هَذَا الْمَسْجِدِ فَنَادَى بِأَعْلَى صَوْتِهِ إِنَّ الْمَسْجِدَ لَا يَحِلُّ لِجُنُبٍ وَلَا لِحَائِضٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Muhammad bin Yahya] keduanya berkata; telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami [Ibnu Abu Ghaniyyah] dari [Abul Khaththab Al Hajari] dari [Mahduj Adz Dzuhli] dari [Jasrah] berkata; [Ummu Salamah] mengabarkan kepadaku, bahwa Rasulullah pernah memasuki halaman masjid ini kemudian berseru dengan suaranya yang sangat keras: \"Sesungguhnya masjid tidak halal bagi orang junub dan haidl.\""},"606":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ شَيْبَانَ النَّحْوِيِّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ أُمِّ بَكْرٍ أَنَّهَا أُخْبِرَتْ أَنَّ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَرْأَةِ تَرَى مَا يَرِيبُهَا بَعْدَ الطُّهْرِ قَالَ إِنَّمَا هِيَ عِرْقٌ أَوْ عُرُوقٌقَالَ مُحَمَّدُ بْنُ يَحْيَى يُرِيدُ بَعْدَ الطُّهْرِ بَعْدَ الْغُسْلِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Ubaidullah bin Musa] dari [Syaiban An Nahwi] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Ummu Bakr] ia telah diberi kabar bahwa [Aisyah] berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda dalam perkara seorang wanita yang melihat sesuatu yang membingunkannya setelah suci, beliau bersabda: \"Itu hanyalah penyakit.\" Muhammad bin Yahya berkata; \"Yang dimaksud dengan 'setelah suci' adalah setelah mandi.\""},"607":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى أَنْبَأَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا مَعْمَرٌ عَنْ أَيُّوبَ عَنْ ابْنِ سِيرِينَ عَنْ أُمِّ عَطِيَّةَ قَالَتْلَمْ نَكُنْ نَرَى الصُّفْرَةَ وَالْكُدْرَةَ شَيْئًاقَالَ مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الرَّقَاشِيُّ حَدَّثَنَا وُهَيْبٌ عَنْ أَيُّوبَ عَنْ حَفْصَةَ عَنْ أُمِّ عَطِيَّةَ قَالَتْ كُنَّا لَا نَعُدُّ الصُّفْرَةَ وَالْكُدْرَةَ شَيْئًا قَالَ مُحَمَّدُ بْنُ يَحْيَى وُهَيْبٌ أَوْلَاهُمَا عِنْدَنَا بِهَذَا","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah memberitakan kepada kami [Abdurrazzaq] berkata, telah memberitakan kepada kami [Ma'mar] dari [Ayyub] dari [Ibnu Sirin] dari [Ummu Athiyyah] ia berkata; \"Warna kuning atau warna keruh, kami tidak menganggapnya.\" [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Muhammad bin Abdullah Ar Raqasyi] berkata, telah menceritakan kepada kami [Wuhaib] dari [Ayyub] dari [Hafshah] dari [Ummu Athiyyah] ia berkata; \"Warna kuning atau warna keruh, kami tidak menganggapnya.\" Muhammad bin Yahya berkata; \"Menurut kami Wuhaib lebih layak dari keduanya.\""},"608":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا شُجَاعُ بْنُ الْوَلِيدِ عَنْ عَلِيِّ بْنِ عَبْدِ الْأَعْلَى عَنْ أَبِي سَهْلٍ عَنْ مُسَّةَ الْأَزْدِيَّةِ عَنْ أُمِّ سَلَمَةَ قَالَتْكَانَتْ النُّفَسَاءُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَجْلِسُ أَرْبَعِينَ يَوْمًا وَكُنَّا نَطْلِي وُجُوهَنَا بِالْوَرْسِ مِنْ الْكَلَفِ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] berkata, telah menceritakan kepada kami [Syuja' Ibnul Walid] dari [Ali bin Abdul A'la] dari [Abu Sahal] dari [Mussah Al Azdiah] dari [Ummu Salamah] ia berkata; \"Pada masa Rasulullah shallallahu 'alaihi wasallam wanita-wanita yang nifas duduk berdiam diri selama empat puluh hari, dan kami membersihkan wajah mereka dengan waras (semacam tumbuhan yang wangi) dari kotoran.\""},"609":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا الْمُحَارِبِيُّ عَنْ سَلَّامِ بْنِ سُلَيْمٍ أَوْ سَلْمٍ شَكَّ أَبُو الْحَسَنِ وَأَظُنُّهُ هُوَ أَبُو الْأَحْوَصِ عَنْ حُمَيْدٍ عَنْ أَنَسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَّتَ لِلنُّفَسَاءِ أَرْبَعِينَ يَوْمًا إِلَّا أَنْ تَرَى الطُّهْرَ قَبْلَ ذَلِكَ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id] berkata, telah menceritakan kepada kami [Al Muharibi] dari [Sallam bin Sulaim] atau Salm -Abul Hasan masih merasa ragu, dan menurutku dia adalah Abul Ahwash- dari [Humaid] dari [Anas], ia berkata; \"Rasulullah shallallahu 'alaihi wasallam memberikan waktu bagi wanita-wanita yang nifas empat puluh hari, kecuali jika mereka telah suci sebelum itu.\""},"610":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْجَرَّاحِ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ عَبْدِ الْكَرِيمِ عَنْ مِقْسَمٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ الرَّجُلُ إِذَا وَقَعَ عَلَى امْرَأَتِهِ وَهِيَ حَائِضٌ أَمَرَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَتَصَدَّقَ بِنِصْفِ دِينَارٍ","id":"Telah menceritakan kepada kami [Abdullah Ibnul Jarrah] berkata, telah menceritakan kepada kami [Abul Ahwash] dari [Abdul Karim] dari [Miqsam] dari [Ibnu 'Abbas] ia berkata; \"Jika ada seorang laki-laki yang menggauli isterinya dalam keadaan junub, maka Nabi shallallahu 'alaihi wasallam memerintahkannya untuk bersedekah setengah dinar.\""},"611":{"ar":"حَدَّثَنَا أَبُو بِشْرٍ بَكْرُ بْنُ خَلَفٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ عَنْ الْعَلَاءِ بْنِ الْحَارِثِ عَنْ حَرَامِ بْنِ حَكِيمٍ عَنْ عَمِّهِ عَبْدِ اللَّهِ بْنِ سَعْدٍ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ مُؤَاكَلَةِ الْحَائِضِ فَقَالَ وَاكِلْهَا","id":"Telah menceritakan kepada kami [Abu Bisyr Bakr bin Khalaf] berkata, telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Mu'awiyah bin Shalih] dari [Al 'Ala` Ibnul Harits] dari [Haram bin Hakim] dari pamannya [Abdullah bin Sa'd], ia berkata; Aku bertanya kepada Rasulullah shallallahu 'alaihi wasallam hukum makan bersama wanita haidl, maka beliau menjawab: \"Makanlah bersamanya.\""},"612":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ طَلْحَةَ بْنِ يَحْيَى عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي وَأَنَا إِلَى جَنْبِهِ وَأَنَا حَائِضٌ وَعَلَيَّ مِرْطٌ لِي وَعَلَيْهِ بَعْضُهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Waki'] dari [Thalhah bin Yahya] dari [Ubaidullah bin Abdullah bin 'Utbah] dari [Aisyah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam shalat di sampingku yang waktu itu sedang haidl, dan di tubuhku ada kain wol yang sebagiannya mengenai Rasulullah.\""},"613":{"ar":"حَدَّثَنَا سَهْلُ بْنُ أَبِي سَهْلٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ حَدَّثَنَا الشَّيْبَانِيُّ عَنْ عَبْدِ اللَّهِ بْنِ شَدَّادٍ عَنْ مَيْمُونَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى وَعَلَيْهِ مِرْطٌ بَعْضُهُ عَلَيْهِ وَعَلَيْهَا بَعْضُهُ وَهِيَ حَائِضٌ","id":"Telah menceritakan kepada kami [Sahal bin Abu Sahal] berkata, telah menceritakan kepada kami [Sufyan bin 'Uyainah] berkata, telah menceritakan kepada kami [Asy Syaibani] dari [Abdullah bin Syaddad] dari [Maimunah] bahwa, pernah Rasulullah shallallahu 'alaihi wasallam shalat dengan memakai kain wol yang sebagian mengenai isterinya, padahal ia sedang haidl.\""},"614":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ عَبْدِ الْكَرِيمِ عَنْ عَمْرِو بْنِ سَعِيدٍ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَيْهَا فَاخْتَبَأَتْ مَوْلَاةٌ لَهَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَاضَتْ فَقَالَتْ نَعَمْ فَشَقَّ لَهَا مِنْ عِمَامَتِهِ فَقَالَ اخْتَمِرِي بِهَذَا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Abdul Karim] dari ['Amru bin Sa'id] dari [Aisyah] bahwa Nabi shallallahu 'alaihi wasallam menemuinya, lalu mantan budaknya bersembunyi. Maka Nabi shallallahu 'alaihi wasallam pun bertanya: \"Apakah ia telah haidl?\" Aisyah menjawab; \"Ya.\" Beliau kemudian membelah imamahnya dan diberikan kepadanya seraya bersabda: \"Berkerudunglah dengan ini.\""},"615":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا أَبُو الْوَلِيدِ وَأَبُو النُّعْمَانِ قَالَا حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ قَتَادَةَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ صَفِيَّةَ بِنْتِ الْحَارِثِ عَنْ عَائِشَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَقْبَلُ اللَّهُ صَلَاةَ حَائِضٍ إِلَّا بِخِمَارٍ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Abul Walid] dan [Abu An Nu'man] keduanya berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Qotadah] dari [Muhammad bin Sirin] dari [Shafiah binti Al Harits] dari [Aisyah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Allah tidak menerima shalat wanita yang telah haidl kecuali dengan mengenakan kerudung.\""},"616":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا حَجَّاجٌ حَدَّثَنَا يَزِيدُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَيُّوبُ عَنْ مُعَاذَةَأَنَّ امْرَأَةً سَأَلَتْ عَائِشَةَ قَالَتْ تَخْتَضِبُ الْحَائِضُ فَقَالَتْ قَدْ كُنَّا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ نَخْتَضِبُ فَلَمْ يَكُنْ يَنْهَانَا عَنْهُ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Hajjaj] berkata, telah menceritakan kepada kami [Yazid bin Ibrahim] berkata, telah menceritakan kepada kami [Ayyub] dari [Mu'adzah] berkata; Seorang wanita bertanya kepada [Aisyah], \"Apakah seorang wanita yang sedang haidl boleh menyemir rambutnya?\" ia menjawab, \"Pernah kami di sisi Nabi shallallahu 'alaihi wasallam menyemir rambut, dan beliau tidak melarang kami.\" "},"617":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبَانَ الْبَلْخِيُّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا إِسْرَائِيلُ عَنْ عَمْرِو بْنِ خَالِدٍ عَنْ زَيْدِ بْنِ عَلِيٍّ عَنْ أَبِيهِ عَنْ جَدِّهِ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ قَالَانْكَسَرَتْ إِحْدَى زَنْدَيَّ فَسَأَلْتُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَنِي أَنْ أَمْسَحَ عَلَى الْجَبَائِرِقَالَ أَبُو الْحَسَنِ بْنُ سَلَمَةَ أَنْبَأَنَا الدَّبَرِيُّ عَنْ عَبْدِ الرَّزَّاقِ نَحْوَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Aban Al Balkhi] berkata, telah menceritakan kepada kami [Abdurrazzaq] berkata, telah memberitakan kepada kami [Isra`il] dari ['Amru bin Khalid] dari [Zaid bin Ali] dari [Bapaknya] dari [Kakeknya] dari [Ali bin Abu Thalib] ia berkata; \"Salah satu lengan tanganku retak, maka aku tanyakan hal itu kepada Nabi shallallahu 'alaihi wasallam. Kemudian beliau memerintahkan kepadaku agar mengusap bagian atas kain pembalut luka.\" Abu Al Hasan bin Salamah berkata; telah memberitakan kepada kami Ad Dabari dari Abdurrazzaq sebagaimana hadits diatas tersebut."},"618":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ زِيَادٍ عَنْ أَبِي هُرَيْرَةَ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَامِلَ الْحُسَيْنِ بْنِ عَلِيٍّ عَلَى عَاتِقِهِ وَلُعَابُهُ يَسِيلُ عَلَيْهِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Hammad bin Salamah] dari [Muhammad bin Ziyad] dari [Abu Hurairah] ia berkata; \"Aku melihat Nabi shallallahu 'alaihi wasallam menggendong Husain bin Ali di atas pundaknya, sedang air liurnya mengalir ke tubuh beliau.\""},"619":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّ��َنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ مِسْعَرٍ ح و حَدَّثَنَا مُحَمَّدُ بْنُ عُثْمَانَ بْنِ كَرَامَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ مِسْعَرٍ عَنْ عَبْدِ الْجَبَّارِ بْنِ وَائِلٍ عَنْ أَبِيهِ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِدَلْوٍ فَمَضْمَضَ مِنْهُ فَمَجَّ فِيهِ مِسْكًا أَوْ أَطْيَبَ مِنْ الْمِسْكِ وَاسْتَنْثَرَ خَارِجًا مِنْ الدَّلْوِ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] berkata, telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Mis'ar]. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Muhammad bin Utsman bin Karamah] berkata, telah menceritakan kepada kami [Abu Usamah] dari [Mis'ar] dari [Abdul Jabbar bin Wa`il] dari [Bapaknya] ia berkata; \"Aku melihat Rasulullah shallallahu 'alaihi wasallam diberi satu ember air, lalu beliau berkumur-kumur dan mengeluarkan air dari mulutnya seharum minyak misk, atau lebih baik dari itu, dan beliau mengeluarkan air dari hidung di luar ember.\" "},"620":{"ar":"حَدَّثَنَا أَبُو مَرْوَانَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ الزُّهْرِيِّ عَنْ مَحْمُودِ بْنِ الرَّبِيعِوَكَانَ قَدْ عَقَلَ مَجَّةً مَجَّهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي دَلْوٍ مِنْ بِئْرٍ لَهُمْ","id":"Telah menceritakan kepada kami [Abu Marwan] berkata, telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Az Zuhri] dari [Mahmud bin Ar Rabi']; dia telah menjaga Majjah (air yang dikeluarkan dari dalam mulut) dalam ember yang Rasulullah shallallahu 'alaihi wasallam keluarkan (muntahkan) ke dalam sumur milik mereka.\""},"621":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ عَنْ الضَّحَّاكِ بْنِ عُثْمَانَ حَدَّثَنَا زَيْدُ بْنُ أَسْلَمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَنْظُرْ الْمَرْأَةُ إِلَى عَوْرَةِ الْمَرْأَةِ وَلَا يَنْظُرْ الرَّجُلُ إِلَى عَوْرَةِ الرَّجُلِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Zaid bin Al Hubab] dari [Adl Dlahak bin Utsman] berkata, telah menceritakan kepada kami [Zaid bin Aslam] dari [Abdurrahman bin Abu Sa'id Al Khudri] dari [Bapaknya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah seorang wanita melihat aurat wanita lain, dan janganlah seorang lelaki melihat aurat lelaki lain.\""},"622":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ عَنْ مُوسَى بْنِ عَبْدِ اللَّهِ بْنِ يَزِيدَ عَنْ مَوْلًى لِعَائِشَةَ عَنْ عَائِشَةَ قَالَتْمَا نَظَرْتُ أَوْ مَا رَأَيْتُ فَرْجَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَطُّقَالَ أَبُو بَكْرٍ كَانَ أَبُو نُعَيْمٍ يَقُولُ عَنْ مَوْلَاةٍ لِعَائِشَةَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Manshur] dari [Musa bin Abdullah bin Yazid] dari [Mantan budak Aisyah] dari [Aisyah] ia berkata; \"Aku tidak pernah melihat kemaluan Rasulullah shallallahu 'alaihi wasallam sama sekali.\" Abu Bakr berkata; \"Abu Nu'aim menceritakan dari mantan budak Aisyah. "},"623":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَإِسْحَقُ بْنُ مَنْصُورٍ قَالَا حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا مُسْتَلِمُ بْنُ سَعِيدٍ عَنْ أَبِي عَلِيٍّ الرَّحَبِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اغْتَسَلَ مِنْ جَنَابَةٍ فَرَأَى لُمْعَةً لَمْ يُصِبْهَا الْمَاءُ فَقَالَ بِجُمَّتِهِ فَبَلَّهَا عَلَيْهَا قَالَ إِسْحَقُ فِي حَدِيثِهِ فَعَصَرَ شَعْرَهُ عَلَيْهَا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ishaq bin Manshur] keduanya berkata; telah menceritakan kepada kami [Yazid bin Harun] berkata, telah memberitakan kepada kami [Mustalim bin Sa'id] dari [Abu Ali Ar Rahabi] dari [Ikrimah] dari [Ibnu 'Abbas] berkata; \"Pernah Nabi shallallahu 'alaihi wasallam mandi junub lalu beliau melihat bagian tubuhnya ada yang belum terkena air. Lalu beliau mengatakan dengan isyarat rambut panjangnya seraya membasahi bagian yang belum terkena air.\" Ishaq menyebutkan dalam haditsnya; \"Lalu beliau memeras air rambutnya dan membasahi pada bagian yang belum basah.\""},"624":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ عَنْ الْحَسَنِ بْنِ سَعْدٍ عَنْ أَبِيهِ عَنْ عَلِيٍّ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنِّي اغْتَسَلْتُ مِنْ الْجَنَابَةِ وَصَلَّيْتُ الْفَجْرَ ثُمَّ أَصْبَحْتُ فَرَأَيْتُ قَدْرَ مَوْضِعِ الظُّفْرِ لَمْ يُصِبْهُ الْمَاءُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ كُنْتَ مَسَحْتَ عَلَيْهِ بِيَدِكَ أَجْزَأَكَ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] berkata, telah menceritakan kepada kami [Abul Ahwash] dari [Muhammad bin Abdullah] dari [Al Hasan bin Sa'd] dari [Bapaknya] dari [Ali] ia berkata; Seorang lelaki datang menemui Nabi shallallahu 'alaihi wasallam dan bertanya; \"Aku mandi junub dan shalat fajar, kemudian di pagi harinya aku melihat seukuran tempat kuku yang tidak terkena air?\" Maka Rasulullah shallallahu 'alaihi wasallam pun menjawab: \"Sekiranya engkau mengusapnya dengan tanganmu, maka itu telah cukup.\" "},"625":{"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ رَجُلًا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ تَوَضَّأَ وَتَرَكَ مَوْضِعَ الظُّفْرِ لَمْ يُصِبْهُ الْمَاءُ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ارْجِعْ فَأَحْسِنْ وُضُوءَكَ","id":"Telah menceritakan kepada kami [Harmalah bin Yahya] berkata, telah menceritakan kepada kami [Abdullah bin Wahb] berkata, telah menceritakan kepada kami [Jarir bin Hazim] dari [Qotadah] dari [Anas] berkata; Seorang laki-laki datang menemui Nabi shallallahu 'alaihi wasallam, laki-laki tersebut telah berwudlu namun masih menyisakan seukuran kuku yang belum terkena air, maka Nabi shallallahu 'alaihi wasallam pun bersabda kepadanya: \"Kembali dan perbaikilah wudlumu.\""},"626":{"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى حَدَّثَنَا ابْنُ وَهْبٍ ح و حَدَّثَنَا ابْنُ حُمَيْدٍ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ قَالَا حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ عَنْ عُمَرَ بْنِ الْخَطَّابِ قَالَرَأَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا تَوَضَّأَ فَتَرَكَ مَوْضِعَ الظُّفْرِ عَلَى قَدَمِهِ فَأَمَرَهُ أَنْ يُعِيدَ الْوُضُوءَ وَالصَّلَاةَ قَالَ فَرَجَعَ","id":"Telah menceritakan kepada kami [Harmalah bin Yahya] berkata, telah menceritakan kepada kami [Ibnu Wahb]. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Ibnu Humaid] berkata, telah menceritakan kepada kami [Zaid Ibnul Hubab] keduanya berkata; telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Az Zubair] dari [Jabir] dari [Umar Ibnul Khaththab] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam melihat seorang laki-laki berwudlu namun masih menyisakan seukuran kuku yang belum terbasuh air di kakinya, maka beliau pun memerintahkannya agar mengulangi wudlu dan shalatnya.\" Umar Ibnul Khaththab berkata; \"Lalu laki-laki itu pun kembali mengulangi.\""},"627":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ وَأَحْمَدُ بْنُ سِنَانٍ قَالَا حَدَّثَنَا إِسْحَقُ بْنُ يُوسُفَ الْأَزْرَقُ أَنْبَأَنَا سُفْيَانُ ح وَحَدَّثَنَا عَلِيُّ بْنُ مَيْمُونٍ الرَّقِّيُّ حَدَّثَنَا مَخْلَدُ بْنُ يَزِيدَ عَنْ سُفْيَانَ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ سُلَيْمَانَ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهُ عَنْ وَقْتِ الصَّلَاةِ فَقَالَ صَلِّ مَعَنَا هَذَيْنِ الْيَوْمَيْنِ فَلَمَّا زَالَتْ الشَّمْسُ أَمَرَ بِلَالًا فَأَذَّنَ ثُمَّ أَمَرَهُ فَأَقَامَ الظُّهْرَ ثُمَّ أَمَرَهُ فَأَقَامَ الْعَصْرَ وَالشَّمْسُ مُرْتَفِعَةٌ بَيْضَاءُ نَقِيَّةٌ ثُمَّ أَمَرَهُ فَأَقَامَ الْمَغْرِبَ حِينَ غَابَتْ الشَّمْسُ ثُمَّ أَمَرَهُ فَأَقَامَ الْعِشَاءَ حِينَ غَابَ الشَّفَقُ ثُمَّ أَمَرَهُ فَأَقَامَ الْفَجْرَ حِينَ طَلَعَ الْفَجْرُ فَلَمَّا كَانَ مِنْ الْيَوْمِ الثَّانِي أَمَرَهُ فَأَذَّنَ الظُّهْرَ فَأَبْرَدَ بِهَا وَأَنْعَمَ أَنْ يُبْرِدَ بِهَا ثُمَّ صَلَّى الْعَصْرَ وَالشَّمْسُ مُرْتَفِعَةٌ أَخَّرَهَا فَوْقَ الَّذِي كَانَ فَصَلَّى الْمَغْرِبَ قَبْلَ أَنْ يَغِيبَ الشَّفَقُ وَصَلَّى الْعِشَاءَ بَعْدَ مَا ذَهَبَ ثُلُثُ اللَّيْلِ وَصَلَّى الْفَجْرَ فَأَسْفَرَ بِهَا ثُمَّ قَالَ أَيْنَ السَّائِلُ عَنْ وَقْتِ الصَّلَاةِ فَقَالَ الرَّجُلُ أَنَا يَا رَسُولَ اللَّهِ قَالَ وَقْتُ صَلَاتِكُمْ بَيْنَ مَا رَأَيْتُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] dan [Ahmad bin Sinan] keduanya berkata; telah menceritakan kepada kami [Ishaq bin Yusuf Al Azraq] berkata, telah memberitakan kepada kami [Sufyan]. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Ali bin Maimun Ar Raqqi] berkata, telah menceritakan kepada kami [Makhlad bin Yazid] dari [Sufyan] dari [Alqamah bin Martsad] dari [Sulaiman bin Buraidah] dari [Bapaknya] ia berkata; Seorang laki-laki datang menemui Nabi shallallahu 'alaihi wasallam dan bertanya kepadanya tentang waktu shalat, maka beliau bersabda: \"Shalatlah bersama kami dalam dua hari ini.\" Maka ketika matahari telah condong beliau memerintahkan Bilal maka Bilal pun adzan, kemudian beliau memerintahkan Bilal maka Bilal pun iqamah, setelah itu beliau melaksanakan shalat zhuhur. Kemudian beliau memerintahkannya lagi, maka Bilal pun iqamah, lalu beliau melaksanakan shalat ashar sementara matahari masih tinggi dan bersinar terang. Kemudian beliau memerintahkannya lagi, lalu beliau melaksanakan shalat maghrib ketika matahari terbenam. Kemudian beliau memerintahkannya lagi, lalu beliau pun melaksanakan shalat isya ketika warna merah di langit hilang. Kemudian beliau memerintahkannya lagi, lalu beliau melaksanakan shalat subuh ketika terbit fajar. Pada hari kedua, beliau memerintahkannya hingga Bilal pun adzan zhuhur, lalu beliau menunggu hingga hari menjadi teduh, kemudian beliau shalat ashar sementara matahari masih tinggi, dan beliau hanya sedikit mengakhirkan dari waktu kemarin. Lalu beliau shalat maghrib sebelum warna merah di langit hilang. Dan shalat isya setelah berlalu dari waktu sepertiga malam. Dan shalat subuh ketika langit telah terang. Setelah itu beliau bersabda: \"Kemana orang yang bertanya tentang waktu shalat?\" Lalu berkatalah seorang laki-laki; \"Saya wahai Rasulullah, \" beliau bersabda: \"Waktu shalat kalian adalah antara waktu-waktu yang telah kalian saksikan.\""},"628":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ الْمِصْرِيُّ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ أَنَّهُ كَانَ قَاعِدًا عَلَى مَيَاثِرِ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ فِي إِمَارَتِهِ عَلَى الْمَدِينَةِ وَمَعَهُ عُرْوَةُ بْنُ الزُّبَيْرِ فَأَخَّرَ عُمَرُ الْعَصْرَ شَيْئًا فَقَالَ لَهُ عُرْوَةُ أَمَا إِنَّ جِبْرِيلَ نَزَلَ فَصَلَّى إِمَامَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُ عُمَرُ اعْلَمْ مَا تَقُولُ يَا عُرْوَةُ قَالَ سَمِعْتُ بَشِيرَ بْنَ أَبِي مَسْعُودٍ يَقُولُ سَمِعْتُ أَبَا مَسْعُودٍ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ نَزَلَ جِبْرِيلُ فَأَمَّنِي فَصَلَّيْتُ مَعَهُ ثُمَّ صَلَّيْتُ مَعَهُ ثُمَّ صَلَّيْتُ مَعَهُ ثُمَّ صَلَّيْتُ مَعَهُ ثُمَّ صَلَّيْتُ مَعَهُ يَحْسُبُ بِأَصَابِعِهِ خَمْسَ صَلَوَاتٍ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh Al Mishri] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Ibnu Syihab] bahwasanya ia pernah duduk di atas kasur milik Umar bin Abdul Aziz ketika ia masih menjadi pemimpin di Madinah. Dan waktu itu Umar bersama ['Urwah bin Az Zubair]. Umar bin Abdul Aziz mengakhirkan sedikit dari waktu shalat ashar hingga 'Urwah berkata kepadanya; \"Jibril pernah turun dan shalat menjadi Imam bagi Rasulullah shallallahu 'alaihi wasallam, \" Umar pun ganti berkata kepadanya; \"Hati-hati dengan yang engkau katakan ya 'Urwah! \" 'Urwah berkata; \"Aku mendengar [Basyir bin Abu Mas'ud] berkata; Aku mendengar [Abu Mas'ud] berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jibril turun dan mengimami aku shalat, maka aku pun shalat bersamanya, kemudian aku shalat bersamanya, kemudian aku shalat bersamanya, kemudian aku shalat bersamanya, kemudian aku shalat bersamanya, \" dia menghitung dengan jemarinya lima kali."},"629":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْكُنَّ نِسَاءُ الْمُؤْمِنَاتِ يُصَلِّينَ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الصُّبْحِ ثُمَّ يَرْجِعْنَ إِلَى أَهْلِهِنَّ فَلَا يَعْرِفُهُنَّ أَحَدٌ تَعْنِي مِنْ الْغَلَسِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari ['Urwah] dari [Aisyah] ia berkata; \"Para wanita mukminah shalat subuh bersama Nabi shallallahu 'alaihi wasallam, kemudian mereka kembali kepada keluarganya masing-masing dan tidak ada seorangpun yang mengenal mereka karena pagi yang masih gelap.\""},"630":{"ar":"حَدَّثَنَا عُبَيْدُ بْنُ أَسْبَاطِ بْنِ مُحَمَّدٍ الْقُرَشِيُّ حَدَّثَنَا أَبِي عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ اللَّهِ وَالْأَعْمَشُ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ وَقُرْآنَ الْفَجْرِ إِنَّ قُرْآنَ الْفَجْرِ كَانَ مَشْهُودًا }قَالَ تَشْهَدُهُ مَلَائِكَةُ اللَّيْلِ وَالنَّهَارِ","id":"Telah menceritakan kepada kami [Ubaid bin Asbath bin Muhammad Al Qurasyi] berkata, telah menceritakan kepada kami [Bapakku] dari [Al A'masy] dari [Ibrahim] dari [Abdullah] dan [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam tentang firman Allah: \"dan (dirikanlah pula shalat) subuh. Sesungguhnya shalat subuh itu disaksikan (oleh malaikat).\" Beliau bersabda: \"Malaikat malam dan siang ikut menyaksikannya.\""},"631":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنَا نَهِيكُ بْنُ يَرِيمَ الْأَوْزَاعِيُّ حَدَّثَنَا مُغِيثُ بْنُ سُمَيٍّ قَالَصَلَّيْتُ مَعَ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ الصُّبْحَ بِغَلَسٍ فَلَمَّا سَلَّمَ أَقْبَلْتُ عَلَى ابْنِ عُمَرَ فَقُلْتُ مَا هَذِهِ الصَّلَاةُ قَالَ هَذِهِ صَلَاتُنَا كَانَتْ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبِي بَكْرٍ وَعُمَرَ فَلَمَّا طُعِنَ عُمَرُ أَسْفَرَ بِهَا عُثْمَانُ","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim Ad Dimasyqi] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Al Auza'i] berkata, telah menceritakan kepada kami [Nahik bin Yarim Al Auza'i] berkata, telah menceritakan kepada kami [Mughits bin Sumay] ia berkata; Aku shalat subuh bersama Abdullah bin Az Zubair di pagi yang masih gelap, setelah ia salam aku pun menghadap ke arah [Ibnu Umar] seraya berkata kepadanya, \"Shalat apakah ini?\" Dia menjawab; \"Ini adalah shalat yang pernah kami lakukan bersama Rasulullah shallallahu 'alaihi wasallam, Abu Bakar dan Umar. Ketika Umar ditikam, Utsman melakukannya ketika langit telah terang.\" "},"632":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ ابْنِ عَجْلَانَ سَمِعَ عَاصِمَ بْنَ عُمَرَ بْنِ قَتَادَةَ وَجَدُّهُ بَدْرِيٌّ يُخْبِرُ عَنْ مَحْمُودِ بْنِ لَبِيدٍ عَنْ رَافِعِ بْنِ خَدِيجٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَصْبِحُوا بِالصُّبْحِ فَإِنَّهُ أَعْظَمُ لِلْأَجْرِ أَوْ لِأَجْرِكُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah memberitakan kepada kami [Sufyan bin 'Uyainah] dari [Ibnu 'Ajlan] ia mendengar ['Ashim bin Umar bin Qotadah] dan Kakeknya Badri mengabarkan dari [Mahmud bin Labid] dari [Rafi' bin Khadij] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Bersegeralah dalam melaksanakan shalat subuh, sebab hal itu sangat besar pahalanya, atau pahalanya bagi kalian.\""},"633":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ شُعْبَةَ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ جَابِرِ بْنِ سَمُرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي الظُّهْرَ إِذَا دَحَضَتْ الشَّمْسُ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dari [Syu'bah] dari [Simak bin Harb] dari [Jabir bin Samurah] bahwa Nabi shallallahu 'alaihi wasallam menunaikan shalat zhuhur ketika matahari telah bergeser ke barat.\""},"634":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عَوْفِ بْنِ أَبِي جَمِيلَةَ عَنْ سَيَّارِ بْنِ سَلَامَةَ عَنْ أَبِي بَرْزَةَ الْأَسْلَمِيِّ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي صَلَاةَ الْهَجِيرِ الَّتِي تَدْعُونَهَا الظُّهْرَ إِذَا دَحَضَتْ الشَّمْسُ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dari ['Auf bin Abu Jamilah] dari [Sayyar bin Salamah] dari [Abu Barzah Al Aslami] ia berkata; \"Nabi shallallahu 'alaihi wasallam mengerjakan shalat di tengah hari yang kalian sebut dengan zhuhur, ketika matahari telah condong.\""},"635":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي إِسْحَقَ عَنْ حَارِثَةَ بْنِ مُضَرِّبٍ الْعَبْدِيِّ عَنْ خَبَّابٍ قَالَشَكَوْنَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَرَّ الرَّمْضَاءِ فَلَمْ يُشْكِنَاقَالَ الْقَطَّانُ حَدَّثَنَا أَبُو حَاتِمٍ حَدَّثَنَا الْأَنْصَارِيُّ حَدَّثَنَا عَوْفٌ نَحْوَهُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Al A'masy] dari [Abu Ishaq] dari [Haritsah bin Mudlarrib Al 'Abdi] dari [Khabbab] ia berkata; Kami mengeluhkan kepada Rasulullah shallallahu 'alaihi wasallam akan panasnya ramdla` (pasir panas karena sengatan matahari), namun beliau tidak pernah mengeluh kepada kami.\" Al Qaththan berkata; telah menceritakan kepada kami Abu Hatim berkata, telah menceritakan kepada kami Al Anshari berkata, telah menceritakan kepada kami Auf sebagaimana hadits diatas."},"636":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا مُعَاوِيَةُ بْنُ هِشَامٍ عَنْ سُفْيَانَ عَنْ زَيْدِ بْنِ جُبَيْرٍ عَنْ خِشْفِ بْنِ مَالِكٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَشَكَوْنَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَرَّ الرَّمْضَاءِ فَلَمْ يُشْكِنَا","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Mu'awiyah bin Hisyam] dari [Sufyan] dari [Zaid bin Jubair] dari [Khisyf bin Malik] dari [Bapaknya] dari [Abdullah bin Mas'ud] ia berkata; \"Kami mengeluh kepada Rasulullah shallallahu 'alaihi wasallam dari panasnya ramdla` (pasir panas karena sengatan matahari), namun beliau tidak pernah mengeluh kepada kami.\""},"637":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ حَدَّثَنَا أَبُو الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اشْتَدَّ الْحَرُّ فَأَبْرِدُوا بِالصَّلَاةِ فَإِنَّ شِدَّةَ الْحَرِّ مِنْ فَيْحِ جَهَنَّمَ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] berkata, telah menceritakan kepada kami [Malik bin Anas] berkata, telah menceritakan kepada kami [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika panas sangat menyengat, maka tundalah shalat sampai hari menjadi dingin (teduh), sesungguhnya panas yang menyengat adalah dari hembusan jahannam.\""},"638":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيِّبِ وَأَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا اشْتَدَّ الْحَرُّ فَأَبْرِدُوا بِالظُّهْرِ فَإِنَّ شِدَّةَ الْحَرِّ مِنْ فَيْحِ جَهَنَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Ibnu Syihab] dari [Sa'id Ibnul Musayyab] dan [Abu Salamah bin Abdurrahman] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika panas sangat menyengat, maka tundalah shalat zhuhur sampai hari menjadi dingin (teduh), sesungguhnya panas yang menyengat adalah dari hembusan jahannam.\""},"639":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبْرِدُوا بِالظُّهْرِ فَإِنَّ شِدَّةَ الْحَرِّ مِنْ فَيْحِ جَهَنَّمَ","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Sa'id] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tundalah shalat zhuhur sampai hari menjadi dingin (teduh), sesungguhnya panas yang menyengat adalah dari hembusan neraka Jahannam.\""},"640":{"ar":"حَدَّثَنَا تَمِيمُ بْنُ الْمُنْتَصِرِ الْوَاسِطِيُّ حَدَّثَنَا إِسْحَقُ بْنُ يُوسُفَ عَنْ شَرِيكٍ عَنْ بَيَانٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَكُنَّا نُصَلِّي مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الظُّهْرِ بِالْهَاجِرَةِ فَقَالَ لَنَا أَبْرِدُوا بِالصَّلَاةِ فَإِنَّ شِدَّةَ الْحَرِّ مِنْ فَيْحِ جَهَنَّمَ","id":"Telah menceritakan kepada kami [Tamim bin Al Muntashir Al Wasithi] berkata, telah menceritakan kepada kami [Ishaq bin Yusuf] dari [Syarik] dari [Bayan] dari [Qais bin Abu Hazim] dari [Mughirah bin Syu'bah] ia berkata; Kami pernah shalat zhuhur bersama Rasulullah shallallahu 'alaihi wasallam pada waktu tengah hari, lalu beliau bersabda: \"Tundalah shalat hingga hari menjadi dingin (teduh), sesungguhnya panas yang menyengat adalah dari hembusan neraka Jahannam.\""},"641":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عُمَرَ حَدَّثَنَا عَبْدُ الْوَهَّابِ الثَّقَفِيُّ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبْرِدُوا بِالظُّهْرِ","id":"Telah menceritakan kepada kami [Abdurrahman bin Umar] berkata, telah menceritakan kepada kami [Abdul Wahhab Ats Tsaqafi] dari [Ubaidullah] dari [Nafi'] dari [Ibnu Umar] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tundalah shalat hingga hari menjadi dingin (teduh).\""},"642":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّهُ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي الْعَصْرَ وَالشَّمْسُ مُرْتَفِعَةٌ حَيَّةٌ فَيَذْهَبُ الذَّاهِبُ إِلَى الْعَوَالِي وَالشَّمْسُ مُرْتَفِعَةٌ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Ibnu Syihab] dari [Anas bin Malik] bahwasanya ia telah mengabarkan kepadanya, bahwa Rasulullah shallallahu 'alaihi wasallam melakukan shalat ashar sementara matahari masih tinggi bersinar, dan seseorang pergi ke 'Awali sedang matahari masih tinggi.\" "},"643":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْصَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَصْرَ وَالشَّمْسُ فِي حُجْرَتِي لَمْ يُظْهِرْهَا الْفَيْءُ بَعْدُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari ['Urwah] dari [Aisyah] ia berkata; \"Nabi shallallahu 'alaihi wasallam menunaikan shalat ashar, sementara matahari di kamarku tidak menampakkan bayang-bayang.\" "},"644":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَاصِمِ بْنِ بَهْدَلَةَ عَنْ زِرِّ بْنِ حُبَيْشٍ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَوْمَ الْخَن��دَقِ مَلَأَ اللَّهُ بُيُوتَهُمْ وَقُبُورَهُمْ نَارًا كَمَا شَغَلُونَا عَنْ الصَّلَاةِ الْوُسْطَى","id":"Telah menceritakan kepada kami [Ahmad bin Abdah] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari ['Ashim bin Bahdalah] dari [Zirr bin Hubaisy] dari [Ali bin Abu Thalib], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda pada waktu perang Khandaq: \"Semoga Allah memenuhi rumah dan kuburan mereka dengan api sebagaimana mereka telah menyibukkan kita dari melaksanakan shalat ashar.\""},"645":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الَّذِي تَفُوتُهُ صَلَاةُ الْعَصْرِ فَكَأَنَّمَا وُتِرَ أَهْلُهُ وَمَالُهُ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Salim] dari [Ibnu Umar], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seseorang yang kehilangan shalat ashar seperti orang yang kehilangan keluarga dan hartanya.\" "},"646":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عَمْرٍو حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ ح و حَدَّثَنَا يَحْيَى بْنُ حَكِيمٍ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ طَلْحَةَ عَنْ زُبَيْدٍ عَنْ مُرَّةَ عَنْ عَبْدِ اللَّهِ قَالَحَبَسَ الْمُشْرِكُونَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ صَلَاةِ الْعَصْرِ حَتَّى غَابَتْ الشَّمْسُ فَقَالَ حَبَسُونَا عَنْ صَلَاةِ الْوُسْطَى مَلَأَ اللَّهُ قُبُورَهُمْ وَبُيُوتَهُمْ نَارًا","id":"Telah menceritakan kepada kami [Hafsh bin 'Amru] berkata, telah menceritakan kepada kami [Abdurrahman bin Mahdi]. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Yahya bin Hakim] berkata, telah menceritakan kepada kami [Yazid bin Harun], keduanya berkata; telah menceritakan kepada kami [Muhammad bin Thalhah] dari [Zubaid] dari [Murrah] dari [Abdullah] ia berkata; Orang-orang kafir Musyrik menghalangi Nabi shallallahu 'alaihi wasallam dari melaksanakan shalat ashar hingga matahari hampir tenggelam. Maka beliau pun bersabda: \"Mereka telah menghalangi kita dari shalat ashar, semoga Allah memenuhi kuburan dan rumah mereka dengan api.\""},"647":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنَا أَبُو النَّجَاشِيِّ قَالَ سَمِعْتُ رَافِعَ بْنَ خَدِيجٍ يَقُولُكُنَّا نُصَلِّي الْمَغْرِبَ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَنْصَرِفُ أَحَدُنَا وَإِنَّهُ لَيَنْظُرُ إِلَى مَوَاقِعِ نَبْلِهِحَدَّثَنَا أَبُو يَحْيَى الزَّعْفَرَانِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى نَحْوَهُ","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim Ad Dimasyqi] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Al Auza'i] berkata, telah menceritakan kepada kami [Abu An Najasyi] ia berkata; Aku mendengar [Rafi' bin Khadij] berkata; \"Pada masa Rasulullah shallallahu 'alaihi wasallam, kami pernah shalat maghrib, lalu salah seorang dari kami berlalu pergi dan ia masih dapat melihat sasaran anak panahnya.\" Telah menceritakan kepada kami Abu Yahya Az Za'farani berkata, telah menceritakan kepada kami Ibrahim bin Musa sebagaimana hadits diatas."},"648":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ حَدَّثَنَا الْمُغِيرَةُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ يَزِيدَ بْنِ أَبِي عُبَيْدٍ عَنْ سَلَمَةَ بْنِ الْأَكْوَعِأَنَّهُ كَانَ يُصَلِّي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَغْرِبَ إِذَا تَوَارَتْ بِالْحِجَابِ","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib] berkata, telah menceritakan kepada kami [Al Mughirah bin Abdurrahman] dari [Yazid bin Abu Ubaid] dari [Salamah bin Al Akwa'] bahwasanya ia pernah shalat maghrib bersama Nabi shallallahu 'alaihi wasallam ketika matahari telah terbenam.\""},"649":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَنْبَأَنَا عَبَّادُ بْنُ الْعَوَّامِ عَنْ عُمَرَ بْنِ إِبْرَاهِيمَ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ الْأَحْنَفِ بْنِ قَيْسٍ عَنْ الْعَبَّاسِ بْنِ عَبْدِ الْمُطَّلِبِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَزَالُ أُمَّتِي عَلَى الْفِطْرَةِ مَا لَمْ يُؤَخِّرُوا الْمَغْرِبَ حَتَّى تَشْتَبِكَ النُّجُومُقَالَ أَبُو عَبْد اللَّهِ بْن مَاجَةَ سَمِعْت مُحَمَّدَ بْنَ يَحْيَى يَقُولُ اضْطَرَبَ النَّاسُ فِي هَذَا الْحَدِيثِ بِبَغْدَادَ فَذَهَبْتُ أَنَا وَأَبُو بَكْرٍ الْأَعْيَنُ إِلَى الْعَوَّامِ بْنِ عَبَّادِ بْنِ الْعَوَّامِ فَأَخْرَجَ إِلَيْنَا أَصْلَ أَبِيهِ فَإِذَا الْحَدِيثُ فِيهِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Ibrahim bin Musa] berkata, telah memberitakan kepada kami [Abbad bin Al 'Awwam] dari [Umar bin Ibrahim] dari [Qotadah] dari [Al Hasan] dari [Al Ahnaf bin Qais] dari [Al 'Abbas bin Abdul Muththalib] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Umatku akan senantiasa di atas fitrah selagi mereka tidak mengakhirkan maghrib hingga bintang bermunculan.\" Abu Abdullah Ibnu Majah berkata; Aku mendengar Muhammad bin Yahya berkata; \"Orang-orang di Baghdad menjadi bingung dengan hadits ini, maka aku dan Abu Bakar Al A'yan pergi menemui Al 'Awwam bin Abbad bin Al 'Awwam. Lalu dia mengeluarkan peninggalan bapaknya yang asli, ternyata di sana terdapat hadits."},"650":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَوْلَا أَنْ أَشُقَّ عَلَى أُمَّتِي لَأَمَرْتُهُمْ بِتَأْخِيرِ الْعِشَاءِ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekiranya tidak memberatkan umatku, sungguh akan aku perintahkan mereka untuk mengakhirkan shalat isya.\""},"651":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ وَعَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ عُبَيْدِ اللَّهِ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْلَا أَنْ أَشُقَّ عَلَى أُمَّتِي لَأَخَّرْتُ صَلَاةَ الْعِشَاءِ إِلَى ثُلُثِ اللَّيْلِ أَوْ نِصْفِ اللَّيْلِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Usamah] dan [Abdullah bin Numair] dari [Ubaidullah] dari [Sa'id bin Abu Sa'id] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekiranya tidak memberatkan umatku, sungguh akan aku akhirkan shalat isya hingga sepertiga atau pertengahan malam.\""},"652":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا حُمَيْدٌ قَالَسُئِلَ أَنَسُ بْنُ مَالِكٍ هَلْ اتَّخَذَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَاتَمًا قَالَ نَعَمْ أَخَّرَ لَيْلَةً صَلَاةَ الْعِشَاءِ إِلَى قَرِيبٍ مِنْ شَطْرِ اللَّيْلِ فَلَمَّا صَلَّى أَقْبَلَ عَلَيْنَا بِوَجْهِهِ فَقَالَ إِنَّ النَّاسَ قَدْ صَلَّوْا وَنَامُوا وَإِنَّكُمْ لَنْ تَزَالُوا فِي صَلَاةٍ مَا انْتَظَرْتُمْ الصَّلَاةَ قَالَ أَنَسٌ كَأَنِّي أَنْظُرُ إِلَى وَبِيصِ خَاتَمِهِ","id":"Telah menceritakan kepada kami [Muhammad Ibnul Mutsanna] berkata, telah menceritakan kepada kami [Khalid Ibnul Harits] berkata, telah menceritakan kepada kami [Humaid] berkata; [Anas bin Malik] ditanya; \"Apakah Nabi shallallahu 'alaihi wasallam mengenakan cincin?\" ia menjawab; \"Ya, beliau mengakhirkan malam shalat isya hingga pertengahan malam, maka ketika selesai shalat beliau menghadap ke arah kami seraya bersabda: \"Orang-orang sudah shalat dan tertidur, dan kalian akan tetap dalam hitungan shalat selama kalian menunggunya.\" Anas berkata; \"Seakan-akan aku melihat kilatan cincinnya.\""},"653":{"ar":"حَدَّثَنَا عِمْرَانُ بْنُ مُوسَى اللَّيْثِيُّ حَدَّثَنَا عَبْدُ الْوَارِثِ بْنُ سَعِيدٍ حَدَّثَنَا دَاوُدُ بْنُ أَبِي هِنْدٍ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ قَالَصَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الْمَغْرِبِ ثُمَّ لَمْ يَخْرُجْ حَتَّى ذَهَبَ شَطْرُ اللَّيْلِ فَخَرَجَ فَصَلَّى بِهِمْ ثُمَّ قَالَ إِنَّ النَّاسَ قَدْ صَلَّوْا وَنَامُوا وَأَنْتُمْ لَمْ تَزَالُوا فِي صَلَاةٍ مَا انْتَظَرْتُمْ الصَّلَاةَ وَلَوْلَا الضَّعِيفُ وَالسَّقِيمُ أَحْبَبْتُ أَنْ أُؤَخِّرَ هَذِهِ الصَّلَاةَ إِلَى شَطْرِ اللَّيْلِ","id":"Telah menceritakan kepada kami [Imran bin Musa Al Laitsi] berkata, telah menceritakan kepada kami [Abdul Warits bin Sa'id] berkata, telah menceritakan kepada kami [Dawud bin Abu Hind] dari [Abu Nadlrah] dari [Abu Sa'id] ia berkata; Rasulullah shallallahu 'alaihi wasallam shalat maghrib bersama kami, kemudian beliau tidak keluar hingga berlalu pertengahan malam, lalu beliau keluar dan shalat bersama mereka. Setelah itu beliau bersabda: \"Sesungguhnya orang-orang telah shalat dan tidur, dan kalian akan senantiasa berada dalam hitungan shalat selagi kalian menunggunya. Sekiranya bukan karena orang lemah dan orang sakit, aku menyukai untuk mengakhirkan shalat ini hingga tengah malam.\""},"654":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ وَمُحَمَّدُ بْنُ الصَّبَّاحِ قَالَا حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْمُهَاجِرِ عَنْ بُرَيْدَةَ الْأَسْلَمِيِّ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةٍ فَقَالَ بَكِّرُوا بِالصَّلَاةِ فِي الْيَوْمِ الْغَيْمِ فَإِنَّهُ مَنْ فَاتَتْهُ صَلَاةُ الْعَصْرِ حَبِطَ عَمَلُهُ","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim] dan [Muhammad bin Ash Shabbah] keduanya berkata; telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Al Auza'i] berkata, telah menceritakan kepadaku [Yahya bin Abu Katsir] dari [Abu Qilabah] dari [Abu Al Muhajir] dari [Buraidah Al Aslami] ia berkata; Kami bersama Rasulullah shallallahu 'alaihi wasallam dalam peperangan, lalu beliau bersabda: \"Bersegeralah kalian kerjakan shalat di hari yang mendung, sebab barangsiapa kehilangan shalat ashar maka amalannya akan musnah.\""},"655":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا حَجَّاجٌ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَسُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الرَّجُلِ يَغْفُلُ عَنْ الصَّلَاةِ أَوْ يَرْقُدُ عَنْهَا قَالَ يُصَلِّيهَا إِذَا ذَكَرَهَا","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] berkata, telah menceritakan kepada kami [Yazid bin Zurai'] berkata, telah menceritakan kepada kami [Hajjaj] berkata, telah menceritakan kepada kami [Qotadah] dari [Anas bin Malik] berkata; Nabi shallallahu 'alaihi wasallam ditanya tentang seorang laki-laki yang lalai atau ketiduran dari mengerjakan shalat, maka beliau menjawab: \"Hendaknya ia kerjakan ketika telah mengingatnya.\""},"656":{"ar":"حَدَّثَنَا جُبَارَةُ بْنُ الْمُغَلِّسِ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ نَسِيَ صَلَاةً فَلْيُصَلِّهَا إِذَا ذَكَرَهَا","id":"Telah menceritakan kepada kami [Jubarah Ibnul Mughallis] berkata, telah menceritakan kepada kami [Abu Awanah] dari [Qotadah] dari [Anas bin Malik] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa lupa mengerjakan shalat maka hendaklah ia mengerjakannya ketika mengingatnya.\""},"657":{"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ حَدَّثَنَا يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيِّبِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ قَفَلَ مِنْ غَزْوَةِ خَيْبَرَ فَسَارَ لَيْلَهُ حَتَّى إِذَا أَدْرَكَهُ الْكَرَى عَرَّسَ وَقَالَ لِبِلَالٍ اكْلَأْ لَنَا اللَّيْلَ فَصَلَّى بِلَالٌ مَا قُدِّرَ لَهُ وَنَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابُهُ فَلَمَّا تَقَارَبَ الْفَجْرُ اسْتَنَدَ بِلَالٌ إِلَى رَاحِلَتِهِ مُوَاجِهَ الْفَجْرِ فَغَلَبَتْ بِلَالًا عَيْنَاهُ وَهُوَ مُسْتَنِدٌ إِلَى رَاحِلَتِهِ فَلَمْ يَسْتَيْقِظْ بِلَالٌ وَلَا أَحَدٌ مِنْ أَصْحَابِهِ حَتَّى ضَرَبَتْهُمْ الشَّمْسُ فَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوَّلَهُمْ اسْتِيقَاظًا فَفَزَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَيْ بِلَالُ فَقَالَ بِلَالٌ أَخَذَ بِنَفْسِي الَّذِي أَخَذَ بِنَفْسِكَ بِأَبِي أَنْتَ وَأُمِّي يَا رَسُولَ اللَّهِ قَالَ اقْتَادُوا فَاقْتَادُوا رَوَاحِلَهُمْ شَيْئًا ثُمَّ تَوَضَّأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَمَرَ بِلَالًا فَأَقَامَ الصَّلَاةَ فَصَلَّى بِهِمْ الصُّبْحَ فَلَمَّا قَضَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّلَاةَ قَالَ مَنْ نَسِيَ صَلَاةً فَلْيُصَلِّهَا إِذَا ذَكَرَهَا فَإِنَّ اللَّهَ عَزَّ وَجَلَّ قَالَ{ وَأَقِمْ الصَّلَاةَ لِذِكْرِي }قَالَ وَكَانَ ابْنُ شِهَابٍ يَقْرَؤُهَا لِلذِّكْرَى","id":"Telah menceritakan kepada kami [Harmalah bin Yahya] berkata, telah menceritakan kepada kami [Abdullah bin Wahb] berkata, telah menceritakan kepada kami [Yunus] dari [Ibnu Syihab] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah] berkata; \"Ketika Rasulullah shallallahu 'alaihi wasallam kembali dari perang Khaibar, beliau bergerak pada waktu malam hingga akhirnya beliau dihinggapi rasa kantuk, beliau berhenti untuk beristirahat seraya bersabda kepada Bilal: \"Jagalah kami pada malam ini.\" Bilal kemudian melaksanakan shalat semampunya, sementara Rasulullah shallallahu 'alaihi wasallam dan para sahabat lainnya tidur. Ketika waktu fajar telah dekat, Bilal menyandarkan dirinya pada kendaraannya menunggu waktu subuh. Namun rasa kantuk menyerangnya hingga ia tertidur dalam keadaan menyandar pada kendaraannya. Ia dan juga para sahabatnya tidak terbangun hingga sinar matahari menyengat. Dan Rasulullah adalah orang yang pertama kali bangun, beliau lalu melompat dan berseru: \"Wahai Bilal! \" Bilal menjawab; \"Wahai Rasulullah, demi ayah dan ibuku, Allah mengambil jiwaku sebagaimana telah mengambil jiwamu.\" Rasulullah bersabda: \"Tuntunlah.\" Maka mereka pun menuntun kendaraan-kendaraan mereka beberapa saat. Kemudian Rasulullah shallallahu 'alaihi wasallam berwudlu dan memerintah Bilal untuk iqamah, hingga Bilal pun mengumandangkan iqamah. Lalu beliau shalat subuh bersama dengan mereka. Setelah Rasulullah shallallahu 'alaihi wasallam selesai shalat, beliau bersabda: \"Barangsiapa lupa melaksanakan shalat, maka hendaklah ia melaksanakannya ketika mengingatnya, sesungguhnya Allah 'azza wajalla berfirman: (Dan dirikanlah shalat untuk mengingatKu).\" "},"658":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ أَنْبَأَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ ثَابِتٍ عَنْ عَبْدِ اللَّهِ بْنِ رَبَاحٍ عَنْ أَبِي قَتَادَةَ قَالَذَكَرُوا تَفْرِيطَهُمْ فِي النَّوْمِ فَقَالَ نَامُوا حَتَّى طَلَعَتْ الشَّمْسُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ فِي النَّوْمِ تَفْرِيطٌ إِنَّمَا التَّفْرِيطُ فِي الْيَقَظَةِ فَإِذَا نَسِيَ أَحَدُكُمْ صَلَاةً أَوْ نَامَ عَنْهَا فَلْيُصَلِّهَا إِذَا ذَكَرَهَا وَلِوَقْتِهَا مِنْ الْغَدِقَالَ عَبْدُ اللَّهِ بْنُ رَبَاحٍ فَسَمِعَنِي عِمْرَانُ بْنُ الْحُصَيْنِ وَأَنَا أُحَدِّثُ بِالْحَدِيثِ فَقَالَ يَا فَتًى انْظُرْ كَيْفَ تُحَدِّثُ فَإِنِّي شَاهِدٌ لِلْحَدِيثِ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَمَا أَنْكَرَ مِنْ حَدِيثِهِ شَيْئًا","id":"Telah menceritakan kepada kami [Ahmad bin 'Abdah] berkata, telah memberitakan kepada kami [Hammad bin Zaid] dari [Tsabit] dari [Abdullah bin Rabah] dari [Abu Qotadah] ia berkata; para sahabat menyebut-nyebut kelalaian mereka dalam masalah tidur, beliau bersabda: \"Tidurlah hingga matahari terbit.\" Lalu Rasulullah shallallahu 'alaihi wasallam bersabda lagi: \"Tidak ada kelalaian di dalam tidur, kelalaian itu hanya ada ketika terbangun. Jika salah seorang di antara kalian lupa shalat atau tertidur, maka hendaklah ia shalat ketika mengingatnya meskipun pada keesokan harinya.\" [Abdullah bin Rabah] berkata; Ketika aku menceritakan sebuah hadits, [Imran bin Hushain] mendengarku, lalu ia berkata; \"Hai anak muda, perhatikan bagaimana kamu menceritakan hadits, sungguh aku menyaksikan hadits Rasulullah shallallahu 'alaihi wasallam itu.\" Dia berkata; \"Maka ia pun tidak mengingkari sesuatupun dari haditsnya.\" "},"659":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ الدَّرَاوَرْدِيُّ أَخْبَرَنِي زَيْدُ بْنُ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ وَعَنْ بُسْرِ بْنِ سَعِيدٍ وَعَنْ الْأَعْرَجِ يُحَدِّثُونَهُ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَدْرَكَ مِنْ الْعَصْرِ رَكْعَةً قَبْلَ أَنْ تَغْرُبَ الشَّمْسُ فَقَدْ أَدْرَكَهَا وَمَنْ أَدْرَكَ مِنْ الصُّبْحِ رَكْعَةً قَبْلَ أَنْ تَطْلُعَ الشَّمْسُ فَقَدْ أَدْرَكَهَا","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah menceritakan kepada kami [Abdul Aziz bin Muhammad Ad Darawardi] berkata, telah mengabarkan kepadaku [Zaid bin Aslam] dari ['Atho` bin Yasar] dan dari [Busr bin Sa'id] dan dari [Al A'raj] mereka menceritakannya dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mendapatkan satu raka'at shalat asar sebelum matahari terbenam, maka ia telah mendapatkannya. Dan barangsiapa mendapatkan satu raka'at subuh sebelum matahari terbit, maka ia telah mendapatkannya.\""},"660":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ وَحَرْمَلَةُ بْنُ يَحْيَى الْمِصْرِيَّانِ قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَدْرَكَ مِنْ الصُّبْحِ رَكْعَةً قَبْلَ أَنْ تَطْلُعَ الشَّمْسُ فَقَدْ أَدْرَكَهَا وَمَنْ أَدْرَكَ مِنْ الْعَصْرِ رَكْعَةً قَبْلَ أَنْ تَغْرُبَ الشَّمْسُ فَقَدْ أَدْرَكَهَاحَدَّثَنَا جَمِيلُ بْنُ الْحَسَنِ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَذَكَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Ahmad bin 'Amru bin As Sarh] dan [Harmalah bin Yahya Al Mishriyani] keduanya berkata; telah menceritakan kepada kami [Abdullah bin Wahb] berkata; telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari ['Urwah] dari [Aisyah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mendapatkan satu raka'at shalat subuh sebelum matahari terbit maka ia telah mendapatkannya. Dan barangsiapa mendapatkan satu raka'at shalat ashar sebelum matahari terbenam maka ia telah mendapatkannya.\" Telah menceritakan kepada kami [Jamil Ibnul Hasan] berkata, telah menceritakan kepada kami [Abdul A'la] berkata, telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda, lalu ia menyebutkan sebagaimana hadits diatas."},"661":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ وَمُحَمَّدُ بْنُ جَعْفَرٍ وَعَبْدُ الْوَهَّابِ قَالُوا حَدَّثَنَا عَوْفٌ عَنْ أَبِي الْمِنْهَالِ سَيَّارِ بْنِ سَلَامَةَ عَنْ أَبِي بَرْزَةَ الْأَسْلَمِيِّ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْتَحِبُّ أَنْ يُؤَخِّرَ الْعِشَاءَ وَكَانَ يَكْرَهُ النَّوْمَ قَبْلَهَا وَالْحَدِيثَ بَعْدَهَا","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dan [Muhammad bin Ja'far] dan [Abdul Wahhab] mereka berkata; telah menceritakan kepada kami ['Auf] dari [Abu Al Minhal Sayyar bin Salamah] dari [Abu Barzah Al Aslami] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam suka mengakhirkan shalat isya`, membenci tidur sebelumnya dan membenci berbincang-bincang setelahnya.\""},"662":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو نُعَيْمٍ ح و حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَامِرٍ قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ بْنِ يَعْلَى الطَّائِفِيُّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْمَا نَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَبْلَ الْعِشَاءِ وَلَا سَمَرَ بَعْدَهَا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Nu'aim]. Dan menurut jalur yang lain; Telah menceritakan kepada kami Muhammad bin Basysyar berkata, telah menceritakan kepada kami Abu Amir keduanya berkata; telah menceritakan kepada kami [Abdullah bin Abdurrahman bin Ya'la Ath Tha`ifi] dari [Abdurrahman bin Al Qasim] dari [Bapaknya] dari [Aisyah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam tidak tidur sebelum Isya dan tidak berbincang-bincang setelahnya.\" "},"663":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ بْنِ حَبِيبٍ وَعَلِيُّ بْنُ الْمُنْذِرِ قَالُوا حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ حَدَّثَنَا عَطَاءُ بْنُ السَّائِبِ عَنْ شَقِيقٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَجَدَبَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ السَّمَرَ بَعْدَ الْعِشَاءِيَعْنِي زَجَرَنَا","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id] dan [Ishaq bin Ibrahim bin Habib] dan [Ali Ibnul Mundzir] mereka berkata; telah menceritakan kepada kami [Muhammad bin Fudlail] berkata, telah menceritakan kepada kami ['Atho` bin As Sa`ib] dari [Syaqiq] dari [Abdullah bin Mas'ud] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang kami berbincang-bincang setelah isya, yakni mencela kami.\""},"664":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ وَمُحَمَّدُ بْنُ الصَّبَّاحِ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي لَبِيدٍ عَنْ أَبِي سَلَمَةَ عَنْ ابْنِ عُمَرَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تَغْلِبَنَّكُمْ الْأَعْرَابُ عَلَى اسْمِ صَلَاتِكُمْ فَإِنَّهَا الْعِشَاءُ وَإِنَّهُمْ لَيُعْتِمُونَ بِالْإِبِلِ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] dan [Muhammad bin Ash Shabbah] keduanya berkata; telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Abdullah bin Abu Labid] dari [Abu Salamah] dari [Ibnu Umar] ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jangan sekali-kali kalian terkalahkan oleh orang-orang arab badui atas nama shalat kalian, sesungguhnya shalat itu adalah isya, dan mereka (orang badui) keluar di malam yang gelap demi memerah susu unta.\" "},"665":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ حَدَّثَنَا الْمُغِيرَةُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ مُحَمَّدِ بْنِ عَجْلَانَ عَنْ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ ح و حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدٍ حَدَّثَنَا ابْنُ أَبِي حَازِمٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ حَرْمَلَةَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَغْلِبَنَّكُمْ الْأَعْرَابُ عَلَى اسْمِ صَلَاتِكُمْزَادَ ابْنُ حَرْمَلَةَ فَإِنَّمَا هِيَ الْعِشَاءُ وَإِنَّمَا يَقُولُونَ الْعَتَمَةُ لِإِعْتَامِهِمْ بِالْإِبِلِ","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib] berkata, telah menceritakan kepada kami [Al Mughirah bin Abdurrahman] dari [Muhammad bin 'Ajlan] dari [Al Maqburi] dari [Abu Hurairah]. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Ya'qub bin Humaid] berkata, telah menceritakan kepada kami [Ibnu Abu Hazim] dari [Abdurrahman bin Harmalah] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Jangan sekali-kali kalian terkalahkan oleh orang-orang arab badui atas nama shalat kalian.\" Ibnu Harmalah menambahkan; \"Maksudnya adalah Isya. Hanyasanya mereka menyebutnya Al 'Atamah karena mereka keluar dimalam hari untuk memerah susu unta.\" "},"666":{"ar":"حَدَّثَنَا أَبُو عُبَيْدٍ مُحَمَّدُ بْنُ عُبَيْدِ بْنِ مَيْمُونٍ الْمَدَنِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ الْحَرَّانِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ حَدَّثَنَا مُحَمَّدُ بْنُ إِبْرَاهِيمَ التَّيْمِيُّ عَنْ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ زَيْدٍ عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ هَمَّ بِالْبُوقِ وَأَمَرَ بِالنَّاقُوسِ فَنُحِتَ فَأُرِيَ عَبْدُ اللَّهِ بْنُ زَيْدٍ فِي الْمَنَامِ قَالَ رَأَيْتُ رَجُلًا عَلَيْهِ ثَوْبَانِ أَخْضَرَانِ يَحْمِلُ نَاقُوسًا فَقُلْتُ لَهُ يَا عَبْدَ اللَّهِ تَبِيعُ النَّاقُوسَ قَالَ وَمَا تَصْنَعُ بِهِ قُلْتُ أُنَادِي بِهِ إِلَى الصَّلَاةِ قَالَ أَفَلَا أَدُلُّكَ عَلَى خَيْرٍ مِنْ ذَلِكَ قُلْتُ وَمَا هُوَ قَالَ تَقُولُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ حَيَّ عَلَى الصَّلَاةِ حَيَّ عَلَى الصَّلَاةِ حَيَّ عَلَى الْفَلَاحِ حَيَّ عَلَى الْفَلَاحِ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ لَا إِلَهَ إِلَّا اللَّهُ قَالَ فَخَرَجَ عَبْدُ اللَّهِ بْنُ زَيْدٍ حَتَّى أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَهُ بِمَا رَأَى قَالَ يَا رَسُولَ اللَّهِ رَأَيْتُ رَجُلًا عَلَيْهِ ثَوْبَانِ أَخْضَرَانِ يَحْمِلُ نَاقُوسًا فَقَصَّ عَلَيْهِ الْخَبَرَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ صَاحِبَكُمْ قَدْ رَأَى رُؤْيَا فَاخْرُجْ مَعَ بِلَالٍ إِلَى الْمَسْجِدِ فَأَلْقِهَا عَلَيْهِ وَلْيُنَادِ بِلَالٌ فَإِنَّهُ أَنْدَى صَوْتًا مِنْكَ قَالَ فَخَرَجْتُ مَعَ بِلَالٍ إِلَى الْمَسْجِدِ فَجَعَلْتُ أُلْقِيهَا عَلَيْهِ وَهُوَ يُنَادِي بِهَا فَسَمِعَ عُمَرُ بْنُ الْخَطَّابِ بِالصَّوْتِ فَخَرَجَ فَقَالَ يَا رَسُولَ اللَّهِ وَاللَّهِ لَقَدْ رَأَيْتُ مِثْلَ الَّذِي رَأَىقَالَ أَبُو عُبَيْدٍ فَأَخْبَرَنِي أَبُو بَكْرٍ الْحَكَمِيُّ أَنَّ عَبْدَ اللَّهِ بْنَ زَيْدٍ الْأَنْصَارِيَّ قَالَ فِي ذَلِكَ أَحْمَدُ اللَّهَ ذَا الْجَلَالِ وَذَا الْإِكْرَامِحَمْدًا عَلَى الْأَذَانِ كَثِيرًاإِذْ أَتَانِي بِهِ الْبَشِيرُ مِنْ اللَّهِفَأَكْرِمْ بِهِ لَدَيَّ بَشِيرًافِي لَيَالٍ وَالَى بِهِنَّ ثَلَاثٍكُلَّمَا جَاءَ زَادَنِي تَوْقِيرًا","id":"Telah menceritakan kepada kami [Abu Ubaid Muhammad bin Ubaid bin Maimun Al Madani] berkata, telah menceritakan kepada kami [Muhammad bin Salamah Al Harrani] berkata, telah menceritakan kepada kami [Muhammad bin Ishaq] berkata, telah menceritakan kepada kami [Muhammad bin Ibrahim At Taimi] dari [Muhammad bin Abdullah bin Zaid] dari [Bapaknya] ia berkata; \"Diawal mula Rasulullah shallallahu'alaihi wasallam berkehendak agar (panggilan shalat) menggunakan terompet, dan beliau suruh sahabatnya memukul kentongan. Lalu Abdullah bin Zaid bermimpi. Ia menuturkan; \"Aku melihat seseorang mengenakan dua kain hijau membawa kentongan. Lalu aku bertanya; \"Wahai hamba Allah, kamu menjual kentongan ini?\" Ia bertanya; \"Apa perlumu dengan kentongan?\" \"Akan kupergunakan untuk panggilan shalat\" Jawabku. Ia lalu berkata; \"Maukah engkau kutunjukkan yang lebih baik dari itu?\" Aku menjawab; \"Apa itu?\" Ia menjawab; \"Ucapkanlah; 'ALLAHU AKBAR ALLAHU AKBAR, ALLAHU AKBAR ALLAHU AKBAR - ASYHADU AN LAA ILAAHA ILLALLAH, ASYHADU AN LAA ILAAHA ILLALLAH - ASYHADU ANNA MUHAMMADAN RASULULLAH, ASYHADU ANNA MUHAMMADAN RASULULLAH - HAYYA 'ALASH SHALAAH. HAYYA 'ALASH SHALAAH - HAYYA 'ALAL FALAAH HAYYA 'ALAL FALAAH-ALLAHU AKBAR ALLAHU AKBAR-LAA ILAAHA ILLALLAH (Allah Maha Besar. Allah Maha Besar. Allah Maha Besar. Allah Maha Besar-Aku bersaksi bahwa tidak ada Tuhan yang berhak disembah selain Allah. Aku bersaksi bahwa tidak ada Tuhan yang berhak disembah selain Allah-Aku bersaksi bahwa Muhammad adalah utusan Allah. Aku bersaksi bahwa Muhammad adalah utusan Allah-Mari menuju shalat. Mari menuju shalat-Mari menuju kemenangan. Mari menuju kemenangan-Allah Maha Besar. Allah Maha Besar-Tidak ada Tuhan Yang berhak disembah selain Allah).\" Ia berkata; Lalu Abdullah bin Zaid mendatangi Rasulullah shallallahu 'alaihi wasallam dan mengabarkan perihal mimpinya, ia berkata; \"Wahai Rasulullah, aku melihat seseorang mengenakan dua kain hijau membawa kentongan, \" lalu ia menceritakan kabar mimpinya kepada beliau. Maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Sesungguhnya sahabat kalian telah bermimpi, keluarlah ke masjid bersama Bilal, beritahukanlah kepada Bilal dan hendaklah ia yang menyerukan hal itu, sebab suaranya lebih keras daripada kamu.\" Abdullah bin Zaid berkata; \"Maka aku keluar bersama Bilal menuju masjid, aku ceritakan mimpiku hingga ia menyerukannya. Dan Umar Ibnul Khaththab mendengar suara itu hingga ia mendatangi Rasulullah seraya berkata; \"Wahai Rasulullah, Demi Allah aku juga bermimpi sebagaimana yang ia impikan! \" Abu Ubaid berkata; \"Abu Bakr Al Hakami mengabarkan kepadaku bahwa Abdullah bin Zaid Al Anshari berkata kaitannya dengan mimpi itu; \"Aku memuji Allah Dzat pemilik Kebesaran dan Kemuliaan\"."},"667":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ خَالِدِ بْنِ عَبْدِ اللَّهِ الْوَاسِطِيُّ حَدَّثَنَا أَبِي عَنْ عَبْدِ الرَّحْمَنِ بْنِ إِسْحَقَ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَشَارَ النَّاسَ لِمَا يُهِمُّهُمْ إِلَى الصَّلَاةِ فَذَكَرُوا الْبُوقَ فَكَرِهَهُ مِنْ أَجْلِ الْيَهُودِ ثُمَّ ذَكَرُوا النَّاقُوسَ فَكَرِهَهُ مِنْ أَجْلِ النَّصَارَى فَأُرِيَ النِّدَاءَ تِلْكَ اللَّيْلَةَ رَجُلٌ مِنْ الْأَنْصَارِ يُقَالُ لَهُ عَبْدُ اللَّهِ بْنُ زَيْدٍ وَعُمَرُ بْنُ الْخَطَّابِ فَطَرَقَ الْأَنْصَارِيُّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلًا فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِلَالًا بِهِ فَأَذَّنَ قَالَ الزُّهْرِيُّ وَزَادَ بِلَالٌ فِي نِدَاءِ صَلَاةِ الْ��َدَاةِ الصَّلَاةُ خَيْرٌ مِنْ النَّوْمِ فَأَقَرَّهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عُمَرُ يَا رَسُولَ اللَّهِ قَدْ رَأَيْتُ مِثْلَ الَّذِي رَأَى وَلَكِنَّهُ سَبَقَنِي","id":"Telah menceritakan kepada kami [Muhammad bin Khalid bin Abdullah Al Wasithi] berkata, telah menceritakan kepada kami [Bapakku] dari [Abdurrahman bin Ishaq] dari [Az Zuhri] dari [Salim] dari [Bapaknya] berkata; Nabi shallallahu 'alaihi wasallam meminta pendapat para sahabat terhadap sesuatu yang membuat mereka berangkat menuju shalat. Maka mereka menyebutkan terompet, tetapi beliau tidak menyukainya karena menyerupai orang-orang Yahudi, kemudian mereka menyebutkan lonceng, tetapi beliau tidak menyukai pula karena menyerupai orang-orang Nasrani. Maka pada malam itu seorang sahabat Anshar bermimpi tentang (lafadz) adzan, sahabat itu dikenal dengan nama Abdullah bin Zaid, dan begitu juga Umar bin Al Khatthab telah memimpikannya. Maka pada saat malam seorang sahabat Anshar mendatangi Rasulullah shallallahu 'alaihi wasallam, lalu Rasulullah shallallahu 'alaihi wasallam memerintahkan Bilal untuk mengumandangkan adzan.\" Az Zuhri berkata; \"Bilal menambah dalam adzan subuh; ASH SHALAATU KHAIRUM MINANNAUM (Shalat itu lebih baik dari pada tidur). Maka Rasulullah shallallahu 'alaihi wasallam pun menetapkannya. Lantas Umar berkata; \"Ya Rasulullah, aku juga bermimpi seperti apa yang dia mimpikan, tetapi dia telah mendahuluiku.\""},"668":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَمُحَمَّدُ بْنُ يَحْيَى قَالَا حَدَّثَنَا أَبُو عَاصِمٍ أَنْبَأَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي عَبْدُ الْعَزِيزِ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي مَحْذُورَةَ عَنْ عَبْدِ اللَّهِ بْنِ مُحَيْرِيزٍ وَكَانَ يَتِيمًا فِي حِجْرِ أَبِي مَحْذُورَةَ بْنِ مِعْيَرٍ حِينَ جَهَّزَهُ إِلَى الشَّامِ فَقُلْتُ لِأَبِي مَحْذُورَةَ أَيْ عَمِّ إِنِّي خَارِجٌ إِلَى الشَّامِ وَإِنِّي أُسْأَلُ عَنْ تَأْذِينِكَ فَأَخْبَرَنِي أَنَّ أَبَا مَحْذُورَةَ قَالَخَرَجْتُ فِي نَفَرٍ فَكُنَّا بِبَعْضِ الطَّرِيقِ فَأَذَّنَ مُؤَذِّنُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالصَّلَاةِ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَمِعْنَا صَوْتَ الْمُؤَذِّنِ وَنَحْنُ عَنْهُ مُتَنَكِّبُونَ فَصَرَخْنَا نَحْكِيهِ نَهْزَأُ بِهِ فَسَمِعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَرْسَلَ إِلَيْنَا قَوْمًا فَأَقْعَدُونَا بَيْنَ يَدَيْهِ فَقَالَ أَيُّكُمْ الَّذِي سَمِعْتُ صَوْتَهُ قَدْ ارْتَفَعَ فَأَشَارَ إِلَيَّ الْقَوْمُ كُلُّهُمْ وَصَدَقُوا فَأَرْسَلَ كُلَّهُمْ وَحَبَسَنِي وَقَالَ لِي قُمْ فَأَذِّنْ فَقُمْتُ وَلَا شَيْءَ أَكْرَهُ إِلَيَّ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا مِمَّا يَأْمُرُنِي بِهِ فَقُمْتُ بَيْنَ يَدَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَلْقَى عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ التَّأْذِينَ هُوَ بِنَفْسِهِ فَقَالَ قُلْ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ ثُمَّ قَالَ لِي ارْفَعْ مِنْ صَوْتِكَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ حَيَّ عَلَى الصَّلَاةِ حَيَّ عَلَى الصَّلَاةِ حَيَّ عَلَى الْفَلَاحِ حَيَّ عَلَى الْفَلَاحِ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ لَا إِلَهَ إِلَّا اللَّهُ ثُمَّ دَعَانِي حِينَ قَضَيْتُ التَّأْذِينَ فَأَعْطَانِي صُرَّةً فِيهَا شَيْءٌ مِنْ فِضَّةٍ ثُمَّ وَضَعَ يَدَهُ عَلَى نَاصِيَةِ أَبِي مَحْذُورَةَ ثُمَّ أَمَرَّهَا عَلَى وَجْهِهِ ثُمَّ عَلَى ثَدْيَيْهِ ثُمَّ عَلَى كَبِدِهِ ثُمَّ بَلَغَتْ يَدُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُرَّةَ أَبِي مَحْذُورَةَ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَارَكَ اللَّهُ لَكَ وَبَارَكَ عَلَيْكَ فَقُلْتُ يَا رَسُولَ اللَّهِ أَمَرْتَنِي بِالتَّأْذِينِ بِمَكَّةَ قَالَ نَعَمْ قَدْ أَمَرْتُكَ فَذَهَبَ كُلُّ شَيْءٍ كَانَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ كَرَاهِيَةٍ وَعَادَ ذَلِكَ كُلُّهُ مَحَبَّةً لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَدِمْتُ عَلَى عَتَّابِ بْنِ أَسِيدٍ عَامِلِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَكَّةَ فَأَذَّنْتُ مَعَهُ بِالصَّلَاةِ عَنْ أَمْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ وَأَخْبَرَنِي ذَلِكَ مَنْ أَدْرَكَ أَبَا مَحْذُورَةَ عَلَى مَا أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ مُحَيْرِيزٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basysysar] dan [Muhammad bin Yahya] keduanya berkata; telah menceritakan kepada kami [Abu 'Ashim] berkata, telah memberitakan kepada kami [Ibnu Juraij] berkata, telah mengabarkan kepadaku [Abdul Aziz bin Abdul Malik bin Abu Mahdzurah] dari [Abdullah bin Muhairiz] -anak yatim yang berada dalam asuhan Abu Mahdzurah bin Mi'yar- tatkala dia akan mengirimnya ke Syam, lalu aku berkata kepada [Abu Mahdzurah]; \"Wahai paman, aku keluar ke Syam, dan aku ingin bertanya bagaimana cara adzanmu?\" lalu ia mengabarkan kepadaku, bahwa Abu Mahdzurah berkata; \"Aku keluar bersama beberapa orang, maka ketika di tengah perjalanan mu`adzin Rasulullah shallallahu 'alaihi wasallam mengumandangkan adzan shalat di sisi Rasulullah shallallahu 'alaihi wasallam, kami mendengar suara mu`adzin, dan kami menjauh sambil berteriak seraya menceritakan dan memperolok-oloknya. Maka hal itu didengar oleh Rasulullah shallallahu 'alaihi wasallam hingga beliau mengirimkan beberapa orang kepada kami, lalu mereka mendudukkan kami di hadapannya, beliau bersabda: \"Kaliankah orang-orang yang aku dengar suaranya meninggi?! \" Maka semua orang menunjuk kepadaku dan membenarkan. Lalu beliau melepaskan mereka semua dan menahanku, setelah itu berkata kepadaku: \"Bangun dan adzanlah.\" Maka aku pun bangun, tidak ada sesuatu yang aku benci selain Rasulullah shallallahu 'alaihi wasallam dan apa yang ia perintahkan kepadaku. Lalu aku berdiri di hadapan Rasulullah shallallahu 'alaihi wasallam, dan beliau sendiri yang mengajarkan lafadz adzan kepadaku. Beliau bersabda: \"Ucapkanlah; ALLAHU AKBAR ALLAHU AKBAR ALLAHU AKBAR ALLAHU AKBAR (Allah Maha Besar. Allah Maha Besar. Allah Maha Besar. Allah Maha Besar). ASYHADU AN LAA ILAAHA ILLALLAH. ASYHADU AN LAA ILAAHA ILLALLAH (Aku bersaksi bahwa tidak ada Tuhan yang berhak disembah selain Allah. Aku bersaksi bahwa tidak ada Tuhan yang berhak disembah selain Allah). ASYHADU ANNA MUHAMMADAN RASULULLAH. ASYHADU ANNA MUHAMMADAN RASULULLAH (Aku bersaksi bahwa Muhammad adalah utusan Allah. Aku bersaksi bahwa Muhammad adalah utusan Allah).\" Kemudian beliau bersabda kepadaku: \"Keraskan suaramu ketika mengucapkan; ASYHADU AN LAA ILAAHA ILLALLAH. ASYHADU AN LAA ILAAHA ILLALLAH (Aku bersaksi bahwa tidak ada Tuhan yang berhak disembah selain Allah. Aku bersaksi bahwa tidak ada Tuhan yang berhak disembah selian Allah). ASYHADU ANNA MUHAMMADAN RASULULLAH. ASYHADU ANNA MUHAMMADAN RASULULLAH (Aku bersaksi bahwa Muhammad adalah utusan Allah. Aku bersaksi bahwa Muhammad adalah utusan Allah). HAYYA 'ALASH SHALAH. HAYYA 'ALASH SHALAH (Marilah menuju shalat. Marilah menuju shalat). HAYYA 'ALAL FALAH. HAYYA 'ALAL FALAH (Marilah menuju kemenangan. Marilah menuju kemenangan). ALLAHU AKBAR ALLAHU AKBAR (Allah Maha Besar. Allah Maha Besar). LAA ILAAHA ILLALLAH (Tidak ada Tuhan yang berhak disembah selain Allah).\" Selesai aku mengumandangkan adzan beliau memanggilku. Beliau memberiku bungkusan yang di dalamnya terdapat perak, kemudian meletakkan tangannya di atas ubun-ubun Abu Mahdzurah, melewatkannya di depan wajahnya, terus pada kedua susunya hingga pada bagian hatinya. Bahkan tangan Rasulullah sampai ke pusar Abu Mahdzurah, setelah itu bersabda: \"Semoga Allah memberimu berkah disaat suka maupun duka.\" Maka aku berkata; \"Ya Rasulullah, apakah engkau menyuruhku untuk adzan di Makkah?\" beliau menjawab: \"Benar, aku telah menyuruhmu.\" Maka segala sesuatu yang aku benci pada diri Rasulullah shallallahu 'alaihi wasallam menjadi sirnah, dan berganti dengan rasa cinta kepada Rasulullah. Kemudian aku datang kepada 'Attab bin Usaid, pegawai Rasulullah shallallahu 'alaihi wasallam di Makkah, lalu bersamanya aku mengumandangkan adzan shalat berdasarkan perintah Rasulullah.\" Ia berkata; orang yang berjumpa Abu Mahzurah telah mengabarkan kepadaku seperti itu, sebagaimana kabar yang sampaikan oleh Abdullah bin Muhairiz kepadaku."},"669":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَفَّانُ حَدَّثَنَا هَمَّامُ بْنُ يَحْيَى عَنْ عَامِرٍ الْأَحْوَلِ أَنَّ مَكْحُولًا حَدَّثَهُ أَنَّ عَبْدَ اللَّهِ بْنَ مُحَيْرِيزٍ حَدَّثَهُ أَنَّ أَبَا مَحْذُورَةَ حَدَّثَهُ قَالَعَلَّمَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْأَذَانَ تِسْعَ عَشْرَةَ كَلِمَةً وَالْإِقَامَةَ سَبْعَ عَشْرَةَ كَلِمَةً الْأَذَانُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ حَيَّ عَلَى الصَّلَاةِ حَيَّ عَلَى الصَّلَاةِ حَيَّ عَلَى الْفَلَاحِ حَيَّ عَلَى الْفَلَاحِ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ لَا إِلَهَ إِلَّا اللَّهُ وَالْإِقَامَةُ سَبْعَ عَشْرَةَ كَلِمَةً اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ حَيَّ عَلَى الصَّلَاةِ حَيَّ عَلَى الصَّلَاةِ حَيَّ عَلَى الْفَلَاحِ حَيَّ عَلَى الْفَلَاحِ قَدْ قَامَتْ الصَّلَاةُ قَدْ قَامَتْ الصَّلَاةُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ لَا إِلَهَ إِلَّا اللَّهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Affan] berkata, telah menceritakan kepada kami [Hammam bin Yahya] dari [Amir Al Ahwal] bahwa [Makhul] menceritakan kepadanya bahwa [Abdullah bin Muhairiz] menceritakan kepadanya, bahwa [Abu Mahdzurah] menceritakan kepadanya, ia berkata; \"Rasulullah shallallahu 'alaihi wasallam mengajariku adzan dengan sembilan belas kalimat, dan iqamah dengan tujuh belas kalimat. Kalimat adzan itu adalah; ALLAHU AKBAR ALLAHU AKBAR ALLAHU AKBAR ALLAHU AKBAR, ASYHADU AN LAA ILAAHA ILLALLAH, ASYHADU AN LAA ILAAHA ILLALLAH, ASYHADU ANNA MUHAMMADAN RASULULLAH, ASYHADU ANNA MUHAMMADAN RASULULLAH, ASYHADU AN LAA ILAAHA ILLALLAH, ASYHADU AN LAA ILAAHA ILLALLAH, ASYHADU ANNA MUHAMMADAN RASULULLAH, ASYHADU ANNA MUHAMMADAN RASULULLAH, HAYYA 'ALASH SHALAH, HAYYA 'ALASH SHALAH, HAYYA 'ALAL FALAH, HAYYA 'ALAL FALAH, ALLAHU AKBAR ALLAHU AKBAR, LAA ILAAHA ILLALLAH. (Allah Maha Besar. Allah Maha Besar. Allah Maha Besar. Allah Maha Besar-Aku bersaksi bahwa tidak ada Tuhan yang berhak disembah selain Allah. Aku bersaksi bahwa tidak ada Tuhan yang berhak disembah selain Allah-Aku bersaksi bahwa Muhammad adalah utusan Allah. Aku bersaksi bahwa Muhammad adalah utusan Allah-Aku bersaksi bahwa tidak ada Tuhan yang berhak disembah selain Allah. Aku bersaksi bahwa tidak ada Tuhan yang berhak disembah selain Allah- Aku bersaksi bahwa Muhammad adalah utusan Allah. Aku bersaksi bahwa Muhammad adalah utusan Allah-Mari menuju shalat. Mari menuju shalat-Mari menuju kemenangan. Mari menuju kemenangan-Allah Maha Besar. Allah Maha Besar-Tidak ada Tuhan Yang berhak disembah selain Allah). Sedangkan kalimat iqamah adalah tujuh belas kalimat; ALLAHU AKBAR ALLAHU AKBAR ALLAHU AKBAR ALLAHU AKBAR, ASYHADU AN LAA ILAAHA ILLALLAH, ASYHADU AN LAA ILAAHA ILLALLAH, ASYHADU ANNA MUHAMMADAN RASULULLAH, ASYHADU ANNA MUHAMMADAN RASULULLAH, HAYYA 'ALASH SHALAH, HAYYA 'ALASH SHALAH, HAYYA 'ALAL FALAH, HAYYA 'ALAL FALAH, QAD QAAMATISH SHALAH, QAD QAAMATISH SHALAH, ALLAHU AKBAR ALLAHU AKBAR, LAA ILAAHA ILLALLAH. (Allah Maha Besar. Allah Maha Besar. Allah Maha Besar. Allah Maha Besar-Aku bersaksi bahwa tidak ada Tuhan yang berhak disembah selain Allah. Aku bersaksi bahwa tidak ada Tuhan yang berhak disembah selain Allah-Aku bersaksi bahwa Muhammad adalah utusan Allah. Aku bersaksi bahwa Muhammad adalah utusan Allah-Shalat telah ditegakkan. Shalat telah ditegakkan-Mari menuju shalat. Mari menuju shalat-Mari menuju kemenangan. Mari menuju kemenangan-Allah Maha Besar. Allah Maha Besar-Tidak ada Tuhan Yang berhak disembah selain Allah).\""},"670":{"ar":"حَدَّ��َنَا هِشَامُ بْنُ عَمَّارٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ سَعْدِ بْنِ عَمَّارِ بْنِ سَعْدٍ مُؤَذِّنِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَنِي أَبِي عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ بِلَالًا أَنْ يَجْعَلَ إِصْبَعَيْهِ فِي أُذُنَيْهِ وَقَالَ إِنَّهُ أَرْفَعُ لِصَوْتِكَ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] berkata; telah menceritakan kepada kami [Abdurrahman Sa'd bin 'Ammar bin Sa'd] mu`adzin Rasulullah, berkata; telah menceritakan kepadaku [Bapakku] dari [Bapaknya] dari [Kakeknya] berkata; Rasulullah shallallahu 'alaihi wasallam memerintahkan kepada Bilal agar meletakkan kedua jarinya pada kedua telinganya, seraya bersabda: \"Sesungguhnya itu lebih mengeraskan suaramu.\""},"671":{"ar":"حَدَّثَنَا أَيُّوبُ بْنُ مُحَمَّدٍ الْهَاشِمِيُّ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ عَنْ حَجَّاجِ بْنِ أَرْطَاةَ عَنْ عَوْنِ بْنِ أَبِي جُحَيْفَةَ عَنْ أَبِيهِ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْأَبْطَحِ وَهُوَ فِي قُبَّةٍ حَمْرَاءَ فَخَرَجَ بِلَالٌ فَأَذَّنَ فَاسْتَدَارَ فِي أَذَانِهِ وَجَعَلَ إِصْبَعَيْهِ فِي أُذُنَيْهِ","id":"Telah menceritakan kepada kami [Ayyub bin Muhammad Al Hasyimi] berkata, telah menceritakan kepada kami [Abdul Wahid bin Ziyad] dari [Hajjaj bin Artha`ah] dari [Aun bin Abu Juhaifah] dari [Bapaknya] ia berkata; \"Aku mendatangi Rasulullah shallallahu 'alaihi wasallam di Al Abthah (nama tempat), ketika itu beliau di dalam tendanya. Lalu bilal keluar mengumandangkan adzan dengan berputar dan meletakkan kedua jari pada kedua telinganya.\""},"672":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُصَفَّى الْحِمْصِيُّ حَدَّثَنَا بَقِيَّةُ عَنْ مَرْوَانَ بْنِ سَالِمٍ عَنْ عَبْدِ الْعَزِيزِ بْنِ أَبِي رَوَّادٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَصْلَتَانِ مُعَلَّقَتَانِ فِي أَعْنَاقِ الْمُؤَذِّنِينَ لَلْمُسْلِمِينَ صَلَاتُهُمْ وَصِيَامُهُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mushaffa Al Himshi] berkata, telah menceritakan kepada kami [Baqiyyah] dari [Marwan bin Salim] dari [Abdul Aziz bin Abu Rawwad] dari [Nafi'] dari [Ibnu Umar] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ada dua perkara kaum muslimin yang tergantung di leher para mu`adzin yaitu shalat dan puasa mereka.\""},"673":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا شَرِيكٌ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَكَانَ بِلَالٌ لَا يُؤَخِّرُ الْأَذَانَ عَنْ الْوَقْتِ وَرُبَّمَا أَخَّرَ الْإِقَامَةَ شَيْئًا","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] berkata, telah menceritakan kepada kami [Abu Dawud] berkata, telah menceritakan kepada kami [Syarik] dari [Simak bin Harb] dari [Jabir bin Samurah] ia berkata; \"Bilal adalah orang yang tidak mengakhirkan adzan dari waktunya, dan terkadang dia mengakhirkan iqamah beberapa saat.\""},"674":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ أَشْعَثَ عَنْ الْحَسَنِ عَنْ عُثْمَانَ بْنِ أَبِي الْعَاصِ قَالَكَانَ آخِرُ مَا عَهِدَ إِلَيَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ لَا أَتَّخِذَ مُؤَذِّنًا يَأْخُذُ عَلَى الْأَذَانِ أَجْرًا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Hafsh bin Ghiyats] dari [Asy'ats] dari [Al Hasan] dari [Utsman bin Abu Al 'Ash] ia berkata; \"Terakhir yang Rasulullah shallallahu 'alaihi wasallam ambil janjinya dariku adalah agar aku tidak mengangkat seorang mu`adzin yang meminta upah dari adzannya.\""},"675":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الْأَسَدِيُّ عَنْ أَبِي إِسْرَائِيلَ عَنْ الْحَكَمِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ بِلَالٍ قَالَأَمَرَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ أُثَوِّبَ فِي الْفَجْرِ وَنَهَانِي أَنْ أُثَوِّبَ فِي الْعِشَاءِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Muhammad bin Abdullah bin Al Asad] dari [Abu Isra`il] dari [Al Hakam] dari [Abdurrahman bin Abu Laila] dari [Bilal] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam memerintahkan kepadaku untuk mengucapkan tatswib dalam shalat subuh dan melarang untuk mengucapkannya dalam shalat isya.\" "},"676":{"ar":"حَدَّثَنَا عَمْرُو بْنُ رَافِعٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ بِلَالٍأَنَّهُ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُؤْذِنُهُ بِصَلَاةِ الْفَجْرِ فَقِيلَ هُوَ نَائِمٌ فَقَالَ الصَّلَاةُ خَيْرٌ مِنْ النَّوْمِ الصَّلَاةُ خَيْرٌ مِنْ النَّوْمِ فَأُقِرَّتْ فِي تَأْذِينِ الْفَجْرِ فَثَبَتَ الْأَمْرُ عَلَى ذَلِكَ","id":"Telah menceritakan kepada kami ['Amru bin Rafi'] berkata, telah menceritakan kepada kami [Abdullah bin Al Mubarak] dari [Ma'mar] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dari [Bilal] bahwa ia mendatangi Nabi shallallahu 'alaihi wasallam untuk adzan shalat subuh, lalu dikatakan kepadanya: \"Beliau sedang tidur.\" Maka bilal pun berkata; \"ASH SHALAATU KHAIRUN MINAN NAUM. ASH SHALAATU KHAIRUN MINAN NAUM (Shalat itu lebih baik daripada tidur. Shalat itu lebih baik daripada tidur).\" Hingga lafadz itu ditetapkan untuk dikumandangkan pada adzan subuh dan perkaranya menjadi tetap seperti itu.\""},"677":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَعْلَى بْنُ عُبَيْدٍ حَدَّثَنَا الِإفْرِيقِيُّ عَنْ زِيَادِ بْنِ نُعَيْمٍ عَنْ زِيَادِ بْنِ الْحَارِثِ الصُّدَائِيِّ قَالَكُنْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَأَمَرَنِي فَأَذَّنْتُ فَأَرَادَ بِلَالٌ أَنْ يُقِيمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَخَا صُدَاءٍ قَدْ أَذَّنَ وَمَنْ أَذَّنَ فَهُوَ يُقِيمُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ya'la bin Ubaid] berkata, telah menceritakan kepada kami [Al Ifriqi] dari [Ziyad bin Nu'aim] dari [Ziyad Ibnul Harits Ash Shuda`i] ia berkata; \"Aku bersama Rasulullah shallallahu 'alaihi wasallam dalam sebuah perjalanan, lalu beliau memerintahkan kepadaku untuk mengumandangkan adzan, maka akupun adzan. Kemudian bilal berniat untuk iqamah, namun Rasulullah shallallahu 'alaihi wasallam bersabda: \"Saudara Shuda` telah mengumandangkan adzan, maka barangsiapa adzan dialah yang berhak iqamah.\""},"678":{"ar":"حَدَّثَنَا أَبُو إِسْحَقَ الشَّافِعِيُّ إِبْرَاهِيمُ بْنُ مُحَمَّدِ بْنِ الْعَبَّاسِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ رَجَاءٍ الْمَكِّيُّ عَنْ عَبَّادِ بْنِ إِسْحَقَ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَذَّنَ الْمُؤَذِّنُ فَقُولُوا مِثْلَ قَوْلِهِ","id":"Telah menceritakan kepada kami [Abu Ishaq As Syafi'i Ibrahim bin Muhammad bin Al 'Abbas] berkata, telah menceritakan kepada kami [Abdullah bin Raja` Al Makki] dari ['Abbad bin Ishaq] dari [Ibnu Syihab] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila seorang muadzin mengumandangkan adzan maka ucapkanlah seperti ucapannya.\""},"679":{"ar":"حَدَّثَنَا شُجَاعُ بْنُ مَخْلَدٍ أَبُو الْفَضْلِ قَالَ حَدَّثَنَا هُشَيْمٌ أَنْبَأَنَا أَبُو بِشْرٍ عَنْ أَبِي الْمَلِيحِ بْنِ أُسَامَةَ عَنْ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ أَبِي سُفْيَانَ حَدَّثَتْنِي عَمَّتِي أُمُّ حَبِيبَةَأَنَّهَا سَمِعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا كَانَ عِنْدَهَا فِي يَوْمِهَا وَلَيْلَتِهَا فَسَمِعَ الْمُؤَذِّنَ يُؤَذِّنُ قَالَ كَمَا يَقُولُ الْمُؤَذِّنُ","id":"Telah menceritakan kepada kami [Syuja' bin Makhlad Abul Fadhl] berkata; telah menceritakan kepada kami [Husyaim] berkata, telah memberitakan kepada kami [Abu Bisyr] dari [Abul Malih bin Usamah] dari [Abdullah bin 'Utbah bin Abu Sufyan] berkata, telah menceritakan kepadaku bibiku [Ummu Habibah], bahwasanya ketika Rasulullah shallallahu 'alaihi wasallam berada bersamanya di hari gilirannya, ia mendengar Rasulullah shallallahu 'alaihi wasallam mengucapkan sebagaimana yang diucapkan oleh mu`adzin ketika beliau mendengar suara adzan.\" "},"680":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ الزُّهْرِيِّ عَنْ عَطَاءِ بْنِ يَزِيدَ اللَّيْثِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَمِعْتُمْ النِّدَاءَ فَقُولُوا كَمَا يَقُولُ الْمُؤَذِّنُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Abu Kuraib] keduanya berkata; telah menceritakan kepada kami [Zaid Ibnul Hubab] dari [Malik bin Anas] dari [Az Zuhri] dari ['Atho` bin Zaid Al Laits] dari [Sa'id Ibnul Musayyab] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika kalian mendengar adzan maka ucapkanlah sebagaimana yang diucapkan oleh mu`adzin.\""},"681":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ الْمِصْرِىُّ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ الْحُكَيْمِ بْنِ عَبْدِ اللَّهِ بْنِ قَيْسٍ عَنْ عَامِرِ بْنِ سَعْدِ بْنِ أَبِي وَقَّاصٍ عَنْ سَعْدِ بْنِ أَبِي وَقَّاصٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ قَالَ حِينَ يَسْمَعُ الْمُؤَذِّنَ وَأَنَا أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ رَضِيتُ بِاللَّهِ رَبًّا وَبِالْإِسْلَامِ دِينًا وَبِمُحَمَّدٍ نَبِيًّا غُفِرَ لَهُ ذَنْبُهُ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh Al Mishri] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Al Hukaim bin Abdullah bin Qais] dari [Amir bin Sa'd bin Abu Waqash] dari [Sa'd bin Abu Waqash] dari Rasulullah shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Barangsiapa mendengar adzan kemudian mengucapkan; 'Aku juga bersaksi bahwa tidak ada Tuhan yang berhak disembah selain Allah semata, tidak ada sekutu bagi-Nya. Dan aku juga bersaksi bahwa Muhammad adalah hamba dan utusan-Nya. Aku ridla Allah sebagai Rabb, Islam sebagai agama dan Muhammad sebagai Nabi, ' maka dosanya akan diampuni.\""},"682":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى وَالْعَبَّاسُ بْنُ الْوَلِيدِ الدِّمَشْقِيُّ وَمُحَمَّدُ بْنُ أَبِي الْحُسَيْنِ قَالُوا حَدَّثَنَا عَلِيُّ بْنُ عَيَّاشٍ الْأَلْهَانِيُّ حَدَّثَنَا شُعَيْبُ بْنُ أَبِي حَمْزَةَ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَالَ حِينَ يَسْمَعُ النِّدَاءَ اللَّهُمَّ رَبَّ هَذِهِ الدَّعْوَةِ التَّامَّةِ وَالصَّلَاةِ الْقَائِمَةِ آتِ مُحَمَّدًا الْوَسِيلَةَ وَالْفَضِيلَةَ وَابْعَثْهُ مَقَامًا مَحْمُودًا الَّذِي وَعَدْتَهُ إِلَّا حَلَّتْ لَهُ الشَّفَاعَةُ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] dan [Al 'Abbas Ibnul Walid Ad Dimasyqi] dan [Muhammad bin Abu Al Husain] mereka berkata; telah menceritakan kepada kami [Ali bin 'Ayyasy Al Alhani] berkata, telah menceritakan kepada kami [Syu'aib bin Abu Hamzah] dari [Muhammad Ibnul Munkadir] dari [Jabir bin Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa ketika mendengar adzan lalu mengucapkan; ALLAHUMMA RABBA HADZIHID DA'WATIT TAAMMATI WASH SHALATIL QAA`IMAHI AATI MUHAMMADANIL WASIILATA WAL FADLIILAH WAB'ATSHU MAQAAMAN MAHMUUDAN ALLADZII WA 'ADTAHU (Ya Allah, Tuhan Pemilik panggilan yang sempurna (adzan) ini dan shalat yang (wajib) didirikan. Berilah Al Wasilah dan Fadlilah kepada Muhammad. Dan bangkitkan beliau sehingga menempati maqam terpuji yang telah Engkau janjikan), ' kecuali ia akan mendapatkan syafa'at pada hari kiamat.\""},"683":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي صَعْصَعَةَ عَنْ أَبِيه�� وَكَانَ أَبُوهُ فِي حِجْرِ أَبِي سَعِيدٍ قَالَ قَالَ لِي أَبُو سَعِيدٍإِذَا كُنْتَ فِي الْبَوَادِي فَارْفَعْ صَوْتَكَ بِالْأَذَانِ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَسْمَعُهُ جِنٌّ وَلَا إِنْسٌ وَلَا شَجَرٌ وَلَا حَجَرٌ إِلَّا شَهِدَ لَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Abdullah bin Abdurrahman bin Abu Sha'sha'ah] dari [Bapaknya] -bapaknya ada dalam asuhan Abu Sa'id- ia berkata; [Abu Sa'id] berkata kepadaku; Jika engkau berada di gurun pasir maka keraskanlah suara adzanmu, sebab aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah mendengar suara adzan itu baik jin, manusia, pepohonan dan batu kecuali ia akan menjadi saksi baginya.\""},"684":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا شَبَابَةُ حَدَّثَنَا شُعْبَةُ عَنْ مُوسَى بْنِ أَبِي عُثْمَانَ عَنْ أَبِي يَحْيَى عَنْ أَبِي هُرَيْرَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْمُؤَذِّنُ يُغْفَرُ لَهُ مَدَى صَوْتِهِ وَيَسْتَغْفِرُ لَهُ كُلُّ رَطْبٍ وَيَابِسٍ وَشَاهِدُ الصَّلَاةِ يُكْتَبُ لَهُ خَمْسٌ وَعِشْرُونَ حَسَنَةً وَيُكَفَّرُ عَنْهُ مَا بَيْنَهُمَا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Syababah] berkata, telah menceritakan kepada kami [Syu'bah] dari [Musa bin Abu Utsman] dari [Abu Yahya] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang mu`adzin akan diampuni sejauh suara adzan yang ia kumandangkan, dan setiap yang basah dan yang kering akan memintakan ampun baginya. Sedangkan orang yang menghadiri shalat jama'ah akan dituliskan baginya dua puluh lima kebaikan dan dosa antara dua shalat akan diampuni dengannya.\""},"685":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَإِسْحَقُ بْنُ مَنْصُورٍ قَالَا حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا سُفْيَانُ عَنْ طَلْحَةَ بْنِ يَحْيَى عَنْ عِيسَى بْنِ طَلْحَةَ قَالَ سَمِعْتُ مُعَاوِيَةَ بْنَ أَبِي سُفْيَانَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُؤَذِّنُونَ أَطْوَلُ النَّاسِ أَعْنَاقًا يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] dan [Ishaq bin Manshur] keduanya berkata; telah menceritakan kepada kami [Abu Amir] berkata, telah menceritakan kepada kami [Sufyan] dari [Thalhah bin Yahya] dari [Isa bin Thalhah] ia berkata; Aku mendengar [Mu'awiyah bin Abu Sufyan] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang paling panjang lehernya pada hari kiamat adalah para mu`adzin.\" "},"686":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا حُسَيْنُ بْنُ عِيسَى أَخُو سُلَيْمٍ الْقَارِيُّ عَنْ الْحَكَمِ بْنِ أَبَانَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيُؤَذِّنْ لَكُمْ خِيَارُكُمْ وَلْيَؤُمَّكُمْ قُرَّاؤُكُمْ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Husain bin Isa] -saudara Sulaim Al Qari`- dari [Al Hakam bin Aban] dari [Ikrimah] dari [Ibnu 'Abbas] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaklah yang mengumandangkan adzan adalah paling baik di antara kalian, dan yang menjadi imam adalah yang paling baik bacaannya di antara kalian.\""},"687":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا مُخْتَارُ بْنُ غَسَّانَ حَدَّثَنَا حَفْصُ بْنُ عُمَرَ الْأَزْرَقُ الْبُرْجُمِيُّ عَنْ جَابِرٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ ح و حَدَّثَنَا رَوْحُ بْنُ الْفَرَجِ حَدَّثَنَا عَلِيُّ بْنُ الْحَسَنِ بْنِ شَقِيقٍ حَدَّثَنَا أَبُو حَمْزَةَ عَنْ جَابِرٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَذَّنَ مُحْتَسِبًا سَبْعَ سِنِينَ كَتَبَ اللَّهُ لَهُ بَرَاءَةً مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Mukhtar bin Ghassan] berkata, telah menceritakan kepada kami [Hafsh bin Umar Al Azraq Al Burjumi] dari [Jabir] dari [Ikrimah] dari [Ibnu 'Abbas]. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Rauh bin Al Furaj] berkata, telah menceritakan kepada kami [Ali bin Al Hasan bin Syaqiq] berkata, telah menceritakan kepada kami [Abu Hamzah] dari [Jabir] dari [Ikrimah] dari [Ibnu 'Abbas] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengumandangkan adzan karena ikhlas selama tujuh tahun, maka Allah akan membebaskan dirinya dari neraka.\""},"688":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى وَالْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ عَنْ ابْنِ جُرَيْجٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَذَّنَ ثِنْتَيْ عَشْرَةَ سَنَةً وَجَبَتْ لَهُ الْجَنَّةُ وَكُتِبَ لَهُ بِتَأْذِينِهِ فِي كُلِّ يَوْمٍ سِتُّونَ حَسَنَةً وَلِكُلِّ إِقَامَةٍ ثَلَاثُونَ حَسَنَةً","id":"Telah menceritakan kepada kami [Muhamad bin Yahya] dan [Al Hasan bin Ali Al Khallal] keduanya berkata; telah menceritakan kepada kami [Abdullah bin Shalih] berkata, telah menceritakan kepada kami [Yahya bin Ayyub] dari [Ibnu Juraij] dari [Nafi'] dari [Ibnu Umar], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengumandangkan adzan selama dua belas tahun, maka wajib baginya surga, Dan dengan adzannya, dalam setiap harinya akan dituliskan enam puluh kebaikan, dan tiga puluh kebaikan untuk setiap iqamah yang ia lakukan.\" "},"689":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْجَرَّاحِ حَدَّثَنَا الْمُعْتَمِرُ بْنُ سُلَيْمَانَ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَالْتَمَسُوا شَيْئًا يُؤْذِنُونَ بِهِ عِلْمًا لِلصَّلَاةِ فَأُمِرَ بِلَالٌ أَنْ يَشْفَعَ الْأَذَانَ وَيُوتِرَ الْإِقَامَةَ","id":"Telah menceritakan kepada kami [Abdullah Ibnul Jarrah] berkata, telah menceritakan kepada kami [Al Mu'tamir bin Sulaiman] dari [Khalid Al Hadzdza`] dari [Abu Qilabah] dari [Anas bin Malik] ia berkata; \"Carilah sesuatu yang dapat kalian gunakan untuk mengingatkan orang mengerjakan shalat. Lalu Bilal diperintahkan menggenapkan bilangan adzan dan mengganjilkan bilangan iqamah.\""},"690":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا عُمَرُ بْنُ عَلِيٍّ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسٍ قَالَأُمِرَ بِلَالٌ أَنْ يَشْفَعَ الْأَذَانَ وَيُوتِرَ الْإِقَامَةَ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] berkata, telah menceritakan kepada kami [Umar bin Ali] dari [Khalid Al Hadzdza`] dari [Abu Qilabah] dari [Anas] ia berkata; \"Bilal diperintahkan menggenapkan bilangan adzan dan mengganjilkan bilangan iqamah.\""},"691":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ سَعْدٍ حَدَّثَنَا عَمَّارُ بْنُ سَعْدٍ مُؤَذِّنُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَنِي أَبِي عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ أَذَانَ بِلَالٍ كَانَ مَثْنَى مَثْنَى وَإِقَامَتَهُ مُفْرَدَةٌ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] berkata, telah menceritakan kepada kami [Abdurrahman bin Sa'd bin 'Ammar bin Sa'd] -mu`adzin Rasulullah shallallahu 'alaihi wasallam- berkata, telah memberitakan kepadaku [Bapakku] dari [Bapaknya] dari [Kakeknya] berkata; \"Adzan bilal adalah dua-dua, sedang iqamahnya adalah satu-satu.\""},"692":{"ar":"حَدَّثَنَا أَبُو بَدْرٍ عَبَّادُ بْنُ الْوَلِيدِ حَدَّثَنِي مُعَمَّرُ بْنُ مُحَمَّدِ بْنِ عُبَيْدِ اللَّهِ بْنِ أَبِي رَافِعٍ مَوْلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَنِي أَبِي مُحَمَّدُ بْنُ عُبَيْدِ اللَّهِ عَنْ أَبِيهِ عُبَيْدِ اللَّهِ عَنْ أَبِي رَافِعٍ قَالَرَأَيْتُ بِلَالًا يُؤَذِّنُ بَيْنَ يَدَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَثْنَى مَثْنَى وَيُقِيمُ وَاحِدَةً","id":"Telah menceritakan kepada kami [Abu Badr 'Abbad bin Al Walid] berkata, telah menceritakan kepadaku [Mu'ammar bin Muhammad bin Ubaidullah bin Abu Rafi'] -mantan budak Nabi shallallahu 'alaihi wasallam- berkata, telah menceritakan kepadaku [Abu Muhammad bin Ubaidullah] dari ayahnya [Ubaidullah] dari [Abu Rafi'], ia berkata; \"Di sisi Rasulullah shallallahu 'alaihi wasallam aku melihat Bilal mengumandangkan adzan dua-dua, dan iqamah satu-satu.\""},"693":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ إِبْرَاهِيمَ بْنِ مُهَاجِرٍ عَنْ أَبِي الشَّعْثَاءِ قَالَكُنَّا قُعُودًا فِي الْمَسْجِدِ مَعَ أَبِي هُرَيْرَةَ فَأَذَّنَ الْمُؤَذِّنُ فَقَامَ رَجُلٌ مِنْ الْمَسْجِدِ يَمْشِي فَأَتْبَعَهُ أَبُو هُرَيْرَةَ بَصَرَهُ حَتَّى خَرَجَ مِنْ الْمَسْجِدِ فَقَالَ أَبُو هُرَيْرَةَ أَمَّا هَذَا فَقَدْ عَصَى أَبَا الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Al Ahwash] dari [Ibrahim bin Muhajir] dari [Abu Asy Sya'tsa`] ia berkata; Kami duduk-duduk bersama [Abu Hurairah] di dalam masjid, lalu seorang mu`adzin mengumandangkan adzan, dan saat itu pula seorang laki-laki keluar dari dalam masjid, sementara Abu Hurairah mengikutinya dengan pandangan mata. Setelah itu ia berkata; \"Orang ini telah mendurhakai Abu Qasim shallallahu 'alaihi wasallam.\""},"694":{"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ قَالَ أَنْبَأَنَا عَبْدُ الْجَبَّارِ بْنُ عُمَرَ عَنْ ابْنِ أَبِي فَرْوَةَ عَنْ مُحَمَّدِ بْنِ يُوسُفَ مَوْلَى عُثْمَانَ بْنِ عَفَّانَ عَنْ أَبِيهِ عَنْ عُثْمَانَ بْنِ عَفَّانَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَدْرَكَهُ الْأَذَانُ فِي الْمَسْجِدِ ثُمَّ خَرَجَ لَمْ يَخْرُجْ لِحَاجَةٍ وَهُوَ لَا يُرِيدُ الرَّجْعَةَ فَهُوَ مُنَافِقٌ","id":"Telah menceritakan kepada kami [Harmalah bin Yahya] berkata, telah menceritakan kepada kami [Abdullah bin Wahb] berkata; telah memberitakan kepada kami [Abdul Jabbar bin Umar] dari [Ibnu Abu Farwah] dari [Muhammad bin Yusuf] -bekas budak Utsman bin Affan- dari [Bapaknya] dari [Utsman bin Affan] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menjumpai adzan di masjid kemudian keluar bukan karena suatu hajat, dan ia tidak ingin kembali lagi, maka ia adalah orang munafik.\""},"695":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ قَالَ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا لَيْثُ بْنُ سَعْدٍ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ قَالَ حَدَّثَنَا دَاوُدُ بْنُ عَبْدِ اللَّهِ الْجَعْفَرِيُّ عَنْ عَبْدِ الْعَزِيزِ بْنِ مُحَمَّدٍ جَمِيعًا عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ أُسَامَةَ بْنِ الْهَادِ عَنْ الْوَلِيدِ بْنِ أَبِي الْوَلِيدِ عَنْ عُثْمَانَ بْنِ عَبْدِ اللَّهِ بْنِ سُرَاقَةَ الْعَدَوِيِّ عَنْ عُمَرَ بْنِ الْخَطَّابِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ بَنَى مَسْجِدًا يُذْكَرُ فِيهِ اسْمُ اللَّهِ بَنَى اللَّهُ لَهُ بَيْتًا فِي الْجَنَّةِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata; telah menceritakan kepada kami [Yunus bin Muhammad] berkata; telah menceritakan kepada kami [Laits bin Sa'd]. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata; telah menceritakan kepada kami [Dawud bin Abdullah Al Ja'fari] dari [Abdul Aziz bin Muhammad], semuanya dari [Yazid bin Abdullah bin Usamah bin Al Had] dari [Al Walid bin Abu Al Walid] dari [Utsman bin Abdullah bin Suraqah Al 'Adawi] dari [Umar Ibnul Khaththab] ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membangun masjid Allah yang di dalamnya digunakan untuk berdzikir kepada Allah, maka Allah akan membangunkan baginya rumah di surga.\""},"696":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو بَكْرٍ الْحَنَفِيُّ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ عَنْ أَبِيهِ عَنْ مَحْمُودِ بْنِ لَبِيدٍ عَنْ عُثْمَانَ بْنِ عَفَّانَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ بَنَى لِلَّهِ مَسْجِدًا بَنَى اللَّهُ لَهُ مِثْلَهُ فِي الْجَنَّةِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Abu Bakar Al Hanafi] berkata, telah menceritakan kepada kami [Abdul Hamid bin Ja'far] dari [Bapaknya] dari [Mahmud bin Labid] dari [Utsman bin Affan] ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membangun masjid karena Allah, maka Allah akan membangunkan baginya masjid di surga.\""},"697":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ عُثْمَانَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ ابْنِ لَهِيعَةَ قَالَ حَدَّثَنِي أَبُو الْأَسْوَدِ عَنْ عُرْوَةَ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ بَنَى مَسْجِدًا مِنْ مَالِهِ بَنَى اللَّهُ لَهُ بَيْتًا فِي الْجَنَّةِ","id":"Telah menceritakan kepada kami [Al 'Abbas bin Utsman Ad Dimasyqi] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] dari [Ibnu Lahi'ah] berkata; telah menceritakan kepadaku [Abul Aswad] dari ['Urwah] dari [Ali bin Abu Thalib] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membangun masjid dari hartanya, maka Allah akan membangunkan baginya istana di surga.\""},"698":{"ar":"حَدَّثَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ عَنْ إِبْرَاهِيمَ بْنِ نَشِيطٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي حُسَيْنٍ النَّوْفَلِيِّ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ بَنَى مَسْجِدًا لِلَّهِ كَمَفْحَصِ قَطَاةٍ أَوْ أَصْغَرَ بَنَى اللَّهُ لَهُ بَيْتًا فِي الْجَنَّةِ","id":"Telah menceritakan kepada kami [Yunus bin Abdul A'la] berkata, telah menceritakan kepada kami [Abdullah bin Wahb] dari [Ibrahim bin Nasyith] dari [Abdullah bin Abdurrahman bin Abu Husain An Naufali] dari ['Atho` bin Abu Rabah] dari [Jabir bin Abdullah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membangun masjid karena Allah meski sebesar sangkar burung, atau bahkan lebih kecil dari itu, maka Allah akan membangunkan baginya satu istana di surga.\""},"699":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُعَاوِيَةَ الْجُمَحِيُّ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقُومُ السَّاعَةُ حَتَّى يَتَبَاهَى النَّاسُ فِي الْمَسَاجِدِ","id":"Telah menceritakan kepada kami [Abdullah bin Mu'awiyah Al Jumahi] berkata, telah menceritakan kepada kami [Hammad bin Salamah] dari [Ayyub] dari [Abu Qilabah] dari [Anas bin Malik] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kiamat tidak akan datang hingga manusia berbangga-bangga dengan masjid.\""},"700":{"ar":"حَدَّثَنَا جُبَارَةُ بْنُ الْمُغَلِّسِ حَدَّثَنَا عَبْدُ الْكَرِيمِ بْنُ عَبْدِ الرَّحْمَنِ الْبَجَلِيُّ عَنْ لَيْثٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرَاكُمْ سَتُشَرِّفُونَ مَسَاجِدَكُمْ بَعْدِي كَمَا شَرَّفَتْ الْيَهُودُ كَنَائِسَهَا وَكَمَا شَرَّفَتْ النَّصَارَى بِيَعَهَا","id":"Telah menceritakan kepada kami [Jubarah bin Al Mughallis] berkata, telah menceritakan kepada kami [Abdul Karim bin Abdurrahman Al Bajali] dari [Laits] dari [Ikrimah] dari [Ibnu 'Abbas] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku melihat kalian akan memegahkan masjid-masjid kalian setelah sepeninggalku, sebagaimana orang-orang Yahudi memegahkan sinagog-sinagog mereka, dan sebagaimana orang-orang Nasrani memegahkan gereja-gereja mereka.\""},"701":{"ar":"حَدَّثَنَا جُبَارَةُ بْنُ الْمُغَلِّسِ حَدَّثَنَا عَبْدُ الْكَرِيمِ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي إِسْحَقَ عَنْ عَمْرِو بْنِ مَيْمُونٍ عَنْ عُمَرَ بْنِ الْخَطَّابِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا سَاءَ عَمَلُ قَوْمٍ قَطُّ إِلَّا زَخْرَفُوا مَسَاجِدَهُمْ","id":"Telah menceritakan kepada kami [Jubarah bin Al Mughallis] berkata, telah menceritakan kepada kami [Abdul Karim bin Abdurrahman] dari [Abu Ishaq] dari ['Amru bin Maimun] dari [Umar bin Al Khatthab] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak buruk amal suatu kaum kecuali membuat hiasan-hiasan dinding di masjid-masjid mereka.\""},"702":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ أَبِي التَّيَّاحِ الضُّبَعِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ مَوْضِعُ مَسْجِدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِبَنِي النَّجَّارِ وَكَانَ فِيهِ نَخْلٌ وَمَقَابِرُ لِلْمُشْرِكِينَ فَقَالَ لَهُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَامِنُونِي بِهِ قَالُوا لَا نَأْخُذُ لَهُ ثَمَنًا أَبَدًا قَالَ فَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَبْنِيهِ وَهُمْ يُنَاوِلُونَهُ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَلَا إِنَّ الْعَيْشَ عَيْشُ الْآخِرَهْفَاغْفِرْ لِلْأَنْصَارِ وَالْمُهَاجِرَهْقَالَ وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي قَبْلَ أَنْ يَبْنِيَ الْمَسْجِدَ حَيْثُ أَدْرَكَتْهُ الصَّلَاةُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Hammad bin Salamah] dari [Abu At Tayyah Adl Dlabbi] dari [Anas bin Malik] ia berkata; Letak masjid Rasulullah shallallahu 'alaihi wasallam adalah di bani Najjar, di situ terdapat pepohon kurma dan pekuburan. Maka Nabi shallallahu 'alaihi wasallam bersabda kepada mereka: \"Juallah kebun ini kepadaku! \" mereka menjawab; \"Selamanya kami tidak akan menjualnya.\" Anas berkata; Nabi shallallahu 'alaihi wasallam membangun masjidnya sementara mereka membantunya, lalu Nabi shallallahu 'alaihi wasallam bersabda: \"Ketahuilah, sesungguhnya kehidupan itu adalah kehidupan akhirat. Ya Allah, ampunilah kaum Anshar dan Muhajirin.\" Anas berkata; \"Sebelum membangun masjid, Nabi shallallahu 'alaihi wasallam biasa melaksanakan shalat di manasaja ketika waktunya telah tiba.\""},"703":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا أَبُو هَمَّامٍ الدَّلَّالُ حَدَّثَنَا سَعِيدُ بْنُ السَّائِبِ عَنْ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ عِيَاضٍ عَنْ عُثْمَانَ بْنِ أَبِي الْعَاصِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَهُ أَنْ يَجْعَلَ مَسْجِدَ الطَّائِفِ حَيْثُ كَانَ طَاغِيَتُهُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Abu Hammam Ad Dallal] berkata, telah menceritakan kepada kami [Sa'id bin As Sa`ib] dari [Muhammad bin Abdullah bin Iyadl] dari [Utsman bin Abul 'Ash] berkata; Rasulullah shallallahu 'alaihi wasallam memerintahkan kepadanya agar memposisikan (menghormati) masjid Tha`if sebagaimana orang-orang memposisikan sesembahan mereka.\" "},"704":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ حَدَّثَنَا مُوسَى بْنُ أَعْيَنَ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَوَسُئِلَ عَنْ الْحِيطَانِ تُلْقَى فِيهَا الْعَذِرَاتُ فَقَالَ إِذَا سُقِيَتْ مِرَارًا فَصَلُّوا فِيهَا يَرْفَعُهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami ['Amru bin Utsman] berkata, telah menceritakan kepada kami [Musa bin A'yun] berkata; telah menceritakan kepada kami [Muhammad bin Ishaq] dari [Nafi'] dari [Ibnu Umar], ia ditanya tentang dinding (lantai) yang terkena kotoran. Maka Ibnu Umar menjawab; \"Jika lantai itu selalu disiram dengan air, maka shalatlah di sana, \" ia memarfu'kan hadits ini kepada Nabi shallallahu 'alaihi wasallam."},"705":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ يَحْيَى عَنْ أَبِيهِ وَحَمَّادُ بْنُ سَلَمَةَ عَنْ عَمْرِو بْنِ يَحْيَى عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْأَرْضُ كُلُّهَا مَسْجِدٌ إِلَّا الْمَقْبَرَةَ وَالْحَمَّامَ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Yazid bin Harun] berkata; telah menceritakan kepada kami [Sufyan] dari ['Amru bin Yahya] dari [Bapaknya] dan [Hammad bin Salamah] dari ['Amru bin Yahya] dari [Bapaknya] dari [Abu Sa'id Al Khudzri] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seluruh bumi adalah tempat masjid, kecuali kuburan dan kamar mandi.\""},"706":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ عَنْ يَحْيَى بْنِ أَيُّوبَ عَنْ زَيْدِ بْنِ جَبِيرَةَ عَنْ دَاوُدَ بْنِ الْحُصَيْنِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُصَلَّى فِي سَبْعِ مَوَاطِنَ فِي الْمَزْبَلَةِ وَالْمَجْزَرَةِ وَالْمَقْبَرَةِ وَقَارِعَةِ الطَّرِيقِ وَالْحَمَّامِ وَمَعَاطِنِ الْإِبِلِ وَفَوْقَ الْكَعْبَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Ibrahim Ad Dimasyqi] berkata, telah menceritakan kepada kami [Abdullah bin Yazid] dari [Yahya bin Ayyub] dari [Zaid bin Jabirah] dari [Dawud bin Al Hushain] dari [Nafi'] dari [Ibnu Umar] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang shalat di tujuh tempat; pembuangan sampah, penyembelihan, pekuburan, tengah jalan, kamar mandi, kandang unta dan di atas Ka'bah.\""},"707":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ دَاوُدَ وَمُحَمَّدُ بْنُ أَبِي الْحُسَيْنِ قَالَا حَدَّثَنَا أَبُو صَالِحٍ حَدَّثَنِي اللَّيْثُ قَالَ حَدَّثَنِي نَافِعٌ عَنْ ابْنِ عُمَرَ عَنْ عُمَرَ بْنِ الْخَطَّابِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَبْعُ مَوَاطِنَ لَا تَجُوزُ فِيهَا الصَّلَاةُ ظَاهِرُ بَيْتِ اللَّهِ وَالْمَقْبَرَةُ وَالْمَزْبَلَةُ وَالْمَجْزَرَةُ وَالْحَمَّامُ وَعَطَنُ الْإِبِلِ وَمَحَجَّةُ الطَّرِيقِ","id":"Telah menceritakan kepada kami [Ali bin Dawud] dan [Muhammad bin Abul Husain] keduanya berkata; telah menceritakan kepada kami [Abu Shalah] berkata, telah menceritakan kepadaku [Al Laits] berkata, telah menceritakan kepadaku [Nafi'] dari [Ibnu Umar] dari [Umar bin Al Khatthab] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tujuh tempat yang tidak boleh dipergunakan untuk shalat; di atas Ka'bah, pekuburan, pembuangan sampah, tempat penyembelihan hewan, kamar mandi, kandang unta, dan tengah jalan.\""},"708":{"ar":"حَدَّثَنَا يَحْيَى بْنُ عُثْمَانَ بْنِ سَعِيدِ بْنِ كَثِيرِ بْنِ دِينَارٍ الْحِمْصِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ حِمْيَرَ حَدَّثَنَا زَيْدُ بْنُ جَبِيرَةَ الْأَنْصَارِيُّ عَنْ دَاوُدَ بْنِ الْحُصَيْنِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خِصَالٌ لَا تَنْبَغِي فِي الْمَسْجِدِ لَا يُتَّخَذُ طَرِيقًا وَلَا يُشْهَرُ فِيهِ سِلَاحٌ وَلَا يُنْبَضُ فِيهِ بِقَوْسٍ وَلَا يُنْشَرُ فِيهِ نَبْلٌ وَلَا يُمَرُّ فِيهِ بِلَحْمٍ نِيءٍ وَلَا يُضْرَبُ فِيهِ حَدٌّ وَلَا يُقْتَصُّ فِيهِ مِنْ أَحَدٍ وَلَا يُتَّخَذُ سُوقًا","id":"Telah menceritakan kepada kami [Yahya bin Utsman bin Sa'id bin Katsir bin Dinar Al Himshi] berkata, telah menceritakan kepada kami [Muhammad bin Himyar] berkata, telah menceritakan kepada kami [Zaid bin Jabirah Al Anshari] dari [Dawud bin Al Hushain] dari [Nafi'] dari [Ibnu Umar] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Beberapa hal yang tidak layak dilakukan di masjid; tidak dijadikan sebagai jalan, tidak boleh senjata dihunuskan, tidak boleh busur ditarik, tidak boleh menyebarkan anak panah, tidak boleh melewatkan daging mentah, tidak boleh dilaksanakan had, tidak boleh menuntut qishash dari seseorang, dan tidak boleh menjadikannya sebagai pasar.\""},"709":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ الْكِنْدِيُّ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ ابْنِ عَجْلَانَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْبَيْعِ وَالِابْتِيَاعِ وَعَنْ تَنَاشُدِ الْأَشْعَارِ فِي الْمَسَاجِدِ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id Al Kindi] berkata, telah menceritakan kepada kami [Abu Khalid Al Ahmar] dari [Ibnu 'Ajlan] dari ['Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang untuk jual beli dan mendendangkan sya'ir dalam masjid.\""},"710":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُوسُفَ السُّلَمِيُّ حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا الْحَارِثُ بْنُ نَبْهَانَ حَدَّثَنَا عُتْبَةُ بْنُ يَقْظَانَ عَنْ أَبِي سَعِيدٍ عَنْ مَكْحُولٍ عَنْ وَاثِلَةَ بْنِ الْأَسْقَعِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ جَنِّبُوا مَسَاجِدَكُمْ صِبْيَانَكُمْ وَمَجَانِينَكُمْ وَشِرَاءَكُمْ وَبَيْعَكُمْ وَخُصُومَاتِكُمْ وَرَفْعَ أَصْوَاتِكُمْ وَإِقَامَةَ حُدُودِكُمْ وَسَلَّ سُيُوفِكُمْ وَاتَّخِذُوا عَلَى أَبْوَابِهَا الْمَطَاهِرَ وَجَمِّرُوهَا فِي الْجُمَعِ","id":"Telah menceritakan kepada kami [Ahmad bin Yusuf As Sulami] berkata, telah menceritakan kepada kami [Muslim bin Ibrahim] berkata, telah menceritakan kepada kami [Al Harits bin Nabhan] berkata, telah menceritakan kepada kami ['Utbah bin Yaqzhan] dari [Abu Sa'id] dari [Makhul] dari [Watsilah bin Al Asqa'] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Hindarkan dari masjid-masjid kalian anak kecil, orang gila, jual beli, perdebatan, meninggikan suara, pelaksanaan hudud dan menghunuskan pedang. Buatlah pada setiap pintunya tempat bersuci dan serta harumkanlah di setiap hari jum'at.\""},"711":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ أَنْبَأَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَكُنَّا نَنَامُ فِي الْمَسْجِدِ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] berkata, telah menceritakan kepada kami [Abdullah bin Numair] berkata, telah memberitakan kepada kami [Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] ia berkata; \"Pada masa Rasulullah shallallahu 'alaihi wasallam kami biasa tidur di masjid.\""},"712":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا الْحَسَنُ بْنُ مُوسَى حَدَّثَنَا شَيْبَانُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ أَنَّ يَعِيشَ بْنَ قَيْسِ بْنِ طِخْفَةَ حَدَّثَهُ عَنْ أَبِيهِ وَكَانَ مِنْ أَصْحَابِ الصُّفَّةِ قَالَقَالَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْطَلِقُوا فَانْطَلَقْنَا إِلَى بَيْتِ عَائِشَةَ وَأَكَلْنَا وَشَرِبْنَا فَقَالَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ شِئْتُمْ نِمْتُمْ هَا هُنَا وَإِنْ شِئْتُمْ انْطَلَقْتُمْ إِلَى الْمَسْجِدِ قَالَ فَقُلْنَا بَلْ نَنْطَلِقُ إِلَى الْمَسْجِدِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Al Hasan bin Musa] berkata, telah menceritakan kepada kami [Syaiban bin Abdurrahman] dari [Yahya bin Abu Katsir] dari [Abu Salamah bin Abdurrahman] bahwa [Ya'isy bin Qais bin Thikhfah] menceritakan kepadanya dari [Bapaknya] -ia termasuk Ashabus Shuffah- ia berkata; Rasulullah shallallahu 'alaihi wasallam berkata kepada kami: \"Berangkatlah.\" Kami pun berangkat menunju rumah Aisyah, lalu kami makan dan minum. Rasulullah shallallahu 'alaihi wasallam kemudian bersabda kepada kami: \"Jika mau, kalian boleh tidur di sini, dan jika mau kalian bisa pergi ke masjid.\" Ia berkata; Maka kami berkata; \"Kami akan pergi ke masjid.\""},"713":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مَيْمُونٍ الرَّقِّيُّ حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ ح و حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ أَبِيهِ عَنْ أَبِي ذَرٍّ الْغِفَارِيِّ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَيُّ مَسْجِدٍ وُضِعَ أَوَّلُ قَالَ الْمَسْجِدُ الْحَرَامُ قَالَ قُلْتُ ثُمَّ أَيٌّ قَالَ ثُمَّ الْمَسْجِدُ الْأَقْصَى قُلْتُ كَمْ بَيْنَهُمَا قَالَ أَرْبَعُونَ عَامًا ثُمَّ الْأَرْضُ لَكَ مُصَلًّى فَصَلِّ حَيْثُ مَا أَدْرَكَتْكَ الصَّلَاةُ","id":"Telah menceritakan kepada kami [Ali bin Maimun Ar Raqqi] berkata, telah menceritakan kepada kami [Muhammad bin Ubaid]. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Ibrahim At Taimi] dari [Bapaknya] dari [Abu Dzar Al Ghifari] ia berkata; Aku bertanya; \" Wahai Rasulullah, masjid manakah yang pertama kali dibangun?\" beliau menjawab: \"Masjidil Haram.\" Abu Dzar berkata; Aku bertanya; \"Lalu mana lagi?\" beliau menjawab: \"Masjidil Aqsha.\" Aku bertanya; \"Berapa jarak antara keduanya?\" beliau menjawab: \"Empat puluh tahun. Dan bumi bagimu adalah masjid, maka shalatlah dimanapun tempatnya ketika waktu shalat telah tiba.\""},"714":{"ar":"حَدَّثَنَا أَبُو مَرْوَانَ مُحَمَّدُ بْنُ عُثْمَانَ الْعُثْمَانِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ مَحْمُودِ بْنِ الرَّبِيعِ الْأَنْصَارِيِّوَكَانَ قَدْ عَقَلَ مَجَّةً مَجَّهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ دَلْوٍ فِي بِئْرٍ لَهُمْ عَنْ عِتْبَانَ بْنِ مَالِكٍ السَّالِمِيِّ وَكَانَ إِمَامَ قَوْمِهِ بَنِي سَالِمٍ وَكَانَ شَهِدَ بَدْرًا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ جِئْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي قَدْ أَنْكَرْتُ مِنْ بَصَرِي وَإِنَّ السَّيْلَ يَأْتِي فَيَحُولُ بَيْنِي وَبَيْنَ مَسْجِدِ قَوْمِي وَيَشُقُّ عَلَيَّ اجْتِيَازُهُ فَإِنْ رَأَيْتَ أَنْ تَأْتِيَنِي فَتُصَلِّيَ فِي بَيْتِي مَكَانًا أَتَّخِذُهُ مُصَلًّى فَافْعَلْ قَالَ أَفْعَلُ فَغَدَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ بَعْدَ مَا اشْتَدَّ النَّهَارُ وَاسْتَأْذَنَ فَأَذِنْتُ لَهُ وَلَمْ يَجْلِسْ حَتَّى قَالَ أَيْنَ تُحِبُّ أَنْ أُصَلِّيَ لَكَ مِنْ بَيْتِكَ فَأَشَرْتُ لَهُ إِلَى الْمَكَانِ الَّذِي أُحِبُّ أَنْ أُصَلِّيَ فِيهِ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَصَفَفْنَا خَلْفَهُ فَصَلَّى بِنَا رَكْعَتَيْنِ ثُمَّ احْتَبَسْتُهُ عَلَى خَزِيرَةٍ تُصْنَعُ لَهُمْ","id":"Telah menceritakan kepada kami [Abu Marwan Muhammad bin Utsman Al Utsmani] berkata, telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Ibnu Syihab] dari [Mahmud bin Ar Rabi' Al Anshari] -dia telah menjaga Majjah (air yang dikeluarkan dari dalam mulut) dalam ember yang Rasulullah shallallahu 'alaihi wasallam keluarkan (muntahkan) ke dalam sumur milik mereka-, dari ['Itban bin Malik As Salimi] -ia adalah imam bagi kaumnya, bani Salim. Dan ia juga pernah ikut dalam perang badar bersama Rasulullah shallallahu 'alaihi wasallam.- Ia berkata; Aku mendatangi Rasulullah shallallahu 'alaihi wasallam, lalu aku bertanya kepadanya; \"Wahai Rasulullah, mataku sakit dan banjir menghalangiku untuk mendatangi masjid kaumku, hingga aku tidak dapat melaluinya, sekiranya engkau berkehendak datang dan shalat di rumahku yang bisa aku jadikan sebagai tempat shalat, maka lakukanlah.\" Beliau bersabda: \"Aku akan datang.\" maka di awal siang Rasulullah shallallahu 'alaihi wasallam dan Abu Bakar berangkat, beliau minta izin dan akupun memberinya izin (masuk). Namun beliau tidak langsung duduk hingga beliau bertanya: \"Tempat mana yang engkau sukai untuk aku jadikan tempat shalat di rumahmu ini?\" lalu aku memberi isyarat kepada beliau tempat yang aku sukai. Rasulullah shallallahu 'alaihi wasallam kemudian berdiri dan kami membuat shaf di belakangnya, lalu beliau shalat dua raka'at bersama kami. Setelah itu aku menghidangkan daging yang berkuah kepada mereka.\""},"715":{"ar":"حَدَّثَنَا يَحْيَى بْنُ الْفَضْلِ الْخُرْقِي حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَاصِمٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَجُلًا مِنْ الْأَنْصَارِ أَرْسَلَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تَعَالَ فَخُطَّ لِي مَسْجِدًا فِي دَارِي أُصَلِّي فِيهِ وَذَلِكَ بَعْدَ مَا عَمِيَ فَجَاءَ فَفَعَلَ","id":"Telah menceritakan kepada kami [Yahya bin Al Fadhl Al Khurqi] berkata, telah menceritakan kepada kami [Abu Amir] berkata, telah menceritakan kepada kami [Hammad bin Salamah] dari ['Ashim] dari [Abu Shalih] dari [Abu Hurairah], berkata; Seorang lelaki Anshar mengutus seseorang kepada Rasulullah shallallahu 'alaihi wasallam, agar ia mengatakan; \"kunjungilah dan garislah untukku sebuah masjid di rumahku, hingga aku bisa shalat di situ.\" Dan hal itu ketika ia mengalami kebutaan. Lalu beliau datang dan melakukkannya."},"716":{"ar":"حَدَّثَنَا يَحْيَى بْنُ حَكِيمٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ ابْنِ عَوْنٍ عَنْ أَنَسِ بْنِ سِيرِينَ عَنْ عَبْدِ الْحَمِيدِ بْنِ الْمُنْذِرِ بْنِ الْجَارُودِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَصَنَعَ بَعْضُ عُمُومَتِي لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَعَامًا فَقَالَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي أُحِبُّ أَنْ تَأْكُلَ فِي بَيْتِي وَتُصَلِّيَ فِيهِ قَالَ فَأَتَاهُ وَفِي الْبَيْتِ فَحْلٌ مِنْ هَذِهِ الْفُحُولِ فَأَمَرَ بِنَاحِيَةٍ مِنْهُ فَكُنِسَ وَرُشَّ فَصَلَّى وَصَلَّيْنَا مَعَهُقَالَ أَبُو عَبْد اللَّهِ بْن مَاجَةَ الْفَحْلُ هُوَ الْحَصِيرُ الَّذِي قَدْ اسْوَدَّ","id":"Telah menceritakan kepada kami [Yahya bin Hakim] berkata, telah menceritakan kepada kami [Ibnu Abu 'Adi] dari [Ibnu 'Aun] dari [Anas bin Sirin] dari [Abdul Hamid bin Al Mundzir bin Al Jarud] dari [Anas bin Malik] ia berkata; Sebagian dari bibiku membuatkan makanan untuk Nabi shallallahu 'alaihi wasallam, lalu ia berkata kepada Nabi shallallahu 'alaihi wasallam; \"Aku suka jika engkau makan dan shalat di rumahku.\" Anas berkata; \"Kemudian beliau mendatanginya, sementara di rumah ada tikar, beliau memerintahkan memegang bagian ujungnya agar di bersihkan dan diperciki air. Kemudian beliau shalat dan kami shalat bersamanya.\" Abu Abdullah Ibnu Majah berkata; \"Al Fahlu adalah tikar yang sudah menghitam lusuh.\""},"717":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ سُلَيْمَانَ بْنِ أَبِي الْجَوْنِ حَدَّثَنَا مُحَمَّدُ بْنُ صَالِحٍ الْمَدَنِيُّ حَدَّثَنَا مُسْلِمُ بْنُ أَبِي مَرْيَمَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَخْرَجَ أَذًى مِنْ الْمَسْجِدِ بَنَى اللَّهُ لَهُ بَيْتًا فِي الْجَنَّةِ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] berkata, telah menceritakan kepada kami [Abdurrahman bin Sulaiman bin Abul Jaun] berkata, telah menceritakan kepada kami [Muhammad bin Shalih Al Madani] berkata, telah menceritakan kepada kami [Muslim bin Abu Maryam] dari [Abu Sa'id Al Khudri] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengeluarkan kotoran dari dalam masjid, maka Allah akan membuatkan baginya rumah di surga.\""},"718":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ بِشْرِ بْنِ الْحَكَمِ وَأَحْمَدُ بْنُ الْأَزْهَرِ قَالَا حَدَّثَنَا مَالِكُ بْنُ سُعَيْرٍ أَنْبَأَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ بِالْمَسَاجِدِ أَنْ تُبْنَى فِي الدُّورِ وَأَنْ تُطَهَّرَ وَتُطَيَّبَ","id":"Telah menceritakan kepada kami [Abdurrahman bin Bisyr bin Al Hakam] dan [Ahmad bin Al Azhar] keduanya berkata; telah menceritakan kepada kami [Malik bin Su'air] berkata, telah memberitakan kepada kami [Hisyam bin 'Urwah] dari [Bapaknya] dari [Aisyah] berkata; \"Rasulullah shallallahu 'alaihi wasallam memerintahkan agar masjid dibangun di perkampungan, dibersihkan dan di beri wewangian.\""},"719":{"ar":"حَدَّثَنَا رِزْقُ اللَّهِ بْنُ مُوسَى حَدَّثَنَا يَعْقُوبُ بْنُ إِسْحَقَ الْحَضْرَمِيُّ حَدَّثَنَا زَائِدَةُ بْنُ قُدَامَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تُتَّخَذَ الْمَسَاجِدُ فِي الدُّورِ وَأَنْ تُطَهَّرَ وَتُطَيَّبَ","id":"Telah menceritakan kepada kami [Rizqullah bin Musa] berkata, telah menceritakan kepada kami [Ya'qub bin Ishaq Al Hadlrami] berkata, telah menceritakan kepada kami [Za`idah bin Qudamah] dari [Hisyam bin 'Urwah] dari [Bapaknya] dari [Aisyah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam memerintahkan agar masjid dibangun di perkampungan, dibersihkan dan diberi wewangian.\""},"720":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ سِنَانٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ خَالِدِ بْنِ إِيَاسٍ عَنْ يَحْيَى بْنِ عَبْدِ الرَّحْمَنِ بْنِ حَاطِبٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَأَوَّلُ مَنْ أَسْرَجَ فِي الْمَسَاجِدِ تَمِيمٌ الدَّارِيُّ","id":"Telah menceritakan kepada kami [Ahmad bin Sinan] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Khalid bin 'Iyas] dari [Yahya bin Abdurrahman bin Hathib] dari [Abu Sa'id Al Khudri] ia berkata; \"Pertama kali yang memberi penerangan di masjid adalah Tamim Ad Daari.\""},"721":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُثْمَانَ الْعُثْمَانِيُّ أَبُو مَرْوَانَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ عَنْ أَبِي هُرَيْرَةَ وَأَبِي سَعِيدٍ الْخُدْرِيِّ أَنَّهُمَا أَخْبَرَاهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى نُخَامَةً فِي جِدَارِ الْمَسْجِدِ فَتَنَاوَلَ حَصَاةً فَحَكَّهَا ثُمَّ قَالَ إِذَا تَنَخَّمَ أَحَدُكُمْ فَلَا يَتَنَخَّمَنَّ قِبَلَ وَجْهِهِ وَلَا عَنْ يَمِينِهِ وَلْيَبْزُقْ عَنْ شِمَالِهِ أَوْ تَحْتَ قَدَمِهِ الْيُسْرَى","id":"Telah menceritakan kepada kami [Muhammad bin Utsman Al Utsmani Abu Marwan] berkata, telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Ibnu Syihab] dari [Humaid bin Abdurrahman bin Auf] dari [Abu Hurairah] dan [Abu Sa'id Al Khudri] bahwa keduanya telah mengabarkan kepadanya, bahwa Rasulullah shallallahu 'alaihi wasallam melihat dahak di dinding masjid, beliau lalu mengambil kerikil seraya membersihkannya. Setelah itu beliau bersabda: \"Jika salah seorang dari kalian membuang dahak, maka janganlah ke bagian depan atau samping kanannya. Tetapi hendaklah ke samping kiri atau di bawah kaki kirinya.\""},"722":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ طَرِيفٍ حَدَّثَنَا عَائِذُ بْنُ حَبِيبٍ عَنْ حُمَيْدٍ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى نُخَامَةً فِي قِبْلَةِ الْمَسْجِدِ فَغَضِبَ حَتَّى احْمَرَّ وَجْهُهُ فَجَاءَتْهُ امْرَأَةٌ مِنْ الْأَنْصَارِ فَحَكَّتْهَا وَجَعَلَتْ مَكَانَهَا خَلُوقًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَحْسَنَ هَذَا","id":"Telah menceritakan kepada kami [Muhammad bin Tharif] berkata, telah menceritakan kepada kami ['Aidz bin Habib] dari [Humaid] dari [Anas] berkata; Nabi shallallahu 'alaihi wasallam melihat dahak di kiblat masjid hingga beliau marah dan memerah wajahnya. Kemudian datanglah seorang wanita Anshar kepada beliau seraya mengerik dan memberi wewangian pada bekasnya. Maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Alangkah bagusnya ini.\""},"723":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ الْمِصْرِيُّ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَرَأَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نُخَامَةً فِي قِبْلَةِ الْمَسْجِدِ وَهُوَ يُصَلِّي بَيْنَ يَدَيْ النَّاسِ فَحَتَّهَا ثُمَّ قَالَ حِينَ انْصَرَفَ مِنْ الصَّلَاةِ إِنَّ أَحَدَكُمْ إِذَا كَانَ فِي الصَّلَاةِ فَإِنَّ اللَّهَ قِبَلَ وَجْهِهِ فَلَا يَتَنَخَّمَنَّ أَحَدُكُمْ قِبَلَ وَجْهِهِ فِي الصَّلَاةِ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh Al Mishri] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Nafi'] dari [Abdullah bin Umar] ia berkata; Ketika Rasulullah shallallahu 'alaihi wasallam sedang shalat, beliau melihat dahak di kiblat masjid lalu beliau mengeriknya. Selesai shalat beliau kemudian bersabda: \"Jika salah seorang dari kalian sedang shalat sesungguhnya Allah berada di depannya, maka ketika shalat janganlah kalian membuang dahaknya ke arah depan.\" "},"724":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَكَّ بُزَاقًا فِي قِبْلَةِ الْمَسْجِدِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Hisyam bin 'Urwah] dari [Bapaknya] dari [Aisyah] berkata; \"Rasulullah shallallahu 'alaihi wasallam membersihkan ludah di kiblat masjid.\""},"725":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ أَبِي سِنَانٍ سَعِيدِ بْنِ سِنَانٍ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ سُلَيْمَانَ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَجُلٌ مَنْ دَعَا إِلَى الْجَمَلِ الْأَحْمَرِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا وَجَدْتَهُ إِنَّمَا بُنِيَتْ الْمَسَاجِدُ لِمَا بُنِيَتْ لَهُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Abu Sinan Sa'id bin Sinan] dari [Alqamah bin Martsad] dari [Sulaiman bin Buraidah] dari [Bapaknya] ia berkata; Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat, lalu seorang laki-laki berkata; \"siapa yang menemukan unta merah?\" maka Nabi shallallahu 'alaihi wasallam bersabda: \"Engkau tidak akan mendapatkannya, masjid itu dibangun untuk sujud.\""},"726":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ لَهِيعَةَ ح و حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ جَمِيعًا عَنْ ابْنِ عَجْلَانَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ إِنْشَادِ الضَّالَّةِ فِي الْمَسْجِدِ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] berkata, telah memberitakan kepada kami [Abdullah bin Lahi'ah]. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Hatim bin Isma'il] semuanya dari [Ibnu 'Ajlan] dari ['Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya] berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang mengumumkan barang hilang di masjid.\""},"727":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي حَيْوَةُ بْنُ شُرَيْحٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ الْأَسَدِيِّ أَبِي الْأَسْوَدِ عَنْ أَبِي عَبْدِ اللَّهِ مَوْلَى شَدَّادِ بْنِ الْهَادِ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ سَمِعَ رَجُلًا يَنْشُدُ ضَالَّةً فِي الْمَسْجِدِ فَلْيَقُلْ لَا رَدَّ اللَّهُ عَلَيْكَ فَإِنَّ الْمَسَاجِدَ لَمْ تُبْنَ لِهَذَا","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib] berkata, telah menceritakan kepada kami [Abdullah bin Wahb] berkata, telah mengabarkan kepadaku [Haiwah bin Syuraih] dari [Muhammad bin Abdurrahman Al Asadi Abu Al Aswad] dari [Abu Abdullah] mantan budak Syaddad Ibnul Had, bahwasanya ia mendengar [Abu Hurairah] berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mendengar seseorang mengumumkan barang hilang di masjid, maka hendaklah ia mengatakan; 'Semoga Allah tidak mengembalikannya kepadamu, ' sebab masjid tidak dibangun untuk ini.\""},"728":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ ح و حَدَّثَنَا أَبُو بِشْرٍ بَكْرُ بْنُ خَلَفٍ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ قَالَا حَدَّثَنَا هِشَامُ بْنُ حَسَّانَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ لَمْ تَجِدُوا إِلَّا مَرَابِضَ الْغَنَمِ وَأَعْطَانَ الْإِبِلِ فَصَلُّوا فِي مَرَابِضِ الْغَنَمِ وَلَا تُصَلُّوا فِي أَعْطَانِ الْإِبِلِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yazid bin Harun]. Dan menurut jalur yang lain; Telah menceritakan kepada kami [Abu Bisyr Bakr bin Khalaf] berkata, telah menceritakan kepada kami [Yazid bin Zurai'] keduanya berkata; telah menceritakan kepada kami [Hisyam bin Hassan] dari [Muhammad bin Sirin] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika kalian tidak menemukan tempat kecuali kandang kambing dan kandang unta, maka shalatlah di kandang kambing, dan jangan shalat di kandang unta.\""},"729":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا هُشَيْمٌ عَنْ يُونُسَ عَنْ الْحَسَنِ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ الْمُزَنِيِّ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلُّوا فِي مَرَابِضِ الْغَنَمِ وَلَا تُصَلُّوا فِي أَعْطَانِ الْإِبِلِ فَإِنَّهَا خُلِقَتْ مِنْ الشَّيَاطِينِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Husyaim] dari [Yunus] dari [Al Hasan] dari [Abdullah bin Mughaffal Al Muzani] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalatlah kalian di kandang kambing dan jangan shalat di kandang unta, sebab ia diciptakan dari setan.\""},"730":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ الرَّبِيعِ بْنِ سَبْرَةَ بْنِ مَعْبَدٍ الْجُهَنِيُّ أَخْبَرَنِي أَبِي عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يُصَلَّى فِي أَعْطَانِ الْإِبِلِ وَيُصَلَّى فِي مُرَاحِ الْغَنَمِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Zaid Ibnul Hubab] berkata, telah menceritakan kepada kami [Abdul Malik bin Ar Rafi' bin Sabrah bin Ma'bad Al Juhani] berkata, telah mengabarkan kepadaku [Bapakku] dari [Bapaknya], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak dibolehkan shalat di kandang unta, namun dibolehkan shalat di kandang kambing.\""},"731":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ وَأَبُو مُعَاوِيَةَ عَنْ لَيْثٍ عَنْ عَبْدِ اللَّهِ بْنِ الْحَسَنِ عَنْ أُمِّهِ عَنْ فَاطِمَةَ بِنْتِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَخَلَ الْمَسْجِدَ يَقُولُ بِسْمِ اللَّهِ وَالسَّلَامُ عَلَى رَسُولِ اللَّهِ اللَّهُمَّ اغْفِرْ لِي ذُنُوبِي وَافْتَحْ لِي أَبْوَابَ رَحْمَتِكَ وَإِذَا خَرَجَ قَالَ بِسْمِ اللَّهِ وَالسَّلَامُ عَلَى رَسُولِ اللَّهِ اللَّهُمَّ اغْفِرْ لِي ذُنُوبِي وَافْتَحْ لِي أَبْوَابَ فَضْلِكَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Isma'il bin Ibrahim] dan [Abu Mu'awiyah] dari [Laits] dari [Abdullah Ibnul Hasan] dari [Ibunya] dari [Fatimah binti Rasulullah shallallahu 'alaihi wasallam], ia berkata; Jika Rasulullah shallallahu 'alaihi wasallam masuk ke dalam masjid, kemudian beliau mengucapkan: \"BISMILLAH WAS SALAMU 'ALA RASUULILLAH ALLAHUMMAGHFIRLI DZUNUUBI WAFTAHLI ABWAABA RAHMATIK (Dengan menyebut nama Allah dan salam -semoga- tercurahkan kepada Rasulullah. Ya Allah, ampunilah dosaku dan bukakanlah bagiku pintu rahmat-Mu).\" Dan jika keluar beliau mengucapkan; \"BISMILLAH WAS SALAMU 'ALA RASUULILLAH ALLAHUMMAGHFIRLI DZUNUUBI WAFTAHLI ABWAABA FADLLIKA (Dengan menyebut nama Allah dan salam -semoga- tercurahkan kepada Rasulullah. Ya Allah, ampunilah dosaku dan bukakanlah bagiku pintu-pintu karunia-Mu).\""},"732":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ بْنِ سَعِيدِ بْنِ كَثِيرِ بْنِ دِينَارٍ الْحِمْصِيُّ وَعَبْدُ الْوَهَّابِ بْنُ الضَّحَّاكِ قَالَا حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ عَنْ عُمَارَةَ بْنِ غَزِيَّةَ عَنْ رَبِيعَةَ بْنِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ الْمَلِكِ بْنِ سَعِيدِ بْنِ سُوَيْدٍ الْأَنْصَارِيِّ عَنْ أَبِي حُمَيْدٍ السَّاعِدِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَخَلَ أَحَدُكُمْ الْمَسْجِدَ فَلْيُسَلِّمْ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ لِيَقُلْ اللَّهُمَّ افْتَحْ لِي أَبْوَابَ رَحْمَتِكَ وَإِذَا خَرَجَ فَلْيَقُلْ اللَّهُمَّ إِنِّي أَسْأَلُكَ مِنْ فَضْلِكَ","id":"Telah menceritakan kepada kami ['Amru bin Utsman bin Sa'id bin Katsir bin Dinar Al Himshi] dan [Abdul Wahhab bin Adl Dlahhak] keduanya berkata; telah menceritakan kepada kami [Isma'il bin 'Ayyasy] dari [Umarah bin Ghaziah] dari [Rabi'ah bin Abu Abdurrahman] dari [Abdul Malik bin Sa'id bin Suwaid Al Anshari] dari [Abu Humaid As Sa'idi] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian masuk masjid hendaklah mengucapkan salam atas Nabi shallallahu 'alaihi wasallam, lalu hendaklah ia mengucapkan; ALLAHUMMAF TAHLI ABWAABA RAHMATIK (Ya Allah, bukakanlah bagiku pintu rahmat-Mu), dan jika keluar ucapkanlah; ALLAHUMMA INNI AS`ALUKA MIN FADLLIKA (Ya Allah, sesungguhnya aku memohon karunia-Mu).\""},"733":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو بَكْرٍ الْحَنَفِيُّ حَدَّثَنَا الضَّحَّاكُ بْنُ عُثْمَانَ حَدَّثَنِي سَعِيدٌ الْمَقْبُرِيُّ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا دَخَلَ أَحَدُكُمْ الْمَسْجِدَ فَلْيُسَلِّمْ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلْيَقُلْ اللَّهُمَّ افْتَحْ لِي أَبْوَابَ رَحْمَتِكَ وَإِذَا خَرَجَ فَلْيُسَلِّمْ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلْيَقُلْ اللَّهُمَّ اعْصِمْنِي مِنْ الشَّيْطَانِ الرَّجِيمِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Abu Bakr Al Hanafi] berkata, telah menceritakan kepada kami [Adl Dlahhak bin Utsman] berkata, telah menceritakan kepadaku [Sa'id Al Maqburi] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang di antara kalian masuk masjid, maka ucapkanlah salam kepada Nabi shallallahu 'alaihi wasallam, dan hendaklah mengucapkan; 'ALLAHUMMAF TAHLII ABWAABA RAHMATIK (Ya Allah, bukakanlah bagiku pintu rahmat-Mu).' Dan jika keluar hendaklah mengucapkan salam kepada Nabi shallallahu 'alaihi wasallam, dan hendaklah mengucapkan; 'ALLAHUMMA'SHIMNII MINASY SYAITHANIR RAJIIM (Ya Allah, lindungilah aku dari setan yang terkutuk).'\""},"734":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا تَوَضَّأَ أَحَدُكُمْ فَأَحْسَنَ الْوُضُوءَ ثُمَّ أَتَى الْمَسْجِدَ لَا يَنْهَزُهُ إِلَّا الصَّلَاةُ لَا يُرِيدُ إِلَّا الصَّلَاةَ لَمْ يَخْطُ خَطْوَةً إِلَّا رَفَعَهُ اللَّهُ بِهَا دَرَجَةً وَحَطَّ عَنْهُ بِهَا خَطِيئَةً حَتَّى يَدْخُلَ الْمَسْجِدَ فَإِذَا دَخَلَ الْمَسْجِدَ كَانَ فِي صَلَاةٍ مَا كَانَتْ الصَّلَاةُ تَحْبِسُهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian berwudlu dan membaguskannya, kemudian datang ke masjid, dan tidak ada yang menggerakkannya berjalan menuju masjid kecuali shalat, maka tidaklah ia melangkahkan kaki kecuali dengannya Allah akan mengangkat derajat dan menghapus dosanya hingga ia masuk masjid. Dan jika masuk masjid, maka ia akan tetap dalam hitungan shalat selama shalatlah yang menahannya (dari keinginan pulang).\" "},"735":{"ar":"حَدَّثَنَا أَبُو مَرْوَانَ الْعُثْمَانِيُّ مُحَمَّدُ بْنُ عُثْمَانَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ وَأَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أُقِيمَتْ الصَّلَاةُ فَلَا تَأْتُوهَا وَأَنْتُمْ تَسْعَوْنَ وَأْتُوهَا تَمْشُونَ وَعَلَيْكُمْ السَّكِينَةُ فَمَا أَدْرَكْتُمْ فَصَلُّوا وَمَا فَاتَكُمْ فَأَتِمُّوا","id":"Telah menceritakan kepada kami [Abu Marwan Al Utsmani Muhammad bin Utsman] berkata, telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Ibnu Syihab] dari [Ibnul Musayyab] dan [Abu Salamah] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika shalat didirikan maka janganlah engkau mendatanginya dengan terburu-buru, tetapi datangilah dengan berjalan dan tenang. Apa yang kalian dapati maka shalatlah dan apa yang kalian tertinggal maka sempurnakanlah.\""},"736":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ أَبِي بُكَيْرٍ حَدَّثَنَا زُهَيْرُ بْنُ مُحَمَّدٍ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَلَا أَدُلُّكُمْ عَلَى مَا يُكَفِّرُ اللَّهُ بِهِ الْخَطَايَا وَيَزِيدُ بِهِ فِي الْحَسَنَاتِ قَالُوا بَلَى يَا رَسُولَ اللَّهِ قَالَ إِسْبَاغُ الْوُضُوءِ عِنْدَ الْمَكَارِهِ وَكَثْرَةُ الْخُطَى إِلَى الْمَسَاجِدِ وَانْتِظَارُ الصَّلَاةِ بَعْدَ الصَّلَاةِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yahya bin Abu Bukair] berkata, telah menceritakan kepada kami [Zuhair bin Muhammad] dari [Abdullah bin Muhammad bin 'Aqil] dari [Sa'id Ibnul Musayyab] dari [Abu Sa'id Al Khudri], bahwasanya ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Maukah kalian aku tunjukkan sesuatu yang dengannya Allah menghapus kesalahan dan menambah kebaikan?\" para sahabat menjawab; \"Tentu, ya Rasulullah, \" beliau bersabda: \"Menyempurnakan wudlu di saat yang tidak disukai, memperbanyak langkah ke masjid dan menunggu shalat setelah shalat.\""},"737":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ إِبْرَاهِيمَ الْهَجَرِيِّ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِ قَالَمَنْ سَرَّهُ أَنْ يَلْقَى اللَّهَ عَزَّ وَجَلَّ غَدًا مُسْلِمًا فَلْيُحَافِظْ عَلَى هَؤُلَاءِ الصَّلَوَاتِ الْخَمْسِ حَيْثُ يُنَادَى بِهِنَّ فَإِنَّهُنَّ مِنْ سُنَنِ الْهُدَى وَإِنَّ اللَّهَ شَرَعَ لِنَبِيِّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُنَنَ الْهُدَى وَلَعَمْرِي لَوْ أَنَّ كُلَّكُمْ صَلَّى فِي بَيْتِهِ لَتَرَكْتُمْ سُنَّةَ نَبِيِّكُمْ وَلَوْ تَرَكْتُمْ سُنَّةَ نَبِيِّكُمْ لَضَلَلْتُمْ وَلَقَدْ رَأَيْتُنَا وَمَا يَتَخَلَّفُ عَنْهَا إِلَّا مُنَافِقٌ مَعْلُومُ النِّفَاقِ وَلَقَدْ رَأَيْتُ الرَّجُلَ يُهَادَى بَيْنَ الرَّجُلَيْنِ حَتَّى يَدْخُلَ فِي الصَّفِّ وَمَا مِنْ رَجُلٍ يَتَطَهَّرُ فَيُحْسِنُ الطُّهُورَ فَيَعْمِدُ إِلَى الْمَسْجِدِ فَيُصَلِّي فِيهِ فَمَا يَخْطُو خَطْوَةً إِلَّا رَفَعَ اللَّهُ لَهُ بِهَا دَرَجَةً وَحَطَّ عَنْهُ بِهَا خَطِيئَةً","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dari [Ibrahim Al Hajari] dari [Abu Al Ahwash] dari [Abdullah] ia berkata; \"Barangsiapa suka bertemu Allah dalam keadaan muslim, maka hendaklah ia menjaga shalat lima waktu setiap ia dipanggil untuk mengerjakannya. Sebab itu adalah jalan menuju petunjuk. Dan Allah telah memerintahkan Nabi kalian untuk mengikuti jalan petunjuk. Demi hidupku, sekiranya kalian semua shalat di rumah masing-masing sungguh kalian telah meninggalkan sunah Nabi kalian. Dan sekiranya kalian meninggalkan sunah Nabi kalian maka kalian akan tersesat. Kami perhatikan bahwa orang-orang yang meninggalkan shalat berjama'ah adalah seorang munafik yang tampak jelas kemunafikannya. Sungguh, aku telah melihat seorang laki-laki yang menyibak antara dua orang hingga ia masuk dalam barisan shalat, tidaklah seorang laki-laki bersuci dan membaguskannya, kemudian menuju masjid untuk shalat, maka tidaklah ia melangkahkan kaki kecuali dengan langkah tersebut Allah akan mengangkat derajatnya dan menghapus dosanya.\""},"738":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَعِيدِ بْنِ يَزِيدَ بْنِ إِبْرَاهِيمَ التُّسْتَرِيُّ حَدَّثَنَا الْفَضْلُ بْنُ الْمُوَفَّقِ أَبُو الْجَهْمِ حَدَّثَنَا فُضَيْلُ بْنُ مَرْزُوقٍ عَنْ عَطِيَّةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ خَرَجَ مِنْ بَيْتِهِ إِلَى الصَّلَاةِ فَقَالَ اللَّهُمَّ إِنِّي أَسْأَلُكَ بِحَقِّ السَّائِلِينَ عَلَيْكَ وَأَسْأَلُكَ بِحَقِّ مَمْشَايَ هَذَا فَإِنِّي لَمْ أَخْرُجْ أَشَرًا وَلَا بَطَرًا وَلَا رِيَاءً وَلَا سُمْعَةً وَخَرَجْتُ اتِّقَاءَ سُخْطِكَ وَابْتِغَاءَ مَرْضَاتِكَ فَأَسْأَلُكَ أَنْ تُعِيذَنِي مِنْ النَّارِ وَأَنْ تَغْفِرَ لِي ذُنُوبِي إِنَّهُ لَا يَغْفِرُ الذُّنُوبَ إِلَّا أَنْتَ أَقْبَلَ اللَّهُ عَلَيْهِ بِوَجْهِهِ وَاسْتَغْفَرَ لَهُ سَبْعُونَ أَلْفِ مَلَكٍ","id":"Telah menceritakan kepada kami [Muhammad bin Sa'id bin Yazid bin Ibrahim At Tustari] berkata, telah menceritakan kepada kami [Al Fadhlu Ibnul Muwaffaq Abu Al Jahm] berkata, telah menceritakan kepada kami [Fudlail bin Marzuq] dari [Athiyyah] dari [Abu Sa'id Al Khudzri], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berjalan menuju masjid lalu mengucapkan; ALAHUMMA INNI AS`ALUKA BI HAQQIS SA`ILIIN 'ALAIKA WA AS`ALUKA BI HAQQI MAMSYAAYA HADZA FA INNI LAM AKHRUJ ASYARAN WA LAA BATHARAN WA LAA RIYA`AN WA LAA SUM'ATAN WA KHARAJTU ITTIQA`A SUKHTHIKA WABTIGHA`A MARDLATIKA FA AS`ALUKA AN TU'IDZANI MINANNAR WA AN TAGHFIRALI DZUNUBI INNAHU LAA YAGHFIRUDZ DZUNUBA ILLA ANTA (Ya Allah, aku meminta kepada-Mu dengan hak peminta kepada-Mu, dan aku juga meminta dengan hak jalanku ini. Sesungguhnya aku keluar bukan untuk keburukan, bukan untuk kesombongan, bukan untuk riya dan bukan untuk dipuji. Aku keluar agar terhindar dari murka-Mu dan mengharap ridla-Mu. Maka, aku meminta agar Engkau melindungiku dari siksa neraka dan mengampuni dosaku, sebab tidak ada yang mengampuni dosa selain-Mu), maka Allah akan menerimanya dengan wajah-Nya, dan tujuh puluh ribu malaikat juga akan memintakan ampunan baginya.\""},"739":{"ar":"حَدَّثَنَا رَاشِدُ بْنُ سَعِيدِ بْنِ رَاشِدٍ الرَّمْلِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ أَبِي رَافِعٍ إِسْمَعِيلَ بْنِ رَافِعٍ عَنْ سُمَيٍّ مَوْلَى أَبِي بَكْرٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَشَّاءُونَ إِلَى الْمَسَاجِدِ فِي الظُّلَمِ أُولَئِكَ الْخَوَّاضُونَ فِي رَحْمَةِ اللَّهِ","id":"Telah menceritakan kepada kami [Rasyid bin Sa'id bin Rasyid Ar Ramli] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] dari [Abu Rafi' Isma'il bin Rafi'] dari [Sumay] mantan budak Abu Bakr, dari [Abu Shalih] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang-orang yang berjalan menuju masjid dalam kegelapan malam, mereka itulah orang-orang yang mendapatkan rahmat Allah.\""},"740":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُحَمَّدٍ الْحُلَبِيُّ حَدَّثَنَا يَحْيَى بْنُ الْحَارِثِ الشِّيرَازِيُّ حَدَّثَنَا زُهَيْرُ بْنُ مُحَمَّدٍ التَّمِيمِيُّ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيَبْشَرْ الْمَشَّاءُونَ فِي الظُّلَمِ إِلَى الْمَسَاجِدِ بِنُورٍ تَامٍّ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Ibrahim bin Muhammad Al Hulabi] berkata, telah menceritakan kepada kami [Yahya bin Al Harits Asy Syirazi] berkata, telah menceritakan kepada kami [Zuhair bin Muhammad At Tamimi] dari [Abu Hazim] dari [Sahl bin Sa'd As Sa'idi] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaklah orang-orang yang berjalan kaki dalam kegelapan menuju masjid berbahagia dengan cahaya sempurna pada hari kiamat.\""},"741":{"ar":"حَدَّثَنَا مَجْزَأَةُ بْنُ سُفْيَانَ بْنِ أَسِيدٍ مَوْلَى ثَابِتٍ الْبُنَانِيِّ حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الصَّائِغُ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَشِّرْ الْمَشَّائِينَ فِي الظُّلَمِ إِلَى الْمَسَاجِدِ بِالنُّورِ التَّامِّ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Majza`ah bin Sufyan bin Usaid] -mantan budak Tsabit Al Bunani- berkata, telah menceritakan kepada kami [Sulaiman bin Dawud Ash Sha`igh] dari [Tsabit Al Bunani] dari [Anas bin Malik], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berilah kabar gembira bagi orang-orang yang berjalan kaki dalam kegelapan menuju masjid dengan cahaya sempurna pada hari kiamat.\""},"742":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ مِهْرَانَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَعْدٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْأَبْعَدُ فَالْأَبْعَدُ مِنْ الْمَسْجِدِ أَعْظَمُ أَجْرًا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Waki'] dari [Ibnu Abu Dzi`b] dari [Abdurrahman bin Mihran] dari [Abdurrahman bin Sa'd] dari [Abu Hurairah], ia berkata; \"Rasululah shallallahu 'alaihi wasallam bersabda: \"Yang paling besar pahalanya adalah yang paling jauh dari masjid.\""},"743":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ حَدَّثَنَا عَبَّادُ بْنُ عَبَّادٍ الْمُهَلَّبِيُّ حَدَّثَنَا عَاصِمٌ الْأَحْوَلُ عَنْ أَبِي عُثْمَانَ النَّهْدِيِّ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَكَانَ رَجُلٌ مِنْ الْأَنْصَارِ بَيْتُهُ أَقْصَى بَيْتٍ بِالْمَدِينَةِ وَكَانَ لَا تُخْطِئُهُ الصَّلَاةُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَتَوَجَّعْتُ لَهُ فَقُلْتُ يَا فُلَانُ لَوْ أَنَّكَ اشْتَرَيْتَ حِمَارًا يَقِيكَ الرَّمَضَ وَيَرْفَعُكَ مِنْ الْوَقَعِ وَيَقِيكَ هَوَامَّ الْأَرْضِ فَقَالَ وَاللَّهِ مَا أُحِبُّ أَنَّ بَيْتِي بِطُنُبِ بَيْتِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَحَمَلْتُ بِهِ حِمْلًا حَتَّى أَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ ذَلِكَ لَهُ فَدَعَاهُ فَسَأَلَهُ فَذَكَرَ لَهُ مِثْلَ ذَلِكَ وَذَكَرَ أَنَّهُ يَرْجُو فِي أَثَرِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ لَكَ مَا احْتَسَبْتَ","id":"Telah menceritakan kepada kami [Ahmad bin 'Abdah] berkata, telah menceritakan kepada kami [Abbad bin 'Abbad Al Muhallabi] berkata, telah menceritakan kepada kami ['Ashim Al Ahwal] dari [Abu Utsman An Nahdi] dari [Ubai bin Ka'ab] ia berkata; Ada seorang laki-laki Anshar yang rumahnya paling jauh di wilayah Madinah, sementara ia tidak pernah ketinggalan shalat bersama Rasulullah. Aku merasa iba hingga aku berkata kepadanya; \"Wahai Fulan, cobalah engkau membeli seekor himar yang bisa menjagamu dari panasnya pasir, mengangkatmu jika jatuh di jalan dan menjagamu dari binatang melata.\" Ia menjawab; \"Demi Allah, aku tidak suka jika rumahku bergandengan dengan rumah Muhammad shallallahu 'alaihi wasallam.\" Ubai berkata; Aku merasa tersinggung dengan ucapannya sehingga aku mendatangi Nabi shallallahu 'alaihi wasallam dan aku ceritakan kejadian itu kepada beliau. Maka beliau memanggil dan bertanya kepadanya. Lalu ia menyebutkan sebagimana yang ia sebutkan, bahwa ia mengharapkan pahala. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh, engkau akan mendapatkan sebagaimana yang engkau harapkan.\" "},"744":{"ar":"حَدَّثَنَا أَبُو مُوسَى مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَأَرَادَتْ بَنُو سَلِمَةَ أَنْ يَتَحَوَّلُوا مِنْ دِيَارِهِمْ إِلَى قُرْبِ الْمَسْجِدِ فَكَرِهَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُعْرُوا الْمَدِينَةَ فَقَالَ يَا بَنِي سَلِمَةَ أَلَا تَحْتَسِبُونَ آثَارَكُمْ فَأَقَامُوا","id":"Telah menceritakan kepada kami [Abu Musa Muhammad bin Al Mutsanna] berkata, telah menceritakan kepada kami [Khalid bin Al Harits] berkata, telah menceritakan kepada kami [Humaid] dari [Anas bin Malik], ia berkata; Bani Salimah berniat memindahkan rumah mereka dekat dengan masjid, namun Nabi shallallahu 'alaihi wasallam tidak menyukai bila mereka memadati Madinah, lalu beliau bersabda: \"Wahai Bani Salimah, tidak maukah kalian mendapatkan pahala?\" Maka mereka pun tetap tinggal di rumah-rumah mereka.\"  "},"745":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا إِسْرَائِيلُ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَتْ الْأَنْصَارُ بَعِيدَةً مَنَازِلُهُمْ مِنْ الْمَسْجِدِ فَأَرَادُوا أَنْ يَقْتَرِبُوا فَنَزَلَتْ{ وَنَكْتُبُ مَا قَدَّمُوا وَآثَارَهُمْ }قَالَ فَثَبَتُوا","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Isra`il] dari [Simak] dari [Ikrimah] dari [Ibnu 'Abbas], ia berkata; \"Kaum Anshar adalah orang-orang yang rumahnya jauh dari masjid, maka mereka ingin agar rumahnya dekat dengan masjid, hingga turunlah ayat: \"Maka kami menulis apa yang mereka persembahkan dan bekas-bekas mereka.\" Ibnu 'Abbas berkata; \"Maka mereka pun tetap tinggal di tempat mereka.\""},"746":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةُ الرَّجُلِ فِي جَمَاعَةٍ تَزِيدُ عَلَى صَلَاتِهِ فِي بَيْتِهِ وَصَلَاتِهِ فِي سُوقِهِ بِضْعًا وَعِشْرِينَ دَرَجَةً","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalat seorang laki-laki dalam jama'ah lebih besar pahalanya dari shalat yang dia lakukan di rumah dan pasar dengan dua puluh derajat lebih.\""},"747":{"ar":"حَدَّثَنَا أَبُو مَرْوَانَ مُحَمَّدُ بْنُ عُثْمَانَ الْعُثْمَانِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَضْلُ الْجَمَاعَةِ عَلَى صَلَاةِ أَحَدِكُمْ وَحْدَهُ خَمْسٌ وَعِشْرُونَ جُزْءًا","id":"Telah menceritakan kepada kami [Abu Marwan Muhammad bin Utsman Al Utsmani] berkata, telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Ibnu Syihab] dari [Sa'id bin Musayyab] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Keutamaan shalat berjama'ah dibadingkan shalat seseorang di antara kalian dengan sendirian adalah dua puluh lima bagian.\""},"748":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ هِلَالِ بْنِ مَيْمُونٍ عَنْ عَطَاءِ بْنِ يَزِيدَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةُ الرَّجُلِ فِي جَمَاعَةٍ تَزِيدُ عَلَى صَلَاتِهِ فِي بَيْتِهِ خَمْسًا وَعِشْرِينَ دَرَجَةً","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Hilal bin Maimun] dari ['Atho` bin Yazid] dari [Abu Sa'id Al Khudri] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalat seseorang dalam jama'ah lebih baik dari shalat yang dia lakukan di rumah dengan dua puluh lima derajat.\""},"749":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عُمَرَ رُسْتَةُ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةُ الرَّجُلِ فِي جَمَاعَةٍ تَفْضُلُ عَلَى صَلَاةِ الرَّجُلِ وَحْدَهُ بِسَبْعٍ وَعِشْرِينَ دَرَجَةً","id":"Telah menceritakan kepada kami [Abdurrahman bin Umar Rustah] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] berkata, telah menceritakan kepada kami [Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalatnya seorang laki-laki dalam jama'ah lebih baik dua puluh tujuh derajat dari shalatnya seseorang yang dilakukan sendirian.\""},"750":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مَعْمَرٍ حَدَّثَنَا أَبُو بَكْرٍ الْحَنَفِيُّ حَدَّثَنَا يُونُسُ بْنُ أَبِي إِسْحَقَ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَصِيرٍ عَنْ أَبِيهِ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةُ الرَّجُلِ فِي جَمَاعَةٍ تَزِيدُ عَلَى صَلَاةِ الرَّجُلِ وَحْدَهُ أَرْبَعًا وَعِشْرِينَ أَوْ خَمْسًا وَعِشْرِينَ دَرَجَةً","id":"Telah menceritakan kepada kami [Muhammad bin Ma'mar] berkata, telah menceritakan kepada kami [Abu Bakr Al Hanafi] berkata, telah menceritakan kepada kami [Yunus bin Abu Ishaq] dari [Bapaknya] dari [Abdullah bin Abu Bashir] berkata, dari [Bapaknya] dari [Ubai bin Ka'ab] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalat seorang lelaki dalam jama'ah lebih baik dari shalat seorang lelaki sendirian dengan dua puluh empat atau dua puluh lima derajat.\""},"751":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقَدْ هَمَمْتُ أَنْ آمُرَ بِالصَّلَاةِ فَتُقَامَ ثُمَّ آمُرَ رَجُلًا فَيُصَلِّيَ بِالنَّاسِ ثُمَّ أَنْطَلِقَ بِرِجَالٍ مَعَهُمْ حُزَمٌ مِنْ حَطَبٍ إِلَى قَوْمٍ لَا يَشْهَدُونَ الصَّلَاةَ فَأُحَرِّقَ عَلَيْهِمْ بُيُوتَهُمْ بِالنَّارِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku sangat berkeinginan agar shalat ditegakkan, lalu aku perintahkan seorang laki-laki shalat bersama manusia, sedangkan aku bersama beberapa laki-laki pergi membawa kayu bakar menuju orang-orang yang tidak ikut shalat berjama'ah, hingga aku dapat membakar rumah mereka.\" "},"752":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ زَائِدَةَ عَنْ عَاصِمٍ عَنْ أَبِي رَزِينٍ عَنْ ابْنِ أُمِّ مَكْتُومٍ قَالَقُلْتُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي كَبِيرٌ ضَرِيرٌ شَاسِعُ الدَّارِ وَلَيْسَ لِي قَائِدٌ يُلَاوِمُنِي فَهَلْ تَجِدُ لِي مِنْ رُخْصَةٍ قَالَ هَلْ تَسْمَعُ النِّدَاءَ قُلْتُ نَعَمْ قَالَ مَا أَجِدُ لَكَ رُخْصَةً","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Usamah] dari [Za`idah] dari ['Ashim] dari [Abu Razin] dari [Ibnu Ummi Maktum] ia berkata; Aku berkata kepada Nabi shallallahu 'alaihi wasallam; \"aku orang yang sudah tua, tidak dapat melihat, jauh rumahnya, dan aku juga tidak memiliki pemandu yang dapat menuntunku. Maka apakah aku bisa mendapatkan keringanan?\" Beliau menjawab: \"Apakah kamu mendengar adzan?\" Aku menjawab; \"Iya.\" Beliau bersabda: \"Aku tidak mendapatkan adanya keringanan bagimu.\" "},"753":{"ar":"حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ بَيَانٍ الْوَاسِطِيُّ أَنْبَأَنَا هُشَيْمٌ عَنْ شُعْبَةَ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ سَمِعَ النِّدَاءَ فَلَمْ يَأْتِهِ فَلَا صَلَاةَ لَهُ إِلَّا مِنْ عُذْرٍ","id":"Telah menceritakan kepada kami [Abdul Hamid bin Bayan Al Wasithi] berkata, telah memberitakan kepada kami [Husyaim] dari [Syu'bah] dari ['Adi bin Tsabit] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa mendengar suara adzan kemudian tidak mendatanginya, maka tidak ada shalat baginya kecuali karena udzur.\""},"754":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامٍ الدَّسْتُوَائِيِّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ الْحَكَمِ بْنِ مِينَاءَ أَخْبَرَنِي ابْنُ عَبَّاسٍ وَابْنُ عُمَرَأَنَّهُمَا سَمِعَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ عَلَى أَعْوَادِهِ لَيَنْتَهِيَنَّ أَقْوَامٌ عَنْ وَدْعِهِمْ الْجَمَاعَاتِ أَوْ لَيَخْتِمَنَّ اللَّهُ عَلَى قُلُوبِهِمْ ثُمَّ لَيَكُونُنَّ مِنْ الْغَافِلِينَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Abu Usamah] dari [Hisyam Ad Dustuwa`i] dari [Yahya bin Abu Katsir] dari [Al Hakam bin Mina`] berkata, telah mengabarkan kepadaku [Ibnu 'Abbas] dan [Ibnu Umar], bahwa keduanya mendengar Nabi shallallahu 'alaihi wasallam bersabda di atas mimbarnya: \"Sungguh, kaum-kaum itu segera berhenti dari kebiasaan meninggalkan shalat berjama'ah, atau Allah akan menutup hati mereka sehingga menjadi orang-orang yang lalai.\""},"755":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ إِسْمَعِيلَ الْهُذَلِيُّ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ الزَّبْرِقَانِ بْنِ عَمْرٍو الضَّمْرِيِّ عَنْ أُسَامَةَ بْنِ زَيْدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيَنْتَهِيَنَّ رِجَالٌ عَنْ تَرْكِ الْجَمَاعَةِ أَوْ لَأُحَرِّقَنَّ بُيُوتَهُمْ","id":"Telah menceritakan kepada kami [Utsman bin Isma'il Al Hudzali Ad Dimasyqi] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] dari [Ibnu Abu Dzi`b] dari [Az Zabriqan bin 'Amru Adl Dlamri] dari [Usamah bin Zaid] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang-orang itu segera berhenti dari meninggalkan shalat berjama'ah atau benar-benar akan aku bakar rumah mereka.\""},"756":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ حَدَّثَنِي مُحَمَّدُ بْنُ إِبْرَاهِيمَ التَّيْمِيُّ حَدَّثَنِي عِيسَى بْنُ طَلْحَةَ حَدَّثَتْنِي عَائِشَةُ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ يَعْلَمُ النَّاسُ مَا فِي صَلَاةِ الْعِشَاءِ وَصَلَاةِ الْفَجْرِ لَأَتَوْهُمَا وَلَوْ حَبْوًا","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim Ad Dimasyqi] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Al Auza'i] berkata, telah menceritakan kepada kami [Yahya bin Abu Katsir] berkata, telah menceritakan kepadaku [Muhammad bin Ibrahim At Taimi] berkata, telah menceritakan kepadaku [Isa bin Thalhah] berkata, telah menceritakan kepadaku [Aisyah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekiranya manusia mengetahui pahala yang ada pada shalat isya dan shalat subuh, pasti mereka akan mendatangi keduanya meskipun dengan merangkak.\""},"757":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ أَنْبَأَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَثْقَلَ الصَّلَاةِ عَلَى الْمُنَافِقِينَ صَلَاةُ الْعِشَاءِ وَصَلَاةُ الْفَجْرِ وَلَوْ يَعْلَمُونَ مَا فِيهِمَا لَأَتَوْهُمَا وَلَوْ حَبْوًا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah memberitakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya shalat yang paling berat bagi orang munafik adalah shalat isya dan shalat subuh. Sekiranya mereka mengetahui pahala yang ada pada keduanya, pasti mereka akan mendatanginya meskipun dengan merangkak.\""},"758":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ عَنْ عُمَارَةَ بْنِ غَزِيَّةَ عَنْ أَنَسِ بْنِ مَالِكٍ عَنْ عُمَرَ بْنِ الْخَطَّابِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يَقُولُ مَنْ صَلَّى فِي مَسْجِدٍ جَمَاعَةً أَرْبَعِينَ لَيْلَةً لَا تَفُوتُهُ الرَّكْعَةُ الْأُولَى مِنْ صَلَاةِ الْعِشَاءِ كَتَبَ اللَّهُ لَهُ بِهَا عِتْقًا مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Isma'il bin 'Ayyasy] dari [Umarah bin Ghaziyah] dari [Anas bin Malik] dari [Umar bin Al Khaththab], dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa shalat di masjid dengan berjama'ah selama empat puluh malam, dan tidak pernah tertingggal pada raka'at pertama dari shalat Isya, maka Allah akan menuliskan kemerdekaan baginya dari api neraka.\""},"759":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَحَدَكُمْ إِذَا دَخَلَ الْمَسْجِدَ كَانَ فِي صَلَاةٍ مَا كَانَتْ الصَّلَاةُ تَحْبِسُهُ وَالْمَلَائِكَةُ يُصَلُّونَ عَلَى أَحَدِكُمْ مَا دَامَ فِي مَجْلِسِهِ الَّذِي صَلَّى فِيهِ يَقُولُونَ اللَّهُمَّ اغْفِرْ لَهُ اللَّهُمَّ ارْحَمْهُ اللَّهُمَّ تُبْ عَلَيْهِ مَا لَمْ يُحْدِثْ فِيهِ مَا لَمْ يُؤْذِ فِيهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh, jika salah seorang dari kalian masuk masjid, ia akan tetap dalam hitungan shalat selama shalatlah yang menahannya. Dan para malaikat tetap mendo'akan salah seorang di antara kalian selama ia berada di dalam majlisnya, tempat ia shalat. Mereka berdo'a: 'Ya Allah ampunilah ia, ya Allah rahmatilah ia, ya Allah terimalah taubatnya, ' Hal ini akan tetap berlangsung selama ia belum berhadats dan tidak menyakiti.\""},"760":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا شَبَابَةُ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ الْمَقْبُرِيِّ عَنْ سَعِيدِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا تَوَطَّنَ رَجُلٌ مُسْلِمٌ الْمَسَاجِدَ لِلصَّلَاةِ وَالذِّكْرِ إِلَّا تَبَشْبَشَ اللَّهُ لَهُ كَمَا يَتَبَشْبَشُ أَهْلُ الْغَائِبِ بِغَائِبِهِمْ إِذَا قَدِمَ عَلَيْهِمْ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Syababah] berkata, telah menceritakan kepada kami [Ibnu Abu Dzi`b] dari [Al Maqburi] dari [Sa'id bin Yasar] dari [Abu Hurairah], dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidaklah seorang muslim mendiami masjid untuk shalat dan dzikir kecuali Allah berbunga-bunga padanya sebagaimana berbunga-bunganya orang yang hartanya hilang kembali lagi.\""},"761":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ سَعِيدٍ الدَّارِمِيُّ حَدَّثَنَا النَّضْرُ بْنُ شُمَيْلٍ حَدَّثَنَا حَمَّادٌ عَنْ ثَابِتٍ عَنْ أَبِي أَيُّوبَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَصَلَّيْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَغْرِبَ فَرَجَعَ مَنْ رَجَعَ وَعَقَّبَ مَنْ عَقَّبَ فَجَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُسْرِعًا قَدْ حَفَزَهُ النَّفَسُ وَقَدْ حَسَرَ عَنْ رُكْبَتَيْهِ فَقَالَ أَبْشِرُوا هَذَا رَبُّكُمْ قَدْ فَتَحَ بَابًا مِنْ أَبْوَابِ السَّمَاءِ يُبَاهِي بِكُمْ الْمَلَائِكَةَ يَقُولُ انْظُرُوا إِلَى عِبَادِي قَدْ قَضَوْا فَرِيضَةً وَهُمْ يَنْتَظِرُونَ أُخْرَى","id":"Telah menceritakan kepada kami [Ahmad bin Sa'id Ad Darimi] berkata, telah menceritakan kepada kami [An Nadlr bin Syumail] berkata, telah menceritakan kepada kami [Hammad] dari [Tsabit] dari [Abu Ayyub] dari [Abdullah bin Umar], ia berkata; Aku shalat maghrib bersama Rasulullah shallallahu 'alaihi wasallam, sehingga pulanglah orang yang pulang dan menunggulah orang yang menunggu. Lalu tiba-tiba datanglah Rasulullah shallallahu 'alaihi wasallam dengan tergesa-gesa sambil menyingkap lututnya, beliau lantas bersabda: \"Berilah kabar gembira, Rabb kalian telah membuka pintu-pintu langit, Ia membanggakan kalian di hadapan para malaikat, Allah berfirman: 'Perhatikanlah para hamba-Ku, mereka telah selesai menunaikan yang fardlu, namun mereka tetap menunggu fardlu yang lain! \""},"762":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا رِشْدِينُ بْنُ سَعْدٍ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ دَرَّاجٍ عَنْ أَبِي الْهَيْثَمِ عَنْ أَبِي سَعِيدٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا رَأَيْتُمْ الرَّجُلَ يَعْتَادُ الْمَسَاجِدَ فَاشْهَدُوا لَهُ بِالْإِيمَانِ قَالَ اللَّهُ تَعَالَى{ إِنَّمَا يَعْمُرُ مَسَاجِدَ اللَّهِ مَنْ آمَنَ بِاللَّهِ }الْآيَةَ","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Risydin bin Sa'd] dari ['Amru Ibnul Harits] dari [Darraj] dari [Abu Al Haitsam] dari [Abu Sa'id] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Jika engkau melihat seorang laki-laki selalu mendatangi masjid, maka bersaksilah bahwa ia seorang yang beriman, Allah Ta'ala berfirman; '(Hanya yang memakmurkan masjid-masjid Allah ialah orang-orang yang beriman kepada Allah...) \""},"763":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ الطَّنَافِسِيُّ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنِي عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرِو بْنِ عَطَاءٍ قَالَ سَمِعْتُ أَبَا حُمَيْدٍ السَّاعِدِيَّ يَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَامَ إِلَى الصَّلَاةِ اسْتَقْبَلَ الْقِبْلَةَ وَرَفَعَ يَدَيْهِ وَقَالَ اللَّهُ أَكْبَرُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad Ath Thanafusi] berkata, telah menceritakan kepada kami [Abu Usamah] berkata, telah menceritakan kepadaku [Abdul Hamid bin Ja'far] berkata, telah menceritakan kepada kami [Muhammad bin 'Amru bin 'Atho`] ia berkata; aku mendengar [Abu Humaid As Sa'idi] berkata; \"Jika akan mendirikan shalat, Rasulullah shallallahu 'alaihi wasallam menghadap kiblat dan mengangkat kedua tangannya, lalu beliau mengucapkan: \"ALLAHU AKBAR (Allah Maha Besar).\""},"764":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ حَدَّثَنِي جَعْفَرُ بْنُ سُلَيْمَانَ الضُّبَعِيُّ حَدَّثَنِي عَلِيُّ بْنُ عَلِيٍّ الرِّفَاعِيُّ عَنْ أَبِي الْمُتَوَكِّلِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْتَفْتِحُ صَلَاتَهُ يَقُولُ سُبْحَانَكَ اللَّهُمَّ وَبِحَمْدِكَ وَتَبَارَكَ اسْمُكَ وَتَعَالَى جَدُّكَ وَلَا إِلَهَ غَيْرُكَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Zaid Ibnul Hubab] berkata, telah menceritakan kepadaku [Ja'far bin Sulaiman Adl Dluba'i] berkata, telah menceritakan kepadaku [Ali bin Ali Ar Rifa'i] dari [Abu Al Mutawakkil] dari [Abu Sa'id Al Khudri] ia berkata; Rasulullah shallallahu 'alaihi wasallam membuka shalatnya dengan membaca: \"SUBHAANAKA ALLAHUMMA WA BIHAMDIKA TABAARAKASMUKA WA TA'ALAA JADDUKA WA LAA ILAAHA GHAIRUKA (Maha suci Engkau ya Allah, dan dengan memuji-Mu, nama-Mu berbarakah dan kemuliaan-Mu sangat agung, dan tidak ada Tuhan selain Engkau).\""},"765":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ عُمَارَةَ بْنِ الْقَعْقَاعِ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَبَّرَ سَكَتَ بَيْنَ التَّكْبِيرِ وَالْقِرَاءَةِ قَالَ فَقُلْتُ بِأَبِي أَنْتَ وَأُمِّي أَرَأَيْتَ سُكُوتَكَ بَيْنَ التَّكْبِيرِ وَالْقِرَاءَةِ فَأَخْبِرْنِي مَا تَقُولُ قَالَ أَقُولُ اللَّهُمَّ بَاعِدْ بَيْنِي وَبَيْنَ خَطَايَايَ كَمَا بَاعَدْتَ بَيْنَ الْمَشْرِقِ وَالْمَغْرِبِ اللَّهُمَّ نَقِّنِي مِنْ خَطَايَايَ كَالثَّوْبِ الْأَبْيَضِ مِنْ الدَّنَسِ اللَّهُمَّ اغْسِلْنِي مِنْ خَطَايَايَ بِالْمَاءِ وَالثَّلْجِ وَالْبَرَدِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Muhammad bin Fudlail] dari [Umarah Ibnul Qa'qa'] dari [Abu Zur'ah] dari [Abu Hurairah], ia berkata; Jika Rasulullah shallallahu 'alaihi wasallam bertakbir, beliau diam antara takbir dan bacaan, Abu Hurairah berkata; maka aku bertanya; \"Demi bapak dan ibuku, kabarkanlah kepadaku apa yang engkau baca di saat diam antara takbir dan bacaan? Beliau menjawab: \"Aku mengucapkan; ALLAHUMMA BAA'ID BAINI WA BAINA KHATHAAYAAYA KAMAA BAA'ADTA BAINAL MASYRIQI WAL MAGHRIBI. ALLAHUMMA NAQQINI MIN KHATHAAYAAYA KATS TSAUBIL ABYADLI MINAD DANAS. ALLAHUMMA IGHSILNI MIN KHATHAAYAAYA BIL MAA`I WATS TSALJI WAL BARADI (Ya Allah, jauhkanlah antara aku dan kesalahan-kesalahanku sebagaimana Engkau jauhkan antara timur dan barat. Ya Allah, bersihkanlah kesalahan-kesalahanku sebagaimana bersihnya kain putih dari noda. Ya Allah, bersihkanlah aku dari kesalahan-kesalahanku dengan air, es dan embun).\""},"766":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَعَبْدُ اللَّهِ بْنُ عِمْرَانَ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا حَارِثَةُ بْنُ أَبِي الرِّجَالِ عَنْ عَمْرَة�� عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا افْتَتَحَ الصَّلَاةَ قَالَ سُبْحَانَكَ اللَّهُمَّ وَبِحَمْدِكَ تَبَارَكَ اسْمُكَ وَتَعَالَى جَدُّكَ وَلَا إِلَهَ غَيْرُكَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan [Abdullah bin Imran] keduanya berkata; telah menceritakan kepada kami [Abu Mu'awiyah] berkata, telah menceritakan kepada kami [Haritsah bin Abu Rijal] dari ['Amrah] dari [Aisyah], bahwa Nabi shallallahu 'alaihi wasallam jika hendak membuka shalat, beliau mengucapkan; \"SUBHAANAKA ALLAHUMMA WA BIHAMDIKA TABAARAKASMUKA WA TA'ALAA JADDUKA WA LAA ILAAHA GHAIRUKA (Maha suci Engkau ya Allah, dan dengan memuji-Mu, nama-Mu berbarakah dan kemuliaan-Mu sangat agung, dan tidak ada Tuhan selain Engkau).\""},"767":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ عَاصِمٍ الْعَنَزِيِّ عَنْ ابْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ أَبِيهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ دَخَلَ فِي الصَّلَاةِ قَالَ اللَّهُ أَكْبَرُ كَبِيرًا اللَّهُ أَكْبَرُ كَبِيرًا ثَلَاثًا الْحَمْدُ لِلَّهِ كَثِيرًا الْحَمْدُ لِلَّهِ كَثِيرًا ثَلَاثًا سُبْحَانَ اللَّهِ بُكْرَةً وَأَصِيلًا ثَلَاثَ مَرَّاتِ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الشَّيْطَانِ الرَّجِيمِ مِنْ هَمْزِهِ وَنَفْخِهِ وَنَفْثِهِقَالَ عَمْرٌو هَمْزُهُ الْمُوتَةُ وَنَفْثُهُ الشِّعْرُ وَنَفْخُهُ الْكِبْرُ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dari ['Amru bin Murrah] dari ['Ashim Al 'Anazi] dari [Ibnu Jubair bin Muth'im] dari [Bapaknya] ia berkata; Ketika membuka shalat, aku melihat Rasulullah shallallahu 'alaihi wasallam mengucapkan; \"ALLAHU AKBAR KABIIRA, ALLAHU AKBAR KABIIRA (Sungguh Maha besar Allah, Sungguh Maha besar Allah) sebanyak tiga kali, ALHAMDULILLAHI KATSIIRA, ALHAMDULILLAHI KATSIIRA (Segala puji bagi Allah sebanyak-banyaknya. Segala puji bagi Allah sebanyak-banyaknya) sebanyak tiga kali, SUBHAANAALLAHI BUKRATAU WA ASHIILA (Maha suci Allah diwaktu pagi dan petang) sebanyak tiga kali, ALLAHUMMA INNI A'UDZU BIKA MINASY SYAITHANIR RAJIIM MIN HAMZIHI WA NAFKHIHI WA NAFTSIHI (Ya Allah sesungguhnya aku berlindung kepada-Mu dari setan yang terkutuk; dari goda, tiupan dan hembusannya).\" 'Amru berkata; \"Godaannya adalah kebimbangan, tiupannya adalah sya'ir dan hembusannya adalah kesombongan.\""},"768":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ الْمُنْذِرِ حَدَّثَنَا ابْنُ فُضَيْلٍ حَدَّثَنَا عَطَاءُ بْنُ السَّائِبِ عَنْ أَبِي عَبْدِ الرَّحْمَنِ السُّلَمِيِّ عَنْ ابْنِ مَسْعُودٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الشَّيْطَانِ الرَّجِيمِ وَهَمْزِهِ وَنَفْخِهِ وَنَفْثِهِ قَالَ هَمْزُهُ الْمُوتَةُ وَنَفْثُهُ الشِّعْرُ وَنَفْخُهُ الْكِبْرُ","id":"Telah menceritakan kepada kami [Ali Ibnul Mundzir] berkata, telah menceritakan kepada kami [ibnu Fudlail] berkata, telah menceritakan kepada kami ['Atho` bin As Sa`ib] dari [Abu Abdurrahman As Sulami] dari [Ibnu Mas'ud], dari Nabi shallallahu 'alaihi wasallam, beliau mengucapkan: \"ALLAHUMMA INNI A'UDZU BIKA MINASY SYAITHANIR RAJIIM WA HAMZIHI WA NAFKHIHI WA NAFTSIHI (Ya Allah sesungguhnya aku berlindung kepada-Mu dari setan yang terkutuk; dari goda, tiupan dan hembusannya).\" dia menjelaskan; \"Godaannya adalah kebimbangan, tiupannya adalah sya'ir dan hembusannya adalah kesombongan.\""},"769":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ قَبِيصَةَ بْنِ هُلْبٍ عَنْ أَبِيهِ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَؤُمُّنَا فَيَأْخُذُ شِمَالَهُ بِيَمِينِهِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abul Ahwash] dari [Simak bin Harb] dari [Qabishah bin Hulb] dari [Bapaknya] ia berkata; \"Nabi shallallahu 'alaihi wasallam mengimami kami, beliau memegang tangan kirinya dengan tangan kanannya. \""},"770":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ ح و حَدَّثَنَا بِشْرُ بْنُ مُعَاذٍ الضَّرِيرُ حَدَّثَنَا بِشْرُ بْنُ الْمَفَضَّلِ قَالَا حَدَّثَنَا عَاصِمُ بْنُ كُلَيْبٍ عَنْ أَبِيهِ عَنْ وَائِلِ بْنِ حُجْرٍ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فَأَخَذَ شِمَالَهُ بِيَمِينِهِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Abdullah bin Idris]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Busyr bin Mu'adz Adl Dlarir] berkata, telah menceritakan kepada kami [Bisyr Ibnul Mufadldlal] keduanya berkata; telah menceritakan kepada kami ['Ashim bin Kulaib] dari [Bapaknya] dari [Wa`il bin Hujr] ia berkata; \"Aku melihat Nabi shallallahu 'alaihi wasallam shalat, tangan kanannya menggenggam tangan kiri.\""},"771":{"ar":"حَدَّثَنَا أَبُو إِسْحَقَ الْهَرَوِيُّ إِبْرَاهِيمُ بْنُ عَبْدِ اللَّهِ بْنِ حَاتِمٍ أَنْبَأَنَا هُشَيْمٌ أَنْبَأَنَا الْحَجَّاجُ بْنُ أَبِي زَيْنَبَ السُّلَمِيُّ عَنْ أَبِي عُثْمَانَ النَّهْدِيِّ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَمَرَّ بِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا وَاضِعٌ يَدِي الْيُسْرَى عَلَى الْيُمْنَى فَأَخَذَ بِيَدِي الْيُمْنَى فَوَضَعَهَا عَلَى الْيُسْرَى","id":"Telah menceritakan kepada kami [Abu Ishaq Al Harawi Ibrahim bin Abdullah bin Hatim] berkata, telah memberitakan kepada kami [Husyaim] berkata, telah memberitakan kepada kami [Al Hajjaj bin Abu Zainab As Sulami] dari [Abu Utsman An Nahdi] dari [Abdullah bin Mas'ud] ia berkata, \"Nabi shallallahu 'alaihi wasallam melewatiku, sementara aku meletakkan tangan kiri di atas tangan kananku (dalam shalat), maka beliau meraih tangan kananku dan meletakkannya di atas tangan kiriku.\""},"772":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ حُسَيْنٍ الْمُعَلِّمِ عَنْ بُدَيْلِ بْنِ مَيْسَرَةَ عَنْ أَبِي الْجَوْزَاءِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَفْتَتِحُ الْقِرَاءَةَ بِ{ الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ }","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yazid bin Harun] dari [Husain Al Muallim] dari [Budail bin Maisarah] dari [Abu Al Jauza`] dari [Aisyah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam memulai bacaannya dengan; ALHAMDULILLAHI RABBIL 'ALAMIIN (segala puji bagi Allah, Rabb semesta alam).\""},"773":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا سُفْيَانُ عَنْ أَيُّوبَ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ ح و حَدَّثَنَا جُبَارَةُ بْنُ الْمُغَلِّسِ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ وَعُمَرُ يَفْتَتِحُونَ الْقِرَاءَةَ بِ{ الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ }","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah memberitakan kepada kami [Sufyan] dari [Ayyub] dari [Qatadah] dari [Anas bin Malik]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Jubarah Ibnul Mughallis] berkata, telah menceritakan kepada kami [Abu Awanah] dari [Qatadah] dari [Anas bin Malik] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam, Abu Bakar dan Umar membuka bacaannya dengan; ALHAMDULILLAHI RABBIL 'ALAMIIN (segala puji bagi Allah, Rabb semesta alam). \""},"774":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ وَبَكْرُ بْنُ خَلَفٍ وَعُقْبَةُ بْنُ مُكْرَمٍ قَالُوا حَدَّثَنَا صَفْوَانُ بْنُ عِيسَى حَدَّثَنَا بِشْرُ بْنُ رَافِعٍ عَنْ أَبِي عَبْدِ اللَّهِ ابْنِ عَمِّ أَبِي هُرَيْرَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَفْتَتِحُ الْقِرَاءَةَ بِ{ الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ }","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] dan [Bakr bin Khalaf] dan [Uqbah bin Mukram] mereka berkata; telah menceritakan kepada kami [Shafwan bin Isa] berkata, telah menceritakan kepada kami [Bisyr bin Rafi'] dari [Abu Abdullah] keponakan Abu Hurairah, dari [Abu Hurairah] berkata; \"Nabi shallallahu 'alaihi wasallam membuka bacaannya dengan; ALHAMDULILLAHI RABBIL 'ALAMIIN (segala puji bagi Allah, Rabb semesta alam). \""},"775":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ الْجُرَيْرِيِّ عَنْ قَيْسِ بْنِ عَبَايَةَ حَدَّثَنِي ابْنُ عَبْدِ اللَّهِ بْنِ الْمُغَفَّلِ عَنْ أَبِيهِ قَالَ وَقَلَّمَا رَأَيْتُ رَجُلًا أَشَدَّ عَلَيْهِ فِي الْإِسْلَامِ حَدَثًا مِنْهُفَسَمِعَنِي وَأَنَا أَقْرَأُ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ فَقَالَ أَيْ بُنَيَّ إِيَّاكَ وَالْحَدَثَ فَإِنِّي صَلَّيْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَ أَبِي بَكْرٍ وَمَعَ عُمَرَ وَمَعَ عُثْمَانَ فَلَمْ أَسْمَعْ رَجُلًا مِنْهُمْ يَقُولُهُ فَإِذَا قَرَأْتَ فَقُلْ{ الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ }","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Isma'il bin Ulayyah] dari [Al Jurairi] dari [Qais bin Abayah] berkata, telah menceritakan kepadaku [Ibnu Abdullah Ibnul Mughaffal] dari [Bapaknya] ia berkata; \"Jarang sekali aku melihat seseorang yang lebih peka terhadap perkara baru yang muncul dalam agama Islam selain dia. Suatu ketika ia mendengar tatkala aku sedang membaca; BISMILAAHIR RAHMAANIR RAHIIM (Dengan menyebut nama Allah Yang Maha Pemurah lagi Maha Pengasih), maka ia pun berkata kepadaku, \"Wahai anakku, jauhilah perkara baru! Aku pernah shalat bersama Rasulullah shallallahu 'alaihi wasallam, Abu Bakar, Umar dan Utsman. Namun aku tidak pernah melihat seorang pun dari mereka yang mengucapkan itu, jika engkau membaca maka bacalah; ALHAMDULILLAHI RABBIL 'ALAMIIN (segala puji bagi Allah, Rabb semesta alam). \""},"776":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا شَرِيكٌ وَسُفْيَانُ بْنُ عُيَيْنَةَ عَنْ زِيَادِ بْنِ عِلَاقَةَ عَنْ قُطْبَةَ بْنِ مَالِكٍسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الصُّبْحِ وَالنَّخْلَ بَاسِقَاتٍ لَهَا طَلْعٌ نَضِيدٌ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Syarik] dan [Sufyan bin Uyainah] dari [Ziyad bin Ilaqah] dari [Qutaibah bin Malik] ia mendengar Nabi shallallahu 'alaihi wasallam dalam shalat subuh membaca; \" (dan pohon kurma yang tinggi-tinggi yang mempunyai mayang yang bersusun-susun). \""},"777":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ عَنْ أَصْبَغَ مَوْلَى عَمْرِو بْنِ حُرَيْثٍ عَنْ عَمْرِو بْنِ حُرَيْثٍ قَالَصَلَّيْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَانَ يَقْرَأُ فِي الْفَجْرِ كَأَنِّي أَسْمَعُ قِرَاءَتَهُ فَلَا أُقْسِمُ بِالْخُنَّسِ الْجَوَارِ الْكُنَّسِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] berkata, telah menceritakan kepada kami [Bapakku] berkata, telah menceritakan kepada kami [Isma'il bin Abu Khalid] dari [Ashbagh] mantan budak Amru bin Huraits, dari [Amru bin Huraits] ia berkata; \"Aku pernah shalat bersama Nabi shallallahu 'alaihi wasallam, dalam shalat subuh seakan aku mendengar beliau membaca; (Sungguh, Aku bersumpah dengan bintang-bintang yang beredar dan terbenam). \""},"778":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ حَدَّثَنَا عَبَّادُ بْنُ الْعَوَّامِ عَنْ عَوْفٍ عَنْ أَبِي الْمِنْهَالِ عَنْ أَبِي بَرْزَةَ ح و حَدَّثَنَا سُوَيْدٌ حَدَّثَنَا مُعْتَمِرُ بْنُ سُلَيْمَانَ عَنْ أَبِيهِ حَدَّثَهُ أَبُو الْمِنْهَالِ عَنْ أَبِي بَرْزَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ فِي الْفَجْرِ مَا بَيْنَ السِّتِّينَ إِلَى الْمِائَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah menceritakan kepada kami [Abbad bin Al Awwam] dari [Auf] dari [Abu Al Minhal] dari [Abu Barzah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Suwaid] berkata, telah menceritakan kepada kami [Mu'tamir bin Sulaiman] dari [Bapaknya] bahwa [Abu Al Minhal] menceritakan kepadanya dari [Abu Barzah] berkata, \"Dalam shalat subuh Rasulullah shallallahu 'alaihi wasallam membaca antara enam puluh hingga seratus ayat. \""},"779":{"ar":"حَدَّثَنَا أَبُو بِشْرٍ بَكْرُ بْنُ خَلَفٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ حَجَّاجٍ الصَّوَّافِ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ وَعَنْ أَبِي سَلَمَةَ عَنْ أَبِي قَتَادَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي بِنَا فَيُطِيلُ فِي الرَّكْعَةِ الْأُولَى مِنْ الظُّهْرِ وَيُقْصِرُ فِي الثَّانِيَةِ وَكَذَلِكَ فِي الصُّبْحِ","id":"Telah menceritakan kepada kami [Abu Bisyr Bakr bin Khalaf] berkata, telah menceritakan kepada kami [Ibnu Abu Adi] dari [Hajjaj Ash Shawwaf] dari [Yahya bin Abu Katsir] dari [Abdullah bin Abu Qatadah] dan dari [Abu Salamah] dari [Abu Qatadah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam shalat bersama kami. Dalam shalat zhuhur beliau memperpanjang raka'at pertama dan mempersingkat pada raka'at kedua. Hal itu beliau lakukan juga dalam shalat subuh. \""},"780":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ ابْنِ جُرَيْجٍ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ عَبْدِ اللَّهِ بْنِ السَّائِبِ قَالَقَرَأَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي صَلَاةِ الصُّبْحِ بِالْمُؤْمِنُونَ فَلَمَّا أَتَى عَلَى ذِكْرِ عِيسَى أَصَابَتْهُ شَرْقَةٌ فَرَكَعَ يَعْنِي سَعْلَةً","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Ibnu Juraij] dari [Ibnu Abu Mulaikah] dari [Abdullah bin As Sa`ib] ia berkata; \"Dalam shalat subuh Nabi shallallahu 'alaihi wasallam membaca surat Al Mukminun, ketika sampai pada ayat yang membicarakan Isa beliau terserang batuk hingga beliau pun rukuk. \""},"781":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ خَلَّادٍ الْبَاهِلِيُّ حَدَّثَنَا وَكِيعٌ وَعَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ مُخَوَّلٍ عَنْ مُسْلِمٍ الْبَطِينِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي صَلَاةِ الصُّبْحِ يَوْمَ الْجُمُعَةِ الم تَنْزِيلُ السَّجْدَةَ وَهَلْ أَتَى عَلَى الْإِنْسَانِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Khallad Al Bahili] berkata, telah menceritakan kepada kami [Waki'] dan ['Abdurrahman bin Mahdi] keduanya berkata; telah menceritakan kepada kami [Sufyan] dari [Mukhawwal] dari [Muslim Al Bathin] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata; \"Pada hari jum'at dalam shalat subuh beliau membaca ALIIF LAAM MIIM TANZIIL surat As Sajadah dan HAL ATA 'ALAL INSAN. \""},"782":{"ar":"حَدَّثَنَا أَزْهَرُ بْنُ مَرْوَانَ حَدَّثَنَا الْحَارِثُ بْنُ نَبْهَانَ حَدَّثَنَا عَاصِمُ بْنُ بَهْدَلَةَ عَنْ مُصْعَبِ بْنِ سَعْدٍ عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي صَلَاةِ الْفَجْرِ يَوْمَ الْجُمُعَةِ الم تَنْزِيلُ وَهَلْ أَتَى عَلَى الْإِنْسَانِ","id":"Telah menceritakan kepada kami [Azhar bin Marwan] berkata, telah menceritakan kepada kami [Al Harits bin Nabhan] berkata, telah menceritakan kepada kami ['Ashim bin Bahdalah] dari [Mush'ab bin Sa'd] dari [Bapaknya] ia berkata, \"Dalam shalat subuh di hari Jum'at, Rasulullah shallallahu 'alaihi wasallam membaca ALIIF LAAM MIIM TANZIIL dan HAL ATA 'ALAL INSAN. \""},"783":{"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ أَبِيهِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ فِي صَلَاةِ الصُّبْحِ يَوْمَ الْجُمُعَةِ الم تَنْزِيلُ وَهَلْ أَتَى عَلَى الْإِنْسَانِ","id":"Telah menceritakan kepada kami [Harmalah bin Yahya] berkata, telah menceritakan kepada kami [Abdullah bin Wahb] berkata, telah mengabarkan kepadaku [Ibrahim bin Sa'd] dari [Bapaknya] dari [Al A'raj] dari [Abu Hurairah] berkata; \"Rasulullah shallallahu 'alaihi wasallam membaca ALIIF LAAM MIIM TANZIIL dan HAL ATA 'ALAL INSAN dalam shalat subuh di hari jum'at. \""},"784":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَنْبَأَنَا إِسْحَقُ بْنُ سُلَيْمَانَ أَنْبَأَنَا عَمْرُو بْنُ أَبِي قَيْسٍ عَنْ أَبِي فَرْوَةَ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ فِي صَلَاةِ الصُّبْحِ يَوْمَ الْجُمُعَةِ الم تَنْزِيلُ وَهَلْ أَتَى عَلَى الْإِنْسَانِقَالَ إِسْحَقُ بْنُ سُلَيْمَانَ هَكَذَا حَدَّثَنَا عَمْرٌو عَنْ عَبْدِ اللَّهِ لَا أَشُكُّ فِيهِ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] berkata, telah memberitakan kepada kami [Ishaq bin Sulaiman] berkata, telah memberitakan kepada kami [Amru bin Abu Qais] dari [Abu Farwah] dari [Abul Ahwash] dari [Abdullah bin Mas'ud] berkata, \"Dalam shalat fajar di hari Jum'at, Rasulullah shallallahu 'alaihi wasallam membaca ALIIF LAAM MIIM TANZIIL dan HAL ATA 'ALAL INSAN. \""},"785":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ حَدَّثَنَا مُعَاوِيَةُ بْنُ صَالِحٍ حَدَّثَنَا رَبِيعَةُ بْنُ يَزِيدَ عَنْ قَزَعَةَ قَالَسَأَلْتُ أَبَا سَعِيدٍ الْخُدْرِيَّ عَنْ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَيْسَ لَكَ فِي ذَلِكَ خَيْرٌ قُلْتُ بَيِّنْ رَحِمَكَ اللَّهُ قَالَ كَانَتْ الصَّلَاةُ تُقَامُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الظُّهْرَ فَيَخْرُجُ أَحَدُنَا إِلَى الْبَقِيعِ فَيَقْضِي حَاجَتَهُ فَيَجِيءُ فَيَتَوَضَّأُ فَيَجِدُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الرَّكْعَةِ الْأُولَى مِنْ الظُّهْرِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Zaid Ibnul Hubab] berkata, telah menceritakan kepada kami [Mu'awiyah bin Shalih] berkata, telah menceritakan kepada kami [Rabi'ah bin Yazid] dari [Qaza'ah] ia berkata; \"Aku bertanya kepada [Abu Sa'id Al khudzri] tentang shalat Rasulullah shallallahu 'alaihi wasallam, lalu ia menjawab, \"Tidak ada kebaikannya bagimu mengetahui hal itu, \" aku berkata; \"Jelaskanlah, semoga Allah merahmatimu. \" Ia berkata; \"Shalat zhuhur didirikan ketika Rasulullah shallallahu 'alaihi wasallam datang, lalu salah seorang dari kami keluar menuju Baqi' untuk buang hajat, setelah itu ia datang dan berwudlu, namun ia masih mendapati Rasulullah shallallahu 'alaihi wasallam pada raka'at pertama dalam shalat zhuhur. \""},"786":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ عَنْ عُمَارَةَ بْنِ عُمَيْرٍ عَنْ أَبِي مَعْمَرٍ قَالَقُلْنَا لِخَبَّابٍ بِأَيِّ شَيْءٍ كُنْتُمْ تَعْرِفُونَ قِرَاءَةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الظُّهْرِ وَالْعَصْرِ قَالَ بِاضْطِرَابِ لِحْيَتِهِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Al A'masy] dari [Umarah bin Umair] dari [Abu Ma'mar] ia berkata; \"Kami bertanya kepada [Khabbab], \"Dari mana kalian mengetahui bacaan Rasulullah shallallahu 'alaihi wasallam dalam shalat zhuhur dan ashar?\" ia menjawab, \"Dari gerakan jenggot beliau. \""},"787":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو بَكْرٍ الْحَنَفِيُّ حَدَّثَنَا الضَّحَّاكُ بْنُ عُثْمَانَ حَدَّثَنِي بُكَيْرُ بْنُ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَ قَالَمَا رَأَيْتُ أَحَدًا أَشْبَهَ صَلَاةً بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ فُلَانٍ قَالَ وَكَانَ يُطِيلُ الْأُولَيَيْنِ مِنْ الظُّهْرِ وَيُخَفِّفُ الْأُخْرَيَيْنِ وَيُخَفِّفُ الْعَصْرَ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Abu Bakr Al Hanafi] berkata, telah menceritakan kepada kami [Adl Dlahhak bin Utsman] berkata, telah menceritakan kepadaku [Bukair bin Ubaidullah bin Al Asyaj] dari [Sulaiman bin Yashar] dari [Abu Hurairah] ia berkata; \"Aku tidak pernah melihat seseorang yang shalatnya mirip Rasulullah shallallahu 'alaihi wasallam selain si fulan. \" Abu Hurairah berkata, \"Dalam shalat zhuhur ia memanjangkan dua raka'at pertama dan meringankan dua raka'at terakhir, dan ia juga meringankan shalat ashar. \""},"788":{"ar":"حَدَّثَنَا يَحْيَى بْنُ حَكِيمٍ حَدَّثَنَا أَبُو دَاوُدَ الطَّيَالِسِيُّ حَدَّثَنَا الْمَسْعُودِيُّ حَدَّثَنَا زَيْدٌ الْعَمِّيُّ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَاجْتَمَعَ ثَلَاثُونَ بَدْرِيًّا مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا تَعَالَوْا حَتَّى نَقِيسَ قِرَاءَةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيمَا لَمْ يَجْهَرْ فِيهِ مِنْ الصَّلَاةِ فَمَا اخْتَلَفَ مِنْهُمْ رَجُلَانِ فَقَاسُوا قِرَاءَتَهُ فِي الرَّكْعَةِ الْأُولَى مِنْ الظُّهْرِ بِقَدْرِ ثَلَاثِينَ آيَةً وَفِي الرَّكْعَةِ الْأُخْرَى قَدْرَ النِّصْفِ مِنْ ذَلِكَ وَقَاسُوا ذَلِكَ فِي صَلَاةِ الْعَصْرِ عَلَى قَدْرِ النِّصْفِ مِنْ الرَّكْعَتَيْنِ الْأُخْرَيَيْنِ مِنْ الظُّهْرِ","id":"Telah menceritakan kepada kami [Yahya bin Hakim] berkata, telah menceritakan kepada kami [Abu Dawud Ath Thayalisi] berkata, telah menceritakan kepada kami [Al Mas'udi] berkata, telah menceritakan kepada kami [Zaid Al Ammi] dari [Abu Nadlrah] dari [Abu Sa'id Al Khudzri] ia berkata, \"Tiga puluh orang sahabat Rasulullah shallallahu 'alaihi wasallam yang pernah ikut perang badar berkumpul, mereka berkata; \"Kemarilah berkumpul hingga kita bisa diskusi berapa panjang bacaan Rasulullah shallallahu 'alaihi wasallam dalam shalat yang bacaannya tidak dikeraskan. \" Tidak ada dua orang pun dari mereka yang saling berselisih, lalu mereka membandingkan bahwa bacaan beliau di raka'at pertama dari shalat zhuhur sekitar tiga puluh ayat, sedangkan dalam raka'at yang lainnya hanya separuhnya. Kemudian mereka membandingkan dengan shalat ashar, bahwa panjangnya adalah separuh dari bacaan dua raka'at terakhir shalat zhuhur. \""},"789":{"ar":"حَدَّثَنَا بِشْرُ بْنُ هِلَالٍ الصَّوَّافُ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا هِشَامٌ الدَّسْتُوَائِيُّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ بِنَا فِي الرَّكْعَتَيْنِ الْأُولَيَيْنِ مِنْ صَلَاةِ الظُّهْرِ وَيُسْمِعُنَا الْآيَةَ أَحْيَانًا","id":"Telah menceritakan kepada kami [Bisyr bin Hilal Ash Shawwaf] berkata, telah menceritakan kepada kami [Yazid bin Zurai'] berkata, telah menceritakan kepada kami [Hisyam bin Ad Dastuwa`i] dari [Yahya bin Abu Katisr] dari [Abdullah bin Abu Qatadah] dari [Bapaknya] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam mengimami kami dan membaca surat di dua raka'at pertama dari shalat zhuhur. Dan terkadang beliau memperdengarkan bacaannya kepada kami. \""},"790":{"ar":"حَدَّثَنَا عُقْبَةُ بْنُ مُكْرَمٍ حَدَّثَنَا سَلْمُ بْنُ قُتَيْبَةَ عَنْ هَاشِمِ بْنِ الْبَرِيدِ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي بِنَا الظُّهْرَ فَنَسْمَعُ مِنْهُ الْآيَةَ بَعْدَ الْآيَاتِ مِنْ سُورَةِ لُقْمَانَ وَالذَّارِيَاتِ","id":"Telah menceritakan kepada kami [Uqbah bin Mukram] berkata, telah menceritakan kepada kami [Salm bin Qutaibah] dari [Hasyim bin Al Barid] dari [Abu Ishaq] dari [Al Barra` bin Azib] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam shalat zhuhur bersama kami, lalu kami mendengar beliau membaca surat Luqman dan Adz Dzariyat ayat demi ayat. \" "},"791":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَهِشَامُ بْنُ عَمَّارٍ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ عَنْ أُمِّهِ قَالَ أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ هِيَ لُبَابَةُ أَنَّهَاسَمِعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الْمَغْرِبِ بِ وَالْمُرْسَلَاتِ عُرْفًا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Hisyam bin Ammar] keduanya berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Ubaidullah bin Abdullah] dari [Ibnu Abbas] dari [Ibunya] -Abu Bakr bin Abu Syaibah mengatakan bahwa ia adalah Lubabah- bahwasanya ia pernah mendengar Rasulullah shallallahu 'alaihi wasallam dalam shalat maghrib membaca WAL MURSALAATI 'URFA. \""},"792":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ مُحَمَّدِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ أَبِيهِ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الْمَغْرِبِ بِالطُّورِقَالَ جُبَيْرٌ فِي غَيْرِ هَذَا الْحَدِيثِ فَلَمَّا سَمِعْتُهُ يَقْرَأُ{ أَمْ خُلِقُوا مِنْ غَيْرِ شَيْءٍ أَمْ هُمْ الْخَالِقُونَ إِلَى قَوْلِهِ فَلْيَأْتِ مُسْتَمِعُهُمْ بِسُلْطَانٍ مُبِينٍ }كَادَ قَلْبِي يَطِيرُ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah memberitakan kepada kami [Sufyan] dari [Az Zuhri] dari [Muhammad bin Jubair bin Muth'im] dari [Bapaknya] ia berkata; \"Aku mendengar Nabi shallallahu 'alaihi wasallam dalam shalat maghrib membaca surat Ath Thuur. \" Di selain hadits ini Jubair menyebutkan, \"Ketika aku mendengar beliau membaca; AM KHULIQUU MIN GHAIRI SYA`IN AM HUMUL KHAALIQUUN (Apakah mereka diciptakan tanpa sesuatupun ataukah mereka yang menciptakan (diri mereka sendiri)? Hingga ayat; FALYA`TI MUSTAMI'UHUM BISULTHAANIM MUBIIN (Ataukah mereka mempunyai tangga (ke langit) untuk mendengarkan pada tangga itu (hal-hal yang gaib)? Maka hendaklah orang yang mendengarkan di antara mereka mendatangkan suatu keterangan yang nyata), seakan hatiku terbang. \""},"793":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ بُدَيْلٍ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الْمَغْرِبِ قُلْ يَا أَيُّهَا الْكَافِرُونَ وَقُلْ هُوَ اللَّهُ أَحَدٌ","id":"Telah menceritakan kepada kami [Ahmad bin Budail] berkata, telah menceritakan kepada kami [Hafsh bin Ghiyats] berkata, telah menceritakan kepada kami [Ubaidullah] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Dalam shalat maghrib Nabi shallallahu 'alaihi wasallam selalu membaca; \"QUL YAA AYYUHAA AL KAAFIRUUNA (Katakanlah: \"Hai orang-orang kafir), dan QUL HUWA ALLAHU AHAD (Katakanlah: \"Dia-lah Allah, Yang Maha Esa). \""},"794":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا سُفْيَانُ بْنُ عُيَيْنَةَ ح و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَامِرِ بْنِ زُرَارَةَ حَدَّثَنَا يَحْيَى بْنُ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ جَمِيعًا عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ الْبَرَاءِ بْنِ عَازِبٍأَنَّهُ صَلَّى مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعِشَاءَ الْآخِرَةَ قَالَ فَسَمِعْتُهُ يَقْرَأُ بِالتِّينِ وَالزَّيْتُونِحَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا سُفْيَانُ ح و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَامِرِ بْنِ زُرَارَةَ حَدَّثَنَا ابْنُ أَبِي زَائِدَةَ جَمِيعًا عَنْ مِسْعَرٍ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ الْبَرَاءِ مِثْلَهُ قَالَ فَمَا سَمِعْتُ إِنْسَانًا أَحْسَنَ صَوْتًا أَوْ قِرَاءَةً مِنْهُ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah memberitakan kepada kami [Sufyan bin Uyainah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abdullah bin Amir bin Zurarah] berkata, telah menceritakan kepada kami [Yahya bin Zakaria bin Abu Za`idah] semuanya dari [Yahya bin Sa'id] dari [Adi bin Tsabit] dari [Al Barra` bin Azib] Bahwasanya ia pernah shalat isya yang akhir bersama Nabi shallallahu 'alaihi wasallam, ia berkata, \"Aku mendengar beliau membaca; WATTIINI WAZZAITUUN (Demi (buah) Tin dan (buah) Zaitun). \" Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah memberitakan kepada kami [Sufyan]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abdullah bin Amir bin Zurarah] berkata, telah menceritakan kepada kami [Ibnu Abu Za`idah] semuanya dari [Mis'ar] dari [Adi bin Tsabit] dari [Al Barra`] seperti itu. Ia berkata; \"Aku tidak pernah mendengar seseorang yang suaranya lebih bagus dari dia, \" atau ia menyebutkan; \"lebih bagus bacaannya daripada dia. \""},"795":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍأَنَّ مُعَاذَ بْنَ جَبَلٍ صَلَّى بِأَصْحَابِهِ الْعِشَاءَ فَطَوَّلَ عَلَيْهِمْ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَأْ بِالشَّمْسِ وَضُحَاهَا وَسَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى وَاللَّيْلِ إِذَا يَغْشَى وَاقْرَأْ بِاسْمِ رَبِّكَ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Abu Az Zubair] dari [Jabir] berkata; \"Mu'adz bin Jabal shalat isya bersama para sahabatnya dengan memanjangkan bacaannya. Maka Nabi shallallahu 'alaihi wasallam bersabda kepadanya: \"Bacalah WASY SYAMSI WA DLUHAHA (Demi matahari dan cahayanya di pagi hari), SABBIHISMA RABBIKAL A'LA (Sucikanlah nama Tuhanmu Yang Maha Tinggi) dan WAL LAILI IDZA YAGHSYA (Demi malam apabila menutupi (cahaya siang)). Dan bacalah BISMI RABBIKA (Bacalah dengan (menyebut) nama Tuhanmu). \""},"796":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ وَسَهْلُ بْنُ أَبِي سَهْلٍ وَإِسْحَقُ بْنُ إِسْمَعِيلَ قَالُوا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ مَحْمُودِ بْنِ الرَّبِيعِ عَنْ عُبَادَةَ بْنِ الصَّامِتِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا صَلَاةَ لِمَنْ لَمْ يَقْرَأْ فِيهَا بِفَاتِحَةِ الْكِتَابِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] dan [Sahl bin Abu Sahl] dan [Ishaq bin Ismail] mereka berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Mahmud bin Ar Rabi'] dari [Ubadah bin Ash Shamit] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak ada shalat bagi orang yang tidak membaca di dalamnya Fatihatul Kitab (Al Fatihah). \""},"797":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ ابْنِ جُرَيْجٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ يَعْقُوبَ أَنَّ أَبَا السَّائِبِ أَخْبَرَهُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَلَّى صَلَاةً لَمْ يَقْرَأْ فِيهَا بِأُمِّ الْقُرْآنِ فَهِيَ خِدَاجٌ غَيْرُ تَمَامٍفَقُلْتُ يَا أَبَا هُرَيْرَةَ فَإِنِّي أَكُونُ أَحْيَانًا وَرَاءَ الْإِمَامِ فَغَمَزَ ذِرَاعِي وَقَالَ يَا فَارِسِيُّ اقْرَأْ بِهَا فِي نَفْسِكَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Isma'il bin Ulayyah] dari [Ibnu Juraij] dari [Al 'Ala` bin 'Abdurrahman bin Ya'qub] bahwa [Abu As Sa`ib] mengabarkan kepadanya, bahwa ia mendengar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa melaksanakan shalat dan tidak membaca Ummul Qur`an di dalamnya maka ia kurang dan tidak sempurna. \" Aku bertanya, \"Wahai Abu Hurairah, terkadang aku di belakang imam, \" lalu ia mencubit lenganku seraya berkata; \"Wahai orang Persia, bacalah di dalam hatimu. \""},"798":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا مُحَمَّدُ بْنُ الْفُضَيْلِ ح و حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ جَمِيعًا عَنْ أَبِي سُفْيَانَ السَّعْدِيِّ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا صَلَاةَ لِمَنْ لَمْ يَقْرَأْ فِي كُلِّ رَكْعَةٍ بِالْحَمْدُ لِلَّهِ وَسُورَةٍ فِي فَرِيضَةٍ أَوْ غَيْرِهَا","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Muhammad bin Al Fudlail]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Suwaid bin Sa'id] berkata, telah menceritakan kepada kami [Ali bin Mushir] semuanya dari [Abu Sufyan As Sa'di] dari [Abu Nadlrah] dari [Abu Sa'id] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada shalat bagi orang yang tidak membaca AL HAMDULILLAH (Al Fatihah) dan surat dalam setiap raka'at, baik shalat fardlu atau yang lainnya. \""},"799":{"ar":"حَدَّثَنَا الْفَضْلُ بْنُ يَعْقُوبَ الْجَزَرِيُّ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ يَحْيَى بْنِ عَبَّادِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ كُلُّ صَلَاةٍ لَا يُقْرَأُ فِيهَا بِأُمِّ الْكِتَابِ فَهِيَ خِدَاجٌ","id":"Telah menceritakan kepada kami [Al Fadll bin Ya`qub Al Jazari] berkata, telah menceritakan kepada kami [Abdul A'la] dari [Muhammad bin Ishaq] dari [Yahya bin Abbad bin Abdullah bin Az Zubair] dari [bapaknya] dari [Aisyah] ia berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap shalat yang tidak dibacakan di dalamnya Ummul Kitab (Al Fatihah) maka ia kurang. \""},"800":{"ar":"حَدَّثَنَا الْوَلِيدُ بْنُ عَمْرِو بْنِ السُّكَيْنِ حَدَّثَنَا يُوسُفُ بْنُ يَعْقُوبَ السَّلْعِيُّ حَدَّثَنَا حُسَيْنٌ الْمُعَلِّمُ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُلُّ صَلَاةٍ لَا يُقْرَأُ فِيهَا بِفَاتِحَةِ الْكِتَابِ فَهِيَ خِدَاجٌ فَهِيَ خِدَاجٌ","id":"Telah menceritakan kepada kami [Al Walid bin Amru bin Sukain] berkata, telah menceritakan kepada kami [Yusuf bin Ya'qub As Sal'i] berkata, telah menceritakan kepada kami [Husain Al Mu'allim] dari [Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap shalat yang tidak dibacakan di dalamnya Fatihatul Kitab (Al Fatihah), maka shalatnya kurang, maka shalatnya sempurna. \""},"801":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا إِسْحَقُ بْنُ سُلَيْمَانَ حَدَّثَنَا مُعَاوِيَةُ بْنُ يَحْيَى عَنْ يُونُسَ بْنِ مَيْسَرَةَ عَنْ أَبِي إِدْرِيسَ الْخَوْلَانِيِّ عَنْ أَبِي الدَّرْدَاءِ قَالَسَأَلَهُ رَجُلٌ فَقَالَ أَقْرَأُ وَالْإِمَامُ يَقْرَأُ فَقَالَ سَأَلَ رَجُلٌ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفِي كُلِّ صَلَاةٍ قِرَاءَةٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعَمْ فَقَالَ رَجُلٌ مِنْ الْقَوْمِ وَجَبَ هَذَا","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Ishaq bin Sulaiman] berkata, telah menceritakan kepada kami [Mu'awiyah bin Yahya] dari [Yunus bin Maisarah] dari [Abu Idris Al Khaulani] dari [Abu Darda`] ia berkata; \"Seorang laki-laki bertanya kepadanya, ia berkata; \"Aku membaca ketika imam membaca, \" Abu Darda` menjawab, \"Seorang laki-laki bertanya kepada Nabi shallallahu 'alaihi wasallam; apakah pada setiap shalat ada bacaannya?\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Ya, \" lalu berkatalah seorang laki-laki dari mereka, \"Perkara ini telah wajib. \""},"802":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا سَعِيدُ بْنُ عَامِرٍ حَدَّثَنَا شُعْبَةُ عَنْ مِسْعَرٍ عَنْ يَزِيدَ الْفَقِيرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكُنَّا نَقْرَأُ فِي الظُّهْرِ وَالْعَصْرِ خَلْفَ الْإِمَامِ فِي الرَّكْعَتَيْنِ الْأُولَيَيْنِ بِفَاتِحَةِ الْكِتَابِ وَسُورَةٍ وَفِي الْأُخْرَيَيْنِ بِفَاتِحَةِ الْكِتَابِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Sa'id bin Amir] berkata, telah menceritakan kepada kami [Syu'bah] dari [Mis'ar] dari [Yazid Al Fuqiri] dari [Jabir bin Abdullah] ia berkata, \"Dalam shalat zhuhur dan ashar kami selalu membaca Fatihatul Kitab (Al Fatihah) di belakang imam. Di dua raka'at pertama membaca Fatihatul Kitab dan satu surat. Sementara di dua raka'at terakhir hanya dengan Fatihatul Kitab. \" "},"803":{"ar":"حَدَّثَنَا جَمِيلُ بْنُ الْحَسَنِ بْنِ جَمِيلٍ الْعَتَكِيُّ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَ بْنِ جُنْدَبٍ قَالَسَكْتَتَانِ حَفِظْتُهُمَا عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَفَأَنْكَرَ ذَلِكَ عِمْرَانُ بْنُ الْحُصَيْنِ فَكَتَبْنَا إِلَى أُبَيِّ بْنِ كَعْبٍ بِالْمَدِينَةِ فَكَتَبَ أَنَّ سَمُرَةَ قَدْ حَفِظَ قَالَ سَعِيدٌ فَقُلْنَا لِقَتَادَةَ مَا هَاتَانِ السَّكْتَتَانِ قَالَ إِذَا دَخَلَ فِي صَلَاتِهِ وَإِذَا فَرَغَ مِنْ الْقِرَاءَةِ ثُمَّ قَالَ بَعْدُ وَإِذَا قَرَأَ{ غَيْرِ الْمَغْضُوبِ عَلَيْهِمْ وَلَا الضَّالِّينَ }قَالَ وَكَانَ يُعْجِبُهُمْ إِذَا فَرَغَ مِنْ الْقِرَاءَةِ أَنْ يَسْكُتَ حَتَّى يَتَرَادَّ إِلَيْهِ نَفَسُهُ","id":"Telah menceritakan kepada kami [Jamil Ibnul Husain bin Jamil Al 'Ataki] berkata, telah menceritakan kepada kami [Abdul A'la] berkata, telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Al Hasan] dari [Samurah bin Jundub] ia berkata, \"Ada dua saktah (jeda tidak membaca bacaan) yang aku hafal dari Rasulullah shallallahu 'alaihi wasallam, \" namun hal itu diingkari oleh Imran bin Hushain. Maka kami menulis surat kepada [Ubai bin Ka'ab] di Madinah, dan Ubai pun menulis balasan bahwa Samurah telah menghafalnya. \" Sa'id berkata; \"kami bertanya kepada Qatadah, \"Dua saktah itu letaknya di mana saja?\" ia menjawab, \"Jika ia telah masuk shalat dan ketika selesai dari membaca bacaan (Al Fatihah). \" Setelah itu ia berkata lagi, \"Jika membaca GHAIRIL MAGHDLUUBI 'ALAIHIM WALADLDLAALLIIN. \" Ia berkata; \"Yang menjadikannya ta'ajub adalah diam setelah membaca bacaan (Al Fatihah), hingga hatinya merasa ragu. \""},"804":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ خَالِدِ بْنِ خِدَاشٍ وَعَلِيُّ بْنُ الْحُسَيْنِ بْنِ إِشْكَابَ قَالَا حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ يُونُسَ عَنْ الْحَسَنِ قَالَ قَالَ سَمُرَةُحَفِظْتُ سَكْتَتَيْنِ فِي الصَّلَاةِ سَكْتَةً قَبْلَ الْقِرَاءَةِ وَسَكْتَةً عِنْدَ الرُّكُوعِفَأَنْكَرَ ذَلِكَ عَلَيْهِ عِمْرَانُ بْنُ الْحُصَيْنِ فَكَتَبُوا إِلَى الْمَدِينَةِ إِلَى أُبَيِّ بْنِ كَعْبٍ فَصَدَّقَ سَمُرَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Khalid bin Khidasy] dan [Ali Ibnul Husain bin Isykab] keduanya berkata; telah menceritakan kepada kami [Isma'il bin Ulayyah] dari [Yunus] dari [Al Hasan] ia berkata; [Samurah] berkata, \"Dalam shalat aku menghafal ada dua saktah; sebelum bacaan dan ketika rukuk. \" Namun Imran Ibnul Hushain mengingkarinya, hingga mereka mengirim surat kepada [Ubai bin Ka'ab] di Madinah, dan Ubai pun membenarkan Samurah. \""},"805":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ ابْنِ عَجْلَانِ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا جُعِلَ الْإِمَامُ لِيُؤْتَمَّ بِهِ فَإِذَا كَبَّرَ فَكَبِّرُوا وَإِذَا قَرَأَ فَأَنْصِتُوا وَإِذَا قَالَ{ غَيْرِ الْمَغْضُوبِ عَلَيْهِمْ وَلَا الضَّالِّينَ }فَقُولُوا آمِينَ وَإِذَا رَكَعَ فَارْكَعُوا وَإِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَقُولُوا اللَّهُمَّ رَبَّنَا وَلَكَ الْحَمْدُ وَإِذَا سَجَدَ فَاسْجُدُوا وَإِذَا صَلَّى جَالِسًا فَصَلُّوا جُلُوسًا أَجْمَعِينَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Khalid Al Ahmar] dari [Ibnu 'Ajlan] dari [Zaid bin Aslam] dari [Abu Shalih] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dijadikannya imam adalah agar diikuti, jika ia takbir maka bertakbirlah, jika ia membaca maka dengarkanlah, jika ia membaca WALADL DLAALLIIN maka ucapkanlah AMIIN. Jika ia rukuk maka rukuklah, jika ia mengucapkan SAMI'A ALLAHU LIMAN HAMIDAHU maka ucapkanlah ALLAHUMMA RABBANA WA LAKAL HAMDU, jika ia sujud maka sujudlah, dan jika ia shalat dengan duduk maka shalatlah kalian semua dengan duduk. \""},"806":{"ar":"حَدَّثَنَا يُوسُفُ بْنُ مُوسَى الْقَطَّانُ حَدَّثَنَا جَرِيرٌ عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ قَتَادَةَ عَنْ أَبِي غَلَّابٍ عَنْ حِطَّانَ بْنِ عَبْدِ اللَّهِ الرَّقَاشِيِّ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَرَأَ الْإِمَامُ فَأَنْصِتُوا فَإِذَا كَانَ عِنْدَ الْقَعْدَةِ فَلْيَكُنْ أَوَّلَ ذِكْرِ أَحَدِكُمْ التَّشَهُّدُ","id":"Telah menceritakan kepada kami [Yusuf bin Musa Al Qaththan] berkata, telah menceritakan kepada kami [Jarir] dari [Sulaiman At Taimi] dari [Qatadah] dari [Abu Ghallab] dari [Hithan bin Abdullah Ar Raqasyi] dari [Abu Musa Al Asy'ari] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika imam membaca maka diamlah, dan jika ia duduk maka hendaklah dzikir pertama kali yang kalian ucapkan adalah tasyahud. \""},"807":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَهِشَامُ بْنُ عَمَّارٍ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ ابْنِ أُكَيْمَةَ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُصَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأَصْحَابِهِ صَلَاةً نَظُنُّ أَنَّهَا الصُّبْحُ فَقَالَ هَلْ قَرَأَ مِنْكُمْ مِنْ أَحَدٍ قَالَ رَجُلٌ أَنَا قَالَ إِنِّي أَقُولُ مَا لِي أُنَازَعُ الْقُرْآنَحَدَّثَنَا جَمِيلُ بْنُ الْحَسَنِ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ ابْنِ أُكَيْمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَ صَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ نَحْوَهُ وَزَادَ فِيهِ قَالَ فَسَكَتُوا بَعْدُ فِيمَا جَهَرَ فِيهِ الْإِمَامُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Hisyam bin Ammar] keduanya berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Ibnu Ukaimah] berkata; Aku mendengar [Abu Hurairah] berkata; \"Nabi shallallahu 'alaihi wasallam shalat bersama para sahabatnya yang kami mengira bahwa itu adalah shalat subuh. Beliau bersabda: \"Apakah salah seorang dari kalian ada yang membaca?\" seorang laki-laki menjawab, \"Saya, \" beliau lalu bersabda: \"Kenapa aku ditandingi dalam membaca Al Qur`an?\" Telah menceritakan kepada kami [Jamil Ibnul Hasan] berkata, telah menceritakan kepada kami [Abdul A'la] berkata, telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Ibnu Ukaimah] dari [Abu Hurairah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam shalat bersama kami, lalu ia menyebutkan sebagaimana dalam hadits. Namun ia menambahkan, ia berkata; \"Para sahabat diam dalam shalat yang imam mengeraskan bacaannya. \""},"808":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ الْحَسَنِ بْنِ صَالِحٍ عَنْ جَابِرٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَ لَهُ إِمَامٌ فَقِرَاءَةُ الْإِمَامِ لَهُ قِرَاءَةٌ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Ubaidullah bin Musa] dari [Al Hasan bin Shalih] dari [Jabir] dari [Abu Az Zubair] dari [Jabir] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mempunyai (shalat bersama) imam, maka bacaan imam adalah bacaannya. \""},"809":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَهِشَامُ بْنُ عَمَّارٍ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَمَّنَ الْقَارِئُ فَأَمِّنُوا فَإِنَّ الْمَلَائِكَةَ تُؤَمِّنُ فَمَنْ وَافَقَ تَأْمِينُهُ تَأْمِينَ الْمَلَائِكَةِ غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Hisyam bin Ammar] keduanya berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Sa'id Ibnul Musayyab] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika Qari` (imam) membaca AMIIN maka bacalah AMIIN, sesungguhnya para malaikat juga membacanya. Maka barangsiapa bacaan AMIIN nya berbarengan dengan bacaan malaikat, dosa-dosanya yang telah lalu akan diampuni. \""},"810":{"ar":"حَدَّثَنَا بَكْرُ بْنُ خَلَفٍ وَجَمِيلُ بْنُ الْحَسَنِ قَالَا حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا مَعْمَرٌ ح و حَدَّثَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ الْمِصْرِيُّ وَهَاشِمُ بْنُ الْقَاسِمِ الْحَرَّانِيُّ قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ عَنْ يُونُسَ جَمِيعًا عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ وَأَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَمَّنَ الْقَارِئُ فَأَمِّنُوا فَمَنْ وَافَقَ تَأْمِينُهُ تَأْمِينَ الْمَلَائِكَةِ غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah menceritakan kepada kami [Bakr bin Khalaf] dan [Jamil Ibnul Hasan] keduanya berkata; telah menceritakan kepada kami [Abdul A'la] berkata, telah menceritakan kepada kami [Ma'mar]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ahmad bin Amru bin As Sarh Al Mishri] dan [Hasyim Ibnul Qasim Al Harrani] keduanya berkata; telah menceritakan kepada kami [Abdullah bin Wahb] dari [Yunus] semuanya dari [Az Zuhri] dari [Sa'id Ibnul Musayyab] dan [Abu Salamah bin 'Abdurrahman] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika Qari` (imam) membaca AMIIN maka bacalah AMIIN, barangsiapa yang bacaan AMIIN nya berbarengan dengan bacaan malaikat, maka dosa-dosanya yang telah lalu akan diampuni. \""},"811":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا صَفْوَانُ بْنُ عِيسَى حَدَّثَنَا بِشْرُ بْنُ رَافِعٍ عَنْ أَبِي عَبْدِ اللَّهِ ابْنِ عَمِّ أَبِي هُرَيْرَةَ عَنْ أَبِي هُرَيْرَةَ قَالَتَرَكَ النَّاسُ التَّأْمِينَ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَالَ{ غَيْرِ الْمَغْضُوبِ عَلَيْهِمْ وَلَا الضَّالِّينَ }قَالَ آمِينَ حَتَّى يَسْمَعَهَا أَهْلُ الصَّفِّ الْأَوَّلِ فَيَرْتَجُّ بِهَا الْمَسْجِدُ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Shofwan bin Isa] berkata, telah menceritakan kepada kami [Bisyr bin Rafi'] dari [Abu Abbdullah bin Ammi Abu Hurairah] dari [Abu Hurairah] ia berkata; \"Orang-orang banyak meninggalkan bacaan AMIIN, padahal Rasulullah shallallahu 'alaihi wasallam jika membaca GHAIRIL MAGHDLUUBI 'ALAIHIM WALADL DLALLIIN beliau mengucapkan AMIIN hingga orang-orang yang berada di shaf pertama mendengarnya, dan masjid pun bergemuruh. \""},"812":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا حُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ حَدَّثَنَا ابْنُ أَبِي لَيْلَى عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ حُجَيَّةَ بْنِ عَدِيٍّ عَنْ عَلِيٍّ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَالَ{ وَلَا الضَّالِّينَ }قَالَ آمِينَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Humaid bin 'Abdurrahman] berkata, telah menceritakan kepada kami [Ibnu Abu Laila] dari [Salamah bin Kuhail] dari [Hujayyah bin Adi] dari [Ali] ia berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam apabila membaca WALADL DLALLIIN, beliau mengucapkan AMIIN. \""},"813":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ وَعَمَّارُ بْنُ خَالِدٍ الْوَاسِطِيُّ قَالَا حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ أَبِي إِسْحَقَ عَنْ عَبْدِ الْجَبَّارِ بْنِ وَائِلٍ عَنْ أَبِيهِ قَالَصَلَّيْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا قَالَ{ وَلَا الضَّالِّينَ }قَالَ آمِينَ فَسَمِعْنَاهَا","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] dan [Ammar bin Khalid Al Wasithi] keduanya berkata; telah menceritakan kepada kami [Abu Bakr bin Ayyasy] dari [Abu Ishaq] dari [Abdul Jabbar bin Wa`il] dari [Bapaknya] ia berkata; \"Aku pernah shalat bersama Nabi shallallahu 'alaihi wasallam, maka ketika membaca WALADL DLALLIIN, beliau mengucapkan AMIIN hingga kami pun mendengarnya. \""},"814":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَخْبَرَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ حَدَّثَنَا سُهَيْلُ بْنُ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ عَائِشَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا حَسَدَتْكُمْ الْيَهُودُ عَلَى شَيْءٍ مَا حَسَدَتْكُمْ عَلَى السَّلَامِ وَالتَّأْمِينِ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] berkata, telah mengabarkan kepada kami [Abdu Ash Shamad bin Abdul Warits] berkata, telah menceritakan kepada kami [Hammad bin Salamah] berkata, telah menceritakan kepada kami [Suhail bin Abu Shalih] dari [Bapaknya] dari [Aisyah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak ada yang didengki kaum Yahudi atas kalian terhadap sesuatu selain bacaan salam dan amiin. \""},"815":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ الْوَلِيدِ الْخَلَّالُ الدِّمَشْقِيُّ حَدَّثَنَا مَرْوَانُ بْنُ مُحَمَّدٍ وَأَبُو مُسْهِرٍ قَالَا حَدَّثَنَا خَالِدُ بْنُ يَزِيدَ بْنِ صَالِحِ بْنِ صُبَيْحٍ الْمُرِّيُّ حَدَّثَنَا طَلْحَةُ بْنُ عَمْرٍو عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا حَسَدَتْكُمْ الْيَهُودُ عَلَى شَيْءٍ مَا حَسَدَتْكُمْ عَلَى آمِينَ فَأَكْثِرُوا مِنْ قَوْلِ آمِينَ","id":"Telah menceritakan kepada kami [Al Abbas bin Al Walid Al Khallal Ad Dimasyqi] berkata, telah menceritakan kepada kami [Marwan bin Muhammad] dan [Abu Mushir] keduanya berkata; telah menceritakan kepada kami [Khalid bin Yazid bin Shalih bin Shubaih Al Murri] berkata, telah menceritakan kepada kami [Thalhah bin Amru] dari ['Atho`] dari [Ibnu Abbas] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah kaum Yahudi mendengki kalian terhadap sesuatu, seperti mereka mendengki kalian terhadap lafadz AMIIN, maka perbanyaklah ucapan AMIIN. \" "},"816":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَهِشَامُ بْنُ عَمَّارٍ وَأَبُو عُمَرَ الضَّرِيرُ قَالُوا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا افْتَتَحَ الصَّلَاةَ رَفَعَ يَدَيْهِ حَتَّى يُحَاذِيَ بِهِمَا مَنْكِبَيْهِ وَإِذَا رَكَعَ وَإِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ وَلَا يَرْفَعُ بَيْنَ السَّجْدَتَيْنِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan [Hisyam bin Ammar] dan [Abu Umar Adl Dlarir] mereka berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Salim] dari [Ibnu Umar] ia berkata; \"Aku melihat Rasulullah shallallahu 'alaihi wasallam jika membuka shalat beliau mengangkat kedua tangannya hingga sejajar dengan kedua pundaknya, begitu juga ketika rukuk dan ketika mengangkat kepala dari rukuk. Tetapi beliau tidak mengangkatnya ketika duduk antara dua sujud. \""},"817":{"ar":"حَدَّثَنَا حُمَيْدُ بْنُ مَسْعَدَةَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ نَصْرِ بْنِ عَاصِمٍ عَنْ مَالِكِ بْنِ الْحُوَيْرِثِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا كَبَّرَ رَفَعَ يَدَيْهِ حَتَّى يَجْعَلَهُمَا قَرِيبًا مِنْ أُذُنَيْهِ وَإِذَا رَكَعَ صَنَعَ مِثْلَ ذَلِكَ وَإِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ صَنَعَ مِثْلَ ذَلِكَ","id":"Telah menceritakan kepada kami [Humaid bin Mas'adah] berkata, telah menceritakan kepada kami [Yazid bin Zurai'] berkata, telah menceritakan kepada kami [Hisyam] dari [Qatadah] dari [Nashr bin Ashim] dari [Malik Ibnul Huwairits] berkata, \"Jika takbir Rasulullah shallallahu 'alaihi wasallam mengangkat kedua tangannya hingga dekat dengan kedua telinga. Ketika rukuk dan mengangkat kepalanya dari rukuk, beliau juga melakukan hal yang sama. \""},"818":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَهِشَامُ بْنُ عَمَّارٍ قَالَا حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ عَنْ صَالِحِ بْنِ كَيْسَانَ عَنْ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْفَعُ يَدَيْهِ فِي الصَّلَاةِ حَذْوَ مَنْكِبَيْهِ حِينَ يَفْتَتِحُ الصَّلَاةَ وَحِينَ يَرْكَعُ وَحِينَ يَسْجُدُ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] dan [Hisyam bin Ammar] keduanya berkata; telah menceritakan kepada kami [Isma'il bin Ayyasy] dari [Shalih bin Kaisan] dari ['Abdurrahman Al A'raj] dari [Abu Hurairah] ia berkata; \"Dalam shalat aku melihat Rasulullah shallallahu 'alaihi wasallam mengangkat kedua tangannya ketika membuka shalat, ketika rukuk dan ketika akan sujud. \""},"819":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا رِفْدَةُ بْنُ قُضَاعَةَ الْغَسَّانِيُّ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ عَبْدِ اللَّهِ بْنِ عُبَيْدِ بْنِ عُمَيْرٍ عَنْ أَبِيهِ عَنْ جَدِّهِ عُمَيْرِ بْنِ حَبِيبٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْفَعُ يَدَيْهِ مَعَ كُلِّ تَكْبِيرَةٍ فِي الصَّلَاةِ الْمَكْتُوبَةِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Rifdah bin Qudla'ah Al Ghassani] berkata, telah menceritakan kepada kami [Al Auza'I] dari [Abdullah bin Ubaid bin Umair] dari [Bapaknya] dari kakeknya [Umair bin Habib] ia berkata, \"Dalam shalat wajib Rasulullah shallallahu 'alaihi wasallam selalu mengangkat kedua tangannya ketika takbir. \" "},"820":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرِو بْنِ عَطَاءٍ عَنْ أَبِي حُمَيْدٍ السَّاعِدِيِّ قَالَ سَمِعْتُهُ وَهُوَ فِي عَشَرَةٍ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحَدُهُمْ أَبُو قَتَادَةَ بْنُ رِبْعِيٍّ قَالَأَنَا أَعْلَمُكُمْ بِصَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا قَامَ فِي الصَّلَاةِ اعْتَدَلَ قَائِمًا وَرَفَعَ يَدَيْهِ حَتَّى يُحَاذِيَ بِهِمَا مَنْكِبَيْهِ ثُمَّ قَالَ اللَّهُ أَكَبْرُ وَإِذَا أَرَادَ أَنْ يَرْكَعَ رَفَعَ يَدَيْهِ حَتَّى يُحَاذِيَ بِهِمَا مَنْكِبَيْهِ فَإِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ رَفَعَ يَدَيْهِ فَاعْتَدَلَ فَإِذَا قَامَ مِنْ الثِّنْتَيْنِ كَبَّرَ وَرَفَعَ يَدَيْهِ حَتَّى يُحَاذِيَ مَنْكِبَيْهِ كَمَا صَنَعَ حِينَ افْتَتَحَ الصَّلَاةَ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] berkata, telah menceritakan kepada kami [Abdul Hamid bin Ja'far] berkata, telah menceritakan kepada kami [Muhammad bin Amru bin 'Atho`] dari [Abu Humaid As Sa'idi] -ia berkata; \"Aku mendengarnya berkata, ketika itu ia termasuk salah seorang dari sepuluh sahabat Rasulullah shallallahu 'alaihi wasallam (yang berkumpul), di antara mereka juga ada- [Abu Qatadah bin Rib'i], ia berkata; \"Aku adalah orang yang paling tahu dengan shalat Rasulullah shallallahu 'alaihi wasallam di antara kalian. Jika shalat beliau berdiri tegak dan mengangkat kedua tangannya hingga sejajar dengan kedua pundak seraya mengucapkan ALLAHU AKBAR. Ketika rukuk beliau juga mengangkat kedua tangannya sejajar dengan kedua pundaknya. Apabila mengucapkan SAMI'A ALLAHU LIMAN HAMIDAHU beliau mengangkat kedua tangannya tegak berimbang. Dan ketika bangun pada raka'at kedua beliau takbir dan mengangkat kedua tangannya sejajar dengan kedua pundak sebagaimana ketika beliau membuka shalat. \""},"821":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا فُلَيْحُ بْنُ سُلَيْمَانَ حَدَّثَنَا عَبَّاسُ بْنُ سَهْلٍ السَّاعِدِيُّ قَالَاجْتَمَعَ أَبُو حُمَيْدٍ السَّاعِدِيُّ وَأَبُو أُسَيْدٍ السَّاعِدِيُّ وَسَهْلُ بْنُ سَعْدٍ وَمُحَمَّدُ بْنُ مَسْلَمَةَ فَذَكَرُوا صَلَاةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَبُو حُمَيْدٍ أَنَا أَعْلَمُكُمْ بِصَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ فَكَبَّرَ وَرَفَعَ يَدَيْهِ ثُمَّ رَفَعَ حِينَ كَبَّرَ لِلرُّكُوعِ ثُمَّ قَامَ فَرَفَعَ يَدَيْهِ وَاسْتَوَى حَتَّى رَجَعَ كُلُّ عَظْمٍ إِلَى مَوْضِعِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Abu Amir] berkata, telah menceritakan kepada kami [Fulaih bin Sulaiman] berkata, telah menceritakan kepada kami [Abbas bin Sahl As Sa'idi] ia berkata; \"Abu Humaid As Sa'idi, Abu Usaid As Sa'idi, Sahl bin Sa'd dan Muhammad bin Maslamah berkumpul dan menyebut-nyebut tentang shalat Rasulullah shallallahu 'alaihi wasallam. [Abu Humaid] berkata; \"Aku adalah orang yang paling tahu shalatnya Rasulullah shallallahu 'alaihi wasallam dari kalian semua, Rasulullah shallallahu 'alaihi wasallam berdiri takbir dan mengangkat kedua tangannya. Kemudian beliau mengangkatnya kembali ketika takbir untuk rukuk dan ketika bangun dari rukuk, beliau angkat secara imbang hingga setiap tulang kembali ke tempatnya semula. \""},"822":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ الْعَنْبَرِيُّ حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ أَبُو أَيُّوبَ الْهَاشِمِيُّ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي الزِّنَادِ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ عَبْدِ اللَّهِ بْنِ الْفَضْلِ عَنْ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي رَافِعٍ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَامَ إِلَى الصَّلَاةِ الْمَكْتُوبَةِ كَبَّرَ وَرَفَعَ يَدَيْهِ حَتَّى يَكُونَا حَذْوَ مَنْكِبَيْهِ وَإِذَا أَرَادَ أَنْ يَرْكَعَ فَعَلَ مِثْلَ ذَلِكَ وَإِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ فَعَلَ مِثْلَ ذَلِكَ وَإِذَا قَامَ مِنْ السَّجْدَتَيْنِ فَعَلَ مِثْلَ ذَلِكَ","id":"Telah menceritakan kepada kami [Al Abbas bin Abdul Azhim Al 'Anbari] berkata, telah menceritakan kepada kami [Sulaiman bin Dawud Ayyub Al hasyimi] berkata, telah menceritakan kepada kami ['Abdurrahman bin Abu Az Zinad] dari [Musa bin Uqbah] dari [Abdullah bin Al Fadll] dari ['Abdurrahman Al A'raj] dari [Ubaidullah bin Abu Rafi'] dari [Ali bin Abu Thalib] ia berkata, \"Jika Nabi shallallahu 'alaihi wasallam mengerjakan shalat wajib, beliau takbir dan mengangkat kedua tangannya hingga sejajar kedua pundaknya. Dan beliau melakukan seperti itu ketika akan rukuk, ketika mengangkat kepala dari rukuk dan ketika akan bangun dari dua sujud. \""},"823":{"ar":"حَدَّثَنَا أَيُّوبُ بْنُ مُحَمَّدٍ الْهَاشِمِيُّ حَدَّثَنَا عُمَرُ بْنُ رِيَاحٍ عَنْ عَبْدِ اللَّهِ بْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَرْفَعُ يَدَيْهِ عِنْدَ كُلِّ تَكْبِيرَةٍ","id":"Telah menceritakan kepada kami [Ayyub bin Muhammad Al Hasyimi] berkata, telah menceritakan kepada kami [Umar bin Riyah] dari [Abdullah bin Thawus] dari [Bapaknya] dari [Ibnu Abbas] berkata, \"Rasulullah shallallahu 'alaihi wasallam selalu mengangkat kedua tangannya dalam setiap bertakbir. \""},"824":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَرْفَعُ يَدَيْهِ إِذَا دَخَلَ فِي الصَّلَاةِ وَإِذَا رَكَعَ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Abdul Wahhab] berkata, telah menceritakan kepada kami [Humaid] dari [Anas] berkata, \"Rasulullah shallallahu 'alaihi wasallam selalu mengangkat kedua tangannya jika memulai shalat dan ketika akan rukuk. \" "},"825":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا أَبُو حُذَيْفَةَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ طَهْمَانَ عَنْ أَبِي الزُّبَيْرِأَنَّ جَابِرَ بْنَ عَبْدِ اللَّهِ كَانَ إِذَا افْتَتَحَ الصَّلَاةَ رَفَعَ يَدَيْهِ وَإِذَا رَكَعَ وَإِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ فَعَلَ مِثْلَ ذَلِكَ وَيَقُولُ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَلَ مِثْلَ ذَلِكَ وَرَفَعَ إِبْرَاهِيمُ بْنُ طَهْمَانَ يَدَيْهِ إِلَى أُذُنَيْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Abu Hudzaifah] berkata, telah menceritakan kepada kami [Ibrahim bin Thahman] dari [Abu Zubair] berkata; \" [Jabir bin Abdullah] selalu mengangkat kedua tangannya ketika memulai shalat, ketika akan rukuk dan ketika mengangkat kepalanya dari rukuk. Ia lalu berkata; \"Aku melihat Rasulullah shallallahu 'alaihi wasallam melakukan seperti itu. \" Ibrahim bin Thahman juga mengangkat kedua tangannya sejajar dengan ke kedua telinganya. \""},"826":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ حُسَيْنٍ الْمُعَلِّمِ عَنْ بُدَيْلٍ عَنْ أَبِي الْجَوْزَاءِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَكَعَ لَمْ يَشْخَصْ رَأْسَهُ وَلَمْ يُصَوِّبْهُ وَلَكِنْ بَيْنَ ذَلِكَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yazid bin Harun] dari [Husain Al Mu'allim] dari [Budail] dari [Abu Al Jauza`] dari [Aisyah] ia berkata, \"Jika Rasulullah shallallahu 'alaihi wasallam rukuk, beliau tidak mengangkat kepala atau merendahkannya, akan tetapi antara keduanya. \" "},"827":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَعَمْرُو بْنُ عَبْدِ اللَّهِ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ عُمَارَةَ عَنْ أَبِي مَعْمَرٍ عَنْ أَبِي مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُجْزِئُ صَلَاةٌ لَا يُقِيمُ الرَّجُلُ فِيهَا صُلْبَهُ فِي الرُّكُوعِ وَالسُّجُودِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan [Amru bin Abdullah] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Al A'masy] dari [Umarah] dari [Abu Ma'mar] dari [Abu Mas'ud] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak sah shalat seorang laki-laki yang tidak menegakkan tulang punggungnya ketika rukuk dan sujud. \""},"828":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُلَازِمُ بْنُ عَمْرٍو عَنْ عَبْدِ اللَّهِ بْنِ بَدْرٍ أَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ عَلِيِّ بْنِ شَيْبَانَ عَنْ أَبِيهِ عَلِيِّ بْنِ شَيْبَانَ وَكَانَ مِنْ الْوَفْدِ قَالَخَرَجْنَا حَتَّى قَدِمْنَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَايَعْنَاهُ وَصَلَّيْنَا خَلْفَهُ فَلَمَحَ بِمُؤْخِرِ عَيْنِهِ رَجُلًا لَا يُقِيمُ صَلَاتَهُ يَعْنِي صُلْبَهُ فِي الرُّكُوعِ وَالسُّجُودِ فَلَمَّا قَضَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّلَاةَ قَالَ يَا مَعْشَرَ الْمُسْلِمِينَ لَا صَلَاةَ لِمَنْ لَا يُقِيمُ صُلْبَهُ فِي الرُّكُوعِ وَالسُّجُودِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Mulazim bin Amru] dari [Abdullah bin Badr] berkata, telah mengabarkan kepadaku ['Abdurrahman bin Ali bin Syaiban] dari bapaknya [Ali bin Syaiban] -ia adalah seorang utusan- ia berkata; \"Kami berangkat hingga kami sampai di hadapan Rasulullah shallallahu 'alaihi wasallam, lalu kami membai'at dan shalat di belakangnya. Ketika itu beliau melihat seorang laki-laki yang tidak menegakkan tulang punggungnya ketika rukuk dan sujud. Maka ketika shalat telah selesai, Nabi shallallahu 'alaihi wasallam bersabda: \"Wahai kaum muslimin, tidak sah shalat seorang laki-laki yang tidak menegakkan tulang punggungnya ketika rukuk dan sujud. \""},"829":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُحَمَّدِ بْنِ يُوسُفَ الْفِرْيَابِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُثْمَانَ بْنِ عَطَاءٍ حَدَّثَنَا طَلْحَةُ بْنُ زَيْدٍ عَنْ رَاشِدٍ قَالَ سَمِعْتُ وَابِصَةَ بْنَ مَعْبَدٍ يَقُولُرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فَكَانَ إِذَا رَكَعَ سَوَّى ظَهْرَهُ حَتَّى لَوْ صُبَّ عَلَيْهِ الْمَاءُ لَاسْتَقَرَّ","id":"Telah menceritakan kepada kami [Ibrahim bin Muhammad bin Yusuf Al Firyabi] berkata, telah menceritakan kepada kami [Abdullah bin Utsman bin 'Atho`] berkata, telah menceritakan kepada kami [Thalhah bin Zaid] dari [Rasyid] ia berkata; \"Aku mendengar [Wabishah bin Ma'bad] berkata; \"Aku melihat Rasulullah shallallahu 'alaihi wasallam menunaikan shalat, jika rukuk beliau meluruskan punggungnya, sehingga jika dituangkan air di atasnya tidak akan tumpah. \" "},"830":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ عَنْ الزُّبَيْرِ بْنِ عَدِيٍّ عَنْ مُصْعَبِ بْنِ سَعْدٍ قَالَرَكَعْتُ إِلَى جَنْبِ أَبِي فَطَبَّقْتُ فَضَرَبَ يَدِي وَقَالَ قَدْ كُنَّا نَفْعَلُ هَذَا ثُمَّ أُمِرْنَا أَنْ نَرْفَعَ إِلَى الرُّكَبِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] berkata; telah menceritakan kepada kami [Muhammad bin Bisyr] berkata, telah menceritakan kepada kami [Isma'il bin Abu Khalid] dari [Az Zubair bin Adi] dari [Mush'ab bin Sa'd] ia berkata, \"Aku pernah rukuk di sisi [bapakku], lalu aku meletakkan kedua tanganku di antara lutut hingga bapakku memukulku, ia berkata; \"Kami pernah melakukan seperti ini, kemudian kami diperintahkan untuk meletakkan pada lutut. \""},"831":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ حَارِثَةَ بْنِ أَبِي الرِّجَالِ عَنْ عَمْرَةَ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْكَعُ فَيَضَعُ يَدَيْهِ عَلَى رُكْبَتَيْهِ وَيُجَافِي بِعَضُدَيْهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami ['Abdah bin Sulaiman] dari [Haritsah bin Abu Rijal] dari ['Amrah] dari [Aisyah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam jika rukuk selalu meletakkan kedua tangannya di atas kedua lututnya dan merenggangkannya. \""},"832":{"ar":"حَدَّثَنَا أَبُو مَرْوَانَ مُحَمَّدُ بْنُ عُثْمَانَ الْعُثْمَانِيُّ وَيَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ قَالَا حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ وَأَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ قَالَ رَبَّنَا وَلَكَ الْحَمْدُ","id":"Telah menceritakan kepada kami [Abu Marwan Muhammad bin Utsman Al Utsmani] dan [Ya'qub bin Humaid bin Kasib] keduanya berkata; telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Ibnu Syihab] dari [Sa'id Ibnul Musayyab] dan [Abu Salamah bin 'Abdurrahman] dari [Abu Hurairah] berkata, \"Jika Rasulullah shallallahu 'alaihi wasallam mengucapkan; SAMI'A ALLAHU LIMAN HAMIDAHU (semoga Allah mendengar pujian hamba yang memuji-Nya) beliau lalu mengucapkan RABBANAA LAKAL HAMDU (Wahai Rabb kami, bagi-Mu segala pujian). \" "},"833":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا قَالَ الْإِمَامُ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَقُولُوا رَبَّنَا وَلَكَ الْحَمْدُ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Anas bin Malik] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika imam mengucapkan SAMI'A ALLAHU LIMAN HAMIDAHU (semoga Allah mendengar pujian hamba yang memuji-Nya) maka ucapkanlah RABBANAA WA LAKAL HAMDU (Wahai Rabb kami, dan bagi-Mu lah segala pujian). \" "},"834":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ أَبِي بُكَيْرٍ حَدَّثَنَا زُهَيْرُ بْنُ مُحَمَّدٍ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا قَالَ الْإِمَامُ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَقُولُوا اللَّهُمَّ رَبَّنَا وَلَكَ الْحَمْدُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yahya bin Abu Bukair] berkata, telah menceritakan kepada kami [Zuhair bin Muhammad] dari [Abdullah bin Muhammad bin Aqil] dari [Sa'id Ibnul Musayyab] dari [Abu Sa'id Al Hudri] bahwasanya ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika imam mengucapkan SAMI'A ALLAHU LIMAN HAMIDAHU (semoga Allah mendengar pujian hamba yang memuji-Nya) maka ucapkanlah ALLAHUMMA RABBANAA WA LAKAL HAMDU (Ya Allah, Rabb kami, bagi-Mu lah segala pujian). \" "},"835":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ عَنْ عُبَيْدِ بْنِ الْحَسَنِ عَنْ ابْنِ أَبِي أَوْفَى قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ اللَّهُمَّ رَبَّنَا وَلَكَ الْحَمْدُ مِلْءَ السَّمَوَاتِ وَمِلْءَ الْأَرْضِ وَمِلْءَ مَا شِئْتَ مِنْ شَيْءٍ بَعْدُ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Al A'masy] dari [Ubaid Ibnul Hasan] dari [Ibnu Abu Aufa] ia berkata, \"Jika mengangkat kepalanya dari rukuk, Nabi shallallahu 'alaihi wasallam mengucapkan; SAMI'A ALLAHU LIMAN HAMIDAHU RABBANAA WA LAKAL HAMDU MIL`AS SAMAAWAATI WA MIL`AL ARDLI WA MIL`A MAA SYI`TA MIN SYAI`IN BA'DU (Semoga Allah mendengar pujian hamba yang memuji-Nya. Wahai Tuhan kami, bagi-Mu segala pujian. Pujian sepenuh langit dan sepenuh bumi, sepenuh apa yang Engkau kehendaki setelah itu). \""},"836":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ مُوسَى السُّدِّيُّ حَدَّثَنَا شَرِيكٌ عَنْ أَبِي عُمَرَ قَالَ سَمِعْتُ أَبَا جُحَيْفَةَ يَقُولُذُكِرَتْ الْجُدُودُ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي الصَّلَاةِ فَقَالَ رَجُلٌ جَدُّ فُلَانٍ فِي الْخَيْلِ وَقَالَ آخَرُ جَدُّ فُلَانٍ فِي الْإِبِلِ وَقَالَ آخَرُ جَدُّ فُلَانٍ فِي الْغَنَمِ وَقَالَ آخَرُ جَدُّ فُلَانٍ فِي الرَّقِيقِ فَلَمَّا قَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاتَهُ وَرَفَعَ رَأْسَهُ مِنْ آخِرِ الرَّكْعَةِ قَالَ اللَّهُمَّ رَبَّنَا وَلَكَ الْحَمْدُ مِلْءَ السَّمَوَاتِ وَمِلْءَ الْأَرْضِ وَمِلْءَ مَا شِئْتَ مِنْ شَيْءٍ بَعْدُ اللَّهُمَّ لَا مَانِعَ لِمَا أَعْطَيْتَ وَلَا مُعْطِيَ لِمَا مَنَعْتَ وَلَا يَنْفَعُ ذَا الْجَدِّ مِنْكَ الْجَدُّ وَطَوَّلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَوْتَهُ بِالْجَدِّ لِيَعْلَمُوا أَنَّهُ لَيْسَ كَمَا يَقُولُونَ","id":"Telah menceritakan kepada kami [Ismail bin Musa As Suddi] berkata, telah menceritakan kepada kami [Syarik] dari [Abu Umar] ia berkata; \"Aku mendengar [Abu Juhahifah] berkata; \"Ketika Rasulullah shallallahu 'alaihi wasallam sedang melaksanakan shalat, para sahabat membicarakan harta kekayaan. Maka ada seseorang yang berkata; \"Kekayaan fulan terletak pada kudanya. \" Yang lain menyahut, \"Kekayaan si fulan terletak pada untanya. \" Yang menyahut, \"Kekayaan si fulan terletak pada kambingnya. \" Yang lainnya pun menyahut, \"Kekayaan si fulan terletak pada budak. \" Ketika Rasulullah shallallahu 'alaihi wasallam selesai dari shalatnya, dan mengangkat kepalanya dari raka'at akhir, beliau mengucapkan: \"ALLAHUMMA RABBANAA, WA LAKAL HAMDU MIL'AS SAMAAWAATI WA MIL'AL ARDLI WA MIL'A MAA SYI'TA MIN SAYIN BA'DU. ALLAHUMMA LAA MAANI'A LIMAA A'THAITA WALAA MU'THIYA LIMAA MANA'TA WALAA YANFA'U DZAL JADDI MINKAL JADDU (Ya Allah Engkau Rabb kami, dan bagi-Mu segala puji sepenuh langit dan sepenuh bumi dan sepenuh apa yang Engkau kehendaki selain itu. Ya Allah, tidak ada yang dapat mencegah dari apa yang telah Engkau berikan, dan tidak ada yang dapat memberikan atas apa yang Engkau cegah. Tidak bermanfaat usaha yang sungguh-sungguh, dari-Mu lah segala usaha yang sungguh-sungguh itu). \" Beliau memperpanjang suaranya dengan serius, agar mereka mengetahui bahwa beliau bukan seperti yang mereka perbincangkan. \""},"837":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ الْأَصَمِّ عَنْ عَمِّهِ يَزِيدَ بْنِ الْأَصَمِّ عَنْ مَيْمُونَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا سَجَدَ جَافَى يَدَيْهِ فَلَوْ أَنَّ بَهْمَةً أَرَادَتْ أَنْ تَمُرَّ بَيْنَ يَدَيْهِ لَمَرَّتْ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Ubaidullah bin Al Asham] dari pamannya [Yazid bin Al Asham] dari [Maimunah] berkata, \"Nabi shallallahu 'alaihi wasallam jika sujud menjauhkan kedua tangannya dari lambung, sekiranya ada anak kambing lewat antara keduanya tangannya, pasti ia akan dapat melewatinya. \""},"838":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ دَاوُدَ بْنِ قَيْسٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ أَقْرَمَ الْخُزَاعِيِّ عَنْ أَبِيهِ قَالَكُنْتُ مَعَ أَبِي بِالْقَاعِ مِنْ نَمِرَةَ فَمَرَّ بِنَا رَكْبٌ فَأَنَاخُوا بِنَاحِيَةِ الطَّرِيقِ فَقَالَ لِي أَبِي كُنْ فِي بَهْمِكَ حَتَّى آتِيَ هَؤُلَاءِ الْقَوْمَ فَأُسَائِلَهُمْ قَالَ فَخَرَجَ وَجِئْتُ يَعْنِي دَنَوْتُ فَإِذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَحَضَرْتُ الصَّلَاةَ فَصَلَّ��ْتُ مَعَهُمْ فَكُنْتُ أَنْظُرُ إِلَى عُفْرَتَيْ إِبْطَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلَّمَا سَجَدَقَالَ ابْن مَاجَةَ النَّاسُ يَقُولُونَ عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ و قَالَ أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ يَقُولُ النَّاسُ عَبْدُ اللَّهِ بْنُ عُبَيْدِ اللَّهِ حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ وَصَفْوَانُ بْنُ عِيسَى وَأَبُو دَاوُدَ قَالُوا حَدَّثَنَا دَاوُدُ بْنُ قَيْسٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ أَقْرَمَ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Waki'] dari [Dawud bin Qais] dari [Ubaidullah bin Abdullah bin Aqram Al Khuza'i] dari [Bapaknya] ia berkata; \"Aku bersama bapakku berada di sebuah lembah di wilayah Namirah, tiba-tiba serombongan penunggang kuda melewati kami dan turun di ujung jalan, bapakku lalu berkata kepadaku, \"Tetaplah kamu di atas batumu hingga aku mendatangi dan bertanya kepada mereka. \" Ia berkata; \"Rombongan itu keluar dan aku pun mendekat, ternyata rombongan itu adalah Rasulullah shallallahu 'alaihi wasallam. Ketika waktu shalat tiba aku shalat bersama mereka hingga aku dapat melihat putihnya kedua ketiak Rasulullah shallallahu 'alaihi wasallam ketika beliau sujud. \" Ibnu Majah berkata; \"Orang-orang berkata; \"Ubaidullah bin Abdullah. \" Dan [Abu Bakr bin Abu Syaibah] berkata; \"Abdullah bin Ubaidullah berkata; telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami ['Abdurrahman bin Mahdi] dan [Shafwan bin Isa] dan [Abu Dawud] mereka berkata; telah menceritakan kepada kami [Dawud bin Qais] dari [Ubaidullah bin Abdullah bin Arqam] dari [Bapaknya] dari Nabi shallallahu 'alaihi wasallam, sebagaimana dalam hadits. \""},"839":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا شَرِيكٌ عَنْ عَاصِمِ بْنِ كُلَيْبٍ عَنْ أَبِيهِ عَنْ وَائِلِ بْنِ حُجْرٍ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَجَدَ وَضَعَ رُكْبَتَيْهِ قَبْلَ يَدَيْهِ وَإِذَا قَامَ مِنْ السُّجُودِ رَفَعَ يَدَيْهِ قَبْلَ رُكْبَتَيْهِ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Khallal] berkata, telah menceritakan kepada kami [Yazid bin Harun] berkata, telah memberitakan kepada kami [Syarik] dari [Ashim bin Kulaib] dari [Bapaknya] dari [Wa`il bin Hujr] ia berkata; \"Aku melihat Nabi shallallahu 'alaihi wasallam, jika sujud beliau meletakkan kedua lutut sebelum kedua tangannya. Dan jika bangun dari sujud beliau mengangkat kedua tangannya sebelum kedua lutut. \" "},"840":{"ar":"حَدَّثَنَا بِشْرُ بْنُ مُعَاذٍ الضَّرِيرُ حَدَّثَنَا أَبُو عَوَانَةَ وَحَمَّادُ بْنُ زَيْدٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أُمِرْتُ أَنْ أَسْجُدَ عَلَى سَبْعَةِ أَعْظُمٍ","id":"Telah menceritakan kepada kami [Bisyr bin Mu'adz Adl Dlarir] berkata, telah menceritakan kepada kami [Abu Awanah] dan [Hammad bin Zaid] dari [Amru bin Dinar] dari [Thawus] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Aku diperintahkan untuk sujud di atas tujuh tulang. \""},"841":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُمِرْتُ أَنْ أَسْجُدَ عَلَى سَبْعٍ وَلَا أَكُفَّ شَعَرًا وَلَا ثَوْبًاقَالَ ابْنُ طَاوُسٍ فَكَانَ أَبِي يَقُولُ الْيَدَيْنِ وَالرُّكْبَتَيْنِ وَالْقَدَمَيْنِ وَكَانَ يَعُدُّ الْجَبْهَةَ وَالْأَنْفَ وَاحِدًا","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Sufyan] dari [Ibnu Thawus] dari [Bapaknya] dari [Ibnu Abbas] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku diperintahkan untuk sujud di atas tujuh (tulang) tanpa menahan rambut dan kain. \" Ibnu Thawus berkata; \"Bapakku berkata; \" (Yaitu) kedua tangan, dua lutut dan dua telapak kaki, \" dan ia menghitung satu antara kening dan hidung. \""},"842":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ عَنْ يَزِيدَ بْنِ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ عَامِرِ بْنِ سَعْدٍ عَنْ الْعَبَّاسِ بْنِ عَبْدِ الْمُطَّلِبِأَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا سَجَدَ الْعَبْدُ سَجَدَ مَعَهُ سَبْعَةُ آرَابٍ وَجْهُهُ وَكَفَّاهُ وَرُكْبَتَاهُ وَقَدَمَاهُ","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib] berkata, telah menceritakan kepada kami [Abdul Aziz bin Abu Hazim] dari [Yazid bin Al Had] dari [Muhammad bin Ibrahim At Taimi] dari [Amir bin Sa'd] dari [Al Abbas bin Abdul Muthallib] bahwasanya ia pernah mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Jika seorang hamba sujud hendaklah ia sujud di atas tujuh anggota badan; muka, dua tangan, dua lutut dan dua telapak kaki. \""},"843":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا عَبَّادُ بْنُ رَاشِدٍ عَنْ الْحَسَنِ حَدَّثَنَا أَحْمَرُ صَاحِبُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَإِنْ كُنَّا لَنَأْوِي لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِمَّا يُجَافِي بِيَدَيْهِ عَنْ جَنْبَيْهِ إِذَا سَجَدَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Abbad bin Rasyid] dari [Al Hasan] berkata, telah menceritakan kepada kami [Ahmar] sahabat Rasulullah shallallahu 'alaihi wasallam, ia berkata, \"Kami merasa iba kepada Rasulullah shallallahu 'alaihi wasallam ketika beliau menjauhkan kedua tangannya dari lambung saat sujud. \""},"844":{"ar":"حَدَّثَنَا عَمْرُو بْنُ رَافِعٍ الْبَجَلِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ مُوسَى بْنِ أَيُّوبَ الْغَافِقِيِّ قَالَ سَمِعْتُ عَمِّي إِيَاسَ بْنَ عَامِرٍ يَقُولُ سَمِعْتُ عُقْبَةَ بْنَ عَامِرٍ الْجُهَنِيَّ يَقُولُلَمَّا نَزَلَتْ{ فَسَبِّحْ بِاسْمِ رَبِّكَ الْعَظِيمِ }قَالَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اجْعَلُوهَا فِي رُكُوعِكُمْ فَلَمَّا نَزَلَتْ{ سَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى }قَالَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اجْعَلُوهَا فِي سُجُودِكُمْ","id":"Telah menceritakan kepada kami [Amru bin Rafi' Al Bajali] berkata, telah menceritakan kepada kami [Abdullah Ibnul Mubarak] dari [Musa bin Ayyub Al Ghafiqi] berkata; \"Aku mendengar [Iyas bin Amir] berkata; \"Aku mendengar [Uqbah bin Amir Al Juhani] berkata, \"Ketika turun ayat; (Sucikanlah nama Tuhanmu Yang Maha Tinggi), Rasulullah shallallahu 'alaihi wasallam bersabda kepada kami: \"Lakukanlah itu dalam sujud kalian. \" "},"845":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ الْمِصْرِيُّ أَنْبَأَنَا ابْنُ لَهِيعَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي جَعْفَرٍ عَنْ أَبِي الْأَزْهَرِ عَنْ حُذَيْفَةَ بْنِ الْيَمَانِأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا رَكَعَ سُبْحَانَ رَبِّيَ الْعَظِيمِ ثَلَاثَ مَرَّاتٍ وَإِذَا سَجَدَ قَالَ سُبْحَانَ رَبِّيَ الْأَعْلَى ثَلَاثَ مَرَّاتٍ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh Al Mishri] berkata, telah memberitakan kepada kami [Ibnu Lahi'ah] dari [Ubaidullah bin Abu Ja'far] dari [Abu Al Azhar] dari [Hudzaifah Al Yamani] bahwasanya ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda di saat rukuk: \"SUBHAANA RABBIYAL 'AZHIM (Maha Suci Tuhanku Yang Maha Agung) tiga kali. Dan ketika sujud mengucapkan; SUBHAANA RABBIYAL A'LA (Maha Suci Tuhanku Yang Maha Tinggi) tiga kali. \""},"846":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُكْثِرُ أَنْ يَقُولَ فِي رُكُوعِهِ وَسُجُودِهِ سُبْحَانَكَ اللَّهُمَّ وَبِحَمْدِكَ اللَّهُمَّ اغْفِرْ لِي يَتَأَوَّلُ الْقُرْآنَ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Abu Dhluha] dari [Masruq] dari [Aisyah] ia berkata; \"Dalam rukuk dan sujud Rasulullah shallallahu 'alaihi wasallam memperbanyak do'a: \"SUBHAANAKA ALLAHUMMA WA BI HAMDIKA ALLAHUMMA IGHFIR LII\" (Maha Suci Engkau ya Allah, dan dengan memuji-Mu ya Allah, ampunilah aku, \" beliau mentakwilkan Al Qur'an. \""},"847":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ خَلَّادٍ الْبَاهِلِيُّ حَدَّثَنَا وَكِيعٌ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ إِسْحَقَ بْنِ يَزِيدَ الْهُذَلِيِّ عَنْ عَوْنِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ ابْنِ مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَكَعَ أَحَدُكُمْ فَلْيَقُلْ فِي رُكُوعِهِ سُبْحَانَ رَبِّيَ الْعَظِيمِ ثَلَاثًا فَإِذَا فَعَلَ ذَلِكَ فَقَدْ تَمَّ رُكُوعُهُ وَإِذَا سَجَدَ أَحَدُكُمْ فَلْيَقُلْ فِي سُجُودِهِ سُبْحَانَ رَبِّيَ الْأَعْلَى ثَلَاثًا فَإِذَا فَعَلَ ذَلِكَ فَقَدْ تَمَّ سُجُودُهُ وَذَلِكَ أَدْنَاهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Khallad Al Bahili] berkata, telah menceritakan kepada kami [Waki'] dari [Ibnu Abu Dzi`b] dari [Ishaq bin Yazid Al Hudzali] dari [Aun bin Abdullah bin Utbah] dari [Ibnu Mas'ud] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian rukuk maka ucapkanlah; SUBHAANA RABBIYA AL 'AZHIIM (Maha Suci Rabbku Yang Maha Agung) sebanyak tiga kali, jika melakukan seperti itu maka telah sempurna rukuknya. Dan apabila sujud, maka ucapkanlah \"SUBHAANA RABBIYA AL A'LAA (Maha Suci Rabbku Yang Maha Tinggi) sebanyak tiga kali, jika melakukan itu maka telah sempurna sujudnya. Dan itu adalah bacaan yang paling ringan. \""},"848":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَجَدَ أَحَدُكُمْ فَلْيَعْتَدِلْ وَلَا يَفْتَرِشْ ذِرَاعَيْهِ افْتِرَاشَ الْكَلْبِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian sujud hendaklah dengan seimbang, dan jangan membentangkan kedua tangannya seperti anjing. \" "},"849":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اعْتَدِلُوا فِي السُّجُودِ وَلَا يَسْجُدْ أَحَدُكُمْ وَهُوَ بَاسِطٌ ذِرَاعَيْهِ كَالْكَلْبِ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] berkata, telah menceritakan kepada kami [Abdul A'la] berkata, telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Anas bin Malik] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Seimbanglah kalian ketika sujud, dan janganlah salah seorang dari kalian sujud dengan membentangkan kedua sikunya sebagaimana anjing. \""},"850":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ حُسَيْنٍ الْمُعَلِّمِ عَنْ بُدَيْلٍ عَنْ أَبِي الْجَوْزَاءِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ لَمْ يَسْجُدْ حَتَّى يَسْتَوِيَ قَائِمًا وَإِذَا سَجَدَ فَرَفَعَ رَأْسَهُ لَمْ يَسْجُدْ حَتَّى يَسْتَوِيَ جَالِسًا وَكَانَ يَفْتَرِشُ رِجْلَهُ الْيُسْرَى","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yazid bin Harun] dari [Husain Al Mu'allim] dari [Budail] dari [Abu Al Jauza`] dari [Aisyah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam jika hendak mengangkat kepala dari rukuk, beliau tidak melakukannya hingga tegak dan seimbang. Dan jika beliau sujud lalu mengangkat kepalanya, beliau tidak (akan) sujud hingga duduk dan seimbang, dan beliau membentangkan kaki kirinya. \""},"851":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا ��ُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ الْحَارِثِ عَنْ عَلِيٍّ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُقْعِ بَيْنَ السَّجْدَتَيْنِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Ubaidullah bin Musa] dari [Isra'il] dari [Abu Ishaq] dari [Al Harits] dari [Ali] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Janganlah duduk Iq'a (duduk dengan meletakkan bokong pada lantai dan menegakkan kedua betis) di antara dua sujud. \""},"852":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ ثَوَابٍ حَدَّثَنَا أَبُو نُعَيْمٍ النَّخَعِيُّ عَنْ أَبِي مَالِكٍ عَنْ عَاصِمِ بْنِ كُلَيْبٍ عَنْ أَبِيهِ عَنْ أَبِي مُوسَى وَأَبِي إِسْحَقَ عَنْ الْحَارِثِ عَنْ عَلِيٍّ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عَلِيُّ لَا تُقْعِ إِقْعَاءَ الْكَلْبِ","id":"Telah menceritakan kepada kami [Muhammad bin Tsawab] berkata, telah menceritakan kepada kami [Abu Nu'aim An Nakha'i] dari [Abu Malik] dari ['Ashim bin Kulaib] dari [Bapaknya] dari [Abu Musa] dan [Abu Ishaq] dari [Al Harits] dari [Ali] ia berkata; \"Nabi shallallahu 'alaihi wasallam bersabda: \"Hai Ali, janganlah duduk seperti duduknya anjing (dalam shalat). \""},"853":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ مُحَمَّدِ بْنِ الصَّبَّاحِ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا الْعَلَاءُ أَبُو مُحَمَّدٍ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُقَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَفَعْتَ رَأْسَكَ مِنْ السُّجُودِ فَلَا تُقْعِ كَمَا يُقْعِي الْكَلْبُ ضَعْ أَلْيَتَيْكَ بَيْنَ قَدَمَيْكَ وَأَلْزِقْ ظَاهِرَ قَدَمَيْكَ بِالْأَرْضِ","id":"Telah menceritakan kepada kami [Al Hasan bin Muhammad bin Ash Shabbah] berkata, telah menceritakan kepada kami [Yazid bin Harun] berkata, telah memberitakan kepada kami [Al 'Ala Abu Muhammad] ia berkata; aku mendengar [Anas bin Malik] berkata; Nabi shallallahu 'alaihi wasallam bersabda kepadaku: \"Apabila kamu mengangkat kepalamu dari sujud, maka jangan duduk sebagaimana duduknya anjing. Letakkanlah bokongmu di antara kedua kaki, dan tempelkan bagian atas kedua kakimu ke tanah. \""},"854":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ حَدَّثَنَا الْعَلَاءُ بْنُ الْمُسَيَّبِ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ طَلْحَةَ بْنِ يَزِيدَ عَنْ حُذَيْفَةَ ح و حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ الْأَعْمَشِ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ الْمُسْتَوْرِدِ بْنِ الْأَحْنَفِ عَنْ صِلَةَ بْنِ زُفَرَ عَنْ حُذَيْفَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ بَيْنَ السَّجْدَتَيْنِ رَبِّ اغْفِرْ لِي رَبِّ اغْفِرْ لِي","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Hafsh bin Ghiyats] berkata, telah menceritakan kepada kami [Al 'Ala Ibnul Musayyab] dari [Amru bin Murrah] dari [Thalhah bin Yazid] dari [Hudzaifah]. (dalam jalur yang lain disebutkan; Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Hafsh bin Ghiyat] dari [Al A'masy] dari [Sa'd bin Ubaidah] dari [Al Mustaurid Ibnul Ahnaf] dari [Shillah bin Zufar] dari [Hudzaifah] berkata; \"Ketika duduk antara dua sujud Nabi shallallahu 'alaihi wasallam mengucapkan: \"RABBIGHFIRLI RABBIGHFIRLI (Ya Allah ampunilah aku, Ya Allah ampunilah aku). \" "},"855":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا إِسْمَعِيلُ بْنُ صَبِيحٍ عَنْ كَامِلٍ أَبِي الْعَلَاءِ قَالَ سَمِعْتُ حَبِيبَ بْنَ أَبِي ثَابِتٍ يُحَدِّثُ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ بَيْنَ السَّجْدَتَيْنِ فِي صَلَاةِ اللَّيْلِ رَبِّ اغْفِرْ لِي وَارْحَمْنِي وَاجْبُرْنِي وَارْزُقْنِي وَارْفَعْنِي","id":"Telah menceritakan kepada kami [Abu Kuraib Muhammad bin Al 'Ala] berkata, telah menceritakan kepada kami [Isma'il bin Shubaih] dari [Kamil Abul 'Ala] ia berkata; aku mendengar [Habib bin Abu Tsabit] menceritakan dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata; \"Dalam shalat malam Rasulullah shallallahu 'alaihi wasallam membaca di antara dua sujud; \"RABBIGHFIRLI, WARHAMNI, WAJBURNI, WARZUQNI, WARFA'NI\" (Wahai Tuhanku, ampunilah aku, rahmatilah aku, perbaikilah keraguanku, limpahkanlah rizkiku dan angkatlah derajatku). \""},"856":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقِ بْنِ سَلَمَةَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ خَلَّادٍ الْبَاهِلِيُّ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَكُنَّا إِذَا صَلَّيْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْنَا السَّلَامُ عَلَى اللَّهِ قَبْلَ عِبَادِهِ السَّلَامُ عَلَى جِبْرَائِيلَ وَمِيكَائِيلَ وَعَلَى فُلَانٍ وَفُلَانٍ يَعْنُونَ الْمَلَائِكَةَ فَسَمِعَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَا تَقُولُوا السَّلَامُ عَلَى اللَّهِ فَإِنَّ اللَّهَ هُوَ السَّلَامُ فَإِذَا جَلَسْتُمْ فَقُولُوا التَّحِيَّاتُ لِلَّهِ وَالصَّلَوَاتُ وَالطَّيِّبَاتُ السَّلَامُ عَلَيْكَ أَيُّهَا النَّبِيُّ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ السَّلَامُ عَلَيْنَا وَعَلَى عِبَادِ اللَّهِ الصَّالِحِينَ فَإِنَّهُ إِذَا قَالَ ذَلِكَ أَصَابَتْ كُلَّ عَبْدٍ صَالِحٍ فِي السَّمَاءِ وَالْأَرْضِ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُحَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا الثَّوْرِيُّ عَنْ مَنْصُورٍ وَالْأَعْمَشِ وُحُصَيْنٍ وَأَبِي هَاشِمٍ وَحَمَّادٌ عَنْ أَبِي وَائِلٍ وَعَنْ أَبِي إِسْحَقَ عَنْ الْأَسْوَدِ وَأَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ حَدَّثَنَا مُحَمَّدُ بْنُ مَعْمَرٍ حَدَّثَنَا قَبِيصَةُ أَنْبَأَنَا سُفْيَانُ عَنْ الْأَعْمَشِ وَمَنْصُورٍ وَحُصَيْنٍ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ ح قَالَ و حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي عُبَيْدَةَ وَالْأَسْوَدِ وَأَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُعَلِّمُهُمْ التَّشَهُّدَ فَذَكَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] berkata, telah menceritakan kepada kami [Bapakku] berkata, telah menceritakan kepada kami [Al A'masy] dari [Syaqiq bin Salamah] dari [Abdullah bin Mas'ud]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abu Bakr bin Khallad Al bahili] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] berkata, telah menceritakan kepada kami [Al A'masy] dari [Syaqiq] dari [Abdullah bin Mas'ud] ia berkata; \"Jika kami shalat bersama Nabi shallallahu 'alaihi wasallam, kami mengucapkan; AS SALAAMU 'ALA ALLAHI QABLA IBAADIHI, AS SALAAMU 'ALA JIBRA`IIL WA MIKAA`IIL WA 'ALA FULAN WA FULAN -yang mereka maksud adalah para malaikat-. Lalu hal itu didengar oleh Rasulullah shallallahu 'alaihi wasallam, maka beliau pun bersabda: \"Janganlah kalian ucapkan AS SALAAMU 'ALA ALLAHI, sebab AS SALAAMU adalah Allah. Jika kalian duduk (tasyahud) maka ucapkanlah; AT TAHIYYATU LILLAH WASH SHALAWATU WATH THAYYIBAT AS SALAAMU 'ALAIKA AYYUHAN NABIU WA RAHMATULLAHI WA BARAKA'ATUH, AS SALAAMU 'ALAINA WA 'ALA IBAADILAHISH SHALIHIIN (Segala penghormatan milik Allah, shalat dan amal shalih. Semoga keselamatan, rahmat dan berkah Allah limpahkan kepadamu, wahai Nabi -shallallahu 'alaihi wasallam- dan juga kepada hamba-hamba Allah yang shalih). Sungguh, jika ia mengucapkan seperti itu, maka hal itu akan mencakup seluruh hamba yang shalih baik di langit maupun di bumi. ASYHADU AN LAA ILAAHA ILLAALLAHU WA ASYHADU ANNA MUHAMMADAN 'ANDUHU WA RASUULUHU (Aku bersaksi bahwa tidak ada Tuhan selain Allah, dan aku bersaksi bahwa Muhammad adalah hamba dan Rasul-Nya). \" Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Abdurrazaq] berkata, telah menceritakan kepada kami [Ats Tsauri] dari [Manshur] dan [Al A'masy] dan [Hushain] dan [Abu Hasyim] dan [Hammad] dari [Abu Wa`il] dari [Abu Ishaq] dari [Al Aswad] dari [Abul Ahwash] dari [Abdullah bin Mas'ud] dari Nabi shallallahu 'alaihi wasallam sebagaimana dalam hadits. Telah menceritakan kepada kami [Muhammad bin Ma'mar] berkata, telah menceritakan kepada kami [Qabishah] berkata, telah memberitakan kepada kami [Sufyan] dari [Al A'masy] dan [Manshur] dari [Hushain] dari [Abu Wa`il] dari [Abdullah bin Mas'ud]. (dalam jalur lain disebutkan) Ia berkata; telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq] dari [Abu Ubaidah] dari [Al Aswad] dari [Abul Al Ahwash] dari [Abdullah bin Mas'ud] bahwa Nabi shallallahu 'alaihi wasallam mengajari mereka tasyahud, lalu ia menyebutkan sebagaimana dalam hadits. \""},"857":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ أَبِي الزُّبَيْرِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ وَطَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعَلِّمُنَا التَّشَهُّدَ كَمَا يُعَلِّمُنَا السُّورَةَ مِنْ الْقُرْآنِ فَكَانَ يَقُولُ التَّحِيَّاتُ الْمُبَارَكَاتُ الصَّلَوَاتُ الطَّيِّبَاتُ لِلَّهِ السَّلَامُ عَلَيْكَ أَيُّهَا النَّبِيُّ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ السَّلَامُ عَلَيْنَا وَعَلَى عِبَادِ اللَّهِ الصَّالِحِينَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Abu Az Zubair] dari [Sa'id bin Jubair] dan [Thawus] dari [Ibnu Abbas] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam mengajari kami tasyahud sebagaimana mengajari kami surat al Qur`an, beliau mengucapkan: \"ATTAHIYYAATUL MUBAARAKA'ATUSH SHALWAATUTH THAYYIBAATU LILAHI AS SALAAMU 'ALAIKA AYYUHAN NABIYYU WA RAHNMATULLAHI WA BARAKA'ATUH AS SALAAMU 'ALAINA WA 'ALAA 'IBAADILLAHISH SHAALIHIIN ASYHADU AN LAA ILAAHA ILLA ALLAHU WA ASYHADU ANNA MUHAMMADAN 'ABDUHUU WA RASUULUH (Segala penghormatan, keberkahan, shalat dan amal shalih hanya milik Allah. Semoga keselamatan, rahmat dan berkah Allah limpahkan kepadamu, wahai Nabi -shallallahu 'alaihi wasallam- dan juga kepada hamba-hamba Allah yang shalih. Aku bersaksi bahwa tidak ada Tuhan selain Allah, dan aku bersaksi bahwa Muhammad adalah hamba dan Rasul-Nya). \""},"858":{"ar":"حَدَّثَنَا جَمِيلُ بْنُ الْحَسَنِ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ ح و حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عُمَرَ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ وَهِشَامُ بْنُ أَبِي عَبْدِ اللَّهِ عَنْ قَتَادَةَ وَهَذَا حَدِيثُ عَبْدِ الرَّحْمَنِ عَنْ يُونُسَ بْنِ جُبَيْرٍ عَنْ حِطَّانَ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطَبَنَا وَبَيَّنَ لَنَا سُنَّتَنَا وَعَلَّمَنَا صَلَاتَنَا فَقَالَ إِذَا صَلَّيْتُمْ فَكَانَ عِنْدَ الْقَعْدَةِ فَلْيَكُنْ مِنْ أَوَّلِ قَوْلِ أَحَدِكُمْ التَّحِيَّاتُ الطَّيِّبَاتُ الصَّلَوَاتُ لِلَّهِ السَّلَامُ عَلَيْكَ أَيُّهَا النَّبِيُّ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ السَّلَامُ عَلَيْنَا وَعَلَى عِبَادِ اللَّهِ الصَّالِحِينَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ سَبْعُ كَلِمَاتٍ هُنَّ تَحِيَّةُ الصَّلَاةِ","id":"Telah menceritakan kepada kami [Jamil Ibnul Hasan] berkata, telah menceritakan kepada kami [Abdul A'la] berkata, telah menceritakan kepada kami [Sa'id] dari [Qatadah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami ['Abdurrahman bin Umar] berkata, telah menceritakan kepada kami [Ibnu Abu Adi] berkata, telah menceritakan kepada kami [Sa'id bin Abu Arubah] dan [Hisyam bin Abu Abdullah] dari [Qatadah], dan ini adalah hadits 'Abdurrahman, dari [Yunus bin Jubair] dari [Hithan bin Abdullah] dari [Abu Musa Al Asy'ari] berkata; \"Rasulullah shallallahu 'alaihi wasallam berkhutbah di hadapan kami, menjelaskan sunnah dan mengajari shalat kami. Beliau bersabda: \"Jika kalian melaksanakan shalat dan duduk di tasyahud, maka hendaklah pertama kali yang kalian ucapkan adalah; \"ATTAHIYYAATUTH THAYYIBAATUSH SHALAWAATU LILLAH AS SALAAMU 'ALAIKA AYYUHAN NABIYYU WA RAHNMATULLAHI WA BARAKA'ATUH AS SALAAMU 'ALAINA WA 'ALAA 'IBAADILLAHISH SHAALIHIIN ASYHADU AN LAA ILAAHA ILLA ALLAHU WA ASYHADU ANNA MUHAMMADAN 'ABDUHUU WA RASUULUH (Segala penghormatan, amal shalih dan shalat hanya milik Allah. Semoga keselamatan, rahmat dan berkah Allah limpahkan kepadamu, wahai Nabi -shallallahu 'alaihi wasallam- dan juga kepada hamba-hamba Allah yang shalih. Aku bersaksi bahwa tidak ada Tuhan selain Allah, dan aku bersaksi bahwa Muhammad adalah hamba dan Rasul-Nya). \" Tujuh kalimat itulah pembuka shalat. \""},"859":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ زِيَادٍ حَدَّثَنَا الْمُعْتَمِرُ بْنُ سُلَيْمَانَ ح و حَدَّثَنَا يَحْيَى بْنُ حَكِيمٍ حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ قَالَا حَدَّثَنَا أَيْمَنُ بْنُ نَابِلٍ حَدَّثَنَا أَبُو الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعَلِّمُنَا التَّشَهُّدَ كَمَا يُعَلِّمُنَا السُّورَةَ مِنْ الْقُرْآنِ بِاسْمِ اللَّهِ وَبِاللَّهِ التَّحِيَّاتُ لِلَّهِ وَالصَّلَوَاتُ وَالطَّيِّبَاتُ لِلَّهِ السَّلَامُ عَلَيْكَ أَيُّهَا النَّبِيُّ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ السَّلَامُ عَلَيْنَا وَعَلَى عِبَادِ اللَّهِ الصَّالِحِينَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ أَسْأَلُ اللَّهَ الْجَنَّةَ وَأَعُوذُ بِاللَّهِ مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Muhammad bin Ziyad] berkata, telah menceritakan kepada kami [Al Mu'tamar bin Sulaiman]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Yahya bin Hakim] berkata, telah menceritakan kepada kami [Muhammad bin Bakr] keduanya berkata; telah menceritakan kepada kami [Aiman bin Nabil] berkata, telah menceritakan kepada kami [Abu Zubair] dari [Jabir bin Abdullah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam mengajarkan kami tasyahud sebagaimana mengajarkan kami surat dari Al Qur`an: BISMILLAH, WABILLAH, AT TAHIYYAATU LILLAH, WASH SHALAWAATU WATH THAYYIBAATU LILLAH, ASSALAAMU 'ALAIKA AYYUHAN NABIYYU WA RAHMATULLAHI WA BARAKA'ATUH, ASSALAMU ALAINAA WA 'ALA IBAADILLAHISH SHALIHIIN. ASYHADU AN LAA ILAAHA ILLALLAH WA ASYHADU ANNA MUHAMMADAN ABDUHUU WA RASUULUH. AS`ALULLAHA AL JANNAH WA A'UUDZU BILLAHI MINAN NAAR (Dengan nama Allah, dan karena Allah. Segala penghormatan hanya untuk Allah, shalawat beserta kebaikan itu hanya milik Allah. Semoga kesejahteraan tercurahkan atasmu wahai Nabi, begitu juga dengan rahmat dan keberkahan dari Allah atasmu. Semoga kesejahteraan juga dicurahkan kepada kami dan hamba-hamba Allah yang shalih. Aku bersaksi bahwa tidak ada Tuhan yang berhak disembah kecuali Allah. Dan aku bersaksi bahwa Muhammad adalah hamba dan utusan-Nya. Aku memohon kepada Allah surga dan berlindung kepada Allah dari neraka). \""},"860":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ ح و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا أَبُو عَامِرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ جَعْفَرٍ عَنْ يَزِيدَ بْنِ الْهَادِ عَنْ عَبْدِ اللَّهِ بْنِ خَبَّابٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقُلْنَا يَا رَسُولَ اللَّهِ هَذَا السَّلَامُ عَلَيْكَ قَدْ عَرَفْنَاهُ فَكَيْفَ الصَّلَاةُ قَالَ قُولُوا اللَّهُمَّ صَلِّ عَلَى مُحَمَّدٍ عَبْدِكَ وَرَسُولِكَ كَمَا صَلَّيْتَ عَلَى إِبْرَاهِيمَ وَبَارِكْ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ كَمَا بَارَكْتَ عَلَى إِبْرَاهِيمَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Khalid bin Makhlad]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad Ibnul Mutsanna] berkata, telah menceritakan kepada kami [Abu Amir] berkata; telah memberitakan kepada kami [Abdullah bin Ja'far] dari [Yazid Ibnul Had] dari [Abdullah bin Khabbab] dari [Abu Sa'id Al Khudzri] ia berkata; \"Kami berkata; \"Wahai Rasulullah, salam kepadamu ini kami telah mengetahuinya, lalu bagaimana cara bershalawat kepadamu?\" beliau menjawab: \"Ucapkanlah; ALLAHUMMA SHALLI 'ALA MUHAMMADIN ABDIKA WA RASUULIKA KAMAA SHALLAITA 'ALA IBRAHIM WA BAARIK 'ALA MUHAMMADIN WA 'ALA ALI MUHAMMADIN KAMAA BAARAKTA 'ALA IBRAHIM (Ya Allah, berilah shalawat kepada Muhammad, hamba dan Rasul-Mu, sebagaimana Engkau memberi shalawat kepada Ibrahim. Dan berkahilah Muhammad dan keluarganya sebagaimana Engkau memberkahi Ibrahim). \""},"861":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا شُعْبَةُ ح و حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ وَمُحَمَّدُ بْنُ جَعْفَرٍ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ قَالَ سَمِعْتُ ابْنَ أَبِي لَيْلَى قَالَلَقِيَنِي كَعْبُ بْنُ عُجْرَةَ فَقَالَ أَلَا أُهْدِي لَكَ هَدِيَّةً خَرَجَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْنَا قَدْ عَرَفْنَا السَّلَامَ عَلَيْكَ فَكَيْفَ الصَّلَاةُ عَلَيْكَ قَالَ قُولُوا اللَّهُمَّ صَلِّ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ كَمَا صَلَّيْتَ عَلَى إِبْرَاهِيمَ إِنَّكَ حَمِيدٌ مَجِيدٌ اللَّهُمَّ بَارِكْ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ كَمَا بَارَكْتَ عَلَى إِبْرَاهِيمَ إِنَّكَ حَمِيدٌ مَجِيدٌ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Syu'bah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami ['Abdurrahman bin Mahdi] dan [Muhammad bin Ja'far] keduanya berkata; telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] ia berkata; aku mendengar [Ibnu Abu Laila] berkata; [Ka'ab bin Ujrah] menemuiku dan berkata; \"Maukah kamu aku beri suatu hadiah? Rasulullah shallallahu 'alaihi wasallam keluar menemui kami, lalu kami bertanya, \"Kami telah mengetahui bagaimana salam kepadamu, lalu bagaimana cara shalawat kepadamu?\" beliau menjawab: \"Ucapkanlah; ALLAHUMMA SHALLI 'ALA MUHAMMADIN WA 'ALA ALI MUHAMMADIN KAMAA SHLLAITA 'ALA IBRAHIM INNAKA HAMIDUN MAJIIDUN. ALLAHUMMA BAARIK 'ALA MUHAMMADIN WA 'ALA ALI MUHAMMADIN KAMAA BAARAKTA 'ALA IBRAHIM INNAKA HAMIIDUN MAJIIDUN (Ya Allah, berilah shalawat kepada Muhammad dan keluarganya sebagaimana Engkau memberi shalawat kepada Ibrahim dan keluarganya. Sesungguhnya Engkau Maha Terpuji dan Maha Agung. Ya Allah, berkahilah Muhammad dan keluarganya sebagaimana Engkau memberkahi Ibrahim dan keluarganya. Sesungguhnya Engkau Maha Terpuji dan Maha Agung). \""},"862":{"ar":"حَدَّثَنَا عَمَّارُ بْنُ طَالُوتَ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ عَبْدِ الْعَزِيزِ الْمَاجِشُونُ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ أَبِيهِ عَنْ عَمْرِو بْنِ سُلَيْمٍ الزُّرَقِيِّ عَنْ أَبِي حُمَيْدٍ السَّاعِدِيِّأَنَّهُمْ قَالُوا يَا رَسُولَ اللَّهِ أُمِرْنَا بِالصَّلَاةِ عَلَيْكَ فَكَيْفَ نُصَلِّي عَلَيْكَ فَقَالَ قُولُوا اللَّهُمَّ صَلِّ عَلَى مُحَمَّدٍ وَأَزْوَاجِهِ وَذُرِّيَّتِهِ كَمَا صَلَّيْتَ عَلَى إِبْرَاهِيمَ وَبَارِكْ عَلَى مُحَمَّدٍ وَأَزْوَاجِهِ وَذُرِّيَّتِهِ كَمَا بَارَكْتَ عَلَى آلِ إِبْرَاهِيمَ فِي الْعَالَمِينَ إِنَّكَ حَمِيدٌ مَجِيدٌ","id":"Telah menceritakan kepada kami [Ammar bin Thalut] berkata, telah menceritakan kepada kami [Abdul Malik bin Abdul Aziz Al Majisyun] berkata, telah menceritakan kepada kami [Malik bin Anas] dari [Abdulah bin Abu Bakr bin Muhammad bin Amru bin Hazm] dari [Bapaknya] dari [Amru bin Sulaim Az Zuraqi] dari [Abu Humaid As Sa'idi] bahwasanya mereka berkata; \"Wahai Rasulullah, kami diperintahkan untuk bershalawat kepadamu, lalu bagaimana cara kami bershalawat?\" beliau menjawab: \" Ucapkanlah; ALLAHUMMA SHALLI 'ALA MUHAMMADIN WA AZAWAAJIHI WA DZURRIYATIHI KAMAA SHALLAITA 'ALA IBRAHIM WA BAARIK 'ALA MUHAMMADIN WA AZWAAJIHI WA DZURRIAYITIHI KAMAA BAARAKTA 'ALA ALI IBRAHIM FIL 'ALAMIINA INNAKA HAMIIDUN MAJIIDUN (Ya Allah, berilah shalawat kepada Muhammad, isteri-isteri dan keturunannya sebagaimana Engkau bershalawat kepada Ibrahim. Dan berkahilah Muhammad, isteri-isteri dan keturunannya sebagaimana Engkau memberkahi Ibrahim dan keluarganya di antara manusia sealam raya. Sesungguhnya Engkau Maha Terpuji dan Maha Agung. \""},"863":{"ar":"حَدَّثَنَا الْحُسَيْنُ بْنُ بَيَانٍ حَدَّثَنَا زِيَادُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا الْمَسْعُودِيُّ عَنْ عَوْنِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي فَاخِتَةَ عَنْ الْأَسْوَدِ بْنِ يَزِيدَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَإِذَا صَلَّيْتُمْ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَحْسِنُوا الصَّلَاةَ عَلَيْهِ فَإِنَّكُمْ لَا تَدْرُونَ لَعَلَّ ذَلِكَ يُعْرَضُ عَلَيْهِ قَالَ فَقَالُوا لَهُ فَعَلِّمْنَا قَالَ قُولُوا اللَّهُمَّ اجْعَلْ صَلَاتَكَ وَرَحْمَتَكَ وَبَرَكَاتِكَ عَلَى سَيِّدِ الْمُرْسَلِينَ وَإِمَامِ الْمُتَّقِينَ وَخَاتَمِ النَّبِيِّينَ مُحَمَّدٍ عَبْدِكَ وَرَسُولِكَ إِمَامِ الْخَيْرِ وَقَائِدِ الْخَيْرِ وَرَسُولِ الرَّحْمَةِ اللَّهُمَّ ابْعَثْهُ مَقَامًا مَحْمُودًا يَغْبِطُهُ بِهِ الْأَوَّلُونَ وَالْآخِرُونَ اللَّهُمَّ صَلِّ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ كَمَا صَلَّيْتَ عَلَى إِبْرَاهِيمَ وَعَلَى آلِ إِبْرَاهِيمَ إِنَّكَ حَمِيدٌ مَجِيدٌ اللَّهُمَّ بَارِكْ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ كَمَا بَارَكْتَ عَلَى إِبْرَاهِيمَ وَعَلَى آلِ إِبْرَاهِيمَ إِنَّكَ حَمِيدٌ مَجِيدٌ","id":"Telah menceritakan kepada kami [Al Husain bin Bayan] berkata, telah menceritakan kepada kami [Ziyad bin Abdullah] berkata, telah menceritakan kepada kami [Al Mas'udi] dari [Aun bin Abdullah] dari [Abu Fakhitah] dari [Al Aswad bin Yazid] dari [Abdullah bin Mas'ud] ia berkata; \"Jika kalian membaca shalawat kepada Rasulullah shallallahu 'alaihi wasallam maka baguskanlah, sebab kalian tidak tahu, bisa jadi shalawat itu dihadirkan di hadapannya (Rasulullah). \" Al Aswad berkata; \"Orang-orang pun berkata Abdullah bin Mas'ud, \"Ajarkanlah kepada kami, \" Abdullah bin Mas'ud berkata; \"Bacalah; ALLAHUMMA IJ'AL SHALAATAKA WA RAHMATAKA WA BARAKA'ATIKA 'ALA SAYYIDIL MURSALIIN WA IMAAMIL MUTTAQIIN WA KHAATAMIN NABIYYIN MUHAMMADIN 'ABDIKA WA RASUULIKA IMAAMIL KHAIRI WA QAA`IDIL KHAIRI WA RASUULIR RAHMAH. ALLAHUMMAB'ATSHU MAQAAMAN MAHMUUDAN YAGHBITHUHU BIHIL AWWALIIN WAL AKHIRIIN. ALLAHUMMA SHALLI 'ALA MUHAMMADIN WA 'ALA ALI MUHAMMADIN KAMAA SHALLAITA 'ALA IBRAHIM WA 'ALA ALI IBRAHIM INNAKA HAMIIDUN MAJIIDUN. ALLAHUMMA BAARIK 'ALA MUHAMMAD WA 'ALA ALI MUHAMMADIN KAMAA BAARAKTA 'ALA IBRAHIM WA 'ALA ALI IBRAHIM INNAKA HAMIIDUN MAJIIDUN (Ya Allah, jadikanlah shalawat, rahmat dan berkah-Mu kepada pemimpin para Nabi yang diutus, imam orang-orang yang bertakwa dan penutup para Nabi, Muhammad, hamba dan rasul-Mu. Seorang imam dan pemimpin kebaikan, serta rasul pembawa rahmat. Ya Allah, bangkitkanlah ia pada kedudukan yang terpuji, kedudukan yang menjadikan iri orang-orang terdahulu dan yang akan datang. Ya Allah, berilah shalawat kepada Muhammad dan keluarganya sebagaimana Engkau memberi shalawat kepada Ibrahim dan keluarganya. Sesungguhnya Engkau Maha Terpuji dan Maha Agung. Ya Allah, berkahilah Muhammad dan keluarganya sebagaimana Engkau telah memberkahi Ibrahim dan keluarganya. Sesungguhnya Engkau Maha Terpuji dan Maha Agung. \""},"864":{"ar":"حَدَّثَنَا بَكْرُ بْنُ خَلَفٍ أَبُو بِشْرٍ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ عَنْ شُعْبَةَ عَنْ عَاصِمِ بْنِ عُبَيْدِ اللَّهِ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عَامِرِ بْنِ رَبِيعَةَ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا مِنْ مُسْلِمٍ يُصَلِّي عَلَيَّ إِلَّا صَلَّتْ عَلَيْهِ الْمَلَائِكَةُ مَا صَلَّى عَلَيَّ فَلْيُقِلَّ الْعَبْدُ مِنْ ذَلِكَ أَوْ لِيُكْثِرْ","id":"Telah menceritakan kepada kami [Bakr bin Khalaf Abu Bisyr] berkata, telah menceritakan kepada kami [Khalid bin Al Harits] dari [Syu'bah] dari [Ashim bin Ubaidullah] ia berkata; aku mendengar [Abdullah bin Amir bin Rabi'ah] dari [Bapaknya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidaklah seorang muslim bershalawat kepadaku kecuali para malaikat akan mendo'akan kepadanya sebagaimana ia bershalawat kepadaku, maka ucapkanlah shalawat baik sedikit atau banyak. \""},"865":{"ar":"حَدَّثَنَا جُبَارَةُ بْنُ الْمُغَلِّسِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ جَابِرِ بْنِ زَيْدٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ نَسِيَ الصَّلَاةَ عَلَيَّ خَطِئَ طَرِيقَ الْجَنَّةِ","id":"Telah menceritakan kepada kami [Jubarah bin Al Mughallas] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Amru bin Dinar] dari [Jabir bin Zaid] dari [Ibnu Abbas] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa lupa bershalawat kepadaku, maka ia akan keliru menempuh jalan ke surga. \""},"866":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنِي حَسَّانُ بْنُ عَطِيَّةَ حَدَّثَنِي مُحَمَّدُ بْنُ أَبِي عَائِشَةَ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا فَرَغَ أَحَدُكُمْ مِنْ التَّشَهُّدِ الْأَخِيرِ فَلْيَتَعَوَّذْ بِاللَّهِ مِنْ أَرْبَعٍ مِنْ عَذَابِ جَهَنَّمَ وَمِنْ عَذَابِ الْقَبْرِ وَمِنْ فِتْنَةِ الْمَحْيَا وَالْمَمَاتِ وَمِنْ فِتْنَةِ الْمَسِيحِ الدَّجَّالِ","id":"Telah menceritakan kepada kami ['Abdurrahman bin Ibrahim Ad Dimasyqi] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Al Auza'i] berkata, telah menceritakan kepadaku [Hassan bin Athiah] berkata, telah menceritakan kepadaku [Muhammad bin Abu Aisyah] ia berkata; \"Aku mendengar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian selesai membaca tasyahud akhir hendaklah berlindung kepada Allah dari empat perkara; dari siksa neraka jahannam, siksa kubur, fitnah kehidupan dan fitnah setelah mati serta dari fitnah Al Masih Dajjal. \" "},"867":{"ar":"حَدَّثَنَا يُوسُفُ بْنُ مُوسَى الْقَطَّانُ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِرَجُلٍ مَا تَقُولُ فِي الصَّلَاةِ قَالَ أَتَشَهَّدُ ثُمَّ أَسْأَلُ اللَّهَ الْجَنَّةَ وَأَعُوذُ بِهِ مِنْ النَّارِ أَمَا وَاللَّهِ مَا أُحْسِنُ دَنْدَنَتَكَ وَلَا دَنْدَنَةَ مُعَاذٍ فَقَالَ حَوْلَهَا نُدَنْدِنُ","id":"Telah menceritakan kepada kami [Yusuf bin Musa Al Qaththan] berkata, telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bertanya seorang laki-laki: \"Apa yang engkau baca ketika shalat?\" ia menjawab, \"Aku membaca tasyahud, kemudian meminta surga kepada Allah dan berlindung kepada-Nya dari neraka. Namun demi Allah, aku tidak dapat mendengar dandanahmu dan juga dandanah Mu'adz. \" Beliau lantas bersabda: \"Aku melakukan dandanah seputar surga (atau neraka). \" "},"868":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ عِصَامِ بْنِ قُدَامَةَ عَنْ مَالِكِ بْنِ نُمَيْرٍ الْخُزَاعِيِّ عَنْ أَبِيهِ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاضِعًا يَدَهُ الْيُمْنَى عَلَى فَخِذِهِ الْيُمْنَى فِي الصَّلَاةِ وَيُشِيرُ بِإِصْبَعِهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Waki'] dari [Isham bin Qudamah] dari [Malik bin Numair Al Khuza'i] dari [Bapaknya] ia bersabda, \"Dalam shalat aku melihat Nabi shallallahu 'alaihi wasallam meletakkan tangan kanan di atas paha kanannya dan berisyarat dengan jari. \""},"869":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ عَاصِمِ بْنِ كُلَيْبٍ عَنْ أَبِيهِ عَنْ وَائِلِ بْنِ حُجْرٍ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ حَلَّقَ بِالْإِبْهَامِ وَالْوُسْطَى وَرَفَعَ الَّتِي تَلِيهِمَا يَدْعُو بِهَا فِي التَّشَهُّدِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Abdullah bin Idris] dari ['Ashim bin Kulaib] dari [Bapaknya] dari [Wa`il bin Hujr] ia berkata, \"Aku melihat Nabi shallallahu 'alaihi wasallam melingkarkan antara ibu jari dan jari tengah, lalu mengangkat jari setelahnya (telunjuk), beliau berdo'a dengan itu saat tasyahud. \""},"870":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى وَالْحَسَنُ بْنُ عَلِيٍّ وَإِسْحَقُ بْنُ مَنْصُورٍ قَالُوا حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا جَلَسَ فِي الصَّلَاةِ وَضَعَ يَدَيْهِ عَلَى رُكْبَتَيْهِ وَرَفَعَ إِصْبَعَهُ الْيُمْنَى الَّتِي تَلِي الْإِبْهَامَ فَيَدْعُو بِهَا وَالْيُسْرَى عَلَى رُكْبَتِهِ بَاسِطَهَا عَلَيْهَا","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] dan [Al Hasan bin Ali] dan [Ishaq bin Manshur] mereka berkata; telah menceritakan kepada kami [Abdurrazaq] berkata, telah menceritakan kepada kami [Ma'mar] dari [Ubaidullah] dari [Nafi'] dari [Ibnu Umar] berkata, \"Nabi shallallahu 'alaihi wasallam apabila duduk dalam shalat beliau meletakkan kedua tangan di atas kedua pahanya, lalu beliau mengangkat jari kanannya, yakni jari setelah ibu jari (telunjuk) dan berdo`a dengannya. Sedangkan tangan kirinya di atas paha sebelah kiri dengan posisi membentang. \""},"871":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا عُمَرُ بْنُ عُبَيْدٍ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُسَلِّمُ عَنْ يَمِينِهِ وَعَنْ شِمَالِهِ حَتَّى يُرَى بَيَاضُ خَدِّهِ السَّلَامُ عَلَيْكُمْ وَرَحْمَةُ اللَّهِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] berkata, telah menceritakan kepada kami [Umar bin Ubaid] dari [Abu Ishaq] dari [Abu Al Ahwash] dari [Abdullah] berkata, \"Rasulullah shallallahu 'alaihi wasallam ketika salam berpaling ke kanan dan ke kiri hingga terlihat putih pipinya, beliau mengucapkan; ASSALAAMU 'ALAIKUM WA RAHMATULLAH (Semoga kesejahteraan dan rahmat Allah tercurahkan kepadamu). \""},"872":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا بِشْرُ بْنُ السَّرِيِّ عَنْ مُصْعَبِ بْنِ ثَابِتِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ إِسْمَعِيلَ بْنِ مُحَمَّدِ بْنِ سَعْدِ بْنِ أَبِي وَقَّاصٍ عَنْ عَامِرِ بْنِ سَعْدٍ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُسَلِّمُ عَنْ يَمِينِهِ وَعَنْ يَسَارِهِ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] berkata, telah menceritakan kepada kami [Bisyr bin As Sari] dari [Mush'ab bin Tsabit bin Abdullah bin Az Zubair] dari [Isma'il bin Sa'd bin Abi Waqash] dari [Amir bin Sa'd] dari [Bapaknya] berkata, \"Rasulullah shallallahu 'alaihi wasallam ketika salam berpaling ke kanan dan ke kiri. \""},"873":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ أَبِي إِسْحَقَ عَنْ صِلَةَ بْنِ زُفَرَ عَنْ عَمَّارِ بْنِ يَاسِرٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُسَلِّمُ عَنْ يَمِينِهِ وَعَنْ يَسَارِهِ حَتَّى يُرَى بَيَاضُ خَدِّهِ السَّلَامُ عَلَيْكُمْ وَرَحْمَةُ اللَّهِ السَّلَامُ عَلَيْكُمْ وَرَحْمَةُ اللَّهِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Yahya bin Adam] berkata, telah menceritakan kepada kami [Abu Bakr bin 'Ayyasy] dari [Abu Ishaq] dari [Shilah bin Zufar] dari [Ammar bin Yasir] ia berkata, \"Ketika salam Rasulullah shallallahu 'alaihi wasallam berpaling ke kanan dan ke kiri hingga terlihat putih pipinya dengan mengucapkan; ASSALAAMU 'ALAIKUM WARadhiallahu'anhuHMATULLAH, ASSALAAMU 'ALAIKUM WARAHMATULLAH (Semoga kesejahteraan dan rahmat Allah tercurahkan kepadamu. Semoga kesejahteraan dan rahmat Allah tercurahkan kepadamu). \""},"874":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَامِرِ بْنِ زُرَارَةَ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ أَبِي إِسْحَقَ عَنْ بُرَيْدِ بْنِ أَبِي مَرْيَمَ عَنْ أَبِي مُوسَى قَالَصَلَّى بِنَا عَلِيٌّ يَوْمَ الْجَمَلِ صَلَاةً ذَكَّرَنَا صَلَاةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِمَّا أَنْ نَكُونَ نَسِينَاهَا وَإِمَّا أَنْ نَكُونَ تَرَكْنَاهَا فَسَلَّمَ عَلَى يَمِينِهِ وَعَلَى شِمَالِهِ","id":"Telah menceritakan kepada kami [Abdullah bin Amir bin Zurarah] berkata, telah menceritakan kepada kami [Abu Bakr bin 'Ayyasy] dari [Abu Ishaq] dari [Buraid bin Abu Maryam] dari [Abu Musa] dia berkata, \"Ali shalat mengimami kami pada saat perang Jamal, shalat yang mengingatkan kami akan shalat Rasulullah shallallahu 'alaihi wasallam. Entah karena kami lupa atau karena kami meningggalkannya. Maka dia mengucapkan salam ke sebelah kanan dan ke sebelah kirinya. \" "},"875":{"ar":"حَدَّثَنَا أَبُو مُصْعَبٍ الْمَدِينِيُّ أَحْمَدُ بْنُ أَبِي بَكْرٍ حَدَّثَنَا عَبْدُ الْمُهَيْمِنِ بْنُ عَبَّاسِ بْنِ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيُّ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَلَّمَ تَسْلِيمَةً وَاحِدَةً تِلْقَاءَ وَجْهِهِ","id":"Telah menceritakan kepada kami [Abu Mush'ab Al Madini Ahmad bin Abu Bakr] berkata, telah menceritakan kepada kami [Abdul Muhaimin bin Abbas bin Sahl bin Sa'd As Sa'idi] dari [Bapaknya] dari [Kakeknya] berkata, \"Rasulullah shallallahu 'alaihi wasallam mengucapkan satu salam dengan menghadapkan wajahnya ke depan. \""},"876":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ مُحَمَّدٍ الصَّنْعَانِيُّ حَدَّثَنَا زُهَيْرُ بْنُ مُحَمَّدٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُسَلِّمُ تَسْلِيمَةً وَاحِدَةً تِلْقَاءَ وَجْهِهِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Abdul Malik bin Muhammad Ash Shan'ani] berkata, telah menceritakan kepada kami [Zuhair bin Muhammad] dari [Hisyam bin Urwah] dari [Bapaknya] dari ['Aisyah] berkata, \"Rasulullah shallallahu 'alaihi wasallam mengucapkan satu salam dengan menghadapkan wajahnya ke depan. \""},"877":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْحَارِثِ الْمِصْرِيُّ حَدَّثَنَا يَحْيَى بْنُ رَاشِدٍ عَنْ يَزِيدَ مَوْلَى سَلَمَةَ عَنْ سَلَمَةَ بْنِ الْأَكْوَعِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى فَسَلَّمَ مَرَّةً وَاحِدَةً","id":"Telah menceritakan kepada kami [Muhammad bin Al Harits Al Mishri] berkata, telah menceritakan kepada kami [Yahya bin Rasyid] dari [Yazid] mantan budak Salamah, dari [Salamah bin Al Akwa'] ia berkata, \"Aku melihat Rasulullah shallallahu 'alaihi wasallam shalat dengan mengucapkan satu kali salam. \" "},"878":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ حَدَّثَنَا أَبُو بَكْرٍ الْهُذَلِيُّ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَ بْنِ جُنْدَبٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا سَلَّمَ الْإِمَامُ فَرُدُّوا عَلَيْهِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Ismail bin 'Ayyasy] berkata, telah menceritakan kepada kami [Abu Bakr Al Hudzali] dari [Qatadah] dari [Al Hasan] dari [Samurah bin Jundub] Nabi shallallahu 'alaihi wasallam bersabda: \"Apabila imam mengucapkan salam, maka jawablah salamnya. \""},"879":{"ar":"حَدَّثَنَا عَبْدَةُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا عَلِيُّ بْنُ الْقَاسِمِ أَنْبَأَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَ بْنِ جُنْدَبٍ قَالَأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نُسَلِّمَ عَلَى أَئِمَّتِنَا وَأَنْ يُسَلِّمَ بَعْضُنَا عَلَى بَعْضٍ","id":"Telah menceritakan kepada kami ['Abdah bin Abdullah] berkata, telah menceritakan kepada kami [Ali bin Al Qasim] berkata, telah memberitakan kepada kami [Hammam] dari [Qatadah] dari [Al Hasan] dari [Samurah bin Jundub] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam memerintahkan kami untuk mengucapkan salam kepada pemimpin-pemimpin kami, dan agar sebagian kami memberi salam kepada sebagian yang lain. \" "},"880":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُصَفَّى الْحِمْصِيُّ حَدَّثَنَا بَقِيَّةُ بْنُ الْوَلِيدِ عَنْ حَبِيبِ بْنِ صَالِحٍ عَنْ يَزِيدَ بْنِ شُرَيْحٍ عَنْ أَبِي حَيٍّ الْمُؤَذِّنِ عَنْ ثَوْبَانَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَؤُمُّ عَبْدٌ فَيَخُصَّ نَفْسَهُ بِدَعْوَةٍ دُونَهُمْ فَإِنْ فَعَلَ فَقَدْ خَانَهُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mushaffa Al Himshi] berkata, telah menceritakan kepada kami [Baqiyyah bin Al Walid] dari [Habib bin Shalih] dari [Yazid bin Syuraih] dari [Abu Hayy Al Mu`adzdzin] dari [Tsauban] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang hamba tidak boleh menjadi imam kemudian mengkhususkan dirinya dalam sebuah do'a tanpa menyertakan yang lainnya, jika tetap melakukannya maka ia telah mengkhianati mereka. \""},"881":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ قَالَ حَدَّثَنَا عَاصِمٌ الْأَحْوَلُ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَلَّمَ لَمْ يَقْعُدْ إِلَّا مِقْدَارَ مَا يَقُولُ اللَّهُمَّ أَنْتَ السَّلَامُ وَمِنْكَ السَّلَامُ تَبَارَكْتَ يَا ذَا الْجَلَالِ وَالْإِكْرَامِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Mu'awiyah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Abdul Malik bin Abu Asy Syawarib] berkata, telah menceritakan kepada kami [Abdul Wahid bin Ziyad] berkata, telah menceritakan kepada kami ['Ashim Al Ahwal] dari [Abdullah bin Al Harits] dari ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam jika salam beliau tidak duduk kecuali sekadar membaca; ALLAHUMMA ANTAS SALAAM WA MINKAS SALAAM TABAARAKTA YAA DZAL JALAALI WAL IKRAAM. \""},"882":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا شَبَابَةُ حَدَّثَنَا شُعْبَةُ عَنْ مُوسَى بْنِ أَبِي عَائِشَةَ عَنْ مَوْلًى لِأُمِّ سَلَمَةَ عَنْ أُمِّ سَلَمَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ إِذَا صَلَّى الصُّبْحَ حِينَ يُسَلِّمُ اللَّهُمَّ إِنِّي أَسْأَلُكَ عِلْمًا نَافِعًا وَرِزْقًا طَيِّبًا وَعَمَلًا مُتَقَبَّلًا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Syababah] berkata, telah menceritakan kepada kami [Syu'bah] dari [Musa bin Abu 'Aisyah] dari [Mantan budak Ummu Salamah], dari [Ummu Salamah] berkata, \"Ketika salam dalam shalat subuh Nabi shallallahu 'alaihi wasallam mengucapkan; \"ALLAHUMMA INNI AS`ALUKA ILMAN NAAFI'AN WA RIZQAN THAYYIBAN WA 'AMALAN MUTAQABBALAN (Ya Allah, aku memohon kepada-Mu ilmu yang bermanfaat, rizki yang baik dan amal yang diterima). \""},"883":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ وَمُحَمَّدُ بْنُ فُضَيْلٍ وَأَبُو يَحْيَى التَّيْمِيُّ وَابْنُ الْأَجْلَحِ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَصْلَتَانِ لَا يُحْصِيهِمَا رَجُلٌ مُسْلِمٌ إِلَّا دَخَلَ الْجَنَّةَ وَهُمَا يَسِيرٌ وَمَنْ يَعْمَلُ بِهِمَا قَلِيلٌ يُسَبِّحُ اللَّهَ فِي دُبُرِ كُلِّ صَلَاةٍ عَشْرًا وَيُكَبِّرُ عَشْرًا وَيَحْمَدُ عَشْرًا فَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْقِدُهَا بِيَدِهِ فَذَلِكَ خَمْسُونَ وَمِائَةٌ بِاللِّسَانِ وَأَلْفٌ وَخَمْسُ مِائَةٍ فِي الْمِيزَانِ وَإِذَا أَوَى إِلَى فِرَاشِهِ سَبَّحَ وَحَمِدَ وَكَبَّرَ مِائَةً فَتِلْكَ مِائَةٌ بِاللِّسَانِ وَأَلْفٌ فِي الْمِيزَانِ فَأَيُّكُمْ يَعْمَلُ فِي الْيَوْمِ أَلْفَيْنِ وَخَمْسَ مِائَةِ سَيِّئَةٍ قَالُوا وَكَيْفَ لَا يُحْصِيهِمَا قَالَ يَأْتِي أَحَدَكُمْ الشَّيْطَانُ وَهُوَ فِي الصَّلَاةِ فَيَقُولُ اذْكُرْ كَذَا وَكَذَا حَتَّى يَنْفَكَّ الْعَبْدُ لَا يَعْقِلُ وَيَأْتِيهِ وَهُوَ فِي مَضْجَعِهِ فَلَا يَزَالُ يُنَوِّمُهُ حَتَّى يَنَامَ","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Isma'il bin 'Ulayyah] dan [Muhammad bin Fudlail] dan [Abu Yahya At Taimi] dan [Ibnul Ajlah] dari ['Atho` bin As Sa`ib] dari [Bapaknya] dari [Abdullah bin Amru] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ada dua perkara tidaklah seorang muslim menjaganya kecuali ia akan masuk surga, mudah diamalkan namun sedikit yang melakukannya; bertasbih di setiap usai shalat sepuluh kali, bertakbir sepuluh kali dan bertahmid sepuluh kali. \" Lalu aku melihat Rasulullah shallallahu 'alaihi wasallam menghitung dengan jarinya, maka yang demikian itu menjadi seratus lima puluh di lisan dan seribu lima ratus dalam timbangan. Apabila beranjak ke tempat pembaringannya (tidur), beliau bertasbih, bertahmid dan bertakbir seratus kali, maka itu seratus di lisan dan seribu dalam timbangan. Siapa di antara kalian yang melakukan dua ribu lima ratus kejahatan! \" Mereka berkata, \"Bagaimana jika kami tidak menjaga dua perkara tersebut?\" Rasulullah shallallahu 'alaihi wasallam menjawab, \"Setan akan mendatangi salah seorang di antara kalian dalam shalat, lalu setan berkata; 'ingat ini dan itu' hingga seorang hamba terpisah dan tidak ingat shalatnya. Setan juga akan mendatanginya saat di pembaringannya (tidur). Maka setan senantiasa menidurkannya hingga dia tertidur. \""},"884":{"ar":"حَدَّثَنَا الْحُسَيْنُ بْنُ الْحَسَنِ الْمَرْوَزِيُّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ بِشْرِ بْنِ عَاصِمٍ عَنْ أَبِيهِ عَنْ أَبِي ذَرٍّ قَالَقِيلَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرُبَّمَا قَالَ سُفْيَانُ قُلْتُ يَا رَسُولَ اللَّهِ ذَهَبَ أَهْلُ الْأَمْوَالِ وَالدُّثُورِ بِالْأَجْرِ يَقُولُونَ كَمَا نَقُولُ وَيُنْفِقُونَ وَلَا نُنْفِقُ قَالَ لِي أَلَا أُخْبِرُكُمْ بِأَمْرٍ إِذَا فَعَلْتُمُوهُ أَدْرَكْتُمْ مَنْ قَبْلَكُمْ وَفُتُّمْ مَنْ بَعْدَكُمْ تَحْمَدُونَ اللَّهَ فِي دُبُرِ كُلِّ صَلَاةٍ وَتُسَبِّحُونَ وَتُكَبِّرُونَ ثَلَاثًا وَثَلَاثِينَ وَثَلَاثًا وَثَلَاثِينَ وَأَرْبَعًا وَثَلَاثِينَقَالَ سُفْيَانُ لَا أَدْرِي أَيَّتُهُنَّ أَرْبَعٌ","id":"Telah menceritakan kepada kami [Al Husain Ibnul Hasan Al Marwazi] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Bisyr bin Ashim] dari [Bapaknya] dari [Abu Dzar] ia berkata, \"Dikatakan kepada Nabi shallallahu 'alaihi wasallam, dan barangkali Sufyan mengatakan, \"Aku bertanya, \"Wahai Rasulullah, orang-orang kaya banyak pergi dengan membawa pahala! Mereka berkata sebagaimana kami berkata, namun mereka dapat berinfak sementara kami tidak! \" beliau bersabda kepadaku: \"Maukah aku kabarkan kepada kalian suatu perkara yang jika kalian lakukan, maka kalian akan dapat melampaui orang-orang sebelum kalian dan meninggalkan orang-orang setelah kalian? Bertahmidlah kepada Allah setiap selesai shalat tiga puluh tiga kali, bertasbih tiga puluh tiga kali dan bertakbir tiga puluh empat kali. \" Sufyan berkata, \"Aku tidak tahu mana yang harus dibaca empat (tiga puluh empat)?\""},"885":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ حَبِيبٍ حَدَّثَنَا الْأَوْزَاعِيُّ ح و حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنِي شَدَّادٌ أَبُو عَمَّارٍ حَدَّثَنِي أَبُو أَسْمَاءَ الرَّحَبِيُّ حَدَّثَنِي ثَوْبَانُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا انْصَرَفَ مِنْ صَلَاتِهِ اسْتَغْفَرَ ثَلَاثَ مَرَّاتٍ ثُمَّ يَقُولُ اللَّهُمَّ أَنْتَ السَّلَامُ وَمِنْكَ السَّلَامُ تَبَارَكْتَ يَا ذَا الْجَلَالِ وَالْإِكْرَامِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Abdul Hamid bin Habib] berkata, telah menceritakan kepada kami [Al Auza'i]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami ['Abdurrahman bin Ibrahim Ad Dimasyqi] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Al Auza'i] berkata, telah menceritakan kepadaku [Syaddad Abu Ammar] berkata, telah menceritakan kepadaku [Abu Asma Ar Rahabi] berkata, telah menceritakan kepadaku [Tsauban] berkata, \"Rasulullah shallallahu 'alaihi wasallam jika selesai shalat beliau beranjak seraya mengucapkan istighfar tiga kali, setelah itu beliau mengucapkan: \"ALLAHUMMA ANTAS SALAAM WA MINKAS SALAAM TABAARAKTA YAA DZAL JALAALI WAL IKRAM. \""},"886":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ سِمَاكٍ عَنْ قَبِيصَةَ بْنِ هُلْبٍ عَنْ أَبِيهِ قَالَأَمَّنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَانَ يَنْصَرِفُ عَنْ جَانِبَيْهِ جَمِيعًا","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Al Ahwash] dari [Simak] dari [Qabishah bin Hulaib] dari [Bapaknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam mengimami kami, dan beliau berlalu pergi dari sisi kanan dan sisi kiri. \""},"887":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ خَلَّادٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَا حَدَّثَنَا الْأَعْمَشُ عَنْ عُمَارَةَ عَنْ الْأَسْوَدِ قَالَقَالَ عَبْدُ اللَّهِ لَا يَجْعَلَنَّ أَحَدُكُمْ لِلشَّيْطَانِ فِي نَفْسِهِ جُزْءًا يَرَى أَنَّ حَقًّا لِلَّهِ عَلَيْهِ أَنْ لَا يَنْصَرِفَ إِلَّا عَنْ يَمِينِهِ قَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكْثَرُ انْصِرَافِهِ عَنْ يَسَارِهِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki']. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abu Bakr bin Khallad] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] keduanya berkata; telah menceritakan kepada kami [Al A'masy] dari [Umarah] dari [Al Aswad] berkata; [Abdullah] berkata, \"Jangan sekali-kali salah seorang dari kalian memberi celah kepada setan dalam dirinya; ia memandang bahwa hak Allah atas dirinya adalah meninggalkan tempat shalat dari sebelah kanannya. Sungguh saya pernah melihat Rasulullah shallallahu 'alaihi wasallam sering meninggalkan tempat shalat dari sebelah kirinya. \""},"888":{"ar":"حَدَّثَنَا بِشْرُ بْنُ هِلَالٍ الصَّوَّافُ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ حُسَيْنٍ الْمُعَلِّمِ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْفَتِلُ عَنْ يَمِينِهِ وَعَنْ يَسَارِهِ فِي الصَّلَاةِ","id":"Telah menceritakan kepada kami [Bisyr bin Hilal Ash Shawwaf] berkata, telah menceritakan kepada kami [Yazid bin Zura'] dari [Husain Al Mu'allim] dari [Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya] ia berkata, \"Aku melihat Rasulullah shallallahu 'alaihi wasallam berpaling ke kanan dan ke kiri dalam shalat. \""},"889":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ الْمَلِكِ بْنِ وَاقِدٍ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ هِنْدٍ بِنْتِ الْحَارِثِ عَنْ أُمِّ سَلَمَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَلَّمَ قَامَ النِّسَاءُ حِينَ يَقْضِي تَسْلِيمَهُ ثُمَّ يَلْبَثُ فِي مَكَانِهِ يَسِيرًا قَبْلَ أَنْ يَقُومَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ahmad bin Abdul Malik bin Waqid] berkata, telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Ibnu Syihab] dari [Hind binti Al Harits] dari [Ummu Salamah] ia berkata, \"Jika Rasulullah shallallahu 'alaihi wasallam salam dan sempurna salamnya kaum wanita bangun (untuk pergi), kemudian beliau diam sebentar di tempatnya sebelum pergi. \""},"890":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا وُضِعَ الْعَشَاءُ وَأُقِيمَتْ الصَّلَاةُ فَابْدَءُوا بِالْعَشَاءِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Anas bin Malik] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika makan malam telah terhidang kemudian iqamah dikumandangkan, maka mulailah dengan makan malam. \""},"891":{"ar":"حَدَّثَنَا أَزْهَرُ بْنُ مَرْوَانَ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا أَيُّوبُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا وُضِعَ الْعَشَاءُ وَأُقِيمَتْ الصَّلَاةُ فَابْدَءُوا بِالْعَشَاءِقَالَ فَتَعَشَّى ابْنُ عُمَرَ لَيْلَةً وَهُوَ يَسْمَعُ الْإِقَامَةَ","id":"Telah menceritakan kepada kami [Azhar bin Marwan] berkata, telah menceritakan kepada kami [Abdul Warits] berkata, telah menceritakan kepada kami [Ayyub] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika makan malam telah terhidang kemudian iqamah dikumandangkan, maka mulailah dengan makan malam. \" Nafi' berkata, \"Ibnu Umar tetap makan malam meskipun ia mendengar iqamah. \""},"892":{"ar":"حَدَّثَنَا سَهْلُ بْنُ أَبِي سَهْلٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ ح و حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ جَمِيَعًا عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا حَضَرَ الْعَشَاءُ وَأُقِيمَتْ الصَّلَاةُ فَابْدَءُوا بِالْعَشَاءِ","id":"Telah menceritakan kepada kami [Sahl bin Abu Sahl] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] semuanya dari [Hisyam bin Urwah] dari [Bapaknya] dari ['Aisyah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika makan malam telah terhidang dan iqamhan dikumandangkan, maka dahulukanlah makan malam. \""},"893":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي الْمَلِيحِ قَالَخَرَجْتُ فِي لَيْلَةٍ مَطِيرَةٍ فَلَمَّا رَجَعْتُ اسْتَفْتَحْتُ فَقَالَ أَبِي مَنْ هَذَا قَالَ أَبُو الْمَلِيحِ قَالَ لَقَدْ رَأَيْتُنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْحُدَيْبِيَةِ وَأَصَابَتْنَا سَمَاءٌ لَمْ تَبُلَّ أَسَافِلَ نِعَالِنَا فَنَادَى مُنَادِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلُّوا فِي رِحَالِكُمْ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Isma'il bin Ibrahim] dari [Khalid Al Hadzdza`] dari [Abu Al Malih] berkata; Aku keluar di malam yang penuh hujan, ketika pulang aku langsung meminta untuk dibukakan pintu. Bapakku bertanya, \"Siapa itu?\" \"Abu Al Malih, \" jawabku. [Bapakku] berkata, \"Pada hari Hudaibiah aku pernah bersama Rasulullah shallallahu 'alaihi wasallam, lalu kami kehujanan namun tidak sampai membasahi sandal kami, kemudian berserulah utusan Rasulullah shallallahu 'alaihi wasallam, \"Shalatlah di rumah-rumah kalian. \""},"894":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُنَادِي مُنَادِيهِ فِي اللَّيْلَةِ الْمَطِيرَةِ أَوْ اللَّيْلَةِ الْبَارِدَةِ ذَاتِ الرِّيحِ صَلُّوا فِي رِحَالِكُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam menyeru penyerunya di malam yang penuh hujan, atau malam yang dingin berangin agar menyerukan; \"Shalatlah di rumah-rumah kalian. \""},"895":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ الْوَهَّابِ حَدَّثَنَا الضَّحَّاكُ بْنُ مَخْلَدٍ عَنْ عَبَّادِ بْنِ مَنْصُورٍ قَالَ سَمِعْتُ عَطَاءً يُحَدِّثُ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ فِي يَوْمِ جُمُعَةٍ يَوْمِ مَطَرٍ صَلُّوا فِي رِحَالِكُمْ","id":"Telah menceritakan kepada kami ['Abdurrahman bin Abdul Wahhab] berkata, telah menceritakan kepada kami [Adl Dlahhak bin Makhlad] dari [Abbad bin Mashur] berkata; aku mendengar ['Atho`] menceritakan dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda di hari jum'at yang hujan: \"Shalatlah di rumah-rumah kalian. \""},"896":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ حَدَّثَنَا عَبَّادُ بْنُ عَبَّادٍ الْمُهَلَّبِيُّ حَدَّثَنَا عَاصِمٌ الْأَحْوَلُ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ بْنِ نَوْفَلٍأَنَّ ابْنَ عَبَّاسٍ أَمَرَ الْمُؤَذِّنَ أَنْ يُؤَذِّنَ يَوْمَ الْجُمُعَةِ وَذَلِكَ يَوْمٌ مَطِيرٌ فَقَالَ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ ثُمَّ قَالَ نَادِ فِي النَّاسِ فَلْيُصَلُّوا فِي بُيُوتِهِمْ فَقَالَ لَهُ النَّاسُ مَا هَذَا الَّذِي صَنَعْتَ قَالَ قَدْ فَعَلَ هَذَا مَنْ هُوَ خَيْرٌ مِنِّيتَأْمُرُنِي أَنْ أُخْرِجَ النَّاسَ مِنْ بُيُوتِهِمْ فَيَأْتُونِي يَدُوسُونَ الطِّينَ إِلَى رُكَبِهِمْ","id":"Telah menceritakan kepada kami [Ahmad bin Abdah] berkata, telah menceritakan kepada kami [Abbad bin Abbad Al Muhallibi] berkata, telah menceritakan kepada kami [Ashim Al Ahwal] dari [Abdullah Ibnul Harits bin Naifal] bahwa [Ibnu Abbas] memerintahkan kepada mu`adzdzin untuk adzan di hari jum'at yang penuh hujan, lalu ia menyerukan, \"ALLAHU AKBAR, ALLAHU AKBAR, ASYHADU AN LAA ILAAHA ILLA ALLAHU, ASYHADU ANNA MUHAMMADAN RASUULULLAH. \" Kemudian Ibnu Abbas berkata, \"Serukanlah kepada manusia agar mereka shalat di rumah-rumah mereka. \" hingga orang-orang pun berkata kepadanya, \"Apa-apaan yang engkau lakukan ini?\" Ibnu Abbas menjawab, \"Orang yang lebih baik dariku telah melakukan ini, tapi kenapa kalian menyuruhku agar mengeluarkan manusia dari rumah mereka (untuk shalat di hari yang penuh hujan), hingga mereka mendatangiku berjalan di atas tanah yang becek. \""},"897":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا عُمَرُ بْنُ عُبَيْدٍ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ مُوسَى بْنِ طَلْحَةَ عَنْ أَبِيهِ قَالَكُنَّا نُصَلِّي وَالدَّوَابُّ تَمُرُّ بَيْنَ أَيْدِينَا فَذُكِرَ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مِثْلُ مُؤَخِّرَةِ الرَّحْلِ تَكُونُ بَيْنَ يَدَيْ أَحَدِكُمْ فَلَا يَضُرُّهُ مَنْ مَرَّ بَيْنَ يَدَيْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] berkata, telah menceritakan kepada kami [Umar bin Ubaid] dari [Simak bin Harb] dari [Musa bin Thalhah] dari [Bapaknya] berkata; Kami shalat sementara hewan-hewan tunggangan melintas di hadapan kami, lalu hal itu diceritakan kepada Rasulullah shallallahu 'alaihi wasallam, beliau pun bersabda: \"Itu seperti pelana yang ada di hadapan salah seorang dari kalian, maka tidak apa-apa jika ada yang melintas di hadapannya. \" "},"898":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ رَجَاءٍ الْمَكِّيُّ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تُخْرَجُ لَهُ حَرْبَةٌ فِي السَّفَرِ فَيَنْصِبُهَا فَيُصَلِّي إِلَيْهَا","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah memberitakan kepada kami [Abdullah bin Raja` Al Makki] dari [Ubaidullah] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Dalam sebuah perjalanan Nabi shallallahu 'alaihi wasallam diberi sebuah tombak kecil, lalu beliau menancapkannya dan shalat menghadap ke arahnya. \""},"899":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ حَدَّثَنِي سَعِيدُ بْنُ أَبِي سَعِيدٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَ قَالَتْكَانَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَصِيرٌ يُبْسَطُ بِالنَّهَارِ وَيَحْتَجِرُهُ بِاللَّيْلِ يُصَلِّي إِلَيْهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Muhammad bin Bisyr] dari [Ubaidullah bin Umar] berkata, telah menceritakan kepadaku [Sa'id bin Abu Sa'id] dari [Abu Salamah bin 'Abdurrahman] dari ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam mempunyai tikar yang dibentangkan di siang hari, dan menggulungnya (seperti batu) di malam hari, lalu shalat menghadap ke arahnya. \""},"900":{"ar":"حَدَّثَنَا بَكْرُ بْنُ خَلَفٍ أَبُو بِشْرٍ حَدَّثَنَا حُمَيْدُ بْنُ الْأَسْوَدِ حَدَّثَنَا إِسْمَعِيلُ بْنُ أُمَيَّةَ ح و حَدَّثَنَا عَمَّارُ بْنُ خَالِدٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ إِسْمَعِيلَ بْنِ أُمَيَّةَ عَنْ أَبِي عَمْرِو بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حُرَيْثٍ عَنْ جَدِّهِ حُرَيْثِ بْنِ سُلَيْمٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا صَلَّى أَحَدُكُمْ فَلْيَجْعَلْ تِلْقَاءَ وَجْهِهِ شَيْئًا فَإِنْ لَمْ يَجِدْ فَلْيَنْصِبْ عَصًا فَإِنْ لَمْ يَجِدْ فَلْيَخُطَّ خَطًّا ثُمَّ لَا يَضُرُّهُ مَا مَرَّ بَيْنَ يَدَيْهِ","id":"Telah menceritakan kepada kami [Bakr bin Khalaf Abu Bisyr] berkata, telah menceritakan kepada kami [Humaid Ibnul Aswad] berkata, telah menceritakan kepada kami [Isma'il bin Umayyah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ammar bin Khalid] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Isma'il bin Umayyah] dari [Abu Amru bin Muhammad bin Amru bin Huraits] dari Kakeknya [Huraits bin Sulaim] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika salah seorang dari kalian shalat hendaklah meletakkan sesuatu di depannya, jika tidak mendapatkan sesuatu hendaklah menancapkan tongkat, dan jika tidak mendapatkan hendaklah membuat garis. Setelah itu tidak akan membahayakannya apa-apa yang melintas di depannya. \""},"901":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ سَالِمٍ أَبِي النَّضْرِ عَنْ بُسْرِ بْنِ سَعِيدٍ قَالَأَرْسَلُونِي إِلَى زَيْدِ بْنِ خَالِدٍ أَسْأَلُهُ عَنْ الْمُرُورِ بَيْنَ يَدَيْ الْمُصَلِّي فَأَخْبَرَنِي عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَأَنْ يَقُومَ أَرْبَعِينَ خَيْرٌ لَهُ مِنْ أَنْ يَمُرَّ بَيْنَ يَدَيْهِقَالَ سُفْيَانُ فَلَا أَدْرِي أَرْبَعِينَ سَنَةً أَوْ شَهْرًا أَوْ صَبَاحًا أَوْ سَاعَةً","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Salim Abu An Nadlr] dari [Busr bin Sa'id] berkata; Kaumku mengutusku menemui [Zaid bin Khalid], lalu aku bertanya kepadanya tentang hukum melintas di depan orang yang shalat. Maka ia pun memberiku kabar dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sekiranya seseorang berdiri selama empat puluh, maka itu lebih baik daripada ia melintas di depan orang yang shalat. \" Sufyan berkata, \"Aku tidak tahu, apakah itu empat puluh tahun, atau empat puluh bulan, atau empat puluh pagi, atau empat puluh saat. \""},"902":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ سَالِمٍ أَبِي النَّضْرِ عَنْ بُسْرِ بْنِ سَعِيدٍأَنَّ زَيْدَ بْنَ خَالِدٍ أَرْسَلَ إِلَى أَبِي جُهَيْمٍ الْأَنْصَارِيِّ يَسْأَلُهُ مَا سَمِعْتَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الرَّجُلِ يَمُرُّ بَيْنَ يَدَيْ الرَّجُلِ وَهُوَ يُصَلِّي فَقَالَ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَوْ يَعْلَمُ أَحَدُكُمْ مَا لَهُ أَنْ يَمُرَّ بَيْنَ يَدَيْ أَخِيهِ وَهُوَ يُصَلِّي كَانَ لَأَنْ يَقِفَ أَرْبَعِينَ قَالَ لَا أَدْرِي أَرْبَعِينَ عَامًا أَوْ أَرْبَعِينَ شَهْرًا أَوْ أَرْبَعِينَ يَوْمًا خَيْرٌ لَهُ مِنْ ذَلِكَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Sufyan] dari [Salim Abu An Nadlr] dari [Busr bin Sa'id] bahwa Zaid bin Khalid mengutus seseorang kepada [Abu Juhaim Al Anshari] untuk bertanya kepadanya; apa yang engkau dengar dari Rasulullah shallallahu 'alaihi wasallam tentang seorang laki-laki yang melintas di depan orang yang shalat. Lalu ia menjawab, \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Sekiranya salah seorang dari kalian tahu apa yang akan menimpanya ketika melintas di depan orang yang sedang shalat, maka ia berdiri selama empat puluh -ia berkata, \"Aku tidak tahu apakah itu empat puluh tahun, atau empat puluh bulan atau empat puluh hari, \"- lebih baik baginya daripada melintas di depannya. \""},"903":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ مَوْهِبٍ عَنْ عَمِّهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ يَعْلَمُ أَحَدُكُمْ مَا لَهُ فِي أَنْ يَمُرَّ بَيْنَ يَدَيْ أَخِيهِ مُعْتَرِضًا فِي الصَّلَاةِ كَانَ لَأَنْ يُقِيمَ مِائَةَ عَامٍ خَيْرٌ لَهُ مِنْ الْخَطْوَةِ الَّتِي خَطَاهَا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Waki'] dari [Ubaidullah bin 'Abdurrahman bin Mauhib] dari [Pamannya] dari [Abu Hurairah] ia berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Sekiranya salah seorang dari kalian tahu apa yang akan menimpanya ketika melintas di depan saudaranya yang sedang shalat, maka berdiri selama seratus tahun adalah lebih baik daripada melangkahkan kaki (melintasinya). \""},"904":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي بِعَرَفَةَ فَجِئْتُ أَنَا وَالْفَضْلُ عَلَى أَتَانٍ فَمَرَرْنَا عَلَى بَعْضِ الصَّفِّ فَنَزَلْنَا عَنْهَا وَتَرَكْنَاهَا ثُمَّ دَخَلْنَا فِي الصَّفِّ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Ubaidullah bin Abdullah] dari [Ibnu Abbas] berkata, \"Nabi shallallahu 'alaihi wasallam shalat di Arafah, lalu aku dan Al Fadll datang dengan menunggang himar, kami melintas di depan sebagian shaf. Lalu kami turun dan masuk ke dalam shaf, sementara himar kami tinggalkan begitu saja. \""},"905":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ أُسَامَةَ بْنِ زَيْدٍ عَنْ مُحَمَّدِ بْنِ قَيْسٍ هُوَ قَاصُّ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ عَنْ أَبِيهِ عَنْ أُمِّ سَلَمَةَ قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِي حُجْرَةِ أُمِّ سَلَمَةَ فَمَرَّ بَيْنَ يَدَيْهِ عَبْدُ اللَّهِ أَوْ عُمَرُ بْنُ أَبِي سَلَمَةَ فَقَالَ بِيَدِهِ فَرَجَعَ فَمَرَّتْ زَيْنَبُ بِنْتُ أُمِّ سَلَمَةَ فَقَالَ بِيَدِهِ هَكَذَا فَمَضَتْ فَلَمَّا صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ هُنَّ أَغْلَبُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Waki'] dari [Usamah bin Zaid] dari [Muhammad bin Qais] -ia adalah Qash Umar bin Abdul Aziz- dari [Bapaknya] dari [Ummu Salamah] ia berkata, \"Nabi shallallahu 'alaihi wasallam shalat di kamar Ummu Salamah, lalu Abdullah atau Umar bin Abu Salamah melintas di hadapan beliau. Maka beliau bersabda dengan isyarat tangannya hingga ia pun kembali. Setelah itu Zainab binti Ummu Salamah lewat dan beliau juga bersabda dengan tangannya seperti ini, hingga iapun kembali lagi. Ketika Rasulullah shallallahu 'alaihi wasallam selesai shalat, beliau bersabda: \"Mereka (wanita) lebih sering (berbuat maksiat dan menyimpang). \""},"906":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ خَلَّادٍ الْبَاهِلِيُّ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا قَتَادَةُ حَدَّثَنَا جَابِرُ بْنُ زَيْدٍ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَقْطَعُ الصَّلَاةَ الْكَلْبُ الْأَسْوَدُ وَالْمَرْأَةُ الْحَائِضُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Khallad Al Bahili] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] berkata, telah menceritakan kepada kami [Syu'bah] berkata, telah menceritakan kepada kami [Qatadah] berkata, telah menceritakan kepada kami [Jabir bin Zaid] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Yang memutus shalat adalah anjing hitam dan wanita haid. \""},"907":{"ar":"حَدَّثَنَا زَيْدُ بْنُ أَخْزَمَ أَبُو طَالِبٍ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنَا أَبِي عَنْ قَتَادَةَ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ سَعْدِ بْنِ هِشَامٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَقْطَعُ الصَّلَاةَ الْمَرْأَةُ وَالْكَلْبُ وَالْحِمَارُ","id":"Telah menceritakan kepada kami [Zaid bin Akhzam Abu Thalib] berkata, telah menceritakan kepada kami [Mu'adz bin Hisyam] berkata, telah menceritakan kepada kami [Bapakku] dari [Qatadah] dari [Zurarah bin Aufa] dari [Sa'd bin Hisyam] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Yang memutus shalat adalah wanita, anjing dan himar. \""},"908":{"ar":"حَدَّثَنَا جَمِيلُ بْنُ الْحَسَنِ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَقْطَعُ الصَّلَاةَ الْمَرْأَةُ وَالْكَلْبُ وَالْحِمَارُ","id":"Telah menceritakan kepada kami [Jamil Ibnul Hasan] berkata, telah menceritakan kepada kami [Abdul A'la] berkata, telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Al Hasan] dari [Abdullah bin Mughaffal] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Yang memutus shalat adalah wanita, anjing dan himar. \""},"909":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ عَبْدِ اللَّهِ بْنِ الصَّامِتِ عَنْ أَبِي ذَرٍّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَقْطَعُ الصَّلَاةَ إِذَا لَمْ يَكُنْ بَيْنَ يَدَيْ الرَّجُلِ مِثْلُ مُؤَخِّرَةِ الرَّحْلِ الْمَرْأَةُ وَالْحِمَارُ وَالْكَلْبُ الْأَسْوَدُ قَالَ قُلْتُ مَا بَالُ الْأَسْوَدِ مِنْ الْأَحْمَرِ قَالَ سَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَمَا سَأَلْتَنِي فَقَالَ الْكَلْبُ الْأَسْوَدُ شَيْطَانٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] dari [Syu'bah] dari [Humaid bin Hilal] dari [Abdullah bin Ash Shamit] dari [Abu Dzar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika di depan orang yang shalat tidak ada sesuatu seperti pelana, maka yang akan memutuskan shalat adalah wanita, himar dan anjing hitam, \" Abdullah bin Ash Shamit berkata, \"Aku bertanya, \"Kenapa harus anjing hitam dan tidak merah?\" Abu Dzar menjawab: \"Aku pernah bertanya Rasulullah shallallahu 'alaihi wasallam sebagaimana yang engkau tanyakan kepadaku, beliau menjawab: \"Anjing hitam adalah setan. \" "},"910":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ أَنْبَأَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا يَحْيَى أَبُو الْمُعَلَّى عَنْ الْحَسَنِ الْعُرَنِيِّ قَالَذُكِرَ عِنْدَ ابْنِ عَبَّاسٍ مَا يَقْطَعُ الصَّلَاةَ فَذَكَرُوا الْكَلْبَ وَالْحِمَارَ وَالْمَرْأَةَ فَقَالَ مَا تَقُولُونَ فِي الْجَدْيِ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي يَوْمًا فَذَهَبَ جَدْيٌ يَمُرُّ بَيْنَ يَدَيْهِ فَبَادَرَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْقِبْلَةَ","id":"Telah menceritakan kepada kami [Ahmad bin Abdah] berkata, telah memberitakan kepada kami [Hammad bin Zaid] berkata, telah menceritakan kepada kami [Yahya bin Al Mu'alla] dari [Al Hasan Al 'Urani] ia berkata, \"Disebut-sebut di sisi Ibnu Abbas sesuatu yang dapat memutuskan shalat, mereka menyebutkan anjing, himar dan wanita. Maka [Ibnu Abbas] pun berkata, \"Kalian tidak menyebut anak kambing! Sungguh, suatu hari Rasulullah shallallahu 'alaihi wasallam shalat, lalu seekor anak kambing melintas dan Rasulullah shallallahu 'alaihi wasallam segera mendahuluinya ke arah kiblat (hingga kambing itu lewat di belakang beliau). \""},"911":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ ابْنِ عَجْلَانَ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّى أَحَدُكُمْ فَلْيُصَلِّ إِلَى سُتْرَةٍ وَلْيَدْنُ مِنْهَا وَلَا يَدَعْ أَحَدًا يَمُرُّ بَيْنَ يَدَيْهِ فَإِنْ جَاءَ أَحَدٌ يَمُرُّ فَلْيُقَاتِلْهُ فَإِنَّهُ شَيْطَانٌ","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Abu Khalid Al Ahmar] dari [Ibnu 'Ajlan] dari [Zaid bin Aslam] dari ['Abdurrahman bin Abu Sa'id] dari [Bapaknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian shalat, hendaklah menghadap ke sutrah dan mendekatinya. Jangan membiarkan seseorang melintas di depannya, jika ada seseorang yang melintasinya hendaklah ia bunuh sebab dia adalah setan. \""},"912":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ الْحَمَّالُ وَالْحَسَنُ بْنُ دَاوُدَ الْمُنْكَدِرِيُّ قَالَا حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ عَنْ الضَّحَّاكِ بْنِ عُثْمَانَ عَنْ صَدَقَةَ بْنِ يَسَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا كَانَ أَحَدُكُمْ يُصَلِّي فَلَا يَدَعْ أَحَدًا يَمُرُّ بَيْنَ يَدَيْهِ فَإِنْ أَبَى فَلْيُقَاتِلْهُ فَإِنَّ مَعَهُ الْقَرِينَو قَالَ الْمُنْكَدِرِيُّ فَإِنَّ مَعَهُ الْعُزَّى","id":"Telah menceritakan kepada kami [Harun bin Abdullah Al Hammal] dan [Al Hasan bin Dawud Al Munkadiri] keduanya berkata; telah menceritakan kepada kami [Ibnu Abu Fudaik] dari [Adl Dlahhak bin Utsman] dari [Shodaqoh bin Yasar] dari [Abdullah bin Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian shalat maka jangan membiarkan seorang pun melintas di depannya, jika ia enggan maka bunuhlah sebab ia membawa qarin (setan). \" Al Munkadiri menyebutkan, \"Sesungguhnya ia bersama Al 'Uzza. \""},"913":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي مِنْ اللَّيْلِ وَأَنَا مُعْتَرِضَةٌ بَيْنَهُ وَبَيْنَ الْقِبْلَةِ كَاعْتِرَاضِ الْجِنَازَةِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Urwah] dari ['Aisyah] berkata, \"Nabi shallallahu 'alaihi wasallam shalat malam sementara aku berbaring antara beliau dan arah kiblat seperti jenazah. \""},"914":{"ar":"حَدَّثَنَا بَكْرُ بْنُ خَلَفٍ وَسُوَيْدُ بْنُ سَعِيدٍ قَالَا حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا خَالِدٌ الْحَذَّاءُ عَنْ أَبِي قِلَابَةَ عَنْ زَيْنَبَ بِنْتِ أَبِي سَلَمَةَ عَنْ أُمِّهَا قَالَتْكَانَ فِرَاشُهَا بِحِيَالِ مَسْجَدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Bakr bin Khalaf] dan [Suwaid bin Sa'id] keduanya berkata; telah menceritakan kepada kami [Yazid bin Zurai'] berkata, telah menceritakan kepada kami [Khalid Al Hadzdza`] dari [Abu Qilabah] dari [Zainab binti Abu Salamah] dari [Ibunya] ia berkata, \"Letak tempat tidurnya berhadapan dengan tempat sujud Rasulullah shallallahu 'alaihi wasallam. \""},"915":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبَّادُ بْنُ الْعَوَّامِ عَنْ الشَّيْبَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ شَدَّادٍ قَالَ حَدَّثَتْنِي مَيْمُونَةُ زَوْجُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي وَأَنَا بِحِذَائِهِ وَرُبَّمَا أَصَابَنِي ثَوْبُهُ إِذَا سَجَدَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abbad Ibnul Awwam] dari [Asy Syaibani] dari [Abdullah bin Syaddad] berkata; [Maimunah] isteri Nabi shallallahu 'alaihi wasallam menceritakan kepadaku, ia berkata, \"Nabi shallallahu 'alaihi wasallam shalat sedang aku berada di kakinya. Dan bisa jadi kain beliau mengenaiku di saat beliau sujud. \""},"916":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ حَدَّثَنِي أَبُو الْمِقْدَامِ عَنْ مُحَمَّدِ بْنِ كَعْبٍ عَنْ ابْنِ عَبَّاسٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُصَلَّى خَلْفَ الْمُتَحَدِّثِ وَالنَّائِمِ","id":"Telah menceritakan kepada kami [Muhammad bin Ismail] berkata, telah menceritakan kepada kami [Zaid bin Al Hubab] berkata, telah menceritakan kepadaku [Abul Miqdam] dari [Muhammad bin Ka'b] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang shalat di belakang orang yang berhadats dan orang tidur. \" "},"917":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعَلِّمُنَا أَنْ لَا نُبَادِرَ الْإِمَامَ بِالرُّكُوعِ وَالسُّجُودِ وَإِذَا كَبَّرَ فَكَبِّرُوا وَإِذَا سَجَدَ فَاسْجُدُوا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Muhammad bin Ubaid] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata, \"Nabi shallallahu 'alaihi wasallam mengajarkan kami agar tidak mendahului imam ketika rukuk dan sujud; jika imam takbir maka takbirlah dan jika imam sujud maka sujudlah. \""},"918":{"ar":"حَدَّثَنَا حُمَيْدُ بْنُ مَسْعَدَةَ وَسُوَيْدُ بْنُ سَعِيدٍ قَالَا حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا مُحَمَّدُ بْنُ زِيَادٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا يَخْشَى الَّذِي يَرْفَعُ رَأْسَهُ قَبْلَ الْإِمَامِ أَنْ يُحَوِّلَ اللَّهُ رَأْسَهُ رَأْسَ حِمَارٍ","id":"Telah menceritakan kepada kami [Humaid bin Mas'adah] dan [Suwaid bin Sa'id] keduanya berkata; telah menceritakan kepada kami [Hammad bin Zaid] berkata, telah menceritakan kepada kami [Muhammad bin Ziyad] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak takutkah orang yang mengangkat kepalanya sebelum imam, Allah akan merubah kepalanya menjadi kepala himar. \""},"919":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبُو بَدْرٍ شُجَاعُ بْنُ الْوَلِيدِ عَنْ زِيَادِ بْنِ خَيْثَمَةَ عَنْ أَبِي إِسْحَقَ عَنْ دَارِمٍ عَنْ سَعِيدِ بْنِ أَبِي بُرْدَةَ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي قَدْ بَدَّنْتُ فَإِذَا رَكَعْتُ فَارْكَعُوا وَإِذَا رَفَعْتُ فَارْفَعُوا وَإِذَا سَجَدْتُ فَاسْجُدُوا وَلَا أُلْفِيَنَّ رَجُلًا يَسْبِقُنِي إِلَى الرُّكُوعِ وَلَا إِلَى السُّجُودِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] berkata, telah menceritakan kepada kami [Abu Badr Syuja' bin Al Walid] dari [Ziyad bin Khaitsamah] dari [Abu Ishaq] dari [Darim] dari [Sa'id bin Abu Burdah] dari [Abu Burdah] dari [Abu Musa] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya aku telah lanjut usia, jika aku rukuk maka rukuklah, jika aku mengangkat kepala maka angkatlah kepala kalian, dan jika aku sujud maka sujudlah. Aku tidak ingin ada orang yang mendahului aku dalam rukuk dan sujud. \""},"920":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ عَجْلَانَ ح و حَدَّثَنَا أَبُو بِشْرٍ بَكْرُ بْنُ خ��لَفٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ ابْنِ عَجْلَانَ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ ابْنِ مُحَيْرِيزٍ عَنْ مُعَاوِيَةَ بْنِ أَبِي سُفْيَانَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُبَادِرُونِي بِالرُّكُوعِ وَلَا بِالسُّجُودِ فَمَهْمَا أَسْبِقْكُمْ بِهِ إِذَا رَكَعْتُ تُدْرِكُونِي بِهِ إِذَا رَفَعْتُ وَمَهْمَا أَسْبِقْكُمْ بِهِ إِذَا سَجَدْتُ تُدْرِكُونِي بِهِ إِذَا رَفَعْتُ إِنِّي قَدْ بَدَّنْتُ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Sufyan] dari [Ibnu 'Ajlan]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abu Bisyr bakr bin Khalaf] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dari [Ibnu 'Ajlan] dari [Muhammad bin Yahya bin Habban] dari [Ibnu Muhairiz] dari [Mu'awiyah bin Abu Sufyan] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jangan kalian mendahuluiku dalam rukuk dan sujud. Karena segala rukuk yang lebih dahulu kulakukan sebelum kalian, bisa kalian lakukan saat aku tengah mengangkat rukuk. Dan segala sujud yang lebih dahulu kulakukan sebelum kalian, bisa kalian lakukan saat aku mengangkat sujud. Sungguh aku telah tua dan lemah. \" "},"921":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ بْنِ الْهُدَيْرِ التَّيْمِيُّ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ مِنْ الْجَفَاءِ أَنْ يُكْثِرَ الرَّجُلُ مَسْحَ جَبْهَتِهِ قَبْلَ الْفَرَاغِ مِنْ صَلَاتِهِ","id":"Telah menceritakan kepada kami ['Abdurrahman bin Ibrahim Ad Dimasyqi] berkata, telah menceritakan kepada kami [Ibnu Abu Fudaik] berkata, telah menceritakan kepada kami [Harun bin Abdullah bin Al Hudair At Taimi] dari [Al A'raj] dari [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Termasuk perkara yang sia-sia adalah memperbanyak mengusap keningnya sebelum selesai dari shalatnya. \""},"922":{"ar":"حَدَّثَنَا يَحْيَى بْنُ حَكِيمٍ حَدَّثَنَا أَبُو قُتَيْبَةَ حَدَّثَنَا يُونُسُ بْنُ أَبِي إِسْحَقَ وَإِسْرَائِيلُ بْنُ يُونُسَ عَنْ أَبِي إِسْحَقَ عَنْ الْحَارِثِ عَنْ عَلِيٍّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُفَقِّعْ أَصَابِعَكَ وَأَنْتَ فِي الصَّلَاةِ","id":"Telah menceritakan kepada kami [Yahya bin Hakim] berkata, telah menceritakan kepada kami [Abu Qutaibah] berkata, telah menceritakan kepada kami [Yunus bin Abu Ishaq] dan [Isra'il bin Yunus] dari [Abu Ishaq] dari [Al Harits] dari [Ali] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kamu membunyikan jari-jarimu sementara kamu sedang shalat. \""},"923":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ سُفْيَانُ بْنُ زِيَادٍ الْمُؤَدِّبُ حَدَّثَنَا مُحَمَّدُ بْنُ رَاشِدٍ عَنْ الْحَسَنِ بْنِ ذَكْوَانَ عَنْ عَطَاءٍ عَنْ أَبِي هُرَيْرَةَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُغَطِّيَ الرَّجُلُ فَاهُ فِي الصَّلَاةِ","id":"Telah menceritakan kepada kami [Abu Sa'id Sufyan bin Ziyad Al Mu`addib] berkata, telah menceritakan kepada kami [Muhammad bin Rasyid] dari [Al Hasan bin Dzakwan] dari ['Atho`] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang seseorang menutup mulutnya ketika shalat. \""},"924":{"ar":"حَدَّثَنَا عَلْقَمَةُ بْنُ عَمْرٍو الدَّارِمِيُّ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ مُحَمَّدِ بْنِ عَجْلَانَ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ كَعْبِ بْنِ عُجْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَجُلًا قَدْ شَبَّكَ أَصَابِعَهُ فِي الصَّلَاةِ فَفَرَّجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ أَصَابِعِهِ","id":"Telah menceritakan kepada kami [Alqamah bin Amru Ad Darimi] berkata, telah menceritakan kepada kami [Abu Bakr bin Ayyasy] dari [Muhammad bin 'Ajlan] dari [Sa'id Al Maqburi] dari [Ka'ab bin Ujrah] berkata, \"Rasulullah shallallahu 'alaihi wasallam melihat seorang laki-laki menganyam jemarinya dalam shalat, maka Rasulullah shallallahu 'alaihi wasallam pun membuka jemarinya. \""},"925":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ عَبْدِ اللَّهِ بْنِ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا تَثَاءَبَ أَحَدُكُمْ فَلْيَضَعْ يَدَهُ عَلَى فِيهِ وَلَا يَعْوِي فَإِنَّ الشَّيْطَانَ يَضْحَكُ مِنْهُ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah memberitakan kepada kami [Hafsh bin Ghiyats] dari [Abdullah bin Sa'id Al Maqburi] dari [Bapaknya] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian menguap hendaklah meletakkan tangan pada mulut dan jangan bersuara, sebab setan tertawa karenanya. \""},"926":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا الْفَضْلُ بْنُ دُكَيْنٍ عَنْ شَرِيكٍ عَنْ أَبِي الْيَقْظَانِ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ أَبِيهِ عَنْ جَدِّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْبُزَاقُ وَالْمُخَاطُ وَالْحَيْضُ وَالنُّعَاسُ فِي الصَّلَاةِ مِنْ الشَّيْطَانِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Al Fadll bin Dukain] dari [Syarik] dari [Abul Yaqdhan] dari ['Adi bin Tsabit] dari [Bapaknya] dari [Kakeknya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Ludah, ingus, haid dan kantuk dalam shalat datang dari setan. \""},"927":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ وَجَعْفَرُ بْنُ عَوْنٍ عَنْ الْإِفْرِيقِيِّ عَنْ عِمْرَانَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَةٌ لَا تُقْبَلُ لَهُمْ صَلَاةٌ الرَّجُلُ يَؤُمُّ الْقَوْمَ وَهُمْ لَهُ كَارِهُونَ وَالرَّجُلُ لَا يَأْتِي الصَّلَاةَ إِلَّا دِبَارًا يَعْنِي بَعْدَ مَا يَفُوتُهُ الْوَقْتُ وَمَنْ اعْتَبَدَ مُحَرَّرًا","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami ['Abdah bin Sulaiman] dan [Ja'far bin Aun] dari [Al Ifriqi] dari [Imran] dari [Abdullah bin Amru] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tiga golongan yang shalatnya tidak diterima; seseorang yang mengimami suatu kaum sementara mereka tidak menyukainya, orang yang tidak melaksanakan shalat kecuali telah habis waktunya, dan orang yang memperbudak orang merdeka. \""},"928":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُمَرَ بْنِ هَيَّاجِ حَدَّثَنَا يَحْيَى بْنُ عَبْدِ الرَّحْمَنِ الْأَرْحَبِيُّ حَدَّثَنَا عُبَيْدَةُ بْنُ الْأَسْوَدِ عَنْ الْقَاسِمِ بْنِ الْوَلِيدِ عَنْ الْمِنْهَالِ بْنِ عَمْرٍو عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ثَلَاثَةٌ لَا تَرْتَفِعُ صَلَاتُهُمْ فَوْقَ رُءُوسِهِمْ شِبْرًا رَجُلٌ أَمَّ قَوْمًا وَهُمْ لَهُ كَارِهُونَ وَامْرَأَةٌ بَاتَتْ وَزَوْجُهَا عَلَيْهَا سَاخِطٌ وَأَخَوَانِ مُتَصَارِمَانِ","id":"Telah menceritakan kepada kami [Muhammad bin Umar bin Hayyaj] berkata, telah menceritakan kepada kami [Yahya bin 'Abdurrahman Al Arhabi] berkata, telah menceritakan kepada kami [Ubaidah bin Al Aswad] dari [Al Qasim bin Al Walid] dari [Al Minhal bin Amru] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Tiga golongan yang shalatnya tidak akan di angkat meski satu jengkal dari kepalanya; seseorang yang mengimami suatu kaum sementara mereka tidak menyukainya, seorang perempuan yang bermalam sementara suaminya marah kepadanya, dan dua bersaudara yang saling bermusuhan. \""},"929":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا الرَّبِيعُ بْنُ بَدْرٍ عَنْ أَبِيهِ عَنْ جَدِّهِ عَمْرِو بْنِ جَرَادٍ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اثْنَانِ فَمَا فَوْقَهُمَا جَمَاعَةٌ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Ar Rabi' bin Badr] dari [Bapaknya] dari Kakeknya [Amru bin Jarad] dari [Abu Musa Al Asy'ari] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dua orang atau lebih adalah jama'ah. \""},"930":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ حَدَّثَنَا عَاصِمٌ عَنْ الشَّعْبِيِّ عَنْ ابْنِ عَبَّاسٍ قَالَبِتُّ عِنْدَ خَالَتِي مَيْمُونَةَ فَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي مِنْ اللَّيْلِ فَقُمْتُ عَنْ يَسَارِهِ فَأَخَذَ بِيَدِي فَأَقَامَنِي عَنْ يَمِينِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul Malik bin Abu Asy Syawarib] berkata, telah menceritakan kepada kami [Abdul Wahid bin Ziyad] berkata, telah menceritakan kepada kami [Ashim] dari [Asy Sya'bi] dari [Ibnu Abbas] ia berkata, \"Aku menginap di tempat bibiku, Maimunah. Kemudian Nabi shallallahu 'alaihi wasallam bangun dan shalat malam, lalu aku ikut dan berdiri di sisi kirinya, namun beliau meraihku dan meletakkan di sisi kanannya. \""},"931":{"ar":"حَدَّثَنَا بَكْرُ بْنُ خَلَفٍ أَبُو بِشْرٍ حَدَّثَنَا أَبُو بَكْرٍ الْحَنَفِيُّ حَدَّثَنَا الضَّحَّاكُ بْنُ عُثْمَانَ حَدَّثَنَا شُرَحْبِيلُ قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي الْمَغْرِبَ فَجِئْتُ فَقُمْتُ عَنْ يَسَارِهِ فَأَقَامَنِي عَنْ يَمِينِهِ","id":"Telah menceritakan kepada kami [Bakr bin Khalaf Abu Biysr] berkata, telah menceritakan kepada kami [Abu Bakr Al Hanafi] berkata, telah menceritakan kepada kami [Adl Dlahhak bin Utsman] berkata, telah menceritakan kepada kami [Syurahbil] ia berkata, \"Aku mendengar [Jabir bin Abdullah], ia berkata, \"Rasulullah shallallahu 'alaihi wasallam shalat maghrib, lalu aku datang dan berdiri di sisi kirinya, namun beliau memposisikan aku di sisi kanannya. \""},"932":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ اللَّهِ بْنِ الْمُخْتَارِ عَنْ مُوسَى بْنِ أَنَسٍ عَنْ أَنَسٍ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِامْرَأَةٍ مِنْ أَهْلِهِ وَبِي فَأَقَامَنِي عَنْ يَمِينِهِ وَصَلَّتْ الْمَرْأَةُ خَلْفَنَا","id":"telah menceritakan kepada kami [Nashr bin Ali] berkata, telah menceritakan kepada kami [Bapakku] berkata, telah menceritakan kepada kami [Syu'bah] dari [Abdullah Ibnul Mukhtar] dari [Musa bin Anas] dari [Anas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam shalat denganku dan seorang wanita dari isterinya, lalu beliau memposisikan aku di sisi kanannya dan wanita di belakang kami. \""},"933":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الْأَعْمَشِ عَنْ عُمَارَةَ بْنِ عُمَيْرٍ عَنْ أَبِي مَعْمَرٍ عَنْ أَبِي مَسْعُودٍ الْأَنْصَارِيِّ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْسَحُ مَنَاكِبَنَا فِي الصَّلَاةِ وَيَقُولُ لَا تَخْتَلِفُوا فَتَخْتَلِفَ قُلُوبُكُمْ لِيَلِيَنِّي مِنْكُمْ أُولُوا الْأَحْلَامِ وَالنُّهَى ثُمَّ الَّذِينَ يَلُونَهُمْ ثُمَّ الَّذِينَ يَلُونَهُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah memberitakan kepada kami [Sufyan bin Uyainah] dari [Al A'masy] dari [Umarah bin Umair] dari [Abu Ma'mar] dari [Abu Mas'ud Al Anshari] ia berkata, \"Ketika shalat Rasulullah shallallahu 'alaihi wasallam memegang pundak kami, lalu beliau bersabda: \"Janganlah kalian berselisih hingga hati kalian akan berselisih. Hendaklah yang di belakangku orang yang paling paham, kemudian orang yang di bawahnya kemudian orang yang di bawahnya. \" "},"934":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحِبُّ أَنْ يَلِيَهُ الْمُهَاجِرُونَ وَالْأَنْصَارُ لِيَأْخُذُوا عَنْهُ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Juhani] berkata, telah menceritakan kepada kami [Abdul Wahhab] berkata, telah menceritakan kepada kami [Humaid] dari [Anas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam menyukai jika orang yang di belakangnya adalah kaum Muhajirin dan Anshar hingga mereka dapat menjaganya. \""},"935":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا ابْنُ أَبِي زَائِدَةَ عَنْ أَبِي الْأَشْهَبِ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى فِي أَصْحَابِهِ تَأَخُّرًا فَقَالَ تَقَدَّمُوا فَأْتَمُّوا بِي وَلْيَأْتَمَّ بِكُمْ مَنْ بَعْدَكُمْ لَا يَزَالُ قَوْمٌ يَتَأَخَّرُونَ حَتَّى يُؤَخِّرَهُمْ اللَّهُ","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Ibnu Abu Za`idah] dari [Abu Al Asyhab] dari [Abu Nadlrah] dari [Abu Sa'id] berkata, \"Rasulullah shallallahu 'alaihi wasallam melihat pada sahabatnya orang-orang yang suka memilih shaf terakhir, maka beliau pun bersabda: \"Maju dan ikutilah aku, dan hendaklah orang-orang di belakang mengikuti kalian, akan senantiasa ada suatu kaum berlambat-lambat hingga Allah mengakhirkan mereka pada hari kiamat. \""},"936":{"ar":"حَدَّثَنَا بِشْرُ بْنُ هِلَالٍ الصَّوَّافُ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ عَنْ مَالِكِ بْنِ الْحُوَيْرِثِ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَا وَصَاحِبٌ لِي فَلَمَّا أَرَدْنَا الِانْصِرَافَ قَالَ لَنَا إِذَا حَضَرَتْ الصَّلَاةُ فَأَذِّنَا وَأَقِيمَا وَلْيَؤُمَّكُمَا أَكْبَرُكُمَا","id":"Telah menceritakan kepada kami [Bisyr bin Hilal Ash Shawwaf] berkata, telah menceritakan kepada kami [Yazid bin Zurai'] dari [Khalid Al Hadzdza`] dari [Abu Qilabah] dari [malik Ibnul Huwairits] ia berkata, \"Aku bersama dengan seorang temanku datang menemui Nabi shallallahu 'alaihi wasallam, maka ketika kami akan pergi beliau bersabda kepada kami: \"Jika waktu shalat tiba, maka adzan dan iqamahlah kalian, dan hendaklah yang paling besar dari kalian menjadi imam. \""},"937":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ إِسْمَعِيلَ بْنِ رَجَاءٍ قَالَ سَمِعْتُ أَوْسَ بْنَ ضَمْعَجٍ قَالَ سَمِعْتُ أَبَا مَسْعُودٍ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَؤُمُّ الْقَوْمَ أَقْرَؤُهُمْ لِكِتَابِ اللَّهِ فَإِنْ كَانَتْ قِرَاءَتُهُمْ سَوَاءً فَلْيَؤُمَّهُمْ أَقْدَمُهُمْ هِجْرَةً فَإِنْ كَانَتْ الْهِجْرَةُ سَوَاءً فَلْيَؤُمَّهُمْ أَكْبَرُهُمْ سِنًّا وَلَا يُؤَمَّ الرَّجُلُ فِي أَهْلِهِ وَلَا فِي سُلْطَانِهِ وَلَا يُجْلَسْ عَلَى تَكْرِمَتِهِ فِي بَيْتِهِ إِلَّا بِإِذْنٍ أَوْ بِإِذْنِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dari [Isma'il bin Raja`] Ia berkata; aku mendengar [Aus bin Dlam'aj] ia berkata; aku mendengar [Abu Mas'ud] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaknya yang menjadi imam pada suatu kaum yang paling banyak hafalan Al Qur'annya. Jika mereka sama dalam hafalan, maka yang paling dulu hijrah. Dan jika mereka sama dalam hijrah, maka yang paling tua. Seseorang tidak boleh diimami dalam keluarga dan kekuasaannya, serta tidak boleh duduk pada tempat khusus miliknya kecuali dengan izin darinya. \" "},"938":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سَعِيدُ بْنُ سُلَيْمَانَ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ سُلَيْمَانَ أَخُو فُلَيْحٍ حَدَّثَنَا أَبُو حَازِمٍ قَالَكَانَ سَهْلُ بْنُ سَعْدٍ السَّاعِدِيُّ يُقَدِّمُ فِتْيَانَ قَوْمِهِ يُصَلُّونَ بِهِمْ فَقِيلَ لَهُ تَفْعَلُ وَلَكَ مِنْ الْقِدَمِ مَا لَكَ قَالَ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْإِمَامُ ضَامِنٌ فَإِنْ أَحْسَنَ فَلَهُ وَلَهُمْ وَإِنْ أَسَاءَ يَعْنِي فَعَلَيْهِ وَلَا عَلَيْهِمْ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Sa'id bin Sulaiman] berkata, telah menceritakan kepada kami [Abdul Hamid bin Sulaiman] -saudara Fulaih- berkata, telah menceritakan kepada kami [Abu Hazim] ia berkata, \" [Sahl bin Sa'ad As Sa'idi] menunjuk seorang anak muda menjadi imam shalat bersama mereka, maka dikatakan kepadanya, \"Kamu melakukan hal itu, sedangkan kamu lebih dahulu masuk Islam! \" Ia menjawab, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Imam itu orang yang bertanggung jawab. Jika ia berlaku benar maka kebaikan itu baginya dan bagi mereka. Tetapi jika salah, maka kesalahan itu untuk dirinya dan bukan untuk mereka. \""},"939":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ أُمِّ غُرَابٍ عَنْ امْرَأَةٍ يُقَالُ لَهَا عَقِيلَةُ عَنْ سَلَامَةَ بِنْتِ الْحُرِّ أُخْتِ خَرَشَةَ قَالَتْسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَأْتِي عَلَى النَّاسِ زَمَانٌ يَقُومُونَ سَاعَةً لَا يَجِدُونَ إِمَامًا يُصَلِّي بِهِمْ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Waki'] dari [Ummu Ghurab] dari Seorang wanita yang disebut dengan nama [Aqilah], dari [Salamah binti Al Hur] saudara perempuan Kharasyah, ia berkata, \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Akan datang suatu masa pada manusia, mereka berdiri beberapa saat namun tidak mendapatkan seorang imam yang mengimami mereka. \""},"940":{"ar":"حَدَّثَنَا مُحْرِزُ بْنُ سَلَمَةَ الْعَدَنِيُّ حَدَّثَنَا ابْنُ أَبِي حَازِمٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ حَرْمَلَةَ عَنْ أَبِي عَلِيٍّ الْهَمْدَانِيِّأَنَّهُ خَرَجَ فِي سَفِينَةٍ فِيهَا عُقْبَةُ بْنُ عَامِرٍ الْجُهَنِيُّ فَحَانَتْ صَلَاةٌ مِنْ الصَّلَوَاتِ فَأَمَرْنَاهُ أَنْ يَؤُمَّنَا وَقُلْنَا لَهُ إِنَّكَ أَحَقُّنَا بِذَلِكَ أَنْتَ صَاحِبُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَبَى فَقَالَ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ أَمَّ النَّاسَ فَأَصَابَ فَالصَّلَاةُ لَهُ وَلَهُمْ وَمَنْ انْتَقَصَ مِنْ ذَلِكَ شَيْئًا فَعَلَيْهِ وَلَا عَلَيْهِمْ","id":"Telah menceritakan kepada kami [Muhriz bin Salamah Al Adani] berkata, telah menceritakan kepada kami [Ibnu Abu Hazim] dari ['Abdurrahman bin Harmalah] dari [Abu Ali Al Hamdani] Bahwasanya ia pernah bepergian dengan menggunakan kapal yang di dalamnya terdapat [uqbah bin Amir Al Juhani], lalu waktu shalat tiba hingga kami menyuruhnya untuk menjadi imam bagi kami, kami katakan padanya, \"Engkau lebih berhak untuk itu, engkau adalah sahabat Rasulullah shallallahu 'alaihi wasallam, \" namun ia menolak. Ia lalu berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menjadi imam bagi manusia, jika benar maka pahalanya untuknya dan untuk mereka. Namun jika tidak, maka ia menanggung dosanya dan tidak bagi mereka. \""},"941":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا إِسْمَعِيلُ عَنْ قَيْسٍ عَنْ أَبِي مَسْعُودٍ قَالَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي لَأَتَأَخَّرُ فِي صَلَاةِ الْغَدَاةِ مِنْ أَجْلِ فُلَانٍ لِمَا يُطِيلُ بِنَا فِيهَا قَالَ فَمَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَطُّ فِي مَوْعِظَةٍ أَشَدَّ غَضَبًا مِنْهُ يَوْمَئِذٍ فَقَالَ يَا أَيُّهَا النَّاسُ إِنَّ مِنْكُمْ مُنَفِّرِينَ فَأَيُّكُمْ مَا صَلَّى بِالنَّاسِ فَلْيُجَوِّزْ فَإِنَّ فِيهِمْ الضَّعِيفَ وَالْكَبِيرَ وَذَا الْحَاجَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] berkata, telah menceritakan kepada kami [Bapakku] berkata, telah menceritakan kepada kami [Isma'il] dari [Qais] dari [Abu Mas'ud] ia berkata, \"Seorang laki-laki menemui Nabi shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, aku berlambat-lambat menghadiri shalat subuh karena si Fulan panjang dalam bacaannya, \" Abu Mas'ud berkata, \"Aku tidak pernah melihat Rasulullah shallallahu 'alaihi wasallam memberi nasihat dengan kemarahan sebagaimana hari itu, beliau bersabda: \"Wahai manusia sekalian, sesungguhnya di antara kalian ada orang-orang yang menjadikan manusia lari! Siapa saja dari kalian shalat bersama orang banyak hendaklah memperingan shalatnya, sebab di antara mereka ada orang lemah, orang tua dan orang yang mempunyai keperluan. \""},"942":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ وَحُمَيْدُ بْنُ مَسْعَدَةَ قَالَا حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ أَنْبَأَنَا عَبْدُ الْعَزِيزِ بْنُ صُهَيْبٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوجِزُ وَيُتِمُّ الصَّلَاةَ","id":"Telah menceritakan kepada kami [Ahmad bin Abdah] dan [Humaid bin Mas'adah] keduanya berkata; telah menceritakan kepada kami [Hammad bin Zaid] berkata, telah memberitakan kepada kami [Abdul Aziz bin Shuhaib] dari [Anas bin Malik] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam memperingan shalat meskipun sempurna. \""},"943":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَصَلَّى مُعَاذُ بْنُ جَبَلٍ الْأَنْصَارِيُّ بِأَصْحَابِهِ صَلَاةَ الْعِشَاءِ فَطَوَّلَ عَلَيْهِمْ فَانْصَرَفَ رَجُلٌ مِنَّا فَصَلَّى فَأُخْبِرَ مُعَاذٌ عَنْهُ فَقَالَ إِنَّهُ مُنَافِقٌ فَلَمَّا بَلَغَ ذَلِكَ الرَّجُلَ دَخَلَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَهُ مَا قَالَ لَهُ مُعَاذٌ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتُرِيدُ أَنْ تَكُونَ فَتَّانًا يَا مُعَاذُ إِذَا صَلَّيْتَ بِالنَّاسِ فَاقْرَأْ بِالشَّمْسِ وَضُحَاهَا وَسَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى وَاللَّيْلِ إِذَا يَغْشَى وَاقْرَأْ بِاسْمِ رَبِّكَ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Abu Az Zubair] dari [Jabir] ia berkata, \"Mu'adz bin Jabal Al Anshari melaksanakan shalat isya bersama sahabatnya, ia memanjangkan shalat hingga ada seorang laki-laki dari kami keluar dan shalat sendirian. Mu'adz diberi kabar tentang laki-laki itu hingga dia berkata, \"Ia orang munafik. \" Ketika ucapan Mu'adz itu sampai kepada laki-laki tersebut, ia pun mendatangi Rasulullah shallallahu 'alaihi wasallam dan mengabarkan apa yang diucapkan oleh Mu'adz. Maka Nabi shallallahu 'alaihi wasallam pun bersabda: \"Wahai Mu'adz, apakah engkau akan menciptakan fitnah! Jika engkau shalat bersama manusia maka bacalah: WASY SYAMSI WA DLUHAHA, SABBIHISMA RABBIKAL A'LA dan WAL LAILI IDZA YAGHSYA. Bacalah BISMI RABBIKA. \""},"944":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ سَعِيدِ بْنِ أَبِي هِنْدٍ عَنْ مُطَرِّفِ بْنِ عَبْدِ اللَّهِ بْنِ الشِّخِّيرِ قَالَ سَمِعْتُ عُثْمَانَ بْنَ أَبِي الْعَاصِ يَقُولُكَانَ آخِرُ مَا عَهِدَ إِلَيَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ أَمَّرَنِي عَلَى الطَّائِفِ قَالَ لِي يَا عُثْمَانُ تَجَاوَزْ فِي الصَّلَاةِ وَاقْدِرْ النَّاسَ بِأَضْعَفِهِمْ فَإِنَّ فِيهِمْ الْكَبِيرَ وَالصَّغِيرَ وَالسَّقِيمَ وَالْبَعِيدَ وَذَا الْحَاجَةِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Isma'il bin Ulayyah] dari [Muhammad bin Ishaq] dari [Sa'id bin Abu Hind] dari [Mutharrif bin Abdullah bin Asy Syakhkhir] berkata; aku mendengar [Utsman bin Abu Al Ash] berkata, \"Ketika Nabi shallallahu 'alaihi wasallam mengutusku ke Tha`if, terakhir kali yang beliau katakan kepadaku adalah: \"Wahai Utsman, ringankanlah shalatmu, ukurlah manusia dengan orang yang paling lemah dari mereka. Sebab di antara mereka ada orang tua, anak kecil, orang sakit, musafir dan orang yang punya keperluan. \""},"945":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ إِسْمَعِيلَ حَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا يَحْيَى حَدَّثَنَا شُعْبَةُ حَدَّثَنَا عَمْرُو بْنُ مُرَّةَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ قَالَ حَدَّثَ عُثْمَانُ بْنُ أَبِي الْعَاصِأَنَّ آخِرَ مَا قَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَمَمْتَ قَوْمًا فَأَخِفَّ بِهِمْ","id":"Telah menceritakan kepada kami [Ali bin Isma'il] berkata, telah menceritakan kepada kami [Amru bin Ali] berkata, telah menceritakan kepada kami [Yahya] berkata, telah menceritakan kepada kami [Syu'bah] berkata, telah menceritakan kepada kami [Amru bin Murrah] dari [Sa'id Ibnul Musayyab] berkata, [Utsman bin Abu Al 'Ash] menceritakan bahwa terakhir yang dikatakan oleh Rasulullah shallallahu 'alaihi wasallam kepadaku adalah: \"Jika engkau mengimami suatu kaum, maka ringankanlah. \""},"946":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي لَأَدْخُلُ فِي الصَّلَاةِ وَإِنِّي أُرِيدُ إِطَالَتَهَا فَأَسْمَعُ بُكَاءَ الصَّبِيِّ فَأَتَجَوَّزُ فِي صَلَاتِي مِمَّا أَعْلَمُ لِوَجْدِ أُمِّهِ بِبُكَائِهِ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] berkata, telah menceritakan kepada kami [Abdul A'la] berkata, telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Anas bin Malik] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ketika shalat aku ingin memanjangkannya, namun aku mendengar tangisan anak kecil hingga aku mempercepatnya, sebab aku tahu kegundahan hati sang ibu karena tangisan bayinya. \""},"947":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبِي كَرِيمَةَ الْحَرَّانِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ عُلَاثَةَ عَنْ هِشَامِ بْنِ حَسَّانَ عَنْ الْحَسَنِ عَنْ عُثْمَانَ بْنِ أَبِي الْعَاصِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي لَأَسْمَعُ بُكَاءَ الصَّبِيِّ فَأَتَجَوَّزُ فِي الصَّلَاةِ","id":"Telah menceritakan kepada kami [Ismail bin Abu karimah Al Harrani] berkata, telah menceritakan kepada kami [Muhammad bin Salamah] dari [Muhammad bin Abdullah bin 'Ulatsah] dari [Hisyam bin Hassan] dari [Al Hasan] dari [Utsman bin Abul 'Ash] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku mendengar tangisan bayi, maka akupun mempercepat shalat. \""},"948":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ حَدَّثَنَا عُمَرُ بْنُ عَبْدِ الْوَاحِدِ وَبِشْرُ بْنُ بَكْرٍ عَنْ الْأَوْزَاعِيِّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي لَأَقُومُ فِي الصَّلَاةِ وَأَنَا أُرِيدُ أَنْ أُطَوِّلَ فِيهَا فَأَسْمَعُ بُكَاءَ الصَّبِيِّ فَأَتَجَوَّزُ كَرَاهِيَةَ أَنْ يَشُقَّ عَلَى أُمِّهِ","id":"Telah menceritakan kepada kami ['Abdurrahman bin Ibrahim] berkata, telah menceritakan kepada kami [Umar bin Abdul Wahid] dan [Biysr bin Bakr] dari [Al Auza'i] dari [Yahya bin Abu Katsir] dari [Abdullah bin Abu Qatadah] dari [Bapaknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh aku dalam keadaan shalat dan aku ingin memanjangkan shalatku, namun aku mendengar suara tangisan bayi hingga aku memperingan shalatku khawatir memperberat hati sang ibu. \""},"949":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ عَنْ الْمُسَيَّبِ بْنِ رَافِعٍ عَنْ تَمِيمِ بْنِ طَرَفَةَ عَنْ جَابِرِ بْنِ سَمُرَةَ السُّوَائِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا تَصُفُّونَ كَمَا تَصُفُّ الْمَلَائِكَةُ عِنْدَ رَبِّهَا قَالَ قُلْنَا وَكَيْفَ تَصُفُّ الْمَلَائِكَةُ عِنْدَ رَبِّهَا قَالَ يُتِمُّونَ الصُّفُوفَ الْأُوَلَ وَيَتَرَاصُّونَ فِي الصَّفِّ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Al A'masy] dari [Al Musayyab bin Rafi'] dari [Tamim bin Tharafah] dari [Jabir bin Samurah As Suwa`i] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak maukah kalian membuat barisan shalat sebagaimana barisannya para malaikat di hadapan Rabbnya?\" Jabir berkata, \"Kami bertanya, \"Bagaimana para malaikat membuat barisan di hadapan Rabbnya?\" beliau menjawab: \"Mereka menyempurnakan barisan pertama dan rapat dalam barisannya. \""},"950":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ شُعْبَةَ ح و حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ حَدَّثَنَا أَبِي وَبِشْرُ بْنُ عُمَرَ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَوُّوا صُفُوفَكُمْ فَإِنَّ تَسْوِيَةَ الصُّفُوفِ مِنْ تَمَامِ الصَّلَاةِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dari [Syu'bah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Nashr bin Ali] dari [Bapakku] dan [Bisyr bin Umar] keduanya berkata; telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Anas bin Malik] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Luruskanlah barisan kalian, sebab lurusnya barisan termasuk kesempurnaan shalat. \""},"951":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا سِمَاكُ بْنُ حَرْبٍ أَنَّهُ سَمِعَ النُّعْمَانَ بْنَ بَشِيرٍ يَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُسَوِّي الصَّفَّ حَتَّى يَجْعَلَهُ مِثْلَ الرُّمْحِ أَوْ الْقِدْحِ قَالَ فَرَأَى صَدْرَ رَجُلٍ نَاتِئًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَوُّوا صُفُوفَكُمْ أَوْ لَيُخَالِفَنَّ اللَّهُ بَيْنَ وُجُوهِكُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] berkata, telah menceritakan kepada kami [Simak bin Harb] Bahwasanya ia mendengar [An Nu'man bin Basyir] berkata, \"Rasulullah shallallahu 'alaihi wasallam meluruskan barisan seakan beliau menjadikannya seperti tombak atau anak panah. \" An Nu'man berkata, \"Suatu ketika beliau melihat dada seorang laki-laki menonjol ke depan, maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: Luruskanlah barisan kalian, atau Allah akan menceraikan antara wajah kalian! \""},"952":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ وَمَلَائِكَتَهُ يُصَلُّونَ عَلَى الَّذِينَ يَصِلُونَ الصُّفُوفَ وَمَنْ سَدَّ فُرْجَةً رَفَعَهُ اللَّهُ بِهَا دَرَجَةً","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Isma'il bin Ayyasy] berkata, telah menceritakan kepada kami [Hisyam bin Urwah] dari [Bapaknya] dari ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah dan para malaikat-Nya bershalawat bagi orang-orang yang menyambung barisan shalat, maka barangsiapa menutup celah dalam barisan tersebut Allah akan mengangkat derajatnya. \""},"953":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا هِشَامٌ الدَّسْتُوَائِيُّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ عِرْبَاضِ بْنِ سَارِيَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَسْتَغْفِرُ لِلصَّفِّ الْمُقَدَّمِ ثَلَاثًا وَلِلثَّانِي مَرَّةً","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yazid bin Harun] berkata, telah memberitakan kepada kami [Hisyam Ad Dastuwa`i] dari [Yahya bin Abu Katsir] dari [Muhammad bin Ibrahim] dari [Khalid bin Ma'dan] dari [Irbadl bin Sariyah] berkata, \"Rasulullah shallallahu 'alaihi wasallam memintakan ampun bagi orang-orang yang ada di barisan pertama tiga kali dan barisan kedua satu kali. \""},"954":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ وَمُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ طَلْحَةَ بْنَ مُصَرِّفٍ يَقُولُ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ عَوْسَجَةَ يَقُولُ سَمِعْتُ الْبَرَاءَ بْنَ عَازِبٍ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ وَمَلَائِكَتَهُ يُصَلُّونَ عَلَى الصَّفِّ الْأَوَّلِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dan [Muhammad bin Ja'far] berkata; telah menceritakan kepada kami [Syu'bah] berkata; aku mendengar [Thalhah bin Musharrif] berkata; aku mendengar ['Abdurrahman bin Aujasah] berkata; aku mendengar [Al Bara` bin Azib] berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah dan para malaikat-Nya memintakan ampun bagi orang-orang yang ada di barisan pertama. \""},"955":{"ar":"حَدَّثَنَا أَبُو ثَوْرٍ إِبْرَاهِيمُ بْنُ خَالِدٍ حَدَّثَنَا أَبُو قَطَنٍ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ خِلَاسٍ عَنْ أَبِي رَافِعٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ يَعْلَمُونَ مَا فِي الصَّفِّ الْأَوَّلِ لَكَانَتْ قُرْعَةٌ","id":"Telah menceritakan kepada kami [Abu Tsaur Ibrahim bin Khalid] berkata, telah menceritakan kepada kami [Abu Qathan] berkata, telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Khilas] dari [Abu Rafi'] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekiranya orang-orang tahu apa yang ada dalam barisan pertama sungguh mereka akan berundi. \""},"956":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُصَفَّى الْحِمْصِيُّ حَدَّثَنَا أَنَسُ بْنُ عِيَاضٍ حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرِو بْنِ عَلْقَمَةَ عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ وَمَلَائِكَتَهُ يُصَلُّونَ عَلَى الصَّفِّ الْأَوَّلِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mushaffa Al Himshi] berkata, telah menceritakan kepada kami [Anas bin 'Iyadl] berkata, telah menceritakan kepada kami [Muhammad bin Amru bin Alqamah] dari [Ibrahim bin 'Abdurrahman bin 'Auf] dari [Bapaknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah dan para Malaikat-Nya mengucapkan shalawat kepada orang-orang yang berada dalam shaf awal. \""},"957":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ الْعَلَاءِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ و عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرُ صُفُوفِ النِّسَاءِ آخِرُهَا وَشَرُّهَا أَوَّلُهَا وَخَيْرُ صُفُوفِ الرِّجَالِ أَوَّلُهَا وَشَرُّهَا آخِرُهَا","id":"Telah menceritakan kepada kami [Ahmad bin Abdah] berkata, telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Al 'Ala] dari [Bapaknya] dari [Abu Hurairah] dan (menurut jalur yang lain) dari [Suhail] dari [Bapaknya] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik shaf wanita adalah yang paling akhir dan yang paling buruk adalah yang paling depan. Dan sebaik-baik shaf laki-laki adalah yang paling depan dan yang paling buruk adalah yang paling belakang. \""},"958":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرُ صُفُوفِ الرِّجَالِ مُقَدَّمُهَا وَشَرُّهَا مُؤَخَّرُهَا وَخَيْرُ صُفُوفِ النِّسَاءِ مُؤَخَّرُهَا وَشَرُّهَا مُقَدَّمُهَا","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Abdullah bin Muhammad bin Aqil] dari [Jabir bin Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik shaf laki-laki adalah yang paling depan dan yang paling buruk adalah yang paling belakang. Dan sebaik-baik shaf wanita adalah yang paling akhir dan yang paling buruk adalah yang paling depan. \""},"959":{"ar":"حَدَّثَنَا زَيْدُ بْنُ أَخْزَمَ أَبُو طَالِبٍ حَدَّثَنَا أَبُو دَاوُدَ وَأَبُو قُتَيْبَةَ قَالَا حَدَّثَنَا هَارُونُ بْنُ مُسْلِمٍ عَنْ قَتَادَةَ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ عَنْ أَبِيهِ قَالَكُنَّا ن��نْهَى أَنْ نَصُفَّ بَيْنَ السَّوَارِي عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنُطْرَدُ عَنْهَا طَرْدًا","id":"Telah menceritakan kepada kami [Zaid bin Akhzam Abu Thalib] berkata, telah menceritakan kepada kami [Abu Dawud] dan [Abu Qutaibah] keduanya berkata; telah menceritakan kepada kami [Harun bin Muslim] dari [Qatadah] dari [Mu'awiyah bin Qurrah] dari [Bapaknya] ia berkata, \"Pada masa Rasulullah shallallahu 'alaihi wasallam kami dilarang membuat shaf antara tiang-tiang, maka kamipun meninggalkannya. \" "},"960":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُلَازِمُ بْنُ عَمْرٍو عَنْ عَبْدِ اللَّهِ بْنِ بَدْرٍ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ عَلِيِّ بْنِ شَيْبَانَ عَنْ أَبِيهِ عَلِيِّ بْنِ شَيْبَانَ وَكَانَ مِنْ الْوَفْدِ قَالَخَرَجْنَا حَتَّى قَدِمْنَا عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَايَعْنَاهُ وَصَلَّيْنَا خَلْفَهُ ثُمَّ صَلَّيْنَا وَرَاءَهُ صَلَاةً أُخْرَى فَقَضَى الصَّلَاةَ فَرَأَى رَجُلًا فَرْدًا يُصَلِّي خَلْفَ الصَّفِّ قَالَ فَوَقَفَ عَلَيْهِ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ انْصَرَفَ قَالَ اسْتَقْبِلْ صَلَاتَكَ لَا صَلَاةَ لِلَّذِي خَلْفَ الصَّفِّ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Mulazim bin Amru] dari [Abdullah bin Badr] berkata, telah menceritakan kepadaku ['Abdurrahman bin Ali bin Syaiban] dari bapaknya [Ali bin Syaiban] -ia adalah seorang utusan- ia berkata, \"Kami berangkat hingga akhirnya sampai di hadapan Nabi shallallahu 'alaihi wasallam, kemudian kami membai'at dan shalat di belakangnya. Setelah itu kami mengerjakan shalat yang lain di belakang beliau, dan selesai shalat beliau melihat seorang laki-laki shalat sendirian di belakang shaf. \" Ali bin Syaibah berkata, \"Ketika berlalu pergi Nabi shallallahu 'alaihi wasallam berhenti di sisi orang itu, beliau bersabda: \"Ulangilah shalatmu, sebab tidak ada shalat bagi orang yang shalat sendirian di belakang shaf. \""},"961":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ حُصَيْنٍ عَنْ هِلَالِ بْنِ يَسَافٍ قَالَأَخَذَ بِيَدِي زِيَادُ بْنُ أَبِي الْجَعْدِ فَأَوْقَفَنِي عَلَى شَيْخٍ بِالرَّقَّةِ يُقَالُ لَهُ وَابِصَةُ بْنُ مَعْبَدٍ فَقَالَ صَلَّى رَجُلٌ خَلْفَ الصَّفِّ وَحْدَهُ فَأَمَرَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُعِيدَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdullah bin Idris] dari [Hushain] dari [Hilal bin Yasaf] berkata; Ziyad bin Abu Al Ja'd memegang tanganku dan menempatkan aku di sisi seorang syaikh di Riqqah yang biasa disebut dengan nama [Wabishah bin Ma'bad]. Ia kemudian berkata, \"Ada seorang laki-laki shalat sendirian di belakang shaf, lalu Nabi shallallahu 'alaihi wasallam memerintahkan kepadanya untuk mengulangi shalat. \""},"962":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُعَاوِيَةُ بْنُ هِشَامٍ حَدَّثَنَا سُفْيَانُ عَنْ أُسَامَةَ بْنِ زَيْدٍ عَنْ عُثْمَانَ بْنِ عُرْوَةَ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ وَمَلَائِكَتَهُ يُصَلُّونَ عَلَى مَيَامِنِ الصُّفُوفِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Mu'awiyah bin Hisyam] berkata, telah menceritakan kepada kami [Sufyan] dari [Usamah bin Zaid] dari [Utsman bin Urwah] dari [Urwah] dari ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah dan para Malaikat-Nya mengucapkan shalawat kepada orang-orang yang berada dalam shaf bagian kanan. \""},"963":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ مِسْعَرٍ عَنْ ثَابِتِ بْنِ عُبَيْدٍ عَنْ ابْنِ الْبَرَاءِ بْنِ عَازِبٍ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَكُنَّا إِذَا صَلَّيْنَا خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مِسْعَرٌ مِمَّا نُحِبُّ أَوْ مِمَّا أُحِبُّ أَنْ نَقُومَ عَنْ يَمِينِهِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Mis'ar] dari [Tsabit bin Ubaid] dari [Ibnul Bara` bin Azib] dari [Al Bara` bin Azib] ia berkata, \"Jika kami shalat di belakang Rasulullah shallallahu 'alaihi wasallam, Mis'ar berkata, \"Kami suka, atau ia menyebutkan, \"aku suka berdiri di sebelah kanannya. \""},"964":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي الْحُسَيْنِ أَبُو جَعْفَرٍ حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ الْكِلَابِيُّ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَمْرٍو الرَّقِّيُّ عَنْ لَيْثِ بْنِ أَبِي سَلِيمٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقِيلَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مَيْسَرَةَ الْمَسْجِدِ تَعَطَّلَتْ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ عَمَّرَ مَيْسَرَةَ الْمَسْجِدِ كُتِبَ لَهُ كِفْلَانِ مِنْ الْأَجْرِ","id":"Telah menceritakan kepada kami [Muhammad bin Abul Husain Abu Ja'far] berkata, telah menceritakan kepada kami [Amru bin Utsman Al Kilabi] berkata, telah menceritakan kepada kami [Ubaidullah bin Amru Ar Raqqi] dari [Laits bin Abu Salim] dari [Nafi'] dari [Ibnu Umar] ia berkata; dikatakan kepada Nabi shallallahu 'alaihi wasallam; \"Sesungguhnya bagian kiri masjid menjadi kosong\". Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memakmurkan bagian kiri masjid maka akan ditulis baginya dua pahala. \""},"965":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ عُثْمَانَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ جَابِرٍ أَنَّهُ قَالَلَمَّا فَرَغَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ طَوَافِ الْبَيْتِ أَتَى مَقَامَ إِبْرَاهِيمَ فَقَالَ عُمَرُ يَا رَسُولَ اللَّهِ هَذَا مَقَامُ أَبِينَا إِبْرَاهِيمَ الَّذِي قَالَ اللَّهُ{ وَاتَّخِذُوا مِنْ مَقَامِ إِبْرَاهِيمَ مُصَلًّى }قَالَ الْوَلِيدُ فَقُلْتُ لِمَالِكٍ أَهَكَذَا قَرَأَ وَاتَّخِذُوا قَالَ نَعَمْ","id":"Telah menceritakan kepada kami [Al Abbas bin Utsman Ad Dimasyqi] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Malik bin Anas] dari [Ja'far bin Muhammad] dari [Bapaknya] dari [Jabir] Bahwasanya ia berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam selesai thawaf di Ka'bah, beliau mendatangi Maqam Ibrahim. Umar berkata, \"Wahai Rasulullah, ini adalah Maqam bapak kita Ibrahim yang Allah telah berfirman: \" (Dan jadikanlah sebahagian maqam Ibrahim tempat shalat). \" Al Walid berkata, \"Aku berkata kepada Malik, \"'dan jadikanlah' apakah demikian ia membaca?\" ia menjawab, \"Ya. \""},"966":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ حَدَّثَنَا هُشَيْمٌ عَنْ حُمَيْدٍ الطَّوِيلِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَ قَالَ عُمَرُقُلْتُ يَا رَسُولَ اللَّهِ لَوْ اتَّخَذْتَ مِنْ مَقَامِ إِبْرَاهِيمَ مُصَلًّى فَنَزَلَتْ{ وَاتَّخِذُوا مِنْ مَقَامِ إِبْرَاهِيمَ مُصَلًّى }","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah menceritakan kepada kami [Husyaim] dari [Humaid Ath Thawil] dari [Anas bin Malik] ia berkata, \" [Umar] berkata, \"Aku berkata, \"Wahai Rasulullah, sekiranya engkau jadikan maqam Ibrahim sebagai tempat shalat, \" lalu turunlah ayat; \" (Dan jadikanlah sebahagian maqam Ibrahim tempat shalat). \""},"967":{"ar":"حَدَّثَنَا عَلْقَمَةُ بْنُ عَمْرٍو الدَّارِمِيُّ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ قَالَصَلَّيْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ بَيْتِ الْمَقْدِسِ ثَمَانِيَةَ عَشَرَ شَهْرًا وَصُرِفَتْ الْقِبْلَةُ إِلَى الْكَعْبَةِ بَعْدَ دُخُولِهِ إِلَى الْمَدِينَةِ بِشَهْرَيْنِ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّى إِلَى بَيْتِ الْمَقْدِسِ أَكْثَرَ تَقَلُّبَ وَجْهِهِ فِي السَّمَاءِ وَعَلِمَ اللَّهُ مِنْ قَلْبِ نَبِيِّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ يَهْوَى الْكَعْبَةَ فَصَعِدَ جِبْرِيلُ فَجَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُتْبِعُهُ بَصَرَهُ وَهُوَ يَصْعَدُ بَيْنَ السَّمَاءِ وَالْأَرْضِ يَنْظُرُ مَا يَأْتِيهِ بِهِ فَأَنْزَلَ اللَّهُ{ قَدْ نَرَى تَقَلُّبَ وَجْهِكَ فِي السَّمَاءِ }الْآيَةَ فَأَتَانَا آتٍ فَقَالَ إِنَّ الْقِبْلَةَ قَدْ صُرِفَتْ إِلَى الْكَعْبَةِ وَقَدْ صَلَّيْنَا رَكْعَتَيْنِ إِلَى بَيْتِ الْمَقْدِسٍ وَنَحْنُ رُكُوعٌ فَتَحَوَّلْنَا فَبَنَيْنَا عَلَى مَا مَضَى مِنْ صَلَاتِنَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا جِبْرِيلُ كَيْفَ حَالُنَا فِي صَلَاتِنَا إِلَى بَيْتِ الْمَقْدِسِ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَمَا كَانَ اللَّهُ لِيُضِيعَ إِيمَانَكُمْ }","id":"Telah menceritakan kepada kami [Alqamah bin Amru Ad Darimi] berkata, telah menceritakan kepada kami [Abu Bakr bin Ayyasy] dari [Abu Ishaq] dari [Al Bara`] berkata, \"Kami shalat bersama Rasulullah shallallahu 'alaihi wasallam menghadap Baitul Maqdis selama delapan belas bulan, kemudian kiblat dialihkan ke Ka'bah kira-kira dua bulan setelah beliau di Madinah. Ketika shalat, Rasulullah shallallahu 'alaihi wasallam sering menghadapkan wajahnya ke langit, dan Allah tahu bahwa hati Nabi-Nya shallallahu 'alaihi wasallam cenderung ke Ka'bah. Lalu Jibril naik ke langit dan beliau terus memandanginya dengan matanya, beliau menunggu apa yang akan Allah perintahkan kepada Jibril. Maka Allah menurunkan ayat: \" (Sungguh Kami (sering) melihat mukamu menengadah ke langit). \" Lalu datanglah seorang pembawa berita kepada kami, ia mengatakan, \"Kiblat telah dialihkan ke Ka'bah, waktu itu kami telah shalat dua raka'at menghadap Baitul Maqdis, maka kami pun mengalihkan kiblat kami dan tetap menyempurnakan shalat (tidak membatalkan). \" Rasulullah shallallahu 'alaihi wasallam bertanya kepada Malaikat Jibril: \"Wahai Jibril, bagaimana dengan shalat kami ketika masih menghadap Baitul Maqdis?\" Maka Allah Azza wa Jala menurunkan ayat: \" (dan Allah tidak akan menyia-nyiakan imanmu. Sesungguhnya Allah Maha Pengasih lagi Maha Penyayang kepada manusia). \""},"968":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى الْأَزْدِيُّ حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ ح و حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى النَّيْسَابُورِيُّ قَالَ حَدَّثَنَا عَاصِمُ بْنُ عَلِيٍّ قَالَا حَدَّثَنَا أَبُو مَعْشَرٍ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا بَيْنَ الْمَشْرِقِ وَالْمَغْرِبِ قِبْلَةٌ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya Al Azdi] berkata, telah menceritakan kepada kami [Hasyim bin Al Qasim]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Yahya An Naisaburi] ia berkata; telah menceritakan kepada kami [Ashim bin Ali] keduanya berkata; telah menceritakan kepada kami [Abu Ma'syar] dari [Muhammad bin Amru] dari [Abu Salamah] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Antara timur dan barat adalah arah kiblat. \""},"969":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ الْحِزَامِيُّ وَيَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ قَالَا حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ عَنْ كَثِيرِ بْنِ زَيْدٍ عَنْ الْمُطَّلِبِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا دَخَلَ أَحَدُكُمْ الْمَسْجِدَ فَلَا يَجْلِسْ حَتَّى يَرْكَعَ رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir Al Hizami] dan [Ya'qub bin Humaid bin Kasib] keduanya berkata; telah menceritakan kepada kami [Ibnu Abu Fudaik] dari [Katsir bin Zaid] dari [Al Muththalib bin Abdullah] dari [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian masuk masjid, maka janganlah duduk hingga ia shalat dua raka'at. \""},"970":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ عُثْمَانَ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ عَامِرِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ عَمْرِو بْنِ سُلَيْمٍ الزُّرَقِيِّ عَنْ أَبِي قَتَادَةَأَنَّ النّ��بِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا دَخَلَ أَحَدُكُمْ الْمَسْجِدَ فَلْيُصَلِّ رَكْعَتَيْنِ قَبْلَ أَنْ يَجْلِسَ","id":"Telah menceritakan kepada kami [Al Abbas bin Utsman] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Malik bin Anas] dari [Amir bin Abdullah bin Az Zubair] dari [Amru bin Sulaim Az Zuraqqi] dari [Abu Qatadah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian masuk masjid hendaklah shalat dua raka'at sebelum ia duduk. \""},"971":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ الْغَطَفَانِيِّ عَنْ مَعْدَانَ بْنِ أَبِي طَلْحَةَ الْيَعْمُرِيِّأَنَّ عُمَرَ بْنَ الْخَطَّابِ قَامَ يَوْمَ الْجُمُعَةِ خَطِيبًا أَوْ خَطَبَ يَوْمَ الْجُمُعَةِ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ يَا أَيُّهَا النَّاسُ إِنَّكُمْ تَأْكُلُونَ شَجَرَتَيْنِ لَا أُرَاهُمَا إِلَّا خَبِيثَتَيْنِ هَذَا الثُّومُ وَهَذَا الْبَصَلُ وَلَقَدْ كُنْتُ أَرَى الرَّجُلَ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوجَدُ رِيحُهُ مِنْهُ فَيُؤْخَذُ بِيَدِهِ حَتَّى يُخْرَجَ إِلَى الْبَقِيعِ فَمَنْ كَانَ آكِلَهَا لَا بُدَّ فَلْيُمِتْهَا طَبْخًا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Isma'il bin Ulayyah] dari [Sa'id bin Abu Arubah] dari [Qatadah] dari [Salim bin Abu Al Ju'd Al Ghathafani] dari [Ma'dan bin Abu Thalhah Al Ya'muri] berkata, \" [Umar Ibnul Khaththab] berdiri khutbah di hari jum'at, atau berkhutbah pada hari jum'at. Ia bertahmid dan memuji Allah, kemudian berkata, \"Wahai manusia, kalian makan dua macam tumbuhan; bawang merah dan bawang putih, aku tidak melihatnya kecuali sesuatu yang kotor. Sungguh, pada masa Rasulullah shallallahu 'alaihi wasallam aku pernah mendapati seorang laki-laki yang mengeluarkan bau itu (bawang), lalu tangannya ditarik dan dibawa ke Bagi'. Maka barangsiapa memakannya hendaklah ia menghilangkan baunya dengan memasaknya. \""},"972":{"ar":"حَدَّثَنَا أَبُو مَرْوَانَ الْعُثْمَانِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَكَلَ مِنْ هَذِهِ الشَّجَرَةِ الثُّومِ فَلَا يُؤْذِينَا بِهَا فِي مَسْجِدِنَا هَذَاقَالَ إِبْرَاهِيمُ وَكَانَ أَبِي يَزِيدُ فِيهِ الْكُرَّاثَ وَالْبَصَلَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْنِي أَنَّهُ يَزِيدُ عَلَى حَدِيثِ أَبِي هُرَيْرَةَ فِي الثُّومِ","id":"Telah menceritakan kepada kami [Abu Marwan Al Utsmani] berkata, telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Ibnu Syihab] dari [Sa'id Ibnul Musayyab] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa makan tumbuhan ini, maka janganlah ia menyakiti kami di masjid kami ini. \" Ibrahim berkata, \"Bapakku menambahkan al Kurrats (bawang bakung) dan al Bashal (bawang merah) dalam hadits Nabi shallallahu 'alaihi wasallam tersebut. Yakni menambahi dari hadits Abu Hurairah yang berbicara tentang bawang. \""},"973":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ رَجَاءٍ الْمَكِّيُّ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَكَلَ مِنْ هَذِهِ الشَّجَرَةِ شَيْئًا فَلَا يَأْتِيَنَّ الْمَسْجِدَ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah menceritakan kepada kami [Abdullah bin Raja` Al Makki] dari [Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa makan sesuatu dari tumbuhan ini (bawang putih), maka jangan sekali-kali datang ke masjid. \""},"974":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ الطَّنَافِسِيُّ قَالَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَأَتَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَسْجِدَ قُبَاءَ يُصَلِّي فِيهِ فَجَاءَتْ رِجَالٌ مِنْ الْأَنْصَارِ يُسَلِّمُونَ عَلَيْهِ فَسَأَلْتُ صُهَيْبًا وَكَانَ مَعَهُ كَيْفَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرُدُّ عَلَيْهِمْ قَالَ كَانَ يُشِيرُ بِيَدِهِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad Ath Thanafisi] berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Zaid bin Aslam] dari [Abdullah bin Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam datang ke masjid Quba dan shalat di dalamnya. Kemudian datang beberapa laki-laki Anshar seraya memberi salam kepadanya. Aku bertanya kepada Shuhaib bagaimana Rasulullah shallallahu 'alaihi wasallam menjawab salam mereka, sebab ia waktu itu sedang bersamanya. Ia berkata, \"Beliau hanya berisyarat dengan tangannya. \" "},"975":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ الْمِصْرِيُّ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَبَعَثَنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِحَاجَةٍ ثُمَّ أَدْرَكْتُهُ وَهُوَ يُصَلِّي فَسَلَّمْتُ عَلَيْهِ فَأَشَارَ إِلَيَّ فَلَمَّا فَرَغَ دَعَانِي فَقَالَ إِنَّكَ سَلَّمْتَ عَلَيَّ آنِفًا وَأَنَا أُصَلِّي","id":"Telah menceritakan kepada kami [Muhammad bin Rumh Al Mishri] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Abu Zubair] dari [Jabir] ia berkata, \"Nabi shallallahu 'alaihi wasallam mengutusku untuk suatu keperluan, kemudian ketika kembali aku mendapati beliau sedang shalat, aku memberi salam kepada beliau, namun beliau hanya memberi isyarat kepadaku. Tatkala selesai, beliau memanggilku dan bersabda: \"Kamu memanggilku tadi, aku masih shalat. \" "},"976":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ سَعِيدٍ الدَّارِمِيُّ حَدَّثَنَا النَّضْرُ بْنُ شُمَيْلٍ حَدَّثَنَا يُونُسُ بْنُ أَبِي إِسْحَقَ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِ قَالَكُنَّا نُسَلِّمُ فِي الصَّلَاةِ فَقِيلَ لَنَا إِنَّ فِي الصَّلَاةِ لَشُغْلًا","id":"Telah menceritakan kepada kami [Ahmad bin Sa'id Ad Darimi] berkata, telah menceritakan kepada kami [An Nadlr bin Syumail] berkata, telah menceritakan kepada kami [Yunus bin Abu Ishaq] dari [Abu Ishaq] dari [Abu Al Ahwash] dari [Abdullah] ia berkata, \"Ketika shalat kami memberi shalat, \" lalu dikatakan kepada kami: \"Sesungguhnya dalam shalat ada kesibukan. \""},"977":{"ar":"حَدَّثَنَا يَحْيَى بْنُ حَكِيمٍ حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا أَشْعَثُ بْنُ سَعِيدٍ أَبُو الرَّبِيعِ السَّمَّانُ عَنْ عَاصِمِ بْنِ عُبَيْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عَامِرِ بْنِ رَبِيعَةَ عَنْ أَبِيهِ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَتَغَيَّمَتْ السَّمَاءُ وَأَشْكَلَتْ عَلَيْنَا الْقِبْلَةُ فَصَلَّيْنَا وَأَعْلَمْنَا فَلَمَّا طَلَعَتْ الشَّمْسُ إِذَا نَحْنُ قَدْ صَلَّيْنَا لِغَيْرِ الْقِبْلَةِ فَذَكَرْنَا ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنْزَلَ اللَّه{ فَأَيْنَمَا تُوَلُّوا فَثَمَّ وَجْهُ اللَّهِ }","id":"Telah menceritakan kepada kami [Yahya bin Hakim] berkata, telah menceritakan kepada kami [Abu Dawud] berkata, telah menceritakan kepada kami [Asy'ats bin Sa'id Abu Rabi' As Samman] dari [Ashim bin Ubaidullah] dari [Abdullah bin Amir bin Rabi'ah] dari [Bapaknya] ia berkata, \"Kami bersama Rasulullah shallallahu 'alaihi wasallam dalam perjalanan, sementara langit mendung dan menyulitkan kami untuk mengetahui arah kiblat. Ketika matahari terbit, kami mengetahui bahwa kami telah salah shalat bukan menghadap kiblat. Kemudian hal itu kami ceritakan kepada Nabi shallallahu 'alaihi wasallam, maka Allah pun menurunkan ayat: \" (Kemana saja kalian menghadap, maka di situlah wajah Allah). \""},"978":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ عَنْ طَارِقِ بْنِ عَبْدِ اللَّهِ الْمُحَارِبِيِّ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّيْتَ فَلَا تَبْزُقَنَّ بَيْنَ يَدَيْكَ وَلَا عَنْ يَمِينِكَ وَلَكِنْ ابْزُقْ عَنْ يَسَارِكَ أَوْ تَحْتَ قَدَمِكَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Manshur] dari [Rabi' bin Hirasy] dari [Thariq bin Abdullah Al Muharibi] Nabi shallallahu 'alaihi wasallam bersabda: \"Apabila kamu shalat, maka janganlah kamu membuang ludah di hadapan atau samping kananmu, akan tetapi meludahlah ke kiri atau di bawah kakimu. \" "},"979":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ الْقَاسِمِ بْنِ مِهْرَانَ عَنْ أَبِي رَافِعٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى نُخَامَةً فِي قِبْلَةِ الْمَسْجِدِ فَأَقْبَلَ عَلَى النَّاسِ فَقَالَ مَا بَالُ أَحَدِكُمْ يَقُومُ مُسْتَقْبِلَهُ يَعْنِي رَبَّهُ فَيَتَنَخَّعُ أَمَامَهُ أَيُحِبُّ أَحَدُكُمْ أَنْ يُسْتَقْبَلَ فَيُتَنَخَّعَ فِي وَجْهِهِ إِذَا بَزَقَ أَحَدُكُمْ فَلْيَبْزُقَنَّ عَنْ شِمَالِهِ أَوْ لِيَقُلْ هَكَذَا فِي ثَوْبِهِثُمَّ أَرَانِي إِسْمَعِيلُ يَبْزُقُ فِي ثَوْبِهِ ثُمَّ يَدْلُكُهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Isma'il bin Ulayyah] dari [Al Qasim bin Mihran] dari [Abu Rafi'] dari [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam melihat dahak di kiblat masjid, lalu beliau menghadap ke arah orang-orang dan bersabda: \"Kenapa salah seorang dari kalian berdiri di hadapan-Nya (Rabbnya) dan berdahak di depan-Nya? Apakah kalian suka jika seseorang berdiri di hadapannya kemudian meludah di depan mukanya? Jika salah seorang dari kalian ingin meludah hendaklah melakukannya di sebelah kirinya, atau membuang di kainnya seperti ini, \" Isma'il kemudian memperagakan kepadaku dengan meludah dalam kain miliknya, setelah itu menggosoknya. \""},"980":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ وَعَبْدُ اللَّهِ بْنُ عَامِرِ بْنِ زُرَارَةَ قَالَا حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ عَاصِمٍ عَنْ أَبِي وَائِلٍ عَنْ حُذَيْفَةَأَنَّهُ رَأَى شَبَثَ بْنَ رِبْعِيٍّ بَزَقَ بَيْنَ يَدَيْهِ فَقَالَ يَا شَبَثُ لَا تَبْزُقْ بَيْنَ يَدَيْكَ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَنْهَى عَنْ ذَلِكَ وَقَالَ إِنَّ الرَّجُلَ إِذَا قَامَ يُصَلِّي أَقْبَلَ اللَّهُ عَلَيْهِ بِوَجْهِهِ حَتَّى يَنْقَلِبَ أَوْ يُحْدِثَ حَدَثَ سُوءٍ","id":"Telah menceritakan kepada kami [Hannad bin As Sari] dan [Abdullah bin Amir bin Zurarah] keduanya berkata; telah menceritakan kepada kami [Abu Bakr bin 'Ayyasy] dari [Ashim] dari [Abu Wa`il] dari [Hudzaifah] Bahwasanya ia melihat Syabats bin Rabi'i membuang dahak di hadapannya, ia lalu berkata, \"Hai Syabats, janganlah kamu meludah di hadapanmu, sesungguhnya Rasulullah shallallahu 'alaihi wasallam melarang perbuatan itu, beliau bersabda: \"Jika seseorang shalat, Allah menemuinya dengan wajah-Nya hingga ia selesai shalat atau berhadats yang buruk (membatalkan shalat). \" "},"981":{"ar":"حَدَّثَنَا زَيْدُ بْنُ أَخْزَمَ وَعَبْدَةُ بْنُ عَبْدِ اللَّهِ قَالَا حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَزَقَ فِي ثَوْبِهِ وَهُوَ فِي الصَّلَاةِ ثُمَّ دَلَكَهُ","id":"Telah menceritakan kepada kami [Zaid bin Akhzam] dan ['Abdah bin Abdullah] keduanya berkata; telah menceritakan kepada kami [Abdu Ash Shamad] berkata, telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Anas bin Malik] berkata, \"Rasulullah shallallahu 'alaihi wasallam meludah di kainnya kemudian menggosoknya, padahal beliau dalam keadaan shalat. \" "},"982":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ مَسَّ الْحَصَى فَقَدْ لَغَا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengusap kerikil maka ia telah sia-sia. \""},"983":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ وَعَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ قَالَا حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ حَدَّثَنِي أَبُو سَلَمَةَ قَالَ حَدَّثَنِي مُعَيْقِيبٌ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَسْحِ الْحَصَى فِي الصَّلَاةِ إِنْ كُنْتَ فَاعِلًا فَمَرَّةً وَاحِدَةً","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shbbah] dan [Abdurrahman bin Ibrahim] keduanya berkata; telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Al Auza'i] berkata, telah menceritakan kepadaku [Yahya bin Abu Katsir] berkata, telah menceritakan kepada kami [Abu Salamah] berkata; telah menceritakan kepadaku [Mu'aiqib] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda berkenaan dengan hukum mengusap kerikil dalam shalat: \"Jika engkau harus melakukannya, maka cukup sekali saja. \""},"984":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ وَمُحَمَّدُ بْنُ الصَّبَّاحِ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ أَبِي الْأَحْوَصِ اللَّيْثِيِّ عَنْ أَبِي ذَرٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَامَ أَحَدُكُمْ إِلَى الصَّلَاةِ فَإِنَّ الرَّحْمَةَ تُوَاجِهُهُ فَلَا يَمْسَحْ بِالْحَصَى","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] dan [Muhammad bin Ash Shabbah] keduanya berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Abul Ahwash Al Laitsi] dari [Abu Dzar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian berdiri melaksanakan shalat, sesungguhnya rahmat sedang menuju kepada dirinya, maka janganlah mengusap kerikil. \""},"985":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبَّادُ بْنُ الْعَوَّامِ عَنْ الشَّيْبَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ شَدَّادٍ حَدَّثَتْنِي مَيْمُونَةُ زَوْجُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي عَلَى الْخُمْرَةِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abbad Ibnul Awwam] dari [Asy Syaibani] dari [Abdullah bin Syaddad] berkata, telah menceritakan kepadaku [Maimunah] isteri Nabi shallallahu 'alaihi wasallam, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam shalat di atas tikar kecil. \""},"986":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ عَنْ أَبِي سَعِيدٍ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى حَصِيرٍ","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir] dari [Abu Sa'id] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam shalat di atas tikar. \""},"987":{"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ حَدَّثَنِي زَمْعَةُ بْنُ صَالِحٍ عَنْ عَمْرِو بْنِ دِينَارٍ قَالَصَلَّى ابْنُ عَبَّاسٍ وَهُوَ بِالْبَصْرَةِ عَلَى بِسَاطِهِ ثُمَّ حَدَّثَ أَصْحَابَهُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي عَلَى بِسَاطِهِ","id":"Telah menceritakan kepada kami [Harmalah bin Yahya] berkata, telah menceritakan kepada kami [Abdullah bin Wahb] berkata, telah menceritakan kepadaku [Zam'ah bin Shalih] dari [Amru bin Dinar] ia berkata, \"Ketika di Bashrah, [Ibnu Abbas shalat] di atas karpet. Kemudian para sahabatnya menceritakan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam juga shalat di atas karpet. \""},"988":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ الدَّرَاوَرْدِيُّ عَنْ إِسْمَعِيلَ بْنِ أَبِي حَبِيبَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ قَالَجَاءَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى بِنَا فِي مَسْجِدِ بَنِي عَبْدِ الْأَشْهَلِ فَرَأَيْتُهُ وَاضِعًا يَدَيْهِ عَلَى ثَوْبِهِ إِذَا سَجَدَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdul Aziz bin Muhammad Ad Darawardi] dari [Isma'il bin Abu Habibah] dari [Abdullah bin 'Abdurrahman] ia berkata, \"Nabi shallallahu 'alaihi wasallam mendatangi kami dan shalat bersama kami di masjid Bani Abdul Asyhal, dan aku melihatnya meletakkan tangan di atas kainnya ketika sujud. \""},"989":{"ar":"حَدَّثَنَا جَعْفَرُ بْنُ مُسَافِرٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبِي أُوَيْسٍ أَخْبَرَنِي إِبْرَاهِيمُ بْنُ إِسْمَعِيلَ الْأَشْهَلِيُّ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ ثَابِتِ بْنِ الصَّامِتِ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى فِي بَنِي عَبْدِ الْأَشْهَلِ وَعَلَيْهِ كِسَاءٌ مُتَلَفِّفٌ بِهِ يَضَعُ يَدَيْهِ عَلَيْهِ يَقِيهِ بَرْدَ الْحَصَى","id":"Telah menceritakan kepada kami [Ja'far bin Musafir] berkata, telah menceritakan kepada kami [Isma'il bin Abu Uwais] berkata, telah mengabarkan kepadaku [Ibrahim bin Isma'il Al Asyhali] dari [Abdullah bin 'Abdurrahman bin Tsabit bin Ash Shamit] dari [Bapaknya] dari [Kakeknya] berkata, \"Rasulullah shallallahu 'alaihi wasallam shalat di Bani Abdul Asyhal dengan berselimut kain, dan beliau meletakkan tangannya di atas kain tersebut agar terhindar dari dinginnya pasir. \" "},"990":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ بْنِ حَبِيبٍ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ عَنْ غَالِبٍ الْقَطَّانِ عَنْ بَكْرِ بْنِ عَبْدِ اللَّهِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكُنَّا نُصَلِّي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي شِدَّةِ الْحَرِّ فَإِذَا لَمْ يَقْدِرْ أَحَدُنَا أَنْ يُمَكِّنَ جَبْهَتَهُ بَسَطَ ثَوْبَهُ فَسَجَدَ عَلَيْهِ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim bin Habib] berkata, telah menceritakan kepada kami [Biysr Ibnul Mufadldlal] dari [Ghalib bin Al Qaththan] dari [Bakr bin Abdullah] dari [Anas bin Malik] ia berkata, \"Kami pernah shalat bersama Nabi shallallahu 'alaihi wasallam di waktu yang sangat panas. Jika salah seorang dari kami tidak kuat meletakkan keningnya langsung ke pasir, maka ia membentangkan kain dan sujud di atasnya. \""},"991":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَهِشَامُ بْنُ عَمَّارٍ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ التَّسْبِيحُ لِلرِّجَالِ وَالتَّصْفِيقُ لِلنِّسَاءِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Hisyam bin Ammar] keduanya berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bagi laki-laki bertasbih dan bagi wanita menepukkan tangan. \""},"992":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ وَسَهْلُ بْنُ أَبِي سَهْلٍ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ التَّسْبِيحُ لِلرِّجَالِ وَالتَّصْفِيقُ لِلنِّسَاءِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] dan [Sahl bin Abu Sahl] keduanya berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Abu Hazim] dari [Sahl bin Sa'd As Sa'idi] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bagi laki-laki bertasbih dan bagi wanita menepukkan tangan. \""},"993":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا يَحْيَى بْنُ سُلَيْمٍ عَنْ إِسْمَعِيلَ بْنِ أُمَيَّةَ وَعُبَيْدُ اللَّهِ عَنْ نَافِعٍأَنَّهُ كَانَ يَقُولُ قَالَ ابْنُ عُمَرَ رَخَّصَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلنِّسَاءِ فِي التَّصْفِيقِ وَلِلرِّجَالِ فِي التَّسْبِيحِ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] berkata, telah menceritakan kepada kami [Yahya bin Sulaim] dari [Isma'il bin Umayyah] dan [Ubaidullah] dari [Nafi'] ia berkata; [Ibnu Umar] berkata, \"Rasulullah shallallahu 'alaihi wasallam memberi rukhsah (keringanan) bagi para wanita dengan menepuk tangan dan bagi lelaki dengan bertasbih. \""},"994":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا غُنْدَرٌ عَنْ شُعْبَةَ عَنْ النُّعْمَانِ بْنِ سَالِمٍ عَنْ ابْنِ أَبِي أَوْسٍ قَالَكَانَ جَدِّي أَوْسٌ أَحْيَانًا يُصَلِّي فَيُشِيرُ إِلَيَّ وَهُوَ فِي الصَّلَاةِ فَأُعْطِيهِ نَعْلَيْهِ وَيَقُولُ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِي نَعْلَيْهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ghundar] dari [Syu'bah] dari [An Nu'man bin Salim] dari [Ibnu Abu Aus] ia berkata, \" [Aus] kakekku, terkadang dalam shalat ia berisyarat kepadaku, lalu aku ambilkan sandal miliknya. Lalu berkata, \"Aku pernah melihat Rasulullah shallallahu 'alaihi wasallam shalat dengan mengenakan sandal. \""},"995":{"ar":"حَدَّثَنَا بِشْرُ بْنُ هِلَالٍ الصَّوَّافُ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ حُسَيْنٍ الْمُعَلِّمِ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي حَافِيًا وَمُنْتَعِلًا","id":"Telah menceritakan kepada kami [Bisyr bin Hilal Ash Shawwaf] berkata, telah menceritakan kepada kami [Yazid bin Zurai'] dari [Husain Al MuAllim] dari [Amru bin Syu'aib] dari [Bapaknya] dari [kakeknya] ia berkata, \"Aku melihat Rasulullah shallallahu 'alaihi wasallam shalat dengan sandal dan terkadang tidak. \""},"996":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا زُهَيْرٌ عَنْ أَبِي إِسْحَقَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَلَقَدْ رَأَيْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِي النَّعْلَيْنِ وَالْخُفَّيْنِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Yahya bin Adam] berkata, telah menceritakan kepada kami [Zuhair] dari [Abu Ishaq] dari [Alqamah] dari [Abdullah] ia berkata, \"Aku melihat Rasulullah shallallahu 'alaihi wasallam shalat dengan menggunakan sandal dan khuf. \""},"997":{"ar":"حَدَّثَنَا بِشْرُ بْنُ مُعَاذٍ الضَّرِيرُ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ وَأَبُو عَوَانَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُمِرْتُ أَنْ لَا أَكُفَّ شَعَرًا وَلَا ثَوْبًا","id":"Telah menceritakan kepada kami [Bisyr bin Mu'adz Adl Dlarir] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dan [Abu Awanah] dari [Amru bin Dinar] dari [Thawus] dari [Ibnu Abbas] ia berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Aku diperintahkan agar tidak menahan rambut dan kain. \""},"998":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ قَالَأُمِرْنَا أَلَّا نَكُفَّ شَعَرًا وَلَا ثَوْبًا وَلَا نَتَوَضَّأَ مِنْ مَوْطَإٍ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] berkata, telah menceritakan kepada kami [Abdullah bin Idris] dari [A'masy] dari [Abu Wa`il] dari [Abdullah] ia berkata, \"Kami diperintah untuk tidak menahan rambut dan kain saat sujud. Dan kami tidak diperintahkan untuk mengulang wudlu apabila menginjak kotoran. \""},"999":{"ar":"حَدَّثَنَا بَكْرُ بْنُ خَلَفٍ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ عَنْ شُعْبَةَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ أَخْبَرَنِي مُخَوَّلُ بْنُ رَاشِدٍ قَالَ سَمِعْتُ أَبَا سَعْدٍ رَجُلًا مِنْ أَهْلِ الْمَدِينَةِ يَقُولُرَأَيْتُ أَبَا رَافِعٍ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى الْحَسَنَ بْنَ عَلِيٍّ وَهُوَ يُصَلِّي وَقَدْ عَقَصَ شَعْرَهُ فَأَطْلَقَهُ أَوْ نَهَى عَنْهُ وَقَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُصَلِّيَ الرَّجُلُ وَهُوَ عَاقِصٌ شَعَرَهُ","id":"Telah menceritakan kepada kami [Bakr bin Khalaf] berkata, telah menceritakan kepada kami [Khalid Ibnul Harits] dari [Syu'bah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] berkata, telah menceritakan kepadaku [Mukhawwal bin Rasyid] berkata; Aku mendengar [Abu Sa'id] -seorang laki-laki dari Madinah- berkata; Aku melihat [Abu Rafi'] mantan budak Rasulullah shallallahu 'alaihi wasallam, ia pernah melihat Hasan bin Ali shalat dengan menyanggul rambut kemudian melepasnya, atau ia melarang hal hal demikian itu. Ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang seseorang shalat dengan menyanggul rambutnya. \""},"1000":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا طَلْحَةُ بْنُ يَحْيَى عَنْ يُونُسَ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَرْفَعُوا أَبْصَارَكُمْ إِلَى السَّمَاءِ أَنْ تَلْتَمِعَ يَعْنِي فِي الصَّلَاةِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Thalhah bin Yahya] dari [Yunus] dari [Az Zuhri] dari [Salim] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian mengangkat pandangan kalian ke atas langit hingga mata kalian buta. \" -Yakni dalam shalat-. "}};
